      else if (OPCT_IS(pa->instr_type, OPC_0F01))          v |= 0x0f0100;
      op1 = v >> 16;
      if (op1)          g(op1);
      op1 = (v >> 8) & 0xff;
      if (op1)          g(op1);
      g(v);
        if (OPCT_IS(pa->instr_type, OPC_SHIFT)) {
          reg = (opcode - pa->sym) / NBWLX;
          if (reg == 6)              reg = 7;

} else if (OPCT_IS(pa->instr_type, OPC_ARITH)) {
          reg = (opcode - pa->sym) / NBWLX;

} else if (OPCT_IS(pa->instr_type, OPC_FARITH)) {
          reg = (opcode - pa->sym) / 6;

} else {
          reg = (pa->instr_type >> OPC_GROUP_SHIFT) & 7;

}        pc = 0;
      if (pa->instr_type & OPC_MODRM) {
          /* if a register is used in another operand then it is             used instead of group */   if (modreg_index >= 0)       reg = ops[modreg_index].reg;
          pc = asm_modrm(reg, &ops[modrm_index]);

}        /* emit constants */  #ifndef TCC_TARGET_X86_64      if (!(pa->instr_type & OPC_0F)   && (pa->opcode == 0x9a || pa->opcode == 0xea)) {
          /* ljmp or lcall kludge */   gen_expr32(&ops[1].e);
          if (ops[0].e.sym)              tcc_error("cannot relocate");
          gen_le16(ops[0].e.v);
          return;

}  #endif      for(i = 0;
i < nb_ops;
 i++) {
          v = op_type[i];
          if (v & (OP_IM8 | OP_IM16 | OP_IM32 | OP_IM64 | OP_IM8S | OP_ADDR)) {
              /* if multiple sizes are given it means we must look                 at the op size */              if ((v | OP_IM8 | OP_IM64) == (OP_IM8 | OP_IM16 | OP_IM32 | OP_IM64)) {
                  if (s == 0)                      v = OP_IM8;
                  else if (s == 1)                      v = OP_IM16;
                  else if (s == 2 || (v & OP_IM64) == 0)                      v = OP_IM32;
                  else                      v = OP_IM64;

}                if ((v & (OP_IM8 | OP_IM8S | OP_IM16)) && ops[i].e.sym)                  tcc_error("cannot relocate");
                if (v & (OP_IM8 | OP_IM8S)) {
                  g(ops[i].e.v);

} else if (v & OP_IM16) {
                  gen_le16(ops[i].e.v);
  #ifdef TCC_TARGET_X86_64              
} else if (v & OP_IM64) {
                  gen_expr64(&ops[i].e);
  #endif       
} else if (pa->op_type[i] == OPT_DISP || pa->op_type[i] == OPT_DISP8) {
                  gen_disp32(&ops[i].e);

} else {
                  gen_expr32(&ops[i].e);

}          
}      
}        /* after immediate operands, adjust pc-relative address */      if (pc)          add32le(cur_text_section->data + pc - 4, pc - ind);

}

static inline int constraint_priority(const char *str)  {
      int priority, c, pr;
        /* we take the lowest priority */      priority = 0;
      for(;
;
) {
          c = *str;
          if (c == '\0')              break;
          str++;
          switch(c) {
          case 'A':              pr = 0;
              break;
          case 'a':          case 'b':          case 'c':          case 'd':          case 'S':          case 'D':              pr = 1;
              break;
          case 'q':              pr = 2;
              break;
          case 'r':   case 'R':   case 'p':              pr = 3;
              break;
          case 'N':          case 'M':          case 'I':   case 'e':          case 'i':          case 'm':          case 'g':              pr = 4;
              break;
          default:              tcc_error("unknown constraint '%c'", c);
              pr = 0;

}          if (pr > priority)              priority = pr;

}      return priority;

}

static const char *skip_constraint_modifiers(const char *p)  {
      while (*p == '=' || *p == '&' || *p == '+' || *p == '%')          p++;
      return p;

}

ST_FUNC int asm_parse_regvar (int t)  {
      const char *s;
      Operand op;
      if (t < TOK_IDENT || (t & SYM_FIELD))          return -1;
      s = table_ident[t - TOK_IDENT]->str;
      if (s[0] != '%')          return -1;
      t = tok_alloc_const(s + 1);
      unget_tok(t);
      unget_tok('%');
      parse_operand(tcc_state, &op);
      /* Accept only integer regs for now.  */      if (op.type & OP_REG)          return op.reg;
      else          return -1;

}

ST_FUNC void asm_compute_constraints(ASMOperand *operands,                                      int nb_operands, int nb_outputs,                                      const uint8_t *clobber_regs,                                      int *pout_reg)  {
      ASMOperand *op;
      int sorted_op[MAX_ASM_OPERANDS];
      int i, j, k, p1, p2, tmp, reg, c, reg_mask;
      const char *str;
      uint8_t regs_allocated[NB_ASM_REGS];
        /* init fields */      for(i=0;
i<nb_operands;
i++) {
          op = &operands[i];
          op->input_index = -1;
          op->ref_index = -1;
          op->reg = -1;
          op->is_memory = 0;
          op->is_rw = 0;

}      /* compute constraint priority and evaluate references to output         constraints if input constraints */      for(i=0;
i<nb_operands;
i++) {
          op = &operands[i];
          str = op->constraint;
          str = skip_constraint_modifiers(str);
          if (isnum(*str) || *str == '[') {
              /* this is a reference to another constraint */              k = find_constraint(operands, nb_operands, str, NULL);
              if ((unsigned)k >= i || i < nb_outputs)                  tcc_error("invalid reference in constraint %d ('%s')",                        i, str);
              op->ref_index = k;
              if (operands[k].input_index >= 0)                  tcc_error("cannot reference twice the same operand");
              operands[k].input_index = i;
              op->priority = 5;

} else if ((op->vt->r & VT_VALMASK) == VT_LOCAL       && op->vt->sym       && (reg = op->vt->sym->r & VT_VALMASK) < VT_CONST) {
       op->priority = 1;
       op->reg = reg;

} else {
              op->priority = constraint_priority(str);

}      
}        /* sort operands according to their priority */      for(i=0;
i<nb_operands;
i++)          sorted_op[i] = i;
      for(i=0;
i<nb_operands - 1;
i++) {
          for(j=i+1;
j<nb_operands;
j++) {
              p1 = operands[sorted_op[i]].priority;
              p2 = operands[sorted_op[j]].priority;
              if (p2 < p1) {
                  tmp = sorted_op[i];
                  sorted_op[i] = sorted_op[j];
                  sorted_op[j] = tmp;

}          
}      
}        for(i = 0;
i < NB_ASM_REGS;
 i++) {
          if (clobber_regs[i])              regs_allocated[i] = REG_IN_MASK | REG_OUT_MASK;
          else              regs_allocated[i] = 0;

}      /* esp cannot be used */      regs_allocated[4] = REG_IN_MASK | REG_OUT_MASK;
      /* ebp cannot be used yet */      regs_allocated[5] = REG_IN_MASK | REG_OUT_MASK;
        /* allocate registers and generate corresponding asm moves */      for(i=0;
i<nb_operands;
i++) {
          j = sorted_op[i];
          op = &operands[j];
          str = op->constraint;
          /* no need to allocate references */          if (op->ref_index >= 0)              continue;
          /* select if register is used for output, input or both */          if (op->input_index >= 0) {
              reg_mask = REG_IN_MASK | REG_OUT_MASK;

} else if (j < nb_outputs) {
              reg_mask = REG_OUT_MASK;

} else {
              reg_mask = REG_IN_MASK;

}   if (op->reg >= 0) {
       if (is_reg_allocated(op->reg))           tcc_error("asm regvar requests register that's taken already");
       reg = op->reg;

}      try_next:          c = *str++;
          switch(c) {
          case '=':              goto try_next;
          case '+':              op->is_rw = 1;
              /* FALL THRU */          case '&':              if (j >= nb_outputs)                  tcc_error("'%c' modifier can only be applied to outputs", c);
              reg_mask = REG_IN_MASK | REG_OUT_MASK;
              goto try_next;
          case 'A':              /* allocate both eax and edx */              if (is_reg_allocated(TREG_XAX) ||                  is_reg_allocated(TREG_XDX))                  goto try_next;
              op->is_llong = 1;
              op->reg = TREG_XAX;
              regs_allocated[TREG_XAX] |= reg_mask;
              regs_allocated[TREG_XDX] |= reg_mask;
              break;
          case 'a':              reg = TREG_XAX;
              goto alloc_reg;
          case 'b':              reg = 3;
              goto alloc_reg;
          case 'c':              reg = TREG_XCX;
              goto alloc_reg;
          case 'd':              reg = TREG_XDX;
              goto alloc_reg;
          case 'S':              reg = 6;
              goto alloc_reg;
          case 'D':              reg = 7;
          alloc_reg:              if (op->reg >= 0 && reg != op->reg)                  goto try_next;
              if (is_reg_allocated(reg))                  goto try_next;
              goto reg_found;
          case 'q':              /* eax, ebx, ecx or edx */              if (op->reg >= 0) {
                  if ((reg = op->reg) < 4)                      goto reg_found;

} else for(reg = 0;
 reg < 4;
 reg++) {
                  if (!is_reg_allocated(reg))                      goto reg_found;

}              goto try_next;
          case 'r':   case 'R':   case 'p': /* A general address, for x86(64) any register is acceptable*/              /* any general register */              if ((reg = op->reg) >= 0)                  goto reg_found;
              else for(reg = 0;
 reg < 8;
 reg++) {
                  if (!is_reg_allocated(reg))                      goto reg_found;

}              goto try_next;
          reg_found:              /* now we can reload in the register */              op->is_llong = 0;
              op->reg = reg;
              regs_allocated[reg] |= reg_mask;
              break;
   case 'e':          case 'i':              if (!((op->vt->r & (VT_VALMASK | VT_LVAL)) == VT_CONST))                  goto try_next;
              break;
          case 'I':          case 'N':          case 'M':              if (!((op->vt->r & (VT_VALMASK | VT_LVAL | VT_SYM)) == VT_CONST))                  goto try_next;
              break;
          case 'm':          case 'g':              /* nothing special to do because the operand is already in                 memory, except if the pointer itself is stored in a                 memory variable (VT_LLOCAL case) */              /* XXX: fix constant case */              /* if it is a reference to a memory zone, it must lie                 in a register, so we reserve the register in the                 input registers and a load will be generated                 later */              if (j < nb_outputs || c == 'm') {
                  if ((op->vt->r & VT_VALMASK) == VT_LLOCAL) {
                      /* any general register */                      for(reg = 0;
 reg < 8;
 reg++) {
                          if (!(regs_allocated[reg] & REG_IN_MASK))                              goto reg_found1;

}                      goto try_next;
                  reg_found1:                      /* now we can reload in the register */                      regs_allocated[reg] |= REG_IN_MASK;
                      op->reg = reg;
                      op->is_memory = 1;

}              
}              break;
          default:              tcc_error("asm constraint %d ('%s') could not be satisfied",                    j, op->constraint);
              break;

}          /* if a reference is present for that operand, we assign it too */          if (op->input_index >= 0) {
              operands[op->input_index].reg = op->reg;
              operands[op->input_index].is_llong = op->is_llong;

}      
}        /* compute out_reg. It is used to store outputs registers to memory         locations references by pointers (VT_LLOCAL case) */      *pout_reg = -1;
      for(i=0;
i<nb_operands;
i++) {
          op = &operands[i];
          if (op->reg >= 0 &&              (op->vt->r & VT_VALMASK) == VT_LLOCAL  &&              !op->is_memory) {
              for(reg = 0;
 reg < 8;
 reg++) {
                  if (!(regs_allocated[reg] & REG_OUT_MASK))                      goto reg_found2;

}              tcc_error("could not find free output register for reloading");
          reg_found2:              *pout_reg = reg;
              break;

}      
}        /* print sorted constraints */  #ifdef ASM_DEBUG      for(i=0;
i<nb_operands;
i++) {
          j = sorted_op[i];
          op = &operands[j];
          printf("%%%d [%s]: \"%s\" r=0x%04x reg=%d\n",                 j,                 op->id ? get_tok_str(op->id, NULL) : "",                 op->constraint,                 op->vt->r,                 op->reg);

}      if (*pout_reg >= 0)          printf("out_reg=%d\n", *pout_reg);
  #endif  
}

ST_FUNC void subst_asm_operand(CString *add_str,                                SValue *sv, int modifier)  {
      int r, reg, size, val;
        r = sv->r;
      if ((r & VT_VALMASK) == VT_CONST) {
          if (!(r & VT_LVAL) && modifier != 'c' && modifier != 'n' &&       modifier != 'P')              cstr_ccat(add_str, '$');
          if (r & VT_SYM) {
       const char *name = get_tok_str(sv->sym->v, NULL);
       if (sv->sym->v >= SYM_FIRST_ANOM) {
    /* In case of anonymous symbols ("L.42", used       for static data labels) we can't find them       in the C symbol table when later looking up       this name.  So enter them now into the asm label       list when we still know the symbol.  */    get_asm_sym(tok_alloc_const(name), sv->sym);

}              if (tcc_state->leading_underscore)                cstr_ccat(add_str, '_');
              cstr_cat(add_str, name, -1);
              if ((uint32_t)sv->c.i == 0)                  goto no_offset;
       cstr_ccat(add_str, '+');

}          val = sv->c.i;
          if (modifier == 'n')              val = -val;
          cstr_printf(add_str, "%d", (int)sv->c.i);
      no_offset:;
  #ifdef TCC_TARGET_X86_64          if (r & VT_LVAL)              cstr_cat(add_str, "(%rip)", -1);
  #endif      
} else if ((r & VT_VALMASK) == VT_LOCAL) {
          cstr_printf(add_str, "%d(%%%s)", (int)sv->c.i, get_tok_str(TOK_ASM_xax + 5, NULL));

} else if (r & VT_LVAL) {
          reg = r & VT_VALMASK;
          if (reg >= VT_CONST)              tcc_internal_error("");
          cstr_printf(add_str, "(%%%s)", get_tok_str(TOK_ASM_xax + reg, NULL));

} else {
          /* register case */          reg = r & VT_VALMASK;
          if (reg >= VT_CONST)              tcc_internal_error("");
            /* choose register operand size */          if ((sv->type.t & VT_BTYPE) == VT_BYTE ||       (sv->type.t & VT_BTYPE) == VT_BOOL)              size = 1;
          else if ((sv->type.t & VT_BTYPE) == VT_SHORT)              size = 2;
  #ifdef TCC_TARGET_X86_64          else if ((sv->type.t & VT_BTYPE) == VT_LLONG ||     (sv->type.t & VT_BTYPE) == VT_PTR)              size = 8;
  #endif          else              size = 4;
          if (size == 1 && reg >= 4)              size = 4;
            if (modifier == 'b') {
              if (reg >= 4)                  tcc_error("cannot use byte register");
              size = 1;

} else if (modifier == 'h') {
              if (reg >= 4)                  tcc_error("cannot use byte register");
              size = -1;

} else if (modifier == 'w') {
              size = 2;

} else if (modifier == 'k') {
              size = 4;
  #ifdef TCC_TARGET_X86_64          
} else if (modifier == 'q') {
              size = 8;
  #endif          
}            switch(size) {
          case -1:              reg = TOK_ASM_ah + reg;
              break;
          case 1:              reg = TOK_ASM_al + reg;
              break;
          case 2:              reg = TOK_ASM_ax + reg;
              break;
          default:              reg = TOK_ASM_eax + reg;
              break;
  #ifdef TCC_TARGET_X86_64          case 8:              reg = TOK_ASM_rax + reg;
              break;
  #endif          
}          cstr_printf(add_str, "%%%s", get_tok_str(reg, NULL));

}  
}

ST_FUNC void asm_gen_code(ASMOperand *operands, int nb_operands,                           int nb_outputs, int is_output,                           uint8_t *clobber_regs,                           int out_reg)  {
      uint8_t regs_allocated[NB_ASM_REGS];
      ASMOperand *op;
      int i, reg;
        /* Strictly speaking %Xbp and %Xsp should be included in the         call-preserved registers, but currently it doesn't matter.  */  #ifdef TCC_TARGET_X86_64  #ifdef TCC_TARGET_PE      static const uint8_t reg_saved[] = {
 3, 6, 7, 12, 13, 14, 15 
};
  #else      static const uint8_t reg_saved[] = {
 3, 12, 13, 14, 15 
};
  #endif  #else      static const uint8_t reg_saved[] = {
 3, 6, 7 
};
  #endif        /* mark all used registers */      memcpy(regs_allocated, clobber_regs, sizeof(regs_allocated));
      for(i = 0;
 i < nb_operands;
i++) {
          op = &operands[i];
          if (op->reg >= 0)              regs_allocated[op->reg] = 1;

}      if (!is_output) {
          /* generate reg save code */          for(i = 0;
 i < sizeof(reg_saved)/sizeof(reg_saved[0]);
 i++) {
              reg = reg_saved[i];
              if (regs_allocated[reg]) {
    if (reg >= 8)      g(0x41), reg-=8;
                  g(0x50 + reg);

}          
}            /* generate load code */          for(i = 0;
 i < nb_operands;
 i++) {
              op = &operands[i];
              if (op->reg >= 0) {
                  if ((op->vt->r & VT_VALMASK) == VT_LLOCAL &&                      op->is_memory) {
                      /* memory reference case (for both input and                         output cases) */                      SValue sv;
                      sv = *op->vt;
                      sv.r = (sv.r & ~VT_VALMASK) | VT_LOCAL | VT_LVAL;
                      sv.type.t = VT_PTR;
                      load(op->reg, &sv);

} else if (i >= nb_outputs || op->is_rw) {
                      /* load value in register */                      load(op->reg, op->vt);
                      if (op->is_llong) {
                          SValue sv;
                          sv = *op->vt;
                          sv.c.i += 4;
                          load(TREG_XDX, &sv);

}                  
}              
}          
}      
} else {
          /* generate save code */          for(i = 0;
 i < nb_outputs;
 i++) {
              op = &operands[i];
              if (op->reg >= 0) {
                  if ((op->vt->r & VT_VALMASK) == VT_LLOCAL) {
                      if (!op->is_memory) {
                          SValue sv;
                          sv = *op->vt;
                          sv.r = (sv.r & ~VT_VALMASK) | VT_LOCAL;
     sv.type.t = VT_PTR;
                          load(out_reg, &sv);
       sv = *op->vt;
                          sv.r = (sv.r & ~VT_VALMASK) | out_reg;
                          store(op->reg, &sv);

}                  
} else {
                      store(op->reg, op->vt);
                      if (op->is_llong) {
                          SValue sv;
                          sv = *op->vt;
                          sv.c.i += 4;
                          store(TREG_XDX, &sv);

}                  
}              
}          
}          /* generate reg restore code */          for(i = sizeof(reg_saved)/sizeof(reg_saved[0]) - 1;
 i >= 0;
 i--) {
              reg = reg_saved[i];
              if (regs_allocated[reg]) {
    if (reg >= 8)      g(0x41), reg-=8;
                  g(0x58 + reg);

}          
}      
}  
}

ST_FUNC void asm_clobber(uint8_t *clobber_regs, const char *str)  {
      int reg;
  #ifdef TCC_TARGET_X86_64      unsigned int type;
  #endif        if (!strcmp(str, "memory") ||          !strcmp(str, "cc") ||   !strcmp(str, "flags"))          return;
      reg = tok_alloc_const(str);
      if (reg >= TOK_ASM_eax && reg <= TOK_ASM_edi) {
          reg -= TOK_ASM_eax;

} else if (reg >= TOK_ASM_ax && reg <= TOK_ASM_di) {
          reg -= TOK_ASM_ax;
  #ifdef TCC_TARGET_X86_64      
} else if (reg >= TOK_ASM_rax && reg <= TOK_ASM_rdi) {
          reg -= TOK_ASM_rax;

} else if ((reg = asm_parse_numeric_reg(reg, &type)) >= 0) {
  ;
  #endif      
} else {
          tcc_error("invalid clobber register '%s'", str);

}      clobber_regs[reg] = 1;

}

static void out_byte(int c)  {
      *(char *)ind++ = c;

}

static void out_le32(int c)  {
      out_byte(c);
      out_byte(c >> 8);
      out_byte(c >> 16);
      out_byte(c >> 24);

}

static void init_outfile(void)  {
      if (!il_outfile) {
          il_outfile = stdout;
          fprintf(il_outfile,                   ".assembly extern mscorlib\n"                  "{
\n"                  ".ver 1:0:2411:0\n"                  "
}\n\n");

}  
}

static void out_op1(int op)  {
      if (op & 0x100)          out_byte(IL_OP_PREFIX);
      out_byte(op & 0xff);

}

static void out_op(int op)  {
      out_op1(op);
      fprintf(il_outfile, " %s\n", il_opcodes_str[op]);

}

static void out_opb(int op, int c)  {
      out_op1(op);
      out_byte(c);
      fprintf(il_outfile, " %s %d\n", il_opcodes_str[op], c);

}

static void out_opi(int op, int c)  {
      out_op1(op);
      out_le32(c);
      fprintf(il_outfile, " %s 0x%x\n", il_opcodes_str[op], c);

}

static void il_type_to_str(char *buf, int buf_size,                              int t, const char *varstr)  {
      int bt;
      Sym *s, *sa;
      char buf1[256];
      const char *tstr;
        t = t & VT_TYPE;
      bt = t & VT_BTYPE;
      buf[0] = '\0';
      if (t & VT_UNSIGNED)          pstrcat(buf, buf_size, "unsigned ");
      switch(bt) {
      case VT_VOID:          tstr = "void";
          goto add_tstr;
      case VT_BOOL:          tstr = "bool";
          goto add_tstr;
      case VT_BYTE:          tstr = "int8";
          goto add_tstr;
      case VT_SHORT:          tstr = "int16";
          goto add_tstr;
      case VT_ENUM:      case VT_INT:      case VT_LONG:          tstr = "int32";
          goto add_tstr;
      case VT_LLONG:          tstr = "int64";
          goto add_tstr;
      case VT_FLOAT:          tstr = "float32";
          goto add_tstr;
      case VT_DOUBLE:      case VT_LDOUBLE:          tstr = "float64";
      add_tstr:          pstrcat(buf, buf_size, tstr);
          break;
      case VT_STRUCT:          tcc_error("structures not handled yet");
          break;
      case VT_FUNC:          s = sym_find((unsigned)t >> VT_STRUCT_SHIFT);
          il_type_to_str(buf, buf_size, s->t, varstr);
          pstrcat(buf, buf_size, "(");
          sa = s->next;
          while (sa != NULL) {
              il_type_to_str(buf1, sizeof(buf1), sa->t, NULL);
              pstrcat(buf, buf_size, buf1);
              sa = sa->next;
              if (sa)                  pstrcat(buf, buf_size, ", ");

}          pstrcat(buf, buf_size, ")");
          goto no_var;
      case VT_PTR:          s = sym_find((unsigned)t >> VT_STRUCT_SHIFT);
          pstrcpy(buf1, sizeof(buf1), "*");
          if (varstr)              pstrcat(buf1, sizeof(buf1), varstr);
          il_type_to_str(buf, buf_size, s->t, buf1);
          goto no_var;

}      if (varstr) {
          pstrcat(buf, buf_size, " ");
          pstrcat(buf, buf_size, varstr);

}   no_var:;

}

static int out_opj(int op, int c)  {
      out_op1(op);
      out_le32(0);
      if (c == 0) {
          c = ind - (int)cur_text_section->data;

}      fprintf(il_outfile, " %s L%d\n", il_opcodes_str[op], c);
      return c;

}

void gsym(int t)  {
      fprintf(il_outfile, "L%d:\n", t);

}

void load(int r, SValue *sv)  {
      int v, fc, ft;
        v = sv->r & VT_VALMASK;
      fc = sv->c.i;
      ft = sv->t;
        if (sv->r & VT_LVAL) {
          if (v == VT_LOCAL) {
              if (fc >= ARG_BASE) {
                  fc -= ARG_BASE;
                  if (fc >= 0 && fc <= 4) {
                      out_op(IL_OP_LDARG_0 + fc);

} else if (fc <= 0xff) {
                      out_opb(IL_OP_LDARG_S, fc);

} else {
                      out_opi(IL_OP_LDARG, fc);

}              
} else {
                  if (fc >= 0 && fc <= 4) {
                      out_op(IL_OP_LDLOC_0 + fc);

} else if (fc <= 0xff) {
                      out_opb(IL_OP_LDLOC_S, fc);

} else {
                      out_opi(IL_OP_LDLOC, fc);

}              
}          
} else if (v == VT_CONST) {
                  /* XXX: handle globals */                  out_opi(IL_OP_LDSFLD, 0);

} else {
              if ((ft & VT_BTYPE) == VT_FLOAT) {
                  out_op(IL_OP_LDIND_R4);

} else if ((ft & VT_BTYPE) == VT_DOUBLE) {
                  out_op(IL_OP_LDIND_R8);

} else if ((ft & VT_BTYPE) == VT_LDOUBLE) {
                  out_op(IL_OP_LDIND_R8);

} else if ((ft & VT_TYPE) == VT_BYTE)                  out_op(IL_OP_LDIND_I1);
              else if ((ft & VT_TYPE) == (VT_BYTE | VT_UNSIGNED))                  out_op(IL_OP_LDIND_U1);
              else if ((ft & VT_TYPE) == VT_SHORT)                  out_op(IL_OP_LDIND_I2);
              else if ((ft & VT_TYPE) == (VT_SHORT | VT_UNSIGNED))                  out_op(IL_OP_LDIND_U2);
              else                  out_op(IL_OP_LDIND_I4);

}       
} else {
          if (v == VT_CONST) {
              /* XXX: handle globals */              if (fc >= -1 && fc <= 8) {
                  out_op(IL_OP_LDC_I4_M1 + fc + 1);

} else {
                  out_opi(IL_OP_LDC_I4, fc);

}          
} else if (v == VT_LOCAL) {
              if (fc >= ARG_BASE) {
                  fc -= ARG_BASE;
                  if (fc <= 0xff) {
                      out_opb(IL_OP_LDARGA_S, fc);

} else {
                      out_opi(IL_OP_LDARGA, fc);

}              
} else {
                  if (fc <= 0xff) {
                      out_opb(IL_OP_LDLOCA_S, fc);

} else {
                      out_opi(IL_OP_LDLOCA, fc);

}              
}          
} else {
              /* XXX: do it */          
}      
}  
}

void store(int r, SValue *sv)  {
      int v, fc, ft;
        v = sv->r & VT_VALMASK;
      fc = sv->c.i;
      ft = sv->t;
      if (v == VT_LOCAL) {
          if (fc >= ARG_BASE) {
              fc -= ARG_BASE;
              /* XXX: check IL arg store semantics */              if (fc <= 0xff) {
                  out_opb(IL_OP_STARG_S, fc);

} else {
                  out_opi(IL_OP_STARG, fc);

}          
} else {
              if (fc >= 0 && fc <= 4) {
                  out_op(IL_OP_STLOC_0 + fc);

} else if (fc <= 0xff) {
                  out_opb(IL_OP_STLOC_S, fc);

} else {
                  out_opi(IL_OP_STLOC, fc);

}          
}      
} else if (v == VT_CONST) {
          /* XXX: handle globals */          out_opi(IL_OP_STSFLD, 0);

} else {
          if ((ft & VT_BTYPE) == VT_FLOAT)              out_op(IL_OP_STIND_R4);
          else if ((ft & VT_BTYPE) == VT_DOUBLE)              out_op(IL_OP_STIND_R8);
          else if ((ft & VT_BTYPE) == VT_LDOUBLE)              out_op(IL_OP_STIND_R8);
          else if ((ft & VT_BTYPE) == VT_BYTE)              out_op(IL_OP_STIND_I1);
          else if ((ft & VT_BTYPE) == VT_SHORT)              out_op(IL_OP_STIND_I2);
          else              out_op(IL_OP_STIND_I4);

}  
}

void gfunc_start(GFuncContext *c, int func_call)  {
