 /* number of relocation entries */       coff_sec->s_flags = GetCoffFlags(coff_sec->s_name);
 /* flags */       coff_sec->s_reserved = 0;
 /* reserved byte */       coff_sec->s_page = 0;
 /* memory page id */         file_pointer += sizeof(SCNHDR);

}      
}        file_hdr.f_nscns = NSectionsToOutput;
 /* number of sections */        // now loop through and determine file pointer locations      // for the raw data          for (i = 1;
 i < s1->nb_sections;
 i++) {
   coff_sec = &section_header[i];
   tcc_sect = s1->sections[i];
     if (OutputTheSection(tcc_sect)) {
       // put raw data       coff_sec->s_scnptr = file_pointer;
 /* file ptr to raw data for section */       file_pointer += coff_sec->s_size;

}      
}        // now loop through and determine file pointer locations      // for the relocation data        for (i = 1;
 i < s1->nb_sections;
 i++) {
   coff_sec = &section_header[i];
   tcc_sect = s1->sections[i];
     if (OutputTheSection(tcc_sect)) {
       // put relocations data       if (coff_sec->s_nreloc > 0) {
    coff_sec->s_relptr = file_pointer;
 /* file ptr to relocation */    file_pointer += coff_sec->s_nreloc * sizeof(struct reloc);

}   
}      
}        // now loop through and determine file pointer locations      // for the line number data        for (i = 1;
 i < s1->nb_sections;
 i++) {
   coff_sec = &section_header[i];
   tcc_sect = s1->sections[i];
     coff_sec->s_nlnno = 0;
   coff_sec->s_lnnoptr = 0;
