}          fwrite(&CoffLineNo, 6, 1, f);
          last_pc = pc;
        last_line_num = sym->n_desc;
          break;
          /* include files */    case N_BINCL:        str =     (const char *) stabstr_section->data + sym->n_strx;
      add_incl2:        if (incl_index < INCLUDE_STACK_SIZE) {
