    csym.n_value = p->st_value;
 // physical address    csym.n_scnum = CoffTextSectionNo;
    csym.n_type = 0;
    csym.n_sclass = C_FCN;
    csym.n_numaux = 1;
    fwrite(&csym, 18, 1, f);
      // now put aux info      auxbf.regmask = 0;
    auxbf.lineno = 0;
    auxbf.nentries = FuncEntries[k];
    auxbf.localframe = 0;
    auxbf.nextentry = n + 6;
    auxbf.dummy = 0;
    fwrite(&auxbf, 18, 1, f);
      // put a .ef      strcpy(csym._n._n_name, ".ef");
    csym.n_value = EndAddress[k];
 // physical address      csym.n_scnum = CoffTextSectionNo;
    csym.n_type = 0;
    csym.n_sclass = C_FCN;
