static void put_stabs(TCCState *s1, const char *str, int type, int other, int desc,                        unsigned long value)  {
      Stab_Sym *sym;
        unsigned offset;
      if (type == N_SLINE          && (offset = stab_section->data_offset)          && (sym = (Stab_Sym*)(stab_section->data + offset) - 1)          && sym->n_type == type          && sym->n_value == value) {
          /* just update line_number in previous entry */          sym->n_desc = desc;
          return;

}        sym = section_ptr_add(stab_section, sizeof(Stab_Sym));
      if (str) {
          sym->n_strx = put_elf_str(stab_section->link, str);

} else {
          sym->n_strx = 0;

}      sym->n_type = type;
      sym->n_other = other;
      sym->n_desc = desc;
      sym->n_value = value;

}

static void put_stabs_r(TCCState *s1, const char *str, int type, int other, int desc,                          unsigned long value, Section *sec, int sym_index)  {
