static void dwarf_file(TCCState *s1)  {
      int i, j;
      char *filename;
      int index_offset = s1->dwarf < 5;
        if (!strcmp(file->filename, "<command line>")) {
          dwarf_line.cur_file = 1;
   return;

}      filename = strrchr(file->filename, '/');
      if (filename == NULL) {
          for (i = 1;
 i < dwarf_line.filename_size;
 i++)              if (dwarf_line.filename_table[i].dir_entry == 0 &&    strcmp(dwarf_line.filename_table[i].name,           file->filename) == 0) {
        dwarf_line.cur_file = i + index_offset;
               return;

}   i = -index_offset;
   filename = file->filename;

}      else {
   char *undo = filename;
   char *dir = file->filename;
     *filename++ = '\0';
          for (i = 0;
 i < dwarf_line.dir_size;
 i++)       if (strcmp(dwarf_line.dir_table[i], dir) == 0) {
    for (j = 1;
 j < dwarf_line.filename_size;
 j++)        if (dwarf_line.filename_table[j].dir_entry - index_offset     == i &&     strcmp(dwarf_line.filename_table[j].name,            filename) == 0) {
     *undo = '/';
            dwarf_line.cur_file = j + index_offset;
