static void tcc_debug_finish (TCCState *s1, struct _debug_info *cur)  {
      while (cur) {
          struct _debug_info *next = cur->next;
          int i;
            if (s1->dwarf) {
                for (i = cur->n_sym - 1;
 i >= 0;
 i--) {
                  struct debug_sym *s = &cur->sym[i];
      dwarf_data1(dwarf_info_section,                              s->type == N_PSYM         ? DWARF_ABBREV_FORMAL_PARAMETER         : s->type == N_GSYM                              ? DWARF_ABBREV_VARIABLE_EXTERNAL                              : s->type == N_STSYM         ? DWARF_ABBREV_VARIABLE_STATIC         : DWARF_ABBREV_VARIABLE_LOCAL);
                  dwarf_strp(dwarf_info_section, s->str);
    if (s->type == N_GSYM || s->type == N_STSYM) {
                      dwarf_uleb128(dwarf_info_section, s->file);
                      dwarf_uleb128(dwarf_info_section, s->line);

}                  dwarf_data4(dwarf_info_section, s->info - dwarf_info.start);
    if (s->type == N_GSYM || s->type == N_STSYM) {
        /* global/static */        if (s->type == N_GSYM)                          dwarf_data1(dwarf_info_section, 1);
                      dwarf_data1(dwarf_info_section, PTR_SIZE + 1);
                      dwarf_data1(dwarf_info_section, DW_OP_addr);
        if (s->type == N_STSYM)            dwarf_reloc(dwarf_info_section, section_sym, R_DATA_PTR);
  #if PTR_SIZE == 4                      dwarf_data4(dwarf_info_section, s->value);
  #else                      dwarf_data8(dwarf_info_section, s->value);
  #endif    
}    else {
        /* param/local */                      dwarf_data1(dwarf_info_section, dwarf_sleb128_size(s->value) + 1);
                      dwarf_data1(dwarf_info_section, DW_OP_fbreg);
                      dwarf_sleb128(dwarf_info_section, s->value);

}    tcc_free (s->str);

}              tcc_free (cur->sym);
              dwarf_data1(dwarf_info_section,     cur->child ? DWARF_ABBREV_LEXICAL_BLOCK                : DWARF_ABBREV_LEXICAL_EMPTY_BLOCK);
              dwarf_reloc(dwarf_info_section, section_sym, R_DATA_PTR);
  #if PTR_SIZE == 4              dwarf_data4(dwarf_info_section, func_ind + cur->start);
              dwarf_data4(dwarf_info_section, cur->end - cur->start);
  #else              dwarf_data8(dwarf_info_section, func_ind + cur->start);
              dwarf_data8(dwarf_info_section, cur->end - cur->start);
  #endif              tcc_debug_finish (s1, cur->child);
       if (cur->child)                  dwarf_data1(dwarf_info_section, 0);

}          else          {
              for (i = 0;
 i < cur->n_sym;
 i++) {
                  struct debug_sym *s = &cur->sym[i];
                    if (s->sec)                      put_stabs_r(s1, s->str, s->type, 0, 0, s->value,                                  s->sec, s->sym_index);
                  else                      put_stabs(s1, s->str, s->type, 0, 0, s->value);
                  tcc_free (s->str);

}              tcc_free (cur->sym);
              put_stabn(s1, N_LBRAC, 0, 0, cur->start);
              tcc_debug_finish (s1, cur->child);
              put_stabn(s1, N_RBRAC, 0, 0, cur->end);

}          tcc_free (cur);
          cur = next;

}  
}

ST_FUNC void tcc_add_debug_info(TCCState *s1, int param, Sym *s, Sym *e)  {
      CString debug_str;
        if (!(s1->do_debug & 2))          return;
        cstr_new (&debug_str);
      for (;
 s != e;
 s = s->prev) {
          if (!s->v || (s->r & VT_VALMASK) != VT_LOCAL)              continue;
   if (s1->dwarf) {
       tcc_debug_stabs(s1, get_tok_str(s->v, NULL),         param ? N_PSYM : N_LSYM, s->c, NULL, 0,         tcc_get_dwarf_info(s1, s));

}   else          {
              cstr_reset (&debug_str);
              cstr_printf (&debug_str, "%s:%s", get_tok_str(s->v, NULL),      param ? "p" : "");
              tcc_get_debug_info(s1, s, &debug_str);
              tcc_debug_stabs(s1, debug_str.data, param ? N_PSYM : N_LSYM,         s->c, NULL, 0, 0);

}      
}      cstr_free (&debug_str);

}

ST_FUNC void tcc_debug_funcstart(TCCState *s1, Sym *sym)  {
      CString debug_str;
      BufferedFile *f;
        if (!s1->do_debug)          return;
      debug_info_root = NULL;
      debug_info = NULL;
      tcc_debug_stabn(s1, N_LBRAC, ind - func_ind);
      f = put_new_file(s1);
      if (!f)   return;
        if (s1->dwarf) {
          tcc_debug_line(s1);
          dwarf_info.func = sym;
          dwarf_info.line = file->line_num;
   if (s1->do_backtrace) {
       int i, len;
         dwarf_line_op(s1, 0);
 // extended       dwarf_uleb128_op(s1, strlen(funcname) + 2);
       dwarf_line_op(s1, DW_LNE_hi_user - 1);
       len = strlen(funcname) + 1;
       for (i = 0;
 i < len;
 i++)    dwarf_line_op(s1, funcname[i]);

}      
}      else      {
          cstr_new (&debug_str);
          cstr_printf(&debug_str, "%s:%c", funcname, sym->type.t & VT_STATIC ? 'f' : 'F');
          tcc_get_debug_info(s1, sym->type.ref, &debug_str);
          put_stabs_r(s1, debug_str.data, N_FUN, 0, f->line_num, 0, cur_text_section, sym->c);
          cstr_free (&debug_str);
          tcc_debug_line(s1);

}  
}

ST_FUNC void tcc_debug_prolog_epilog(TCCState *s1, int value)  {
      if (!s1->do_debug)          return;
      if (s1->dwarf) {
   dwarf_line_op(s1, value == 0 ? DW_LNS_set_prologue_end           : DW_LNS_set_epilogue_begin);

}  
}

ST_FUNC void tcc_debug_funcend(TCCState *s1, int size)  {
      /* lldb does not like function end and next function start at same pc */      int min_instr_len;
    #if TCC_EH_FRAME      tcc_debug_frame_end(s1, size);
  #endif      if (!s1->do_debug)          return;
      min_instr_len = dwarf_line.last_pc == ind ? 0 : DWARF_MIN_INSTR_LEN;
      ind -= min_instr_len;
      tcc_debug_line(s1);
      ind += min_instr_len;
      tcc_debug_stabn(s1, N_RBRAC, size);
      if (s1->dwarf) {
          int func_sib = 0;
   Sym *sym = dwarf_info.func;
   int n_debug_info = tcc_get_dwarf_info(s1, sym->type.ref);
            dwarf_data1(dwarf_info_section,       sym->type.t & VT_STATIC ? DWARF_ABBREV_SUBPROGRAM_STATIC          : DWARF_ABBREV_SUBPROGRAM_EXTERNAL);
          if ((sym->type.t & VT_STATIC) == 0)              dwarf_data1(dwarf_info_section, 1);
          dwarf_strp(dwarf_info_section, funcname);
          dwarf_uleb128(dwarf_info_section, dwarf_line.cur_file);
          dwarf_uleb128(dwarf_info_section, dwarf_info.line);
   tcc_debug_check_anon(s1, sym->type.ref, dwarf_info_section->data_offset);
          dwarf_data4(dwarf_info_section, n_debug_info - dwarf_info.start);
          dwarf_reloc(dwarf_info_section, section_sym, R_DATA_PTR);
  #if PTR_SIZE == 4          dwarf_data4(dwarf_info_section, func_ind);
 // low_pc          dwarf_data4(dwarf_info_section, size);
 // high_pc  #else          dwarf_data8(dwarf_info_section, func_ind);
 // low_pc          dwarf_data8(dwarf_info_section, size);
 // high_pc  #endif          func_sib = dwarf_info_section->data_offset;
          dwarf_data4(dwarf_info_section, 0);
 // sibling          dwarf_data1(dwarf_info_section, 1);
  #if defined(TCC_TARGET_I386)          dwarf_data1(dwarf_info_section, DW_OP_reg5);
 // ebp  #elif defined(TCC_TARGET_X86_64)          dwarf_data1(dwarf_info_section, DW_OP_reg6);
 // rbp  #elif defined TCC_TARGET_ARM          dwarf_data1(dwarf_info_section, DW_OP_reg13);
 // sp  #elif defined TCC_TARGET_ARM64          dwarf_data1(dwarf_info_section, DW_OP_reg29);
 // reg 29  #elif defined TCC_TARGET_RISCV64          dwarf_data1(dwarf_info_section, DW_OP_reg8);
 // r8(s0)  #else          dwarf_data1(dwarf_info_section, DW_OP_call_frame_cfa);
  #endif          tcc_debug_finish (s1, debug_info_root);
   dwarf_data1(dwarf_info_section, 0);
          write32le(dwarf_info_section->data + func_sib,                    dwarf_info_section->data_offset - dwarf_info.start);

}      else      {
          tcc_debug_finish (s1, debug_info_root);

}      debug_info_root = 0;

}

ST_FUNC void tcc_debug_extern_sym(TCCState *s1, Sym *sym, int sh_num, int sym_bind, int sym_type)  {
      if (!(s1->do_debug & 2))          return;
        if (sym_type == STT_FUNC || sym->v >= SYM_FIRST_ANOM)          return;
      if (s1->dwarf) {
          int debug_type;
            debug_type = tcc_get_dwarf_info(s1, sym);
   dwarf_data1(dwarf_info_section,        sym_bind == STB_GLOBAL        ? DWARF_ABBREV_VARIABLE_EXTERNAL        : DWARF_ABBREV_VARIABLE_STATIC);
   dwarf_strp(dwarf_info_section, get_tok_str(sym->v, NULL));
   dwarf_uleb128(dwarf_info_section, dwarf_line.cur_file);
   dwarf_uleb128(dwarf_info_section, file->line_num);
   tcc_debug_check_anon(s1, sym, dwarf_info_section->data_offset);
   dwarf_data4(dwarf_info_section, debug_type - dwarf_info.start);
   if (sym_bind == STB_GLOBAL)       dwarf_data1(dwarf_info_section, 1);
   dwarf_data1(dwarf_info_section, PTR_SIZE + 1);
   dwarf_data1(dwarf_info_section, DW_OP_addr);
   greloca(dwarf_info_section, sym, dwarf_info_section->data_offset,    R_DATA_PTR, 0);
  #if PTR_SIZE == 4   dwarf_data4(dwarf_info_section, 0);
  #else   dwarf_data8(dwarf_info_section, 0);
  #endif      
}      else      {
          Section *s = sh_num == SHN_COMMON ? common_section         : s1->sections[sh_num];
          CString str;
            cstr_new (&str);
          cstr_printf (&str, "%s:%c",                  get_tok_str(sym->v, NULL),                  sym_bind == STB_GLOBAL ? 'G' : func_ind != -1 ? 'V' : 'S'                  );
          tcc_get_debug_info(s1, sym, &str);
          if (sym_bind == STB_GLOBAL)              tcc_debug_stabs(s1, str.data, N_GSYM, 0, NULL, 0, 0);
          else              tcc_debug_stabs(s1, str.data,                  (sym->type.t & VT_STATIC) && data_section == s                  ? N_STSYM : N_LCSYM, 0, s, sym->c, 0);
          cstr_free (&str);

}  
}

