   if (debug_type != -1) {
       dwarf_data1(dwarf_info_section, DWARF_ABBREV_TYPEDEF);
       dwarf_strp(dwarf_info_section, get_tok_str(sym->v, NULL));
       dwarf_uleb128(dwarf_info_section, dwarf_line.cur_file);
