        if (tcov_data.last_file_name == 0 ||   strcmp ((const char *)(tcov_section->data + tcov_data.last_file_name),    file->true_filename) != 0) {
   char wd[1024];
   CString cstr;
     if (tcov_data.last_func_name)       section_ptr_add(tcov_section, 1);
   if (tcov_data.last_file_name)       section_ptr_add(tcov_section, 1);
   tcov_data.last_func_name = 0;
   cstr_new (&cstr);
   if (file->true_filename[0] == '/') {
       tcov_data.last_file_name = tcov_section->data_offset;
       cstr_printf (&cstr, "%s", file->true_filename);

}   else {
       getcwd (wd, sizeof(wd));
       tcov_data.last_file_name = tcov_section->data_offset + strlen(wd) + 1;
       cstr_printf (&cstr, "%s/%s", wd, file->true_filename);

}   ptr = section_ptr_add(tcov_section, cstr.size + 1);
   strcpy((char *)ptr, cstr.data);
  #ifdef _WIN32          normalize_slashes((char *)ptr);
  #endif   cstr_free (&cstr);

}      if (tcov_data.last_func_name == 0 ||   strcmp ((const char *)(tcov_section->data + tcov_data.last_func_name),    funcname) != 0) {
   size_t len;
     if (tcov_data.last_func_name)       section_ptr_add(tcov_section, 1);
   tcov_data.last_func_name = tcov_section->data_offset;
   len = strlen (funcname);
   ptr = section_ptr_add(tcov_section, len + 1);
   strcpy((char *)ptr, funcname);
   section_ptr_add(tcov_section, -tcov_section->data_offset & 7);
   ptr = section_ptr_add(tcov_section, 8);
   write64le (ptr, file->line_num);

}      if (ind == tcov_data.ind && tcov_data.line == file->line_num)          tcov_data.offset = last_offset;
      else {
          Sym label = {
0
};
          label.type.t = VT_LLONG | VT_STATIC;
            ptr = section_ptr_add(tcov_section, 16);
          tcov_data.line = file->line_num;
          write64le (ptr, (tcov_data.line << 8) | 0xff);
          put_extern_sym(&label, tcov_section,           ((unsigned char *)ptr - tcov_section->data) + 8, 0);
          sv.type = label.type;
          sv.r = VT_SYM | VT_LVAL | VT_CONST;
          sv.r2 = VT_CONST;
          sv.c.i = 0;
          sv.sym = &label;
  #if defined TCC_TARGET_I386 || defined TCC_TARGET_X86_64 || \      defined TCC_TARGET_ARM || defined TCC_TARGET_ARM64 || \      defined TCC_TARGET_RISCV64          gen_increment_tcov (&sv);
  #else          vpushv(&sv);
          inc(0, TOK_INC);
          vpop();
  #endif          tcov_data.offset = (unsigned char *)ptr - tcov_section->data;
          tcov_data.ind = ind;

}  
}

ST_FUNC void tcc_tcov_block_end(TCCState *s1, int line)  {
      if (s1->test_coverage == 0)   return;
      if (line == -1)          line = tcov_data.line;
      if (tcov_data.offset) {
   void *ptr = tcov_section->data + tcov_data.offset;
   unsigned long long nline = line ? line : file->line_num;
     write64le (ptr, (read64le (ptr) & 0xfffffffffull) | (nline << 36));
   tcov_data.offset = 0;

}  
}

ST_FUNC void tcc_tcov_check_line(TCCState *s1, int start)  {
      if (s1->test_coverage == 0)   return;
      if (tcov_data.line != file->line_num) {
          if ((tcov_data.line + 1) != file->line_num) {
       tcc_tcov_block_end (s1, -1);
       if (start)                  tcc_tcov_block_begin (s1);

}   else       tcov_data.line = file->line_num;

}  
}

ST_FUNC void tcc_tcov_start(TCCState *s1)  {
      if (s1->test_coverage == 0)   return;
      if (!s1->dState)          s1->dState = tcc_mallocz(sizeof *s1->dState);
      memset (&tcov_data, 0, sizeof (tcov_data));
      if (tcov_section == NULL) {
          tcov_section = new_section(tcc_state, ".tcov", SHT_PROGBITS,         SHF_ALLOC | SHF_WRITE);
   section_ptr_add(tcov_section, 4);
 // pointer to executable name      
}  
}

ST_FUNC void tcc_tcov_end(TCCState *s1)  {
      if (s1->test_coverage == 0)   return;
      if (tcov_data.last_func_name)          section_ptr_add(tcov_section, 1);
      if (tcov_data.last_file_name)          section_ptr_add(tcov_section, 1);

}

ST_FUNC void tcc_tcov_reset_ind(TCCState *s1)  {
      tcov_data.ind = 0;

}

ST_FUNC void tccelf_new(TCCState *s)  {
      TCCState *s1 = s;
        /* no section zero */      dynarray_add(&s->sections, &s->nb_sections, NULL);
        /* create standard sections */      text_section = new_section(s, ".text", SHT_PROGBITS, SHF_ALLOC | SHF_EXECINSTR);
      data_section = new_section(s, ".data", SHT_PROGBITS, SHF_ALLOC | SHF_WRITE);
      /* create ro data section (make ro after relocation done with GNU_RELRO) */      rodata_section = new_section(s, rdata, SHT_PROGBITS, shf_RELRO);
      bss_section = new_section(s, ".bss", SHT_NOBITS, SHF_ALLOC | SHF_WRITE);
      common_section = new_section(s, ".common", SHT_NOBITS, SHF_PRIVATE);
      common_section->sh_num = SHN_COMMON;
        /* symbols are always generated for linking stage */      symtab_section = new_symtab(s, ".symtab", SHT_SYMTAB, 0,                                  ".strtab",                                  ".hashtab", SHF_PRIVATE);
        /* private symbol table for dynamic symbols */      s->dynsymtab_section = new_symtab(s, ".dynsymtab", SHT_SYMTAB, SHF_PRIVATE|SHF_DYNSYM,                                        ".dynstrtab",                                        ".dynhashtab", SHF_PRIVATE);
      get_sym_attr(s, 0, 1);
        if (s->do_debug) {
          /* add debug sections */          tcc_debug_new(s);

}    #if TCC_EH_FRAME      tcc_eh_frame_start(s);
  #endif    #ifdef CONFIG_TCC_BCHECK      if (s->do_bounds_check) {
          /* if bound checking, then add corresponding sections */          /* (make ro after relocation done with GNU_RELRO) */          bounds_section = new_section(s, ".bounds", SHT_PROGBITS, shf_RELRO);
          lbounds_section = new_section(s, ".lbounds", SHT_PROGBITS, shf_RELRO);

}  #endif  
}

ST_FUNC void free_section(Section *s)  {
      if (!s)          return;
      tcc_free(s->data);
      s->data = NULL;
      s->data_allocated = s->data_offset = 0;

}

ST_FUNC void tccelf_delete(TCCState *s1)  {
      int i;
    #ifndef ELF_OBJ_ONLY      /* free symbol versions */      for (i = 0;
 i < nb_sym_versions;
 i++) {
          tcc_free(sym_versions[i].version);
          tcc_free(sym_versions[i].lib);

}      tcc_free(sym_versions);
      tcc_free(sym_to_version);
  #endif        /* free all sections */      for(i = 1;
 i < s1->nb_sections;
 i++)          free_section(s1->sections[i]);
      dynarray_reset(&s1->sections, &s1->nb_sections);
        for(i = 0;
 i < s1->nb_priv_sections;
 i++)          free_section(s1->priv_sections[i]);
      dynarray_reset(&s1->priv_sections, &s1->nb_priv_sections);
        tcc_free(s1->sym_attrs);
      symtab_section = NULL;
 /* for tccrun.c:rt_printline() */  
}

ST_FUNC void tccelf_begin_file(TCCState *s1)  {
      Section *s;
 int i;
      for (i = 1;
 i < s1->nb_sections;
 i++) {
          s = s1->sections[i];
          s->sh_offset = s->data_offset;

}      /* disable symbol hashing during compilation */      s = s1->symtab, s->reloc = s->hash, s->hash = NULL;
  #if defined TCC_TARGET_X86_64 && defined TCC_TARGET_PE      s1->uw_sym = 0;
      s1->uw_offs = 0;
  #endif  
}

ST_FUNC void tccelf_end_file(TCCState *s1)  {
      Section *s = s1->symtab;
      int first_sym, nb_syms, *tr, i;
        first_sym = s->sh_offset / sizeof (ElfSym);
      nb_syms = s->data_offset / sizeof (ElfSym) - first_sym;
      s->data_offset = s->sh_offset;
      s->link->data_offset = s->link->sh_offset;
      s->hash = s->reloc, s->reloc = NULL;
      tr = tcc_mallocz(nb_syms * sizeof *tr);
        for (i = 0;
 i < nb_syms;
 ++i) {
          ElfSym *sym = (ElfSym*)s->data + first_sym + i;
          if (sym->st_shndx == SHN_UNDEF) {
              int sym_bind = ELFW(ST_BIND)(sym->st_info);
              int sym_type = ELFW(ST_TYPE)(sym->st_info);
              if (sym_bind == STB_LOCAL)                  sym_bind = STB_GLOBAL;
  #ifndef TCC_TARGET_PE              if (sym_bind == STB_GLOBAL && s1->output_type == TCC_OUTPUT_OBJ) {
                  /* undefined symbols with STT_FUNC are confusing gnu ld when                     linking statically to STT_GNU_IFUNC */                  sym_type = STT_NOTYPE;

}  #endif              sym->st_info = ELFW(ST_INFO)(sym_bind, sym_type);

}          tr[i] = set_elf_sym(s, sym->st_value, sym->st_size, sym->st_info,              sym->st_other, sym->st_shndx, (char*)s->link->data + sym->st_name);

}      /* now update relocations */      update_relocs(s1, s, tr, first_sym);
      tcc_free(tr);
      /* record text/data/bss output for -bench info */      for (i = 0;
 i < 4;
 ++i) {
          s = s1->sections[i + 1];
          s1->total_output[i] += s->data_offset - s->sh_offset;

}  
}

ST_FUNC Section *new_section(TCCState *s1, const char *name, int sh_type, int sh_flags)  {
      Section *sec;
        sec = tcc_mallocz(sizeof(Section) + strlen(name));
      sec->s1 = s1;
      strcpy(sec->name, name);
      sec->sh_type = sh_type;
      sec->sh_flags = sh_flags;
      switch(sh_type) {
      case SHT_GNU_versym:          sec->sh_addralign = 2;
          break;
      case SHT_HASH:      case SHT_GNU_HASH:      case SHT_REL:      case SHT_RELA:      case SHT_DYNSYM:      case SHT_SYMTAB:      case SHT_DYNAMIC:      case SHT_GNU_verneed:      case SHT_GNU_verdef:          sec->sh_addralign = PTR_SIZE;
          break;
      case SHT_STRTAB:          sec->sh_addralign = 1;
          break;
      default:          sec->sh_addralign =  PTR_SIZE;
 /* gcc/pcc default alignment */          break;

}        if (sh_flags & SHF_PRIVATE) {
          dynarray_add(&s1->priv_sections, &s1->nb_priv_sections, sec);

} else {
          sec->sh_num = s1->nb_sections;
          dynarray_add(&s1->sections, &s1->nb_sections, sec);

}        return sec;

}

ST_FUNC void init_symtab(Section *s)  {
      int *ptr, nb_buckets = 1;
      put_elf_str(s->link, "");
      section_ptr_add(s, sizeof (ElfW(Sym)));
      ptr = section_ptr_add(s->hash, (2 + nb_buckets + 1) * sizeof(int));
      ptr[0] = nb_buckets;
      ptr[1] = 1;
      memset(ptr + 2, 0, (nb_buckets + 1) * sizeof(int));

}

ST_FUNC Section *new_symtab(TCCState *s1,                             const char *symtab_name, int sh_type, int sh_flags,                             const char *strtab_name,                             const char *hash_name, int hash_sh_flags)  {
      Section *symtab, *strtab, *hash;
      symtab = new_section(s1, symtab_name, sh_type, sh_flags);
      symtab->sh_entsize = sizeof(ElfW(Sym));
      strtab = new_section(s1, strtab_name, SHT_STRTAB, sh_flags);
      symtab->link = strtab;
      hash = new_section(s1, hash_name, SHT_HASH, hash_sh_flags);
      hash->sh_entsize = sizeof(int);
      symtab->hash = hash;
      hash->link = symtab;
      init_symtab(symtab);
      return symtab;

}

ST_FUNC void section_realloc(Section *sec, unsigned long new_size)  {
      unsigned long size;
      unsigned char *data;
        size = sec->data_allocated;
      if (size == 0)          size = 1;
      while (size < new_size)          size = size * 2;
      data = tcc_realloc(sec->data, size);
      memset(data + sec->data_allocated, 0, size - sec->data_allocated);
      sec->data = data;
      sec->data_allocated = size;

}

ST_FUNC size_t section_add(Section *sec, addr_t size, int align)  {
      size_t offset, offset1;
        offset = (sec->data_offset + align - 1) & -align;
      offset1 = offset + size;
      if (sec->sh_type != SHT_NOBITS && offset1 > sec->data_allocated)          section_realloc(sec, offset1);
      sec->data_offset = offset1;
      if (align > sec->sh_addralign)          sec->sh_addralign = align;
      return offset;

}

ST_FUNC void *section_ptr_add(Section *sec, addr_t size)  {
      size_t offset = section_add(sec, size, 1);
      return sec->data + offset;

}

static Section *have_section(TCCState *s1, const char *name)  {
      Section *sec;
      int i;
      for(i = 1;
 i < s1->nb_sections;
 i++) {
          sec = s1->sections[i];
          if (!strcmp(name, sec->name))              return sec;

}      return NULL;

}

ST_FUNC Section *find_section(TCCState *s1, const char *name)  {
      Section *sec = have_section(s1, name);
      if (sec)          return sec;
      /* sections are created as PROGBITS */      return new_section(s1, name, SHT_PROGBITS, SHF_ALLOC);

}

ST_FUNC int put_elf_str(Section *s, const char *sym)  {
      int offset, len;
      char *ptr;
        len = strlen(sym) + 1;
      offset = s->data_offset;
      ptr = section_ptr_add(s, len);
      memmove(ptr, sym, len);
      return offset;

}

static ElfW(Word) elf_hash(const unsigned char *name)  {
      ElfW(Word) h = 0, g;
        while (*name) {
          h = (h << 4) + *name++;
          g = h & 0xf0000000;
          if (g)              h ^= g >> 24;
          h &= ~g;

}      return h;

}

static void rebuild_hash(Section *s, unsigned int nb_buckets)  {
      ElfW(Sym) *sym;
      int *ptr, *hash, nb_syms, sym_index, h;
      unsigned char *strtab;
        strtab = s->link->data;
      nb_syms = s->data_offset / sizeof(ElfW(Sym));
        if (!nb_buckets)          nb_buckets = ((int*)s->hash->data)[0];
        s->hash->data_offset = 0;
      ptr = section_ptr_add(s->hash, (2 + nb_buckets + nb_syms) * sizeof(int));
      ptr[0] = nb_buckets;
      ptr[1] = nb_syms;
      ptr += 2;
      hash = ptr;
      memset(hash, 0, (nb_buckets + 1) * sizeof(int));
      ptr += nb_buckets + 1;
        sym = (ElfW(Sym) *)s->data + 1;
      for(sym_index = 1;
 sym_index < nb_syms;
 sym_index++) {
          if (ELFW(ST_BIND)(sym->st_info) != STB_LOCAL) {
              h = elf_hash(strtab + sym->st_name) % nb_buckets;
              *ptr = hash[h];
              hash[h] = sym_index;

} else {
              *ptr = 0;

}          ptr++;
          sym++;

}  
}

ST_FUNC int put_elf_sym(Section *s, addr_t value, unsigned long size,      int info, int other, int shndx, const char *name)  {
      int name_offset, sym_index;
      int nbuckets, h;
      ElfW(Sym) *sym;
      Section *hs;
        sym = section_ptr_add(s, sizeof(ElfW(Sym)));
      if (name && name[0])          name_offset = put_elf_str(s->link, name);
      else          name_offset = 0;
      /* XXX: endianness */      sym->st_name = name_offset;
      sym->st_value = value;
      sym->st_size = size;
      sym->st_info = info;
      sym->st_other = other;
      sym->st_shndx = shndx;
      sym_index = sym - (ElfW(Sym) *)s->data;
      hs = s->hash;
      if (hs) {
          int *ptr, *base;
          ptr = section_ptr_add(hs, sizeof(int));
          base = (int *)hs->data;
          /* only add global or weak symbols. */          if (ELFW(ST_BIND)(info) != STB_LOCAL) {
              /* add another hashing entry */              nbuckets = base[0];
              h = elf_hash((unsigned char *)s->link->data + name_offset) % nbuckets;
              *ptr = base[2 + h];
              base[2 + h] = sym_index;
              base[1]++;
              /* we resize the hash table */              hs->nb_hashed_syms++;
              if (hs->nb_hashed_syms > 2 * nbuckets) {
                  rebuild_hash(s, 2 * nbuckets);

}          
} else {
              *ptr = 0;
              base[1]++;

}      
}      return sym_index;

}

ST_FUNC int find_elf_sym(Section *s, const char *name)  {
      ElfW(Sym) *sym;
      Section *hs;
      int nbuckets, sym_index, h;
      const char *name1;
        hs = s->hash;
      if (!hs)          return 0;
      nbuckets = ((int *)hs->data)[0];
      h = elf_hash((unsigned char *) name) % nbuckets;
      sym_index = ((int *)hs->data)[2 + h];
      while (sym_index != 0) {
          sym = &((ElfW(Sym) *)s->data)[sym_index];
          name1 = (char *) s->link->data + sym->st_name;
          if (!strcmp(name, name1))              return sym_index;
          sym_index = ((int *)hs->data)[2 + nbuckets + sym_index];

}      return 0;

}

ST_FUNC addr_t get_sym_addr(TCCState *s1, const char *name, int err, int forc)  {
      int sym_index;
      ElfW(Sym) *sym;
      char buf[256];
      if (forc && s1->leading_underscore  #ifdef TCC_TARGET_PE          /* win32-32bit stdcall symbols always have _ already */          && !strchr(name, '@')  #endif          ) {
          buf[0] = '_';
          pstrcpy(buf + 1, sizeof(buf) - 1, name);
          name = buf;

}      sym_index = find_elf_sym(s1->symtab, name);
      sym = &((ElfW(Sym) *)s1->symtab->data)[sym_index];
      if (!sym_index || sym->st_shndx == SHN_UNDEF) {
          if (err)              tcc_error_noabort("%s not defined", name);
          return (addr_t)-1;

}      return sym->st_value;

}

LIBTCCAPI void *tcc_get_symbol(TCCState *s, const char *name)  {
      addr_t addr = get_sym_addr(s, name, 0, 1);
      return addr == -1 ? NULL : (void*)(uintptr_t)addr;

}

ST_FUNC void list_elf_symbols(TCCState *s, void *ctx,      void (*symbol_cb)(void *ctx, const char *name, const void *val))  {
      ElfW(Sym) *sym;
      Section *symtab;
      int sym_index, end_sym;
      const char *name;
      unsigned char sym_vis, sym_bind;
        symtab = s->symtab;
      end_sym = symtab->data_offset / sizeof (ElfSym);
      for (sym_index = 0;
 sym_index < end_sym;
 ++sym_index) {
          sym = &((ElfW(Sym) *)symtab->data)[sym_index];
          if (sym->st_value) {
              name = (char *) symtab->link->data + sym->st_name;
              sym_bind = ELFW(ST_BIND)(sym->st_info);
              sym_vis = ELFW(ST_VISIBILITY)(sym->st_other);
              if (sym_bind == STB_GLOBAL && sym_vis == STV_DEFAULT)                  symbol_cb(ctx, name, (void*)(uintptr_t)sym->st_value);

}      
}  
}

LIBTCCAPI void tcc_list_symbols(TCCState *s, void *ctx,      void (*symbol_cb)(void *ctx, const char *name, const void *val))  {
      list_elf_symbols(s, ctx, symbol_cb);

}

ST_FUNC int set_elf_sym(Section *s, addr_t value, unsigned long size,                         int info, int other, int shndx, const char *name)  {
      TCCState *s1 = s->s1;
      ElfW(Sym) *esym;
      int sym_bind, sym_index, sym_type, esym_bind;
      unsigned char sym_vis, esym_vis, new_vis;
        sym_bind = ELFW(ST_BIND)(info);
      sym_type = ELFW(ST_TYPE)(info);
      sym_vis = ELFW(ST_VISIBILITY)(other);
        if (sym_bind != STB_LOCAL) {
          /* we search global or weak symbols */          sym_index = find_elf_sym(s, name);
          if (!sym_index)              goto do_def;
          esym = &((ElfW(Sym) *)s->data)[sym_index];
          if (esym->st_value == value && esym->st_size == size && esym->st_info == info              && esym->st_other == other && esym->st_shndx == shndx)              return sym_index;
          if (esym->st_shndx != SHN_UNDEF) {
              esym_bind = ELFW(ST_BIND)(esym->st_info);
              /* propagate the most constraining visibility */              /* STV_DEFAULT(0)<STV_PROTECTED(3)<STV_HIDDEN(2)<STV_INTERNAL(1) */              esym_vis = ELFW(ST_VISIBILITY)(esym->st_other);
              if (esym_vis == STV_DEFAULT) {
                  new_vis = sym_vis;

} else if (sym_vis == STV_DEFAULT) {
                  new_vis = esym_vis;

} else {
                  new_vis = (esym_vis < sym_vis) ? esym_vis : sym_vis;

}              esym->st_other = (esym->st_other & ~ELFW(ST_VISIBILITY)(-1))                               | new_vis;
              if (shndx == SHN_UNDEF) {
                  /* ignore adding of undefined symbol if the                     corresponding symbol is already defined */              
} else if (sym_bind == STB_GLOBAL && esym_bind == STB_WEAK) {
                  /* global overrides weak, so patch */                  goto do_patch;

} else if (sym_bind == STB_WEAK && esym_bind == STB_GLOBAL) {
                  /* weak is ignored if already global */              
} else if (sym_bind == STB_WEAK && esym_bind == STB_WEAK) {
                  /* keep first-found weak definition, ignore subsequents */              
} else if (sym_vis == STV_HIDDEN || sym_vis == STV_INTERNAL) {
                  /* ignore hidden symbols after */              
} else if ((esym->st_shndx == SHN_COMMON                              || esym->st_shndx == bss_section->sh_num)                          && (shndx < SHN_LORESERVE                              && shndx != bss_section->sh_num)) {
                  /* data symbol gets precedence over common/bss */                  goto do_patch;

} else if (shndx == SHN_COMMON || shndx == bss_section->sh_num) {
                  /* data symbol keeps precedence over common/bss */              
} else if (s->sh_flags & SHF_DYNSYM) {
                  /* we accept that two DLL define the same symbol */       
} else if (esym->st_other & ST_ASM_SET) {
    /* If the existing symbol came from an asm .set       we can override.  */    goto do_patch;

} else {
  #if 0                  printf("new_bind=%x new_shndx=%x new_vis=%x old_bind=%x old_shndx=%x old_vis=%x\n",                         sym_bind, shndx, new_vis, esym_bind, esym->st_shndx, esym_vis);
  #endif                  tcc_error_noabort("'%s' defined twice", name);

}          
} else {
              esym->st_other = other;
          do_patch:              esym->st_info = ELFW(ST_INFO)(sym_bind, sym_type);
              esym->st_shndx = shndx;
              s1->new_undef_sym = 1;
              esym->st_value = value;
              esym->st_size = size;

}      
} else {
      do_def:          sym_index = put_elf_sym(s, value, size,                                  ELFW(ST_INFO)(sym_bind, sym_type), other,                                  shndx, name);

}      return sym_index;

}

ST_FUNC void put_elf_reloca(Section *symtab, Section *s, unsigned long offset,                              int type, int symbol, addr_t addend)  {
      TCCState *s1 = s->s1;
      char buf[256];
      Section *sr;
      ElfW_Rel *rel;
        sr = s->reloc;
      if (!sr) {
          /* if no relocation section, create it */          snprintf(buf, sizeof(buf), REL_SECTION_FMT, s->name);
          /* if the symtab is allocated, then we consider the relocation             are also */          sr = new_section(s->s1, buf, SHT_RELX, symtab->sh_flags);
          sr->sh_entsize = sizeof(ElfW_Rel);
          sr->link = symtab;
          sr->sh_info = s->sh_num;
          s->reloc = sr;

}      rel = section_ptr_add(sr, sizeof(ElfW_Rel));
      rel->r_offset = offset;
      rel->r_info = ELFW(R_INFO)(symbol, type);
  #if SHT_RELX == SHT_RELA      rel->r_addend = addend;
  #endif      if (SHT_RELX != SHT_RELA && addend)          tcc_error_noabort("non-zero addend on REL architecture");

}

ST_FUNC void put_elf_reloc(Section *symtab, Section *s, unsigned long offset,                             int type, int symbol)  {
      put_elf_reloca(symtab, s, offset, type, symbol, 0);

}

ST_FUNC struct sym_attr *get_sym_attr(TCCState *s1, int index, int alloc)  {
      int n;
      struct sym_attr *tab;
        if (index >= s1->nb_sym_attrs) {
          if (!alloc)              return s1->sym_attrs;
          /* find immediately bigger power of 2 and reallocate array */          n = 1;
          while (index >= n)              n *= 2;
          tab = tcc_realloc(s1->sym_attrs, n * sizeof(*s1->sym_attrs));
          s1->sym_attrs = tab;
          memset(s1->sym_attrs + s1->nb_sym_attrs, 0,                 (n - s1->nb_sym_attrs) * sizeof(*s1->sym_attrs));
          s1->nb_sym_attrs = n;

}      return &s1->sym_attrs[index];

}

static void update_relocs(TCCState *s1, Section *s, int *old_to_new_syms, int first_sym)  {
      int i, type, sym_index;
      Section *sr;
      ElfW_Rel *rel;
        for(i = 1;
 i < s1->nb_sections;
 i++) {
          sr = s1->sections[i];
          if (sr->sh_type == SHT_RELX && sr->link == s) {
              for_each_elem(sr, 0, rel, ElfW_Rel) {
                  sym_index = ELFW(R_SYM)(rel->r_info);
                  type = ELFW(R_TYPE)(rel->r_info);
                  if ((sym_index -= first_sym) < 0)                      continue;
 /* zero sym_index in reloc (can happen with asm) */                  sym_index = old_to_new_syms[sym_index];
                  rel->r_info = ELFW(R_INFO)(sym_index, type);

}          
}      
}  
}

static void sort_syms(TCCState *s1, Section *s)  {
      int *old_to_new_syms;
      ElfW(Sym) *new_syms;
      int nb_syms, i;
      ElfW(Sym) *p, *q;
        nb_syms = s->data_offset / sizeof(ElfW(Sym));
      new_syms = tcc_malloc(nb_syms * sizeof(ElfW(Sym)));
      old_to_new_syms = tcc_malloc(nb_syms * sizeof(int));
        /* first pass for local symbols */      p = (ElfW(Sym) *)s->data;
      q = new_syms;
      for(i = 0;
 i < nb_syms;
 i++) {
          if (ELFW(ST_BIND)(p->st_info) == STB_LOCAL) {
              old_to_new_syms[i] = q - new_syms;
              *q++ = *p;

}          p++;

}      /* save the number of local symbols in section header */      if( s->sh_size )    /* this 'if' makes IDA happy */          s->sh_info = q - new_syms;
        /* then second pass for non local symbols */      p = (ElfW(Sym) *)s->data;
      for(i = 0;
 i < nb_syms;
 i++) {
          if (ELFW(ST_BIND)(p->st_info) != STB_LOCAL) {
              old_to_new_syms[i] = q - new_syms;
              *q++ = *p;

}          p++;

}        /* we copy the new symbols to the old */      memcpy(s->data, new_syms, nb_syms * sizeof(ElfW(Sym)));
      tcc_free(new_syms);
        update_relocs(s1, s, old_to_new_syms, 0);
      tcc_free(old_to_new_syms);

}

ST_FUNC void relocate_syms(TCCState *s1, Section *symtab, int do_resolve)  {
      ElfW(Sym) *sym;
      int sym_bind, sh_num;
      const char *name;
        for_each_elem(symtab, 1, sym, ElfW(Sym)) {
          sh_num = sym->st_shndx;
          if (sh_num == SHN_UNDEF) {
              if (do_resolve == 2) /* relocating dynsym */                  continue;
              name = (char *) s1->symtab->link->data + sym->st_name;
              /* Use ld.so to resolve symbol for us (for tcc -run) */              if (do_resolve) {
  #if defined TCC_IS_NATIVE && !defined TCC_TARGET_PE                  /* dlsym() needs the undecorated name.  */                  void *addr = dlsym(RTLD_DEFAULT, &name[s1->leading_underscore]);
  #if TARGETOS_OpenBSD || TARGETOS_FreeBSD || TARGETOS_NetBSD || TARGETOS_ANDROID    if (addr == NULL) {
        int i;
        for (i = 0;
 i < s1->nb_loaded_dlls;
 i++)                          if ((addr = dlsym(s1->loaded_dlls[i]->handle, name)))         break;

}  #endif                  if (addr) {
                      sym->st_value = (addr_t) addr;
  #ifdef DEBUG_RELOC        printf ("relocate_sym: %s -> 0x%lx\n", name, sym->st_value);
  #endif                      goto found;

}  #endif              /* if dynamic symbol exist, it will be used in relocate_section */              
} else if (s1->dynsym && find_elf_sym(s1->dynsym, name))                  goto found;
              /* XXX: _fp_hw seems to be part of the ABI, so we ignore                 it */              if (!strcmp(name, "_fp_hw"))                  goto found;
              /* only weak symbols are accepted to be undefined. Their                 value is zero */              sym_bind = ELFW(ST_BIND)(sym->st_info);
              if (sym_bind == STB_WEAK)                  sym->st_value = 0;
              else                  tcc_error_noabort("undefined symbol '%s'", name);

} else if (sh_num < SHN_LORESERVE) {
              /* add section base */              sym->st_value += s1->sections[sym->st_shndx]->sh_addr;

}      found:;

}  
}

static void relocate_section(TCCState *s1, Section *s, Section *sr)  {
      ElfW_Rel *rel;
      ElfW(Sym) *sym;
      int type, sym_index;
      unsigned char *ptr;
      addr_t tgt, addr;
      int is_dwarf = s->sh_num >= s1->dwlo && s->sh_num < s1->dwhi;
        qrel = (ElfW_Rel *)sr->data;
      for_each_elem(sr, 0, rel, ElfW_Rel) {
          ptr = s->data + rel->r_offset;
          sym_index = ELFW(R_SYM)(rel->r_info);
          sym = &((ElfW(Sym) *)symtab_section->data)[sym_index];
          type = ELFW(R_TYPE)(rel->r_info);
          tgt = sym->st_value;
  #if SHT_RELX == SHT_RELA          tgt += rel->r_addend;
  #endif          if (is_dwarf && type == R_DATA_32DW              && sym->st_shndx >= s1->dwlo && sym->st_shndx < s1->dwhi) {
              /* dwarf section relocation to each other */              add32le(ptr, tgt - s1->sections[sym->st_shndx]->sh_addr);
              continue;

}          addr = s->sh_addr + rel->r_offset;
          relocate(s1, rel, type, ptr, addr, tgt);

}  #ifndef ELF_OBJ_ONLY      /* if the relocation is allocated, we change its symbol table */      if (sr->sh_flags & SHF_ALLOC) {
          sr->link = s1->dynsym;
          if (s1->output_type & TCC_OUTPUT_DYN) {
              size_t r = (uint8_t*)qrel - sr->data;
              if (sizeof ((Stab_Sym*)0)->n_value < PTR_SIZE                  && 0 == strcmp(s->name, ".stab"))                  r = 0;
 /* cannot apply 64bit relocation to 32bit value */              sr->data_offset = sr->sh_size = r;
  #ifdef CONFIG_TCC_PIE              if (r && (s->sh_flags & SHF_EXECINSTR))                  tcc_warning("%d relocations to %s", (unsigned)(r / sizeof *qrel), s->name);
  #endif          
}      
}  #endif  
}

ST_FUNC void relocate_sections(TCCState *s1)  {
      int i;
      Section *s, *sr;
        for (i = 1;
 i < s1->nb_sections;
 ++i) {
          sr = s1->sections[i];
          if (sr->sh_type != SHT_RELX)              continue;
          s = s1->sections[sr->sh_info];
  #ifndef TCC_TARGET_MACHO          if (s != s1->got              || s1->static_link              || s1->output_type == TCC_OUTPUT_MEMORY)  #endif          {
              relocate_section(s1, s, sr);

}  #ifndef ELF_OBJ_ONLY          if (sr->sh_flags & SHF_ALLOC) {
              ElfW_Rel *rel;
              /* relocate relocation table in 'sr' */              for_each_elem(sr, 0, rel, ElfW_Rel)                  rel->r_offset += s->sh_addr;

}  #endif      
}  
}

ST_FUNC int set_global_sym(TCCState *s1, const char *name, Section *sec, addr_t offs)  {
      int shn = sec ? sec->sh_num : offs || !name ? SHN_ABS : SHN_UNDEF;
      if (sec && offs == -1)          offs = sec->data_offset;
      return set_elf_sym(symtab_section, offs, 0,          ELFW(ST_INFO)(name ? STB_GLOBAL : STB_LOCAL, STT_NOTYPE), 0, shn, name);

}

static void add_init_array_defines(TCCState *s1, const char *section_name)  {
      Section *s;
      addr_t end_offset;
      char buf[1024];
      s = have_section(s1, section_name);
      if (!s || !(s->sh_flags & SHF_ALLOC)) {
          end_offset = 0;
          s = text_section;

} else {
          end_offset = s->data_offset;

}      snprintf(buf, sizeof(buf), "__%s_start", section_name + 1);
      set_global_sym(s1, buf, s, 0);
      snprintf(buf, sizeof(buf), "__%s_end", section_name + 1);
      set_global_sym(s1, buf, s, end_offset);

}

ST_FUNC void add_array (TCCState *s1, const char *sec, int c)  {
      Section *s;
      s = find_section(s1, sec);
      s->sh_flags = shf_RELRO;
      s->sh_type = sec[1] == 'i' ? SHT_INIT_ARRAY : SHT_FINI_ARRAY;
      put_elf_reloc (s1->symtab, s, s->data_offset, R_DATA_PTR, c);
      section_ptr_add(s, PTR_SIZE);

}

static void set_local_sym(TCCState *s1, const char *name, Section *s, int offset)  {
      int c = find_elf_sym(s1->symtab, name);
      if (c) {
          ElfW(Sym) *esym = (ElfW(Sym)*)s1->symtab->data + c;
          esym->st_info = ELFW(ST_INFO)(STB_LOCAL, STT_NOTYPE);
          esym->st_value = offset;
          esym->st_shndx = s->sh_num;

}  
}

static void tcc_compile_string_no_debug(TCCState *s, const char *str)  {
      int save_do_debug = s->do_debug;
      int save_test_coverage = s->test_coverage;
        s->do_debug = 0;
      s->test_coverage = 0;
      tcc_compile_string(s, str);
      s->do_debug = save_do_debug;
      s->test_coverage = save_test_coverage;

}

static void tcc_tcov_add_file(TCCState *s1, const char *filename)  {
      CString cstr;
      void *ptr;
      char wd[1024];
        if (tcov_section == NULL)          return;
      section_ptr_add(tcov_section, 1);
      write32le (tcov_section->data, tcov_section->data_offset);
        cstr_new (&cstr);
      if (filename[0] == '/')          cstr_printf (&cstr, "%s.tcov", filename);
      else {
          getcwd (wd, sizeof(wd));
          cstr_printf (&cstr, "%s/%s.tcov", wd, filename);

}      ptr = section_ptr_add(tcov_section, cstr.size + 1);
      strcpy((char *)ptr, cstr.data);
      unlink((char *)ptr);
  #ifdef _WIN32      normalize_slashes((char *)ptr);
  #endif      cstr_free (&cstr);
        cstr_new(&cstr);
      cstr_printf(&cstr,          "extern char *__tcov_data[];
"          "extern void __store_test_coverage ();
"          "__attribute__((destructor)) static void __tcov_exit() {
"          "__store_test_coverage(__tcov_data);
"          "
}");
      tcc_compile_string_no_debug(s1, cstr.data);
      cstr_free(&cstr);
      set_local_sym(s1, &"___tcov_data"[!s1->leading_underscore], tcov_section, 0);

}

static void tcc_add_linker_symbols(TCCState *s1)  {
      char buf[1024];
      int i;
      Section *s;
        set_global_sym(s1, "_etext", text_section, -1);
      set_global_sym(s1, "_edata", data_section, -1);
      set_global_sym(s1, "_end", bss_section, -1);
  #if TARGETOS_OpenBSD      set_global_sym(s1, "__executable_start", NULL, ELF_START_ADDR);
  #endif  #ifdef TCC_TARGET_RISCV64      /* XXX should be .sdata+0x800, not .data+0x800 */      set_global_sym(s1, "__global_pointer$", data_section, 0x800);
  #endif      /* horrible new standard ldscript defines */      add_init_array_defines(s1, ".preinit_array");
      add_init_array_defines(s1, ".init_array");
      add_init_array_defines(s1, ".fini_array");
      /* add start and stop symbols for sections whose name can be         expressed in C */      for(i = 1;
 i < s1->nb_sections;
 i++) {
          s = s1->sections[i];
          if ((s->sh_flags & SHF_ALLOC)              && (s->sh_type == SHT_PROGBITS || s->sh_type == SHT_NOBITS                  || s->sh_type == SHT_STRTAB)) {
              /* check if section name can be expressed in C */              const char *p0, *p;
              p0 = s->name;
              if (*p0 == '.')                  ++p0;
              p = p0;
              for(;
;
) {
                  int c = *p;
                  if (!c)                      break;
                  if (!isid(c) && !isnum(c))                      goto next_sec;
                  p++;

}              snprintf(buf, sizeof(buf), "__start_%s", p0);
              set_global_sym(s1, buf, s, 0);
              snprintf(buf, sizeof(buf), "__stop_%s", p0);
              set_global_sym(s1, buf, s, -1);

}      next_sec:;

}  
}

ST_FUNC void resolve_common_syms(TCCState *s1)  {
      ElfW(Sym) *sym;
        /* Allocate common symbols in BSS.  */      for_each_elem(symtab_section, 1, sym, ElfW(Sym)) {
          if (sym->st_shndx == SHN_COMMON) {
              /* symbol alignment is in st_value for SHN_COMMONs */       sym->st_value = section_add(bss_section, sym->st_size,       sym->st_value);
              sym->st_shndx = bss_section->sh_num;

}      
}        /* Now assign linker provided symbols their value.  */      tcc_add_linker_symbols(s1);

}

static int tcc_output_elf(TCCState *s1, FILE *f, int phnum, ElfW(Phdr) *phdr)  {
      int i, shnum, offset, size, file_type;
      Section *s;
      ElfW(Ehdr) ehdr;
      ElfW(Shdr) shdr, *sh;
        file_type = s1->output_type;
      shnum = s1->nb_sections;
        memset(&ehdr, 0, sizeof(ehdr));
      if (phnum > 0) {
          ehdr.e_phentsize = sizeof(ElfW(Phdr));
          ehdr.e_phnum = phnum;
          ehdr.e_phoff = sizeof(ElfW(Ehdr));

}        /* fill header */      ehdr.e_ident[0] = ELFMAG0;
      ehdr.e_ident[1] = ELFMAG1;
      ehdr.e_ident[2] = ELFMAG2;
      ehdr.e_ident[3] = ELFMAG3;
      ehdr.e_ident[4] = ELFCLASSW;
      ehdr.e_ident[5] = ELFDATA2LSB;
      ehdr.e_ident[6] = EV_CURRENT;
    #if TARGETOS_FreeBSD || TARGETOS_FreeBSD_kernel      ehdr.e_ident[EI_OSABI] = ELFOSABI_FREEBSD;
  #elif defined TCC_TARGET_ARM && defined TCC_ARM_EABI      ehdr.e_flags = EF_ARM_EABI_VER5;
      ehdr.e_flags |= s1->float_abi == ARM_HARD_FLOAT          ? EF_ARM_VFP_FLOAT : EF_ARM_SOFT_FLOAT;
  #elif defined TCC_TARGET_ARM      ehdr.e_ident[EI_OSABI] = ELFOSABI_ARM;
  #elif defined TCC_TARGET_RISCV64      /* XXX should be configurable */      ehdr.e_flags = EF_RISCV_FLOAT_ABI_DOUBLE;
  #endif        if (file_type == TCC_OUTPUT_OBJ) {
          ehdr.e_type = ET_REL;

} else {
          if (file_type & TCC_OUTPUT_DYN)              ehdr.e_type = ET_DYN;
          else              ehdr.e_type = ET_EXEC;
          if (s1->elf_entryname)              ehdr.e_entry = get_sym_addr(s1, s1->elf_entryname, 1, 0);
          else              ehdr.e_entry = get_sym_addr(s1, "_start", !!(file_type & TCC_OUTPUT_EXE), 0);
          if (ehdr.e_entry == (addr_t)-1)              ehdr.e_entry = text_section->sh_addr;
          if (s1->nb_errors)              return -1;

}        sort_syms(s1, s1->symtab);
        ehdr.e_machine = EM_TCC_TARGET;
      ehdr.e_version = EV_CURRENT;
      ehdr.e_shoff = (sizeof(ElfW(Ehdr)) + phnum * sizeof(ElfW(Phdr)) + 3) & -4;
      ehdr.e_ehsize = sizeof(ElfW(Ehdr));
      ehdr.e_shentsize = sizeof(ElfW(Shdr));
      ehdr.e_shnum = shnum;
      ehdr.e_shstrndx = shnum - 1;
        offset = fwrite(&ehdr, 1, sizeof(ElfW(Ehdr)), f);
      if (phdr)          offset += fwrite(phdr, 1, phnum * sizeof(ElfW(Phdr)), f);
        /* output section headers */      while (offset < ehdr.e_shoff) {
          fputc(0, f);
          offset++;

}        for(i = 0;
 i < shnum;
 i++) {
          sh = &shdr;
          memset(sh, 0, sizeof(ElfW(Shdr)));
          if (i) {
              s = s1->sections[i];
              sh->sh_name = s->sh_name;
              sh->sh_type = s->sh_type;
              sh->sh_flags = s->sh_flags;
              sh->sh_entsize = s->sh_entsize;
              sh->sh_info = s->sh_info;
              if (s->link)                  sh->sh_link = s->link->sh_num;
              sh->sh_addralign = s->sh_addralign;
              sh->sh_addr = s->sh_addr;
              sh->sh_offset = s->sh_offset;
              sh->sh_size = s->sh_size;

}          offset += fwrite(sh, 1, sizeof(ElfW(Shdr)), f);

}        /* output sections */      for(i = 1;
 i < s1->nb_sections;
 i++) {
          s = s1->sections[i];
          if (s->sh_type != SHT_NOBITS) {
              while (offset < s->sh_offset) {
                  fputc(0, f);
                  offset++;

}              size = s->sh_size;
              if (size)                  offset += fwrite(s->data, 1, size, f);

}      
}      return 0;

}

static int tcc_output_binary(TCCState *s1, FILE *f)  {
      Section *s;
      int i, offset, size;
        offset = 0;
      for(i=1;
i<s1->nb_sections;
i++) {
          s = s1->sections[i];
          if (s->sh_type != SHT_NOBITS &&              (s->sh_flags & SHF_ALLOC)) {
              while (offset < s->sh_offset) {
                  fputc(0, f);
                  offset++;

}              size = s->sh_size;
              fwrite(s->data, 1, size, f);
              offset += size;

}      
}      return 0;

}

static int tcc_write_elf_file(TCCState *s1, const char *filename, int phnum,                                ElfW(Phdr) *phdr)  {
      int fd, mode, file_type, ret;
      FILE *f;
        file_type = s1->output_type;
      if (file_type == TCC_OUTPUT_OBJ)          mode = 0666;
      else          mode = 0777;
      unlink(filename);
      fd = open(filename, O_WRONLY | O_CREAT | O_TRUNC | O_BINARY, mode);
      if (fd < 0 || (f = fdopen(fd, "wb")) == NULL)          return tcc_error_noabort("could not write '%s: %s'", filename, strerror(errno));
      if (s1->verbose)          printf("<- %s\n", filename);
  #ifdef TCC_TARGET_COFF      if (s1->output_format == TCC_OUTPUT_FORMAT_COFF)          tcc_output_coff(s1, f);
      else  #endif      if (s1->output_format == TCC_OUTPUT_FORMAT_ELF)          ret = tcc_output_elf(s1, f, phnum, phdr);
      else          ret = tcc_output_binary(s1, f);
      fclose(f);
        return ret;

}

static void alloc_sec_names(TCCState *s1, int is_obj)  {
      int i;
      Section *s, *strsec;
        strsec = new_section(s1, ".shstrtab", SHT_STRTAB, 0);
      put_elf_str(strsec, "");
      for(i = 1;
 i < s1->nb_sections;
 i++) {
          s = s1->sections[i];
          if (is_obj)              s->sh_size = s->data_offset;
   if (s->sh_size || s == strsec || (s->sh_flags & SHF_ALLOC) || is_obj)              s->sh_name = put_elf_str(strsec, s->name);

}      strsec->sh_size = strsec->data_offset;

}

static int elf_output_obj(TCCState *s1, const char *filename)  {
      Section *s;
      int i, ret, file_offset;
      s1->nb_errors = 0;
      /* Allocate strings for section names */      alloc_sec_names(s1, 1);
      file_offset = (sizeof (ElfW(Ehdr)) + 3) & -4;
      file_offset += s1->nb_sections * sizeof(ElfW(Shdr));
      for(i = 1;
 i < s1->nb_sections;
 i++) {
          s = s1->sections[i];
          file_offset = (file_offset + 15) & -16;
          s->sh_offset = file_offset;
          if (s->sh_type != SHT_NOBITS)              file_offset += s->sh_size;

}      /* Create the ELF file with name 'filename' */      ret = tcc_write_elf_file(s1, filename, 0, NULL);
      return ret;

}

LIBTCCAPI int tcc_output_file(TCCState *s, const char *filename)  {
      if (s->test_coverage)          tcc_tcov_add_file(s, filename);
      if (s->output_type == TCC_OUTPUT_OBJ)          return elf_output_obj(s, filename);
  #ifdef TCC_TARGET_PE      return  pe_output_file(s, filename);
  #elif defined TCC_TARGET_MACHO      return macho_output_file(s, filename);
  #else      return elf_output_file(s, filename);
  #endif  
}

ST_FUNC ssize_t full_read(int fd, void *buf, size_t count) {
      char *cbuf = buf;
      size_t rnum = 0;
      while (1) {
          ssize_t num = read(fd, cbuf, count-rnum);
          if (num < 0) return num;
          if (num == 0) return rnum;
          rnum += num;
          cbuf += num;

}  
}

ST_FUNC void *load_data(int fd, unsigned long file_offset, unsigned long size)  {
      void *data;
        data = tcc_malloc(size);
      lseek(fd, file_offset, SEEK_SET);
      full_read(fd, data, size);
      return data;

}

ST_FUNC int tcc_object_type(int fd, ElfW(Ehdr) *h)  {
      int size = full_read(fd, h, sizeof *h);
      if (size == sizeof *h && 0 == memcmp(h, ELFMAG, 4)) {
          if (h->e_type == ET_REL)              return AFF_BINTYPE_REL;
          if (h->e_type == ET_DYN)              return AFF_BINTYPE_DYN;

} else if (size >= 8) {
          if (0 == memcmp(h, ARMAG, 8))              return AFF_BINTYPE_AR;
  #ifdef TCC_TARGET_COFF          if (((struct filehdr*)h)->f_magic == COFF_C67_MAGIC)              return AFF_BINTYPE_C67;
  #endif      
}      return 0;

}

ST_FUNC int tcc_load_object_file(TCCState *s1,                                  int fd, unsigned long file_offset)  {
      ElfW(Ehdr) ehdr;
      ElfW(Shdr) *shdr, *sh;
      unsigned long size, offset, offseti;
      int i, j, nb_syms, sym_index, ret, seencompressed;
      char *strsec, *strtab;
      int stab_index, stabstr_index;
      int *old_to_new_syms;
      char *sh_name, *name;
      SectionMergeInfo *sm_table, *sm;
      ElfW(Sym) *sym, *symtab;
      ElfW_Rel *rel;
      Section *s;
        lseek(fd, file_offset, SEEK_SET);
      if (tcc_object_type(fd, &ehdr) != AFF_BINTYPE_REL)          goto invalid;
      /* test CPU specific stuff */      if (ehdr.e_ident[5] != ELFDATA2LSB ||          ehdr.e_machine != EM_TCC_TARGET) {
  invalid:          return tcc_error_noabort("invalid object file");

}      /* read sections */      shdr = load_data(fd, file_offset + ehdr.e_shoff,                       sizeof(ElfW(Shdr)) * ehdr.e_shnum);
      sm_table = tcc_mallocz(sizeof(SectionMergeInfo) * ehdr.e_shnum);
        /* load section names */      sh = &shdr[ehdr.e_shstrndx];
      strsec = load_data(fd, file_offset + sh->sh_offset, sh->sh_size);
        /* load symtab and strtab */      old_to_new_syms = NULL;
      symtab = NULL;
      strtab = NULL;
      nb_syms = 0;
      seencompressed = 0;
      stab_index = stabstr_index = 0;
      ret = -1;
        for(i = 1;
 i < ehdr.e_shnum;
 i++) {
          sh = &shdr[i];
          if (sh->sh_type == SHT_SYMTAB) {
              if (symtab) {
                  tcc_error_noabort("object must contain only one symtab");
                  goto the_end;

}              nb_syms = sh->sh_size / sizeof(ElfW(Sym));
              symtab = load_data(fd, file_offset + sh->sh_offset, sh->sh_size);
              sm_table[i].s = symtab_section;
                /* now load strtab */              sh = &shdr[sh->sh_link];
              strtab = load_data(fd, file_offset + sh->sh_offset, sh->sh_size);

}   if (sh->sh_flags & SHF_COMPRESSED)       seencompressed = 1;

}        /* now examine each section and try to merge its content with the         ones in memory */      for(i = 1;
 i < ehdr.e_shnum;
 i++) {
          /* no need to examine section name strtab */          if (i == ehdr.e_shstrndx)              continue;
          sh = &shdr[i];
   if (sh->sh_type == SHT_RELX)     sh = &shdr[sh->sh_info];
          /* ignore sections types we do not handle (plus relocs to those) */          if (0 == strncmp(strsec + sh->sh_name, ".debug_", 7)           || 0 == strncmp(strsec + sh->sh_name, ".stab", 5)) {
       if (!s1->do_debug || seencompressed)           continue;

} else          if (sh->sh_type != SHT_PROGBITS &&  #ifdef TCC_ARM_EABI              sh->sh_type != SHT_ARM_EXIDX &&  #endif  #if TARGETOS_OpenBSD || TARGETOS_FreeBSD || TARGETOS_NetBSD              sh->sh_type != SHT_X86_64_UNWIND &&  #endif              sh->sh_type != SHT_NOTE &&              sh->sh_type != SHT_NOBITS &&              sh->sh_type != SHT_PREINIT_ARRAY &&              sh->sh_type != SHT_INIT_ARRAY &&              sh->sh_type != SHT_FINI_ARRAY              )              continue;
     sh = &shdr[i];
          sh_name = strsec + sh->sh_name;
          if (sh->sh_addralign < 1)              sh->sh_addralign = 1;
          /* find corresponding section, if any */          for(j = 1;
 j < s1->nb_sections;
j++) {
              s = s1->sections[j];
              if (!strcmp(s->name, sh_name)) {
                  if (!strncmp(sh_name, ".gnu.linkonce",                               sizeof(".gnu.linkonce") - 1)) {
                      /* if a 'linkonce' section is already present, we                         do not add it again. It is a little tricky as                         symbols can still be defined in                         it. */                      sm_table[i].link_once = 1;
                      goto next;

}                  if (stab_section) {
                      if (s == stab_section)                          stab_index = i;
                      if (s == stab_section->link)                          stabstr_index = i;

}                  goto found;

}          
}          /* not found: create new section */          s = new_section(s1, sh_name, sh->sh_type, sh->sh_flags & ~SHF_GROUP);
          /* take as much info as possible from the section. sh_link and             sh_info will be updated later */          s->sh_addralign = sh->sh_addralign;
          s->sh_entsize = sh->sh_entsize;
          sm_table[i].new_section = 1;
      found:          if (sh->sh_type != s->sh_type  #if TARGETOS_OpenBSD || TARGETOS_FreeBSD || TARGETOS_NetBSD              && strcmp (s->name, ".eh_frame")  #endif              ) {
              tcc_error_noabort("invalid section type");
              goto the_end;

}          /* align start of section */          s->data_offset += -s->data_offset & (sh->sh_addralign - 1);
          if (sh->sh_addralign > s->sh_addralign)              s->sh_addralign = sh->sh_addralign;
          sm_table[i].offset = s->data_offset;
          sm_table[i].s = s;
          /* concatenate sections */          size = sh->sh_size;
          if (sh->sh_type != SHT_NOBITS) {
              unsigned char *ptr;
              lseek(fd, file_offset + sh->sh_offset, SEEK_SET);
              ptr = section_ptr_add(s, size);
              full_read(fd, ptr, size);

} else {
              s->data_offset += size;

}      next:;

}        /* gr relocate stab strings */      if (stab_index && stabstr_index) {
          Stab_Sym *a, *b;
          unsigned o;
          s = sm_table[stab_index].s;
          a = (Stab_Sym *)(s->data + sm_table[stab_index].offset);
          b = (Stab_Sym *)(s->data + s->data_offset);
          o = sm_table[stabstr_index].offset;
          while (a < b) {
              if (a->n_strx)                  a->n_strx += o;
              a++;

}      
}        /* second short pass to update sh_link and sh_info fields of new         sections */      for(i = 1;
 i < ehdr.e_shnum;
 i++) {
          s = sm_table[i].s;
          if (!s || !sm_table[i].new_section)              continue;
          sh = &shdr[i];
          if (sh->sh_link > 0)              s->link = sm_table[sh->sh_link].s;
          if (sh->sh_type == SHT_RELX) {
              s->sh_info = sm_table[sh->sh_info].s->sh_num;
              /* update backward link */              s1->sections[s->sh_info]->reloc = s;

}      
}        /* resolve symbols */      old_to_new_syms = tcc_mallocz(nb_syms * sizeof(int));
        sym = symtab + 1;
      for(i = 1;
 i < nb_syms;
 i++, sym++) {
          if (sym->st_shndx != SHN_UNDEF &&              sym->st_shndx < SHN_LORESERVE) {
              sm = &sm_table[sym->st_shndx];
              if (sm->link_once) {
                  /* if a symbol is in a link once section, we use the                     already defined symbol. It is very important to get                     correct relocations */                  if (ELFW(ST_BIND)(sym->st_info) != STB_LOCAL) {
                      name = strtab + sym->st_name;
                      sym_index = find_elf_sym(symtab_section, name);
                      if (sym_index)                          old_to_new_syms[i] = sym_index;

}                  continue;

}              /* if no corresponding section added, no need to add symbol */              if (!sm->s)                  continue;
              /* convert section number */              sym->st_shndx = sm->s->sh_num;
              /* offset value */              sym->st_value += sm->offset;

}          /* add symbol */          name = strtab + sym->st_name;
          sym_index = set_elf_sym(symtab_section, sym->st_value, sym->st_size,                                  sym->st_info, sym->st_other,                                  sym->st_shndx, name);
          old_to_new_syms[i] = sym_index;

}        /* third pass to patch relocation entries */      for(i = 1;
 i < ehdr.e_shnum;
 i++) {
          s = sm_table[i].s;
          if (!s)              continue;
          sh = &shdr[i];
          offset = sm_table[i].offset;
          size = sh->sh_size;
          switch(s->sh_type) {
          case SHT_RELX:              /* take relocation offset information */              offseti = sm_table[sh->sh_info].offset;
       for (rel = (ElfW_Rel *) s->data + (offset / sizeof(*rel));
     rel < (ElfW_Rel *) s->data + ((offset + size) / sizeof(*rel));
     rel++) {
                  int type;
                  unsigned sym_index;
                  /* convert symbol index */                  type = ELFW(R_TYPE)(rel->r_info);
                  sym_index = ELFW(R_SYM)(rel->r_info);
                  /* NOTE: only one symtab assumed */                  if (sym_index >= nb_syms)                      goto invalid_reloc;
                  sym_index = old_to_new_syms[sym_index];
                  /* ignore link_once in rel section. */                  if (!sym_index && !sm_table[sh->sh_info].link_once  #ifdef TCC_TARGET_ARM                      && type != R_ARM_V4BX  #elif defined TCC_TARGET_RISCV64                      && type != R_RISCV_ALIGN                      && type != R_RISCV_RELAX  #endif                     ) {
                  invalid_reloc:                      tcc_error_noabort("Invalid relocation entry [%2d] '%s' @ %.8x",                          i, strsec + sh->sh_name, (int)rel->r_offset);
                      goto the_end;

}                  rel->r_info = ELFW(R_INFO)(sym_index, type);
                  /* offset the relocation offset */                  rel->r_offset += offseti;
  #ifdef TCC_TARGET_ARM                  /* Jumps and branches from a Thumb code to a PLT entry need                     special handling since PLT entries are ARM code.                     Unconditional bl instructions referencing PLT entries are                     handled by converting these instructions into blx                     instructions. Other case of instructions referencing a PLT                     entry require to add a Thumb stub before the PLT entry to                     switch to ARM mode. We set bit plt_thumb_stub of the                     attribute of a symbol to indicate such a case. */                  if (type == R_ARM_THM_JUMP24)                      get_sym_attr(s1, sym_index, 1)->plt_thumb_stub = 1;
  #endif              
}              break;
          default:              break;

}      
}        ret = 0;
   the_end:      tcc_free(symtab);
      tcc_free(strtab);
      tcc_free(old_to_new_syms);
      tcc_free(sm_table);
      tcc_free(strsec);
      tcc_free(shdr);
      return ret;

}

static unsigned long long get_be(const uint8_t *b, int n)  {
      unsigned long long ret = 0;
      while (n)          ret = (ret << 8) | *b++, --n;
      return ret;

}

static int read_ar_header(int fd, int offset, ArchiveHeader *hdr)  {
      char *p, *e;
      int len;
      lseek(fd, offset, SEEK_SET);
      len = full_read(fd, hdr, sizeof(ArchiveHeader));
      if (len != sizeof(ArchiveHeader))          return len ? -1 : 0;
      if (memcmp(hdr->ar_fmag, ARFMAG, sizeof hdr->ar_fmag))          return -1;
      p = hdr->ar_name;
      for (e = p + sizeof hdr->ar_name;
 e > p && e[-1] == ' ';
)          --e;
      *e = '\0';
      hdr->ar_size[sizeof hdr->ar_size-1] = 0;
      return len;

}

static int tcc_load_alacarte(TCCState *s1, int fd, int size, int entrysize)  {
      int i, bound, nsyms, sym_index, len, ret = -1;
      unsigned long long off;
      uint8_t *data;
      const char *ar_names, *p;
      const uint8_t *ar_index;
      ElfW(Sym) *sym;
      ArchiveHeader hdr;
        data = tcc_malloc(size);
      if (full_read(fd, data, size) != size)          goto invalid;
      nsyms = get_be(data, entrysize);
      ar_index = data + entrysize;
      ar_names = (char *) ar_index + nsyms * entrysize;
        do {
          bound = 0;
          for (p = ar_names, i = 0;
 i < nsyms;
 i++, p += strlen(p)+1) {
              Section *s = symtab_section;
              sym_index = find_elf_sym(s, p);
              if (!sym_index)                  continue;
              sym = &((ElfW(Sym) *)s->data)[sym_index];
              if(sym->st_shndx != SHN_UNDEF)                  continue;
              off = get_be(ar_index + i * entrysize, entrysize);
              len = read_ar_header(fd, off, &hdr);
              if (len <= 0 || memcmp(hdr.ar_fmag, ARFMAG, 2)) {
          invalid:                  tcc_error_noabort("invalid archive");
                  goto the_end;

}              off += len;
              if (s1->verbose == 2)                  printf("   -> %s\n", hdr.ar_name);
              if (tcc_load_object_file(s1, fd, off) < 0)                  goto the_end;
              ++bound;

}      
} while(bound);
      ret = 0;
   the_end:      tcc_free(data);
      return ret;

}

ST_FUNC int tcc_load_archive(TCCState *s1, int fd, int alacarte)  {
      ArchiveHeader hdr;
      /* char magic[8];
 */      int size, len;
      unsigned long file_offset;
      ElfW(Ehdr) ehdr;
        /* skip magic which was already checked */      /* full_read(fd, magic, sizeof(magic));
 */      file_offset = sizeof ARMAG - 1;
        for(;
;
) {
          len = read_ar_header(fd, file_offset, &hdr);
          if (len == 0)              return 0;
          if (len < 0)              return tcc_error_noabort("invalid archive");
          file_offset += len;
          size = strtol(hdr.ar_size, NULL, 0);
          if (alacarte) {
              /* coff symbol table : we handle it */              if (!strcmp(hdr.ar_name, "/"))                  return tcc_load_alacarte(s1, fd, size, 4);
              if (!strcmp(hdr.ar_name, "/SYM64/"))                  return tcc_load_alacarte(s1, fd, size, 8);

} else if (tcc_object_type(fd, &ehdr) == AFF_BINTYPE_REL) {
              if (s1->verbose == 2)                  printf("   -> %s\n", hdr.ar_name);
              if (tcc_load_object_file(s1, fd, file_offset) < 0)                  return -1;

}          /* align to even */          file_offset = (file_offset + size + 1) & ~1;

}  
}

