ST_INLN int is_float(int t)  {
      int bt = t & VT_BTYPE;
      return bt == VT_LDOUBLE          || bt == VT_DOUBLE          || bt == VT_FLOAT          || bt == VT_QFLOAT;

}

static inline int is_integer_btype(int bt)  {
      return bt == VT_BYTE          || bt == VT_BOOL          || bt == VT_SHORT          || bt == VT_INT          || bt == VT_LLONG;

}

static int btype_size(int bt)  {
      return bt == VT_BYTE || bt == VT_BOOL ? 1 :          bt == VT_SHORT ? 2 :          bt == VT_INT ? 4 :          bt == VT_LLONG ? 8 :          bt == VT_PTR ? PTR_SIZE : 0;

}

static int R_RET(int t)  {
      if (!is_float(t))          return REG_IRET;
  #ifdef TCC_TARGET_X86_64      if ((t & VT_BTYPE) == VT_LDOUBLE)          return TREG_ST0;
  #elif defined TCC_TARGET_RISCV64      if ((t & VT_BTYPE) == VT_LDOUBLE)          return REG_IRET;
  #endif      return REG_FRET;

}

static int R2_RET(int t)  {
      t &= VT_BTYPE;
  #if PTR_SIZE == 4      if (t == VT_LLONG)          return REG_IRE2;
  #elif defined TCC_TARGET_X86_64      if (t == VT_QLONG)          return REG_IRE2;
      if (t == VT_QFLOAT)          return REG_FRE2;
  #elif defined TCC_TARGET_RISCV64      if (t == VT_LDOUBLE)          return REG_IRE2;
  #endif      return VT_CONST;

}

static void PUT_R_RET(SValue *sv, int t)  {
      sv->r = R_RET(t), sv->r2 = R2_RET(t);

}

static int RC_RET(int t)  {
      return reg_classes[R_RET(t)] & ~(RC_FLOAT | RC_INT);

}

static int RC_TYPE(int t)  {
      if (!is_float(t))          return RC_INT;
  #ifdef TCC_TARGET_X86_64      if ((t & VT_BTYPE) == VT_LDOUBLE)          return RC_ST0;
      if ((t & VT_BTYPE) == VT_QFLOAT)          return RC_FRET;
  #elif defined TCC_TARGET_RISCV64      if ((t & VT_BTYPE) == VT_LDOUBLE)          return RC_INT;
  #endif      return RC_FLOAT;

}

static int RC2_TYPE(int t, int rc)  {
      if (!USING_TWO_WORDS(t))          return 0;
  #ifdef RC_IRE2      if (rc == RC_IRET)          return RC_IRE2;
  #endif  #ifdef RC_FRE2      if (rc == RC_FRET)          return RC_FRE2;
  #endif      if (rc & RC_FLOAT)          return RC_FLOAT;
      return RC_INT;

}

ST_FUNC int ieee_finite(double d)  {
      int p[4];
      memcpy(p, &d, sizeof(double));
      return ((unsigned)((p[1] | 0x800fffff) + 1)) >> 31;

}

ST_FUNC void test_lvalue(void)  {
      if (!(vtop->r & VT_LVAL))          expect("lvalue");

}

ST_FUNC void check_vstack(void)  {
      if (vtop != vstack - 1)          tcc_error("internal compiler error: vstack leak (%d)",                    (int)(vtop - vstack + 1));

}

ST_FUNC void tccgen_init(TCCState *s1)  {
      vtop = vstack - 1;
      memset(vtop, 0, sizeof *vtop);
        /* define some often used types */      int_type.t = VT_INT;
        char_type.t = VT_BYTE;
      if (s1->char_is_unsigned)          char_type.t |= VT_UNSIGNED;
      char_pointer_type = char_type;
      mk_pointer(&char_pointer_type);
        func_old_type.t = VT_FUNC;
      func_old_type.ref = sym_push(SYM_FIELD, &int_type, 0, 0);
      func_old_type.ref->f.func_call = FUNC_CDECL;
      func_old_type.ref->f.func_type = FUNC_OLD;
  #ifdef precedence_parser      init_prec();
  #endif      cstr_new(&initstr);

}

ST_FUNC int tccgen_compile(TCCState *s1)  {
      funcname = "";
      func_ind = -1;
      anon_sym = SYM_FIRST_ANOM;
      nocode_wanted = DATA_ONLY_WANTED;
 /* no code outside of functions */      debug_modes = (s1->do_debug ? 1 : 0) | s1->test_coverage << 1;
        tcc_debug_start(s1);
      tcc_tcov_start (s1);
  #ifdef TCC_TARGET_ARM      arm_init(s1);
  #endif  #ifdef INC_DEBUG      printf("%s: **** new file\n", file->filename);
  #endif      parse_flags = PARSE_FLAG_PREPROCESS | PARSE_FLAG_TOK_NUM | PARSE_FLAG_TOK_STR;
      next();
      decl(VT_CONST);
      gen_inline_functions(s1);
      check_vstack();
      /* end of translation unit info */  #if TCC_EH_FRAME      tcc_eh_frame_end(s1);
  #endif      tcc_debug_end(s1);
      tcc_tcov_end(s1);
      return 0;

}

ST_FUNC void tccgen_finish(TCCState *s1)  {
      tcc_debug_end(s1);
 /* just in case of errors: free memory */      free_inline_functions(s1);
      sym_pop(&global_stack, NULL, 0);
      sym_pop(&local_stack, NULL, 0);
      /* free preprocessor macros */      free_defines(NULL);
      /* free sym_pools */      dynarray_reset(&sym_pools, &nb_sym_pools);
      cstr_free(&initstr);
      dynarray_reset(&stk_data, &nb_stk_data);
      while (cur_switch)          end_switch();
      local_scope = 0;
      loop_scope = NULL;
      all_cleanups = NULL;
      pending_gotos = NULL;
      nb_temp_local_vars = 0;
      global_label_stack = NULL;
      local_label_stack = NULL;
      cur_text_section = NULL;
      sym_free_first = NULL;

}

ST_FUNC ElfSym *elfsym(Sym *s)  {
    if (!s || !s->c)      return NULL;
    return &((ElfSym *)symtab_section->data)[s->c];

}

ST_FUNC void update_storage(Sym *sym)  {
      ElfSym *esym;
      int sym_bind, old_sym_bind;
        esym = elfsym(sym);
      if (!esym)          return;
        if (sym->a.visibility)          esym->st_other = (esym->st_other & ~ELFW(ST_VISIBILITY)(-1))              | sym->a.visibility;
        if (sym->type.t & (VT_STATIC | VT_INLINE))          sym_bind = STB_LOCAL;
      else if (sym->a.weak)          sym_bind = STB_WEAK;
      else          sym_bind = STB_GLOBAL;
      old_sym_bind = ELFW(ST_BIND)(esym->st_info);
      if (sym_bind != old_sym_bind) {
          esym->st_info = ELFW(ST_INFO)(sym_bind, ELFW(ST_TYPE)(esym->st_info));

}    #ifdef TCC_TARGET_PE      if (sym->a.dllimport)          esym->st_other |= ST_PE_IMPORT;
      if (sym->a.dllexport)          esym->st_other |= ST_PE_EXPORT;
  #endif    #if 0      printf("storage %s: bind=%c vis=%d exp=%d imp=%d\n",          get_tok_str(sym->v, NULL),          sym_bind == STB_WEAK ? 'w' : sym_bind == STB_LOCAL ? 'l' : 'g',          sym->a.visibility,          sym->a.dllexport,          sym->a.dllimport          );
  #endif  
}

ST_FUNC void put_extern_sym2(Sym *sym, int sh_num,                              addr_t value, unsigned long size,                              int can_add_underscore)  {
      int sym_type, sym_bind, info, other, t;
      ElfSym *esym;
      const char *name;
      char buf1[256];
        if (!sym->c) {
          name = get_tok_str(sym->v, NULL);
          t = sym->type.t;
          if ((t & VT_BTYPE) == VT_FUNC) {
              sym_type = STT_FUNC;

} else if ((t & VT_BTYPE) == VT_VOID) {
              sym_type = STT_NOTYPE;
              if ((t & (VT_BTYPE|VT_ASM_FUNC)) == VT_ASM_FUNC)                  sym_type = STT_FUNC;

} else {
              sym_type = STT_OBJECT;

}          if (t & (VT_STATIC | VT_INLINE))              sym_bind = STB_LOCAL;
          else              sym_bind = STB_GLOBAL;
          other = 0;
    #ifdef TCC_TARGET_PE          if (sym_type == STT_FUNC && sym->type.ref) {
              Sym *ref = sym->type.ref;
              if (ref->a.nodecorate) {
                  can_add_underscore = 0;

}              if (ref->f.func_call == FUNC_STDCALL && can_add_underscore) {
                  sprintf(buf1, "_%s@%d", name, ref->f.func_args * PTR_SIZE);
                  name = buf1;
                  other |= ST_PE_STDCALL;
                  can_add_underscore = 0;

}          
}  #endif            if (sym->asm_label) {
              name = get_tok_str(sym->asm_label, NULL);
              can_add_underscore = 0;

}            if (tcc_state->leading_underscore && can_add_underscore) {
              buf1[0] = '_';
              pstrcpy(buf1 + 1, sizeof(buf1) - 1, name);
              name = buf1;

}            info = ELFW(ST_INFO)(sym_bind, sym_type);
          sym->c = put_elf_sym(symtab_section, value, size, info, other, sh_num, name);
            if (debug_modes)              tcc_debug_extern_sym(tcc_state, sym, sh_num, sym_bind, sym_type);

} else {
          esym = elfsym(sym);
          esym->st_value = value;
          esym->st_size = size;
          esym->st_shndx = sh_num;

}      update_storage(sym);

}

ST_FUNC void put_extern_sym(Sym *sym, Section *s, addr_t value, unsigned long size)  {
      if (nocode_wanted && (NODATA_WANTED || (s && s == cur_text_section)))          return;
      put_extern_sym2(sym, s ? s->sh_num : SHN_UNDEF, value, size, 1);

}

ST_FUNC void greloca(Section *s, Sym *sym, unsigned long offset, int type,                       addr_t addend)  {
      int c = 0;
        if (nocode_wanted && s == cur_text_section)          return;
        if (sym) {
          if (0 == sym->c)              put_extern_sym(sym, NULL, 0, 0);
          c = sym->c;

}        /* now we can add ELF relocation info */      put_elf_reloca(symtab_section, s, offset, type, c, addend);

}

static Sym *__sym_malloc(void)  {
      Sym *sym_pool, *sym, *last_sym;
      int i;
        sym_pool = tcc_malloc(SYM_POOL_NB * sizeof(Sym));
      dynarray_add(&sym_pools, &nb_sym_pools, sym_pool);
        last_sym = sym_free_first;
      sym = sym_pool;
      for(i = 0;
 i < SYM_POOL_NB;
 i++) {
          sym->next = last_sym;
          last_sym = sym;
          sym++;

}      sym_free_first = last_sym;
      return last_sym;

}

static inline Sym *sym_malloc(void)  {
      Sym *sym;
  #ifndef SYM_DEBUG      sym = sym_free_first;
      if (!sym)          sym = __sym_malloc();
      sym_free_first = sym->next;
      return sym;
  #else      sym = tcc_malloc(sizeof(Sym));
      return sym;
  #endif  
}

ST_INLN void sym_free(Sym *sym)  {
  #ifndef SYM_DEBUG      sym->next = sym_free_first;
      sym_free_first = sym;
  #else      tcc_free(sym);
  #endif  
}

ST_FUNC Sym *sym_push2(Sym **ps, int v, int t, int c)  {
      Sym *s;
        s = sym_malloc();
      memset(s, 0, sizeof *s);
      s->v = v;
      s->type.t = t;
      s->c = c;
      /* add in stack */      s->prev = *ps;
      *ps = s;
      return s;

}

ST_FUNC Sym *sym_find2(Sym *s, int v)  {
      while (s) {
          if (s->v == v)              return s;
          s = s->prev;

}      return NULL;

}

ST_INLN Sym *struct_find(int v)  {
      v -= TOK_IDENT;
      if ((unsigned)v >= (unsigned)(tok_ident - TOK_IDENT))          return NULL;
      return table_ident[v]->sym_struct;

}

ST_INLN Sym *sym_find(int v)  {
      v -= TOK_IDENT;
      if ((unsigned)v >= (unsigned)(tok_ident - TOK_IDENT))          return NULL;
      return table_ident[v]->sym_identifier;

}

static int sym_scope(Sym *s)  {
    if (IS_ENUM_VAL (s->type.t))      return s->type.ref->sym_scope;
    else      return s->sym_scope;

}

ST_FUNC Sym *sym_push(int v, CType *type, int r, int c)  {
      Sym *s, **ps;
      TokenSym *ts;
        if (local_stack)          ps = &local_stack;
      else          ps = &global_stack;
      s = sym_push2(ps, v, type->t, c);
      s->type.ref = type->ref;
      s->r = r;
      /* don't record fields or anonymous symbols */      /* XXX: simplify */      if (!(v & SYM_FIELD) && (v & ~SYM_STRUCT) < SYM_FIRST_ANOM) {
          /* record symbol in token array */          ts = table_ident[(v & ~SYM_STRUCT) - TOK_IDENT];
          if (v & SYM_STRUCT)              ps = &ts->sym_struct;
          else              ps = &ts->sym_identifier;
          s->prev_tok = *ps;
          *ps = s;
          s->sym_scope = local_scope;
          if (s->prev_tok && sym_scope(s->prev_tok) == s->sym_scope)              tcc_error("redeclaration of '%s'",                  get_tok_str(v & ~SYM_STRUCT, NULL));

}      return s;

}

ST_FUNC Sym *global_identifier_push(int v, int t, int c)  {
      Sym *s, **ps;
      s = sym_push2(&global_stack, v, t, c);
      s->r = VT_CONST | VT_SYM;
      /* don't record anonymous symbol */      if (v < SYM_FIRST_ANOM) {
          ps = &table_ident[v - TOK_IDENT]->sym_identifier;
          /* modify the top most local identifier, so that sym_identifier will             point to 's' when popped;
 happens when called from inline asm */          while (*ps != NULL && (*ps)->sym_scope)              ps = &(*ps)->prev_tok;
          s->prev_tok = *ps;
          *ps = s;

}      return s;

}

ST_FUNC void sym_pop(Sym **ptop, Sym *b, int keep)  {
      Sym *s, *ss, **ps;
      TokenSym *ts;
      int v;
        s = *ptop;
      while(s != b) {
          ss = s->prev;
          v = s->v;
          /* remove symbol in token array */          /* XXX: simplify */          if (!(v & SYM_FIELD) && (v & ~SYM_STRUCT) < SYM_FIRST_ANOM) {
              ts = table_ident[(v & ~SYM_STRUCT) - TOK_IDENT];
              if (v & SYM_STRUCT)                  ps = &ts->sym_struct;
              else                  ps = &ts->sym_identifier;
              *ps = s->prev_tok;

}   if (!keep)       sym_free(s);
          s = ss;

}      if (!keep)   *ptop = b;

}

ST_FUNC Sym *label_find(int v)  {
      v -= TOK_IDENT;
      if ((unsigned)v >= (unsigned)(tok_ident - TOK_IDENT))          return NULL;
      return table_ident[v]->sym_label;

}

ST_FUNC Sym *label_push(Sym **ptop, int v, int flags)  {
      Sym *s, **ps;
      s = sym_push2(ptop, v, VT_STATIC, 0);
      s->r = flags;
      ps = &table_ident[v - TOK_IDENT]->sym_label;
      if (ptop == &global_label_stack) {
          /* modify the top most local identifier, so that             sym_identifier will point to 's' when popped */          while (*ps != NULL)              ps = &(*ps)->prev_tok;

}      s->prev_tok = *ps;
      *ps = s;
      return s;

}

ST_FUNC void label_pop(Sym **ptop, Sym *slast, int keep)  {
      Sym *s, *s1;
      for(s = *ptop;
 s != slast;
 s = s1) {
          s1 = s->prev;
          if (s->r == LABEL_DECLARED) {
              tcc_warning_c(warn_all)("label '%s' declared but not used", get_tok_str(s->v, NULL));

} else if (s->r == LABEL_FORWARD) {
                  tcc_error("label '%s' used but not defined",                        get_tok_str(s->v, NULL));

} else {
              if (s->c) {
                  /* define corresponding symbol. A size of                     1 is put. */                  put_extern_sym(s, cur_text_section, s->jnext, 1);

}          
}          /* remove label */          if (s->r != LABEL_GONE)              table_ident[s->v - TOK_IDENT]->sym_label = s->prev_tok;
          if (!keep)              sym_free(s);
          else              s->r = LABEL_GONE;

}      if (!keep)          *ptop = slast;

}

static void vcheck_cmp(void)  {
      /* cannot let cpu flags if other instruction are generated. Also         avoid leaving VT_JMP anywhere except on the top of the stack         because it would complicate the code generator.           Don't do this when nocode_wanted.  vtop might come from         !nocode_wanted regions (see 88_codeopt.c) and transforming         it to a register without actually generating code is wrong         as their value might still be used for real.  All values         we push under nocode_wanted will eventually be popped         again, so that the VT_CMP/VT_JMP value will be in vtop         when code is unsuppressed again. */        /* However if it's just automatic suppression via CODE_OFF/ON()         then it seems that we better let things work undisturbed.         How can it work at all under nocode_wanted?  Well, gv() will         actually clear it at the gsym() in load()/VT_JMP in the         generator backends */        if (vtop->r == VT_CMP && 0 == (nocode_wanted & ~CODE_OFF_BIT))          gv(RC_INT);

}

static void vsetc(CType *type, int r, CValue *vc)  {
      if (vtop >= vstack + (VSTACK_SIZE - 1))          tcc_error("memory full (vstack)");
      vcheck_cmp();
      vtop++;
      vtop->type = *type;
      vtop->r = r;
      vtop->r2 = VT_CONST;
      vtop->c = *vc;
      vtop->sym = NULL;

}

ST_FUNC void vswap(void)  {
      SValue tmp;
        vcheck_cmp();
      tmp = vtop[0];
      vtop[0] = vtop[-1];
      vtop[-1] = tmp;

}

ST_FUNC void vpop(void)  {
      int v;
      v = vtop->r & VT_VALMASK;
  #if defined(TCC_TARGET_I386) || defined(TCC_TARGET_X86_64)      /* for x86, we need to pop the FP stack */      if (v == TREG_ST0) {
          o(0xd8dd);
 /* fstp %st(0) */      
} else  #endif      if (v == VT_CMP) {
          /* need to put correct jump if && or || without test */          gsym(vtop->jtrue);
          gsym(vtop->jfalse);

}      vtop--;

}

static void vpush(CType *type)  {
      vset(type, VT_CONST, 0);

}

static void vpush64(int ty, unsigned long long v)  {
      CValue cval;
      CType ctype;
      ctype.t = ty;
      ctype.ref = NULL;
      cval.i = v;
      vsetc(&ctype, VT_CONST, &cval);

}

ST_FUNC void vpushi(int v)  {
      vpush64(VT_INT, v);

}

static void vpushs(addr_t v)  {
      vpush64(VT_SIZE_T, v);

}

static inline void vpushll(long long v)  {
      vpush64(VT_LLONG, v);

}

ST_FUNC void vset(CType *type, int r, int v)  {
      CValue cval;
      cval.i = v;
      vsetc(type, r, &cval);

}

static void vseti(int r, int v)  {
      CType type;
      type.t = VT_INT;
      type.ref = NULL;
      vset(&type, r, v);

}

ST_FUNC void vpushv(SValue *v)  {
      if (vtop >= vstack + (VSTACK_SIZE - 1))          tcc_error("memory full (vstack)");
      vtop++;
      *vtop = *v;

}

static void vdup(void)  {
      vpushv(vtop);

}

ST_FUNC void vrotb(int n)  {
      SValue tmp;
      if (--n < 1)          return;
      vcheck_cmp();
      tmp = vtop[-n];
      memmove(vtop - n, vtop - n + 1, sizeof *vtop * n);
      vtop[0] = tmp;

}

ST_FUNC void vrott(int n)  {
      SValue tmp;
      if (--n < 1)          return;
      vcheck_cmp();
      tmp = vtop[0];
      memmove(vtop - n + 1, vtop - n, sizeof *vtop * n);
      vtop[-n] = tmp;

}

ST_FUNC void vrev(int n)  {
      int i;
      SValue tmp;
      vcheck_cmp();
      for (i = 0, n = -n;
 i > ++n;
 --i)          tmp = vtop[i], vtop[i] = vtop[n], vtop[n] = tmp;

}

ST_FUNC void vset_VT_CMP(int op)  {
      vtop->r = VT_CMP;
      vtop->cmp_op = op;
      vtop->jfalse = 0;
      vtop->jtrue = 0;

}

static void vset_VT_JMP(void)  {
      int op = vtop->cmp_op;
        if (vtop->jtrue || vtop->jfalse) {
          int origt = vtop->type.t;
          /* we need to jump to 'mov $0,%R' or 'mov $1,%R' */          int inv = op & (op < 2);
 /* small optimization */          vseti(VT_JMP+inv, gvtst(inv, 0));
          vtop->type.t |= origt & (VT_UNSIGNED | VT_DEFSIGN);

} else {
          /* otherwise convert flags (rsp. 0/1) to register */          vtop->c.i = op;
          if (op < 2) /* doesn't seem to happen */              vtop->r = VT_CONST;

}  
}

static void gvtst_set(int inv, int t)  {
      int *p;
        if (vtop->r != VT_CMP) {
          vpushi(0);
          gen_op(TOK_NE);
          if (vtop->r != VT_CMP) /* must be VT_CONST then */              vset_VT_CMP(vtop->c.i != 0);

}        p = inv ? &vtop->jfalse : &vtop->jtrue;
      *p = gjmp_append(*p, t);

}

static int gvtst(int inv, int t)  {
      int op, x, u;
        gvtst_set(inv, t);
      t = vtop->jtrue, u = vtop->jfalse;
      if (inv)          x = u, u = t, t = x;
      op = vtop->cmp_op;
        /* jump to the wanted target */      if (op > 1)          t = gjmp_cond(op ^ inv, t);
      else if (op != inv)          t = gjmp(t);
      /* resolve complementary jumps to here */      gsym(u);
        vtop--;
      return t;

}

static void gen_test_zero(int op)  {
      if (vtop->r == VT_CMP) {
          int j;
          if (op == TOK_EQ) {
              j = vtop->jfalse;
              vtop->jfalse = vtop->jtrue;
              vtop->jtrue = j;
              vtop->cmp_op ^= 1;

}      
} else {
          vpushi(0);
          gen_op(op);

}  
}

ST_FUNC void vpushsym(CType *type, Sym *sym)  {
      CValue cval;
      cval.i = 0;
      vsetc(type, VT_CONST | VT_SYM, &cval);
      vtop->sym = sym;

}

ST_FUNC Sym *get_sym_ref(CType *type, Section *sec, unsigned long offset, unsigned long size)  {
      int v;
      Sym *sym;
        v = anon_sym++;
      sym = sym_push(v, type, VT_CONST | VT_SYM, 0);
      sym->type.t |= VT_STATIC;
      put_extern_sym(sym, sec, offset, size);
      return sym;

}

static void vpush_ref(CType *type, Section *sec, unsigned long offset, unsigned long size)  {
      vpushsym(type, get_sym_ref(type, sec, offset, size));

}

ST_FUNC Sym *external_global_sym(int v, CType *type)  {
      Sym *s;
        s = sym_find(v);
      if (!s) {
          /* push forward reference */          s = global_identifier_push(v, type->t | VT_EXTERN, 0);
          s->type.ref = type->ref;

} else if (IS_ASM_SYM(s)) {
          s->type.t = type->t | (s->type.t & VT_EXTERN);
          s->type.ref = type->ref;
          update_storage(s);

}      return s;

}

ST_FUNC Sym *external_helper_sym(int v)  {
      CType ct = {
 VT_ASM_FUNC, NULL 
};
      return external_global_sym(v, &ct);

}

ST_FUNC void vpush_helper_func(int v)  {
      vpushsym(&func_old_type, external_helper_sym(v));

}

static void merge_symattr(struct SymAttr *sa, struct SymAttr *sa1)  {
      if (sa1->aligned && !sa->aligned)        sa->aligned = sa1->aligned;
      sa->packed |= sa1->packed;
      sa->weak |= sa1->weak;
      sa->nodebug |= sa1->nodebug;
      if (sa1->visibility != STV_DEFAULT) {
   int vis = sa->visibility;
   if (vis == STV_DEFAULT       || vis > sa1->visibility)     vis = sa1->visibility;
   sa->visibility = vis;

}      sa->dllexport |= sa1->dllexport;
      sa->nodecorate |= sa1->nodecorate;
      sa->dllimport |= sa1->dllimport;

}

static void merge_funcattr(struct FuncAttr *fa, struct FuncAttr *fa1)  {
      if (fa1->func_call && !fa->func_call)        fa->func_call = fa1->func_call;
      if (fa1->func_type && !fa->func_type)        fa->func_type = fa1->func_type;
      if (fa1->func_args && !fa->func_args)        fa->func_args = fa1->func_args;
      if (fa1->func_noreturn)        fa->func_noreturn = 1;
      if (fa1->func_ctor)        fa->func_ctor = 1;
      if (fa1->func_dtor)        fa->func_dtor = 1;

}

static void merge_attr(AttributeDef *ad, AttributeDef *ad1)  {
      merge_symattr(&ad->a, &ad1->a);
      merge_funcattr(&ad->f, &ad1->f);
        if (ad1->section)        ad->section = ad1->section;
      if (ad1->alias_target)        ad->alias_target = ad1->alias_target;
      if (ad1->asm_label)        ad->asm_label = ad1->asm_label;
      if (ad1->attr_mode)        ad->attr_mode = ad1->attr_mode;

}

static void patch_type(Sym *sym, CType *type)  {
      if (!(type->t & VT_EXTERN) || IS_ENUM_VAL(sym->type.t)) {
          if (!(sym->type.t & VT_EXTERN))              tcc_error("redefinition of '%s'", get_tok_str(sym->v, NULL));
          sym->type.t &= ~VT_EXTERN;

}        if (IS_ASM_SYM(sym)) {
          /* stay static if both are static */          sym->type.t = type->t & (sym->type.t | ~VT_STATIC);
          sym->type.ref = type->ref;
          if ((type->t & VT_BTYPE) != VT_FUNC && !(type->t & VT_ARRAY))              sym->r |= VT_LVAL;

}        if (!is_compatible_types(&sym->type, type)) {
          tcc_error("incompatible types for redefinition of '%s'",                    get_tok_str(sym->v, NULL));

} else if ((sym->type.t & VT_BTYPE) == VT_FUNC) {
          int static_proto = sym->type.t & VT_STATIC;
          /* warn if static follows non-static function declaration */          if ((type->t & VT_STATIC) && !static_proto              /* XXX this test for inline shouldn't be here.  Until we                 implement gnu-inline mode again it silences a warning for                 mingw caused by our workarounds.  */              && !((type->t | sym->type.t) & VT_INLINE))              tcc_warning("static storage ignored for redefinition of '%s'",                  get_tok_str(sym->v, NULL));
            /* set 'inline' if both agree or if one has static */          if ((type->t | sym->type.t) & VT_INLINE) {
              if (!((type->t ^ sym->type.t) & VT_INLINE)               || ((type->t | sym->type.t) & VT_STATIC))                  static_proto |= VT_INLINE;

}            if (0 == (type->t & VT_EXTERN)) {
              struct FuncAttr f = sym->type.ref->f;
              /* put complete type, use static from prototype */              sym->type.t = (type->t & ~(VT_STATIC|VT_INLINE)) | static_proto;
              sym->type.ref = type->ref;
              merge_funcattr(&sym->type.ref->f, &f);

} else {
              sym->type.t &= ~VT_INLINE | static_proto;

}            if (sym->type.ref->f.func_type == FUNC_OLD               && type->ref->f.func_type != FUNC_OLD) {
              sym->type.ref = type->ref;

}        
} else {
          if ((sym->type.t & VT_ARRAY) && type->ref->c >= 0) {
              /* set array size if it was omitted in extern declaration */              sym->type.ref->c = type->ref->c;

}          if ((type->t ^ sym->type.t) & VT_STATIC)              tcc_warning("storage mismatch for redefinition of '%s'",                  get_tok_str(sym->v, NULL));

}  
}

static void patch_storage(Sym *sym, AttributeDef *ad, CType *type)  {
      if (type)          patch_type(sym, type);
    #ifdef TCC_TARGET_PE      if (sym->a.dllimport != ad->a.dllimport)          tcc_error("incompatible dll linkage for redefinition of '%s'",              get_tok_str(sym->v, NULL));
  #endif      merge_symattr(&sym->a, &ad->a);
      if (ad->asm_label)          sym->asm_label = ad->asm_label;
      update_storage(sym);

}

static Sym *sym_copy(Sym *s0, Sym **ps)  {
      Sym *s;
      s = sym_malloc(), *s = *s0;
      s->prev = *ps, *ps = s;
      if (s->v < SYM_FIRST_ANOM) {
          ps = &table_ident[s->v - TOK_IDENT]->sym_identifier;
          s->prev_tok = *ps, *ps = s;

}      return s;

}

static void sym_copy_ref(Sym *s, Sym **ps)  {
      int bt = s->type.t & VT_BTYPE;
      if (bt == VT_FUNC || bt == VT_PTR || (bt == VT_STRUCT && s->sym_scope)) {
          Sym **sp = &s->type.ref;
          for (s = *sp, *sp = NULL;
 s;
 s = s->next) {
              Sym *s2 = sym_copy(s, ps);
              sp = &(*sp = s2)->next;
              sym_copy_ref(s2, ps);

}      
}  
}

static Sym *external_sym(int v, CType *type, int r, AttributeDef *ad)  {
      Sym *s;
        /* look for global symbol */      s = sym_find(v);
      while (s && s->sym_scope)          s = s->prev_tok;
        if (!s) {
          /* push forward reference */          s = global_identifier_push(v, type->t, 0);
          s->r |= r;
          s->a = ad->a;
          s->asm_label = ad->asm_label;
          s->type.ref = type->ref;
          /* copy type to the global stack */          if (local_stack)              sym_copy_ref(s, &global_stack);

} else {
          patch_storage(s, ad, type);

}      /* push variables on local_stack if any */      if (local_stack && (s->type.t & VT_BTYPE) != VT_FUNC)          s = sym_copy(s, &local_stack);
      return s;

}

ST_FUNC void save_regs(int n)  {
      SValue *p, *p1;
      for(p = vstack, p1 = vtop - n;
 p <= p1;
 p++)          save_reg(p->r);

}

ST_FUNC void save_reg(int r)  {
      save_reg_upstack(r, 0);

}

ST_FUNC void save_reg_upstack(int r, int n)  {
      int l, size, align, bt, r2;
      SValue *p, *p1, sv;
        if ((r &= VT_VALMASK) >= VT_CONST)          return;
      if (nocode_wanted)          return;
      l = r2 = 0;
      for(p = vstack, p1 = vtop - n;
 p <= p1;
 p++) {
          if ((p->r & VT_VALMASK) == r || p->r2 == r) {
              /* must save value on stack if not already done */              if (!l) {
                  bt = p->type.t & VT_BTYPE;
                  if (bt == VT_VOID)                      continue;
                  if ((p->r & VT_LVAL) || bt == VT_FUNC)                      bt = VT_PTR;
                  sv.type.t = bt;
                  size = type_size(&sv.type, &align);
                  l = get_temp_local_var(size, align, &r2);
                  sv.r = VT_LOCAL | VT_LVAL;
                  sv.c.i = l;
                  store(p->r & VT_VALMASK, &sv);
  #if defined(TCC_TARGET_I386) || defined(TCC_TARGET_X86_64)                  /* x86 specific: need to pop fp register ST0 if saved */                  if (r == TREG_ST0) {
                      o(0xd8dd);
 /* fstp %st(0) */                  
}  #endif                  /* special long long case */                  if (p->r2 < VT_CONST && USING_TWO_WORDS(bt)) {
                      sv.c.i += PTR_SIZE;
                      store(p->r2, &sv);

}              
}              /* mark that stack entry as being saved on the stack */              if (p->r & VT_LVAL) {
                  /* also clear the bounded flag because the                     relocation address of the function was stored in                     p->c.i */                  p->r = (p->r & ~(VT_VALMASK | VT_BOUNDED)) | VT_LLOCAL;

} else {
                  p->r = VT_LVAL | VT_LOCAL;
                  p->type.t &= ~VT_ARRAY;
 /* cannot combine VT_LVAL with VT_ARRAY */              
}              p->sym = NULL;
              p->r2 = r2;
              p->c.i = l;

}      
}  
}

ST_FUNC int get_reg(int rc)  {
      int r;
      SValue *p;
        /* find a free register */      for(r=0;
r<NB_REGS;
r++) {
          if (reg_classes[r] & rc) {
              if (nocode_wanted)                  return r;
              for(p=vstack;
p<=vtop;
p++) {
                  if ((p->r & VT_VALMASK) == r ||                      p->r2 == r)                      goto notfound;

}              return r;

}      notfound:;

}            /* no register left : free the first one on the stack (VERY         IMPORTANT to start from the bottom to ensure that we don't         spill registers used in gen_opi()) */      for(p=vstack;
p<=vtop;
p++) {
          /* look at second register (if long long) */          r = p->r2;
          if (r < VT_CONST && (reg_classes[r] & rc))              goto save_found;
          r = p->r & VT_VALMASK;
          if (r < VT_CONST && (reg_classes[r] & rc)) {
          save_found:              save_reg(r);
              return r;

}      
}      /* Should never comes here */      return -1;

}

static int get_temp_local_var(int size,int align, int *r2)  {
      int i;
      struct temp_local_variable *temp_var;
      SValue *p;
      int r;
      unsigned used = 0;
        /* mark locations that are still in use */      for (p = vstack;
 p <= vtop;
 p++) {
   r = p->r & VT_VALMASK;
   if (r == VT_LOCAL || r == VT_LLOCAL) {
       r = p->r2 - (VT_CONST + 1);
       if (r >= 0 && r < MAX_TEMP_LOCAL_VARIABLE_NUMBER)           used |= 1<<r;

}      
}      for (i=0;
i<nb_temp_local_vars;
i++) {
   temp_var=&arr_temp_local_vars[i];
   if(!(used & 1<<i)    && temp_var->size>=size    && temp_var->align>=align) {
  ret_tmp:       *r2 = (VT_CONST + 1) + i;
       return temp_var->location;

}      
}      loc = (loc - size) & -align;
      if (nb_temp_local_vars<MAX_TEMP_LOCAL_VARIABLE_NUMBER) {
   temp_var=&arr_temp_local_vars[i];
   temp_var->location=loc;
   temp_var->size=size;
   temp_var->align=align;
   nb_temp_local_vars++;
   goto ret_tmp;

}      *r2 = VT_CONST;
      return loc;

}

static void move_reg(int r, int s, int t)  {
      SValue sv;
        if (r != s) {
          save_reg(r);
          sv.type.t = t;
          sv.type.ref = NULL;
          sv.r = s;
          sv.c.i = 0;
          load(r, &sv);

}  
}

ST_FUNC void gaddrof(void)  {
      vtop->r &= ~VT_LVAL;
      /* tricky: if saved lvalue, then we can go back to lvalue */      if ((vtop->r & VT_VALMASK) == VT_LLOCAL)          vtop->r = (vtop->r & ~VT_VALMASK) | VT_LOCAL | VT_LVAL;

}

static void pop_local_syms(Sym *b, int keep)  {
  #ifdef CONFIG_TCC_BCHECK      if (tcc_state->do_bounds_check && !keep && (local_scope || !func_var))          add_local_bounds(local_stack, b);
  #endif      if (debug_modes)          tcc_add_debug_info (tcc_state, !local_scope, local_stack, b);
      sym_pop(&local_stack, b, keep);

}

static void incr_offset(int offset)  {
      int t = vtop->type.t;
      gaddrof();
 /* remove VT_LVAL */      vtop->type.t = VT_PTRDIFF_T;
 /* set scalar type */      vpushs(offset);
      gen_op('+');
      vtop->r |= VT_LVAL;
      vtop->type.t = t;

}

static void incr_bf_adr(int o)  {
      vtop->type.t = VT_BYTE | VT_UNSIGNED;
      incr_offset(o);

}

static void load_packed_bf(CType *type, int bit_pos, int bit_size)  {
      int n, o, bits;
      save_reg_upstack(vtop->r, 1);
      vpush64(type->t & VT_BTYPE, 0);
 // B X      bits = 0, o = bit_pos >> 3, bit_pos &= 7;
      do {
          vswap();
 // X B          incr_bf_adr(o);
          vdup();
 // X B B          n = 8 - bit_pos;
          if (n > bit_size)              n = bit_size;
          if (bit_pos)              vpushi(bit_pos), gen_op(TOK_SHR), bit_pos = 0;
 // X B Y          if (n < 8)              vpushi((1 << n) - 1), gen_op('&');
          gen_cast(type);
          if (bits)              vpushi(bits), gen_op(TOK_SHL);
          vrotb(3);
 // B Y X          gen_op('|');
 // B X          bits += n, bit_size -= n, o = 1;

} while (bit_size);
      vswap(), vpop();
      if (!(type->t & VT_UNSIGNED)) {
          n = ((type->t & VT_BTYPE) == VT_LLONG ? 64 : 32) - bits;
          vpushi(n), gen_op(TOK_SHL);
          vpushi(n), gen_op(TOK_SAR);

}  
}

static void store_packed_bf(int bit_pos, int bit_size)  {
      int bits, n, o, m, c;
      c = (vtop->r & (VT_VALMASK | VT_LVAL | VT_SYM)) == VT_CONST;
      vswap();
 // X B      save_reg_upstack(vtop->r, 1);
      bits = 0, o = bit_pos >> 3, bit_pos &= 7;
      do {
          incr_bf_adr(o);
 // X B          vswap();
 //B X          c ? vdup() : gv_dup();
 // B V X          vrott(3);
 // X B V          if (bits)              vpushi(bits), gen_op(TOK_SHR);
          if (bit_pos)              vpushi(bit_pos), gen_op(TOK_SHL);
          n = 8 - bit_pos;
          if (n > bit_size)              n = bit_size;
          if (n < 8) {
              m = ((1 << n) - 1) << bit_pos;
              vpushi(m), gen_op('&');
 // X B V1              vpushv(vtop-1);
 // X B V1 B              vpushi(m & 0x80 ? ~m & 0x7f : ~m);
              gen_op('&');
 // X B V1 B1              gen_op('|');
 // X B V2          
}          vdup(), vtop[-1] = vtop[-2];
 // X B B V2          vstore(), vpop();
 // X B          bits += n, bit_size -= n, bit_pos = 0, o = 1;

} while (bit_size);
      vpop(), vpop();

}

static int adjust_bf(SValue *sv, int bit_pos, int bit_size)  {
      int t;
      if (0 == sv->type.ref)          return 0;
      t = sv->type.ref->auxtype;
      if (t != -1 && t != VT_STRUCT) {
          sv->type.t = (sv->type.t & ~(VT_BTYPE | VT_LONG)) | t;
          sv->r |= VT_LVAL;

}      return t;

}

ST_FUNC int gv(int rc)  {
      int r, r2, r_ok, r2_ok, rc2, bt;
      int bit_pos, bit_size, size, align;
        /* NOTE: get_reg can modify vstack[] */      if (vtop->type.t & VT_BITFIELD) {
          CType type;
            bit_pos = BIT_POS(vtop->type.t);
          bit_size = BIT_SIZE(vtop->type.t);
          /* remove bit field info to avoid loops */          vtop->type.t &= ~VT_STRUCT_MASK;
            type.ref = NULL;
          type.t = vtop->type.t & VT_UNSIGNED;
          if ((vtop->type.t & VT_BTYPE) == VT_BOOL)              type.t |= VT_UNSIGNED;
            r = adjust_bf(vtop, bit_pos, bit_size);
            if ((vtop->type.t & VT_BTYPE) == VT_LLONG)              type.t |= VT_LLONG;
          else              type.t |= VT_INT;
            if (r == VT_STRUCT) {
              load_packed_bf(&type, bit_pos, bit_size);

} else {
              int bits = (type.t & VT_BTYPE) == VT_LLONG ? 64 : 32;
              /* cast to int to propagate signedness in following ops */              gen_cast(&type);
              /* generate shifts */              vpushi(bits - (bit_pos + bit_size));
              gen_op(TOK_SHL);
              vpushi(bits - bit_size);
              /* NOTE: transformed to SHR if unsigned */              gen_op(TOK_SAR);

}          r = gv(rc);

} else {
          if (is_float(vtop->type.t) &&               (vtop->r & (VT_VALMASK | VT_LVAL)) == VT_CONST) {
              /* CPUs usually cannot use float constants, so we store them                 generically in data segment */              init_params p = {
 rodata_section 
};
              unsigned long offset;
              size = type_size(&vtop->type, &align);
              if (NODATA_WANTED)                  size = 0, align = 1;
              offset = section_add(p.sec, size, align);
              vpush_ref(&vtop->type, p.sec, offset, size);
       vswap();
       init_putv(&p, &vtop->type, offset);
       vtop->r |= VT_LVAL;

}  #ifdef CONFIG_TCC_BCHECK          if (vtop->r & VT_MUSTBOUND)               gbound();
  #endif            bt = vtop->type.t & VT_BTYPE;
    #ifdef TCC_TARGET_RISCV64          /* XXX mega hack */          if (bt == VT_LDOUBLE && rc == RC_FLOAT)            rc = RC_INT;
  #endif          rc2 = RC2_TYPE(bt, rc);
            /* need to reload if:             - constant             - lvalue (need to dereference pointer)             - already a register, but not in the right class */          r = vtop->r & VT_VALMASK;
          r_ok = !(vtop->r & VT_LVAL) && (r < VT_CONST) && (reg_classes[r] & rc);
          r2_ok = !rc2 || ((vtop->r2 < VT_CONST) && (reg_classes[vtop->r2] & rc2));
            if (!r_ok || !r2_ok) {
                if (!r_ok) {
                  if (1 /* we can 'mov (r),r' in cases */                      && r < VT_CONST                      && (reg_classes[r] & rc)                      && !rc2                      )                      save_reg_upstack(r, 1);
                  else                      r = get_reg(rc);

}                if (rc2) {
                  int load_type = (bt == VT_QFLOAT) ? VT_DOUBLE : VT_PTRDIFF_T;
                  int original_type = vtop->type.t;
                    /* two register type load :                     expand to two words temporarily */                  if ((vtop->r & (VT_VALMASK | VT_LVAL)) == VT_CONST) {
                      /* load constant */                      unsigned long long ll = vtop->c.i;
                      vtop->c.i = ll;
 /* first word */                      load(r, vtop);
                      vtop->r = r;
 /* save register value */                      vpushi(ll >> 32);
 /* second word */                  
} else if (vtop->r & VT_LVAL) {
                      /* We do not want to modifier the long long pointer here.                         So we save any other instances down the stack */                      save_reg_upstack(vtop->r, 1);
                      /* load from memory */                      vtop->type.t = load_type;
                      load(r, vtop);
                      vdup();
                      vtop[-1].r = r;
 /* save register value */                      /* increment pointer to get second word */                      incr_offset(PTR_SIZE);

} else {
                      /* move registers */                      if (!r_ok)                          load(r, vtop);
                      if (r2_ok && vtop->r2 < VT_CONST)                          goto done;
                      vdup();
                      vtop[-1].r = r;
 /* save register value */                      vtop->r = vtop[-1].r2;

}                  /* Allocate second register. Here we rely on the fact that                     get_reg() tries first to free r2 of an SValue. */                  r2 = get_reg(rc2);
                  load(r2, vtop);
                  vpop();
                  /* write second register */                  vtop->r2 = r2;
              done:                  vtop->type.t = original_type;

} else {
                  if (vtop->r == VT_CMP)                      vset_VT_JMP();
                  /* one register type load */                  load(r, vtop);

}          
}          vtop->r = r;
  #ifdef TCC_TARGET_C67          /* uses register pairs for doubles */          if (bt == VT_DOUBLE)              vtop->r2 = r+1;
  #endif      
}      return r;

}

ST_FUNC void gv2(int rc1, int rc2)  {
      /* generate more generic register first. But VT_JMP or VT_CMP         values must be generated first in all cases to avoid possible         reload errors */      if (vtop->r != VT_CMP && rc1 <= rc2) {
          vswap();
          gv(rc1);
          vswap();
          gv(rc2);
          /* test if reload is needed for first register */          if ((vtop[-1].r & VT_VALMASK) >= VT_CONST) {
              vswap();
              gv(rc1);
              vswap();

}      
} else {
          gv(rc2);
          vswap();
          gv(rc1);
          vswap();
          /* test if reload is needed for first register */          if ((vtop[0].r & VT_VALMASK) >= VT_CONST) {
              gv(rc2);

}      
}  
}

static void gv_dup(void)  {
      int t, rc, r;
        t = vtop->type.t;
  #if PTR_SIZE == 4      if ((t & VT_BTYPE) == VT_LLONG) {
          if (t & VT_BITFIELD) {
              gv(RC_INT);
              t = vtop->type.t;

}          lexpand();
          gv_dup();
          vswap();
          vrotb(3);
          gv_dup();
          vrotb(4);
          /* stack: H L L1 H1 */          lbuild(t);
          vrotb(3);
          vrotb(3);
          vswap();
          lbuild(t);
          vswap();
          return;

}  #endif      /* duplicate value */      rc = RC_TYPE(t);
      gv(rc);
      r = get_reg(rc);
      vdup();
      load(r, vtop);
      vtop->r = r;

}

static uint64_t value64(uint64_t l1, int t)  {
      if ((t & VT_BTYPE) == VT_LLONG          || (PTR_SIZE == 8 && (t & VT_BTYPE) == VT_PTR))          return l1;
      else if (t & VT_UNSIGNED)          return (uint32_t)l1;
      else          return (uint32_t)l1 | -(l1 & 0x80000000);

}

static uint64_t gen_opic_sdiv(uint64_t a, uint64_t b)  {
      uint64_t x = (a >> 63 ? -a : a) / (b >> 63 ? -b : b);
      return (a ^ b) >> 63 ? -x : x;

}

static int gen_opic_lt(uint64_t a, uint64_t b)  {
      return (a ^ (uint64_t)1 << 63) < (b ^ (uint64_t)1 << 63);

}

static void gen_opic(int op)  {
      SValue *v1 = vtop - 1;
      SValue *v2 = vtop;
      int t1 = v1->type.t & VT_BTYPE;
      int t2 = v2->type.t & VT_BTYPE;
      int c1 = (v1->r & (VT_VALMASK | VT_LVAL | VT_SYM)) == VT_CONST;
      int c2 = (v2->r & (VT_VALMASK | VT_LVAL | VT_SYM)) == VT_CONST;
      uint64_t l1 = c1 ? value64(v1->c.i, v1->type.t) : 0;
      uint64_t l2 = c2 ? value64(v2->c.i, v2->type.t) : 0;
      int shm = (t1 == VT_LLONG) ? 63 : 31;
      int r;
        if (c1 && c2) {
          switch(op) {
          case '+': l1 += l2;
 break;
          case '-': l1 -= l2;
 break;
          case '&': l1 &= l2;
 break;
          case '^': l1 ^= l2;
 break;
          case '|': l1 |= l2;
 break;
          case '*': l1 *= l2;
 break;
            case TOK_PDIV:          case '/':          case '%':          case TOK_UDIV:          case TOK_UMOD:              /* if division by zero, generate explicit division */              if (l2 == 0) {
                  if (CONST_WANTED && !NOEVAL_WANTED)                      tcc_error("division by zero in constant");
                  goto general_case;

}              switch(op) {
              default: l1 = gen_opic_sdiv(l1, l2);
 break;
              case '%': l1 = l1 - l2 * gen_opic_sdiv(l1, l2);
 break;
              case TOK_UDIV: l1 = l1 / l2;
 break;
              case TOK_UMOD: l1 = l1 % l2;
 break;

}              break;
          case TOK_SHL: l1 <<= (l2 & shm);
 break;
          case TOK_SHR: l1 >>= (l2 & shm);
 break;
          case TOK_SAR:              l1 = (l1 >> 63) ? ~(~l1 >> (l2 & shm)) : l1 >> (l2 & shm);
              break;
              /* tests */          case TOK_ULT: l1 = l1 < l2;
 break;
          case TOK_UGE: l1 = l1 >= l2;
 break;
          case TOK_EQ: l1 = l1 == l2;
 break;
          case TOK_NE: l1 = l1 != l2;
 break;
          case TOK_ULE: l1 = l1 <= l2;
 break;
          case TOK_UGT: l1 = l1 > l2;
 break;
          case TOK_LT: l1 = gen_opic_lt(l1, l2);
 break;
          case TOK_GE: l1 = !gen_opic_lt(l1, l2);
 break;
          case TOK_LE: l1 = !gen_opic_lt(l2, l1);
 break;
          case TOK_GT: l1 = gen_opic_lt(l2, l1);
 break;
              /* logical */          case TOK_LAND: l1 = l1 && l2;
 break;
          case TOK_LOR: l1 = l1 || l2;
 break;
          default:              goto general_case;

}          v1->c.i = value64(l1, v1->type.t);
          v1->r |= v2->r & VT_NONCONST;
          vtop--;

} else {
          /* if commutative ops, put c2 as constant */          if (c1 && (op == '+' || op == '&' || op == '^' ||                      op == '|' || op == '*' || op == TOK_EQ || op == TOK_NE)) {
              vswap();
              c2 = c1;
 //c = c1, c1 = c2, c2 = c;
              l2 = l1;
 //l = l1, l1 = l2, l2 = l;

}          if (c1 && ((l1 == 0 &&                      (op == TOK_SHL || op == TOK_SHR || op == TOK_SAR)) ||                     (l1 == -1 && op == TOK_SAR))) {
              /* treat (0 << x), (0 >> x) and (-1 >> x) as constant */              vpop();

} else if (c2 && ((l2 == 0 && (op == '&' || op == '*')) ||                            (op == '|' &&                              (l2 == -1 || (l2 == 0xFFFFFFFF && t2 != VT_LLONG))) ||                            (l2 == 1 && (op == '%' || op == TOK_UMOD)))) {
              /* treat (x & 0), (x * 0), (x | -1) and (x % 1) as constant */              if (l2 == 1)                  vtop->c.i = 0;
              vswap();
              vtop--;

} else if (c2 && (((op == '*' || op == '/' || op == TOK_UDIV ||                            op == TOK_PDIV) &&                             l2 == 1) ||                            ((op == '+' || op == '-' || op == '|' || op == '^' ||                              op == TOK_SHL || op == TOK_SHR || op == TOK_SAR) &&                             l2 == 0) ||                            (op == '&' &&                              (l2 == -1 || (l2 == 0xFFFFFFFF && t2 != VT_LLONG))))) {
              /* filter out NOP operations like x*1, x-0, x&-1... */              vtop--;

} else if (c2 && (op == '*' || op == TOK_PDIV || op == TOK_UDIV)) {
              /* try to use shifts instead of muls or divs */              if (l2 > 0 && (l2 & (l2 - 1)) == 0) {
                  int n = -1;
                  while (l2) {
                      l2 >>= 1;
                      n++;

}                  vtop->c.i = n;
                  if (op == '*')                      op = TOK_SHL;
                  else if (op == TOK_PDIV)                      op = TOK_SAR;
                  else                      op = TOK_SHR;

}              goto general_case;

} else if (c2 && (op == '+' || op == '-') &&                     (r = vtop[-1].r & (VT_VALMASK | VT_LVAL | VT_SYM),                      r == (VT_CONST | VT_SYM) || r == VT_LOCAL)) {
              /* symbol + constant case */              if (op == '-')                  l2 = -l2;
       l2 += vtop[-1].c.i;
       /* The backends can't always deal with addends to symbols          larger than +-1<<31.  Don't construct such.  */       if ((int)l2 != l2)           goto general_case;
              vtop--;
              vtop->c.i = l2;

} else {
          general_case:                  /* call low level op generator */                  if (t1 == VT_LLONG || t2 == VT_LLONG ||                      (PTR_SIZE == 8 && (t1 == VT_PTR || t2 == VT_PTR)))                      gen_opl(op);
                  else                      gen_opi(op);

}          if (vtop->r == VT_CONST)              vtop->r |= VT_NONCONST;
 /* is const, but only by optimization */      
}  
}

static void gen_opif(int op)  {
      int c1, c2, i, bt;
      SValue *v1, *v2;
  #if defined _MSC_VER && defined __x86_64__      /* avoid bad optimization with f1 -= f2 for f1:-0.0, f2:0.0 */      volatile  #endif      long double f1, f2;
        v1 = vtop - 1;
      v2 = vtop;
      if (op == TOK_NEG)          v1 = v2;
      bt = v1->type.t & VT_BTYPE;
        /* currently, we cannot do computations with forward symbols */      c1 = (v1->r & (VT_VALMASK | VT_LVAL | VT_SYM)) == VT_CONST;
      c2 = (v2->r & (VT_VALMASK | VT_LVAL | VT_SYM)) == VT_CONST;
      if (c1 && c2) {
          if (bt == VT_FLOAT) {
              f1 = v1->c.f;
              f2 = v2->c.f;

} else if (bt == VT_DOUBLE) {
              f1 = v1->c.d;
              f2 = v2->c.d;

} else {
              f1 = v1->c.ld;
              f2 = v2->c.ld;

}          /* NOTE: we only do constant propagation if finite number (not             NaN or infinity) (ANSI spec) */          if (!(ieee_finite(f1) || !ieee_finite(f2)) && !CONST_WANTED)              goto general_case;
          switch(op) {
          case '+': f1 += f2;
 break;
          case '-': f1 -= f2;
 break;
          case '*': f1 *= f2;
 break;
          case '/':               if (f2 == 0.0) {
                  union {
 float f;
 unsigned u;

} x1, x2, y;
    /* If not in initializer we need to potentially generate       FP exceptions at runtime, otherwise we want to fold.  */                  if (!CONST_WANTED)                      goto general_case;
                  /* the run-time result of 0.0/0.0 on x87, also of other compilers                     when used to compile the f1 /= f2 below, would be -nan */                  x1.f = f1, x2.f = f2;
                  if (f1 == 0.0)                      y.u = 0x7fc00000;
 /* nan */                  else                      y.u = 0x7f800000;
 /* infinity */                  y.u |= (x1.u ^ x2.u) & 0x80000000;
 /* set sign */                  f1 = y.f;
                  break;

}              f1 /= f2;
              break;
          case TOK_NEG:              f1 = -f1;
              goto unary_result;
          case TOK_EQ:              i = f1 == f2;
   make_int:              vtop -= 2;
              vpushi(i);
              return;
          case TOK_NE:              i = f1 != f2;
       goto make_int;
          case TOK_LT:              i = f1 < f2;
       goto make_int;
          case TOK_GE:              i = f1 >= f2;
       goto make_int;
          case TOK_LE:              i = f1 <= f2;
       goto make_int;
          case TOK_GT:              i = f1 > f2;
       goto make_int;
          default:              goto general_case;

}          vtop--;
      unary_result:          /* XXX: overflow test ? */          if (bt == VT_FLOAT) {
              v1->c.f = f1;

} else if (bt == VT_DOUBLE) {
              v1->c.d = f1;

} else {
              v1->c.ld = f1;

}      
} else {
      general_case:          if (op == TOK_NEG) {
              gen_negf(op);

} else {
              gen_opf(op);

}      
}  
}

static void type_to_str(char *buf, int buf_size,                   CType *type, const char *varstr)  {
      int bt, v, t;
      Sym *s, *sa;
      char buf1[256];
      const char *tstr;
        t = type->t;
      bt = t & VT_BTYPE;
      buf[0] = '\0';
        if (t & VT_EXTERN)          pstrcat(buf, buf_size, "extern ");
      if (t & VT_STATIC)          pstrcat(buf, buf_size, "static ");
      if (t & VT_TYPEDEF)          pstrcat(buf, buf_size, "typedef ");
      if (t & VT_INLINE)          pstrcat(buf, buf_size, "inline ");
      if (bt != VT_PTR) {
          if (t & VT_VOLATILE)              pstrcat(buf, buf_size, "volatile ");
          if (t & VT_CONSTANT)              pstrcat(buf, buf_size, "const ");

}      if (((t & VT_DEFSIGN) && bt == VT_BYTE)          || ((t & VT_UNSIGNED)              && (bt == VT_SHORT || bt == VT_INT || bt == VT_LLONG)              && !IS_ENUM(t)              ))          pstrcat(buf, buf_size, (t & VT_UNSIGNED) ? "unsigned " : "signed ");
        buf_size -= strlen(buf);
      buf += strlen(buf);
        switch(bt) {
      case VT_VOID:          tstr = "void";
          goto add_tstr;
      case VT_BOOL:          tstr = "_Bool";
          goto add_tstr;
      case VT_BYTE:          tstr = "char";
          goto add_tstr;
      case VT_SHORT:          tstr = "short";
          goto add_tstr;
      case VT_INT:          tstr = "int";
          goto maybe_long;
      case VT_LLONG:          tstr = "long long";
      maybe_long:          if (t & VT_LONG)              tstr = "long";
          if (!IS_ENUM(t))              goto add_tstr;
          tstr = "enum ";
          goto tstruct;
      case VT_FLOAT:          tstr = "float";
          goto add_tstr;
      case VT_DOUBLE:          tstr = "double";
          if (!(t & VT_LONG))              goto add_tstr;
      case VT_LDOUBLE:          tstr = "long double";
      add_tstr:          pstrcat(buf, buf_size, tstr);
          break;
      case VT_STRUCT:          tstr = "struct ";
          if (IS_UNION(t))              tstr = "union ";
      tstruct:          pstrcat(buf, buf_size, tstr);
          v = type->ref->v & ~SYM_STRUCT;
          if (v >= SYM_FIRST_ANOM)              pstrcat(buf, buf_size, "<anonymous>");
          else              pstrcat(buf, buf_size, get_tok_str(v, NULL));
          break;
      case VT_FUNC:          s = type->ref;
          buf1[0]=0;
          if (varstr && '*' == *varstr) {
              pstrcat(buf1, sizeof(buf1), "(");
              pstrcat(buf1, sizeof(buf1), varstr);
              pstrcat(buf1, sizeof(buf1), ")");

}          pstrcat(buf1, buf_size, "(");
          sa = s->next;
          while (sa != NULL) {
              char buf2[256];
              type_to_str(buf2, sizeof(buf2), &sa->type, NULL);
              pstrcat(buf1, sizeof(buf1), buf2);
              sa = sa->next;
              if (sa)                  pstrcat(buf1, sizeof(buf1), ", ");

}          if (s->f.func_type == FUNC_ELLIPSIS)              pstrcat(buf1, sizeof(buf1), ", ...");
          pstrcat(buf1, sizeof(buf1), ")");
          type_to_str(buf, buf_size, &s->type, buf1);
          goto no_var;
      case VT_PTR:          s = type->ref;
          if (t & (VT_ARRAY|VT_VLA)) {
              if (varstr && '*' == *varstr)                  snprintf(buf1, sizeof(buf1), "(%s)[%d]", varstr, s->c);
              else                  snprintf(buf1, sizeof(buf1), "%s[%d]", varstr ? varstr : "", s->c);
              type_to_str(buf, buf_size, &s->type, buf1);
              goto no_var;

}          pstrcpy(buf1, sizeof(buf1), "*");
          if (t & VT_CONSTANT)              pstrcat(buf1, buf_size, "const ");
          if (t & VT_VOLATILE)              pstrcat(buf1, buf_size, "volatile ");
          if (varstr)              pstrcat(buf1, sizeof(buf1), varstr);
          type_to_str(buf, buf_size, &s->type, buf1);
          goto no_var;

}      if (varstr) {
          pstrcat(buf, buf_size, " ");
          pstrcat(buf, buf_size, varstr);

}   no_var:;

}

static void type_incompatibility_error(CType* st, CType* dt, const char* fmt)  {
      char buf1[256], buf2[256];
      type_to_str(buf1, sizeof(buf1), st, NULL);
      type_to_str(buf2, sizeof(buf2), dt, NULL);
      tcc_error(fmt, buf1, buf2);

}

static void type_incompatibility_warning(CType* st, CType* dt, const char* fmt)  {
      char buf1[256], buf2[256];
      type_to_str(buf1, sizeof(buf1), st, NULL);
      type_to_str(buf2, sizeof(buf2), dt, NULL);
      tcc_warning(fmt, buf1, buf2);

}

static int pointed_size(CType *type)  {
      int align;
      return type_size(pointed_type(type), &align);

}

static inline int is_null_pointer(SValue *p)  {
      if ((p->r & (VT_VALMASK | VT_LVAL | VT_SYM | VT_NONCONST)) != VT_CONST)          return 0;
      return ((p->type.t & VT_BTYPE) == VT_INT && (uint32_t)p->c.i == 0) ||          ((p->type.t & VT_BTYPE) == VT_LLONG && p->c.i == 0) ||          ((p->type.t & VT_BTYPE) == VT_PTR &&           (PTR_SIZE == 4 ? (uint32_t)p->c.i == 0 : p->c.i == 0) &&           ((pointed_type(&p->type)->t & VT_BTYPE) == VT_VOID) &&           0 == (pointed_type(&p->type)->t & (VT_CONSTANT | VT_VOLATILE))           );

}

static int is_compatible_func(CType *type1, CType *type2)  {
      Sym *s1, *s2;
        s1 = type1->ref;
      s2 = type2->ref;
      if (s1->f.func_call != s2->f.func_call)          return 0;
      if (s1->f.func_type != s2->f.func_type          && s1->f.func_type != FUNC_OLD          && s2->f.func_type != FUNC_OLD)          return 0;
      for (;
;
) {
          if (!is_compatible_unqualified_types(&s1->type, &s2->type))              return 0;
          if (s1->f.func_type == FUNC_OLD || s2->f.func_type == FUNC_OLD )              return 1;
          s1 = s1->next;
          s2 = s2->next;
          if (!s1)              return !s2;
          if (!s2)              return 0;

}  
}

static int compare_types(CType *type1, CType *type2, int unqualified)  {
      int bt1, t1, t2;
        t1 = type1->t & VT_TYPE;
      t2 = type2->t & VT_TYPE;
      if (unqualified) {
          /* strip qualifiers before comparing */          t1 &= ~(VT_CONSTANT | VT_VOLATILE);
          t2 &= ~(VT_CONSTANT | VT_VOLATILE);

}        /* Default Vs explicit signedness only matters for char */      if ((t1 & VT_BTYPE) != VT_BYTE) {
          t1 &= ~VT_DEFSIGN;
          t2 &= ~VT_DEFSIGN;

}      /* XXX: bitfields ? */      if (t1 != t2)          return 0;
        if ((t1 & VT_ARRAY)          && !(type1->ref->c < 0            || type2->ref->c < 0            || type1->ref->c == type2->ref->c))              return 0;
        /* test more complicated cases */      bt1 = t1 & VT_BTYPE;
      if (bt1 == VT_PTR) {
          type1 = pointed_type(type1);
          type2 = pointed_type(type2);
          return is_compatible_types(type1, type2);

} else if (bt1 == VT_STRUCT) {
          return (type1->ref == type2->ref);

} else if (bt1 == VT_FUNC) {
          return is_compatible_func(type1, type2);

} else if (IS_ENUM(type1->t) && IS_ENUM(type2->t)) {
          /* If both are enums then they must be the same, if only one is then             t1 and t2 must be equal, which was checked above already.  */          return type1->ref == type2->ref;

} else {
          return 1;

}  
}

static int combine_types(CType *dest, SValue *op1, SValue *op2, int op)  {
      CType *type1, *type2, type;
      int t1, t2, bt1, bt2;
      int ret = 1;
        /* for shifts, 'combine' only left operand */      if (op == SHIFT_OP)          op2 = op1;
        type1 = &op1->type, type2 = &op2->type;
      t1 = type1->t, t2 = type2->t;
      bt1 = t1 & VT_BTYPE, bt2 = t2 & VT_BTYPE;
        type.t = VT_VOID;
      type.ref = NULL;
        if (bt1 == VT_VOID || bt2 == VT_VOID) {
          ret = op == '?' ? 1 : 0;
          /* NOTE: as an extension, we accept void on only one side */          type.t = VT_VOID;

} else if (bt1 == VT_PTR || bt2 == VT_PTR) {
          if (op == '+') {
            if (!is_integer_btype(bt1 == VT_PTR ? bt2 : bt1))              ret = 0;

}          /* http://port70.net/~nsz/c/c99/n1256.html#6.5.15p6 */          /* If one is a null ptr constant the result type is the other.  */          else if (is_null_pointer (op2)) type = *type1;
          else if (is_null_pointer (op1)) type = *type2;
          else if (bt1 != bt2) {
              /* accept comparison or cond-expr between pointer and integer                 with a warning */              if ((op == '?' || op == CMP_OP)                  && (is_integer_btype(bt1) || is_integer_btype(bt2)))                tcc_warning("pointer/integer mismatch in %s",                            op == '?' ? "conditional expression" : "comparison");
              else if (op != '-' || !is_integer_btype(bt2))                ret = 0;
              type = *(bt1 == VT_PTR ? type1 : type2);

} else {
              CType *pt1 = pointed_type(type1);
              CType *pt2 = pointed_type(type2);
              int pbt1 = pt1->t & VT_BTYPE;
              int pbt2 = pt2->t & VT_BTYPE;
              int newquals, copied = 0;
              if (pbt1 != VT_VOID && pbt2 != VT_VOID                  && !compare_types(pt1, pt2, 1/*unqualif*/)) {
                  if (op != '?' && op != CMP_OP)                    ret = 0;
                  else                    type_incompatibility_warning(type1, type2,                      op == '?'                       ? "pointer type mismatch in conditional expression ('%s' and '%s')"                       : "pointer type mismatch in comparison('%s' and '%s')");

}              if (op == '?') {
                  /* pointers to void get preferred, otherwise the                     pointed to types minus qualifs should be compatible */                  type = *((pbt1 == VT_VOID) ? type1 : type2);
                  /* combine qualifs */                  newquals = ((pt1->t | pt2->t) & (VT_CONSTANT | VT_VOLATILE));
                  if ((~pointed_type(&type)->t & (VT_CONSTANT | VT_VOLATILE))                      & newquals)                    {
                      /* copy the pointer target symbol */                      type.ref = sym_push(SYM_FIELD, &type.ref->type,                                          0, type.ref->c);
                      copied = 1;
                      pointed_type(&type)->t |= newquals;

}                  /* pointers to incomplete arrays get converted to                     pointers to completed ones if possible */                  if (pt1->t & VT_ARRAY                      && pt2->t & VT_ARRAY                      && pointed_type(&type)->ref->c < 0                      && (pt1->ref->c > 0 || pt2->ref->c > 0))                    {
                      if (!copied)                        type.ref = sym_push(SYM_FIELD, &type.ref->type,                                            0, type.ref->c);
                      pointed_type(&type)->ref =                          sym_push(SYM_FIELD, &pointed_type(&type)->ref->type,                                   0, pointed_type(&type)->ref->c);
                      pointed_type(&type)->ref->c =                          0 < pt1->ref->c ? pt1->ref->c : pt2->ref->c;

}              
}          
}          if (op == CMP_OP)            type.t = VT_SIZE_T;

} else if (bt1 == VT_STRUCT || bt2 == VT_STRUCT) {
          if (op != '?' || !compare_types(type1, type2, 1))            ret = 0;
          type = *type1;

} else if (is_float(bt1) || is_float(bt2)) {
          if (bt1 == VT_LDOUBLE || bt2 == VT_LDOUBLE) {
              type.t = VT_LDOUBLE;

} else if (bt1 == VT_DOUBLE || bt2 == VT_DOUBLE) {
              type.t = VT_DOUBLE;

} else {
              type.t = VT_FLOAT;

}      
} else if (bt1 == VT_LLONG || bt2 == VT_LLONG) {
          /* cast to biggest op */          type.t = VT_LLONG | VT_LONG;
          if (bt1 == VT_LLONG)            type.t &= t1;
          if (bt2 == VT_LLONG)            type.t &= t2;
          /* convert to unsigned if it does not fit in a long long */          if ((t1 & (VT_BTYPE | VT_UNSIGNED | VT_BITFIELD)) == (VT_LLONG | VT_UNSIGNED) ||              (t2 & (VT_BTYPE | VT_UNSIGNED | VT_BITFIELD)) == (VT_LLONG | VT_UNSIGNED))            type.t |= VT_UNSIGNED;

} else {
          /* integer operations */          type.t = VT_INT | (VT_LONG & (t1 | t2));
          /* convert to unsigned if it does not fit in an integer */          if ((t1 & (VT_BTYPE | VT_UNSIGNED | VT_BITFIELD)) == (VT_INT | VT_UNSIGNED) ||              (t2 & (VT_BTYPE | VT_UNSIGNED | VT_BITFIELD)) == (VT_INT | VT_UNSIGNED))            type.t |= VT_UNSIGNED;

}      if (dest)        *dest = type;
      return ret;

}

ST_FUNC void gen_op(int op)  {
      int t1, t2, bt1, bt2, t;
      CType type1, combtype;
      int op_class = op;
        if (op == TOK_SHR || op == TOK_SAR || op == TOK_SHL)          op_class = SHIFT_OP;
      else if (TOK_ISCOND(op)) /* == != > ... */          op_class = CMP_OP;
    redo:      t1 = vtop[-1].type.t;
      t2 = vtop[0].type.t;
      bt1 = t1 & VT_BTYPE;
      bt2 = t2 & VT_BTYPE;
                if (bt1 == VT_FUNC || bt2 == VT_FUNC) {
   if (bt2 == VT_FUNC) {
       mk_pointer(&vtop->type);
       gaddrof();

}   if (bt1 == VT_FUNC) {
       vswap();
       mk_pointer(&vtop->type);
       gaddrof();
       vswap();

}   goto redo;

} else if (!combine_types(&combtype, vtop - 1, vtop, op_class)) {
  op_err:          tcc_error("invalid operand types for binary operation");

} else if (bt1 == VT_PTR || bt2 == VT_PTR) {
          /* at least one operand is a pointer */          /* relational op: must be both pointers */          int align;
          if (op_class == CMP_OP)              goto std_op;
          /* if both pointers, then it must be the '-' op */          if (bt1 == VT_PTR && bt2 == VT_PTR) {
              if (op != '-')                  goto op_err;
              vpush_type_size(pointed_type(&vtop[-1].type), &align);
              vtop->type.t &= ~VT_UNSIGNED;
              vrott(3);
              gen_opic(op);
              vtop->type.t = VT_PTRDIFF_T;
              vswap();
              gen_op(TOK_PDIV);

} else {
              /* exactly one pointer : must be '+' or '-'. */              if (op != '-' && op != '+')                  goto op_err;
              /* Put pointer as first operand */              if (bt2 == VT_PTR) {
                  vswap();
                  t = t1, t1 = t2, t2 = t;
                  bt2 = bt1;

}  #if PTR_SIZE == 4              if (bt2 == VT_LLONG)                  /* XXX: truncate here because gen_opl can't handle ptr + long long */                  gen_cast_s(VT_INT);
  #endif              type1 = vtop[-1].type;
              vpush_type_size(pointed_type(&vtop[-1].type), &align);
              gen_op('*');
  #ifdef CONFIG_TCC_BCHECK              if (tcc_state->do_bounds_check && !CONST_WANTED) {
                  /* if bounded pointers, we generate a special code to                     test bounds */                  if (op == '-') {
                      vpushi(0);
                      vswap();
                      gen_op('-');

}                  gen_bounded_ptr_add();

} else  #endif              {
                  gen_opic(op);

}              type1.t &= ~(VT_ARRAY|VT_VLA);
              /* put again type if gen_opic() swaped operands */              vtop->type = type1;

}      
} else {
          /* floats can only be used for a few operations */          if (is_float(combtype.t)              && op != '+' && op != '-' && op != '*' && op != '/'              && op_class != CMP_OP) {
              goto op_err;

}      std_op:          t = t2 = combtype.t;
          /* special case for shifts and long long: we keep the shift as             an integer */          if (op_class == SHIFT_OP)              t2 = VT_INT;
          /* XXX: currently, some unsigned operations are explicit, so             we modify them here */          if (t & VT_UNSIGNED) {
              if (op == TOK_SAR)                  op = TOK_SHR;
              else if (op == '/')                  op = TOK_UDIV;
              else if (op == '%')                  op = TOK_UMOD;
              else if (op == TOK_LT)                  op = TOK_ULT;
              else if (op == TOK_GT)                  op = TOK_UGT;
              else if (op == TOK_LE)                  op = TOK_ULE;
              else if (op == TOK_GE)                  op = TOK_UGE;

}          vswap();
          gen_cast_s(t);
          vswap();
          gen_cast_s(t2);
          if (is_float(t))              gen_opif(op);
          else              gen_opic(op);
          if (op_class == CMP_OP) {
              /* relational op: the result is an int */              vtop->type.t = VT_INT;

} else {
              vtop->type.t = t;

}      
}      // Make sure that we have converted to an rvalue:      if (vtop->r & VT_LVAL)          gv(is_float(vtop->type.t & VT_BTYPE) ? RC_FLOAT : RC_INT);

}

static void force_charshort_cast(void)  {
      int sbt = BFGET(vtop->r, VT_MUSTCAST) == 2 ? VT_LLONG : VT_INT;
      int dbt = vtop->type.t;
      vtop->r &= ~VT_MUSTCAST;
      vtop->type.t = sbt;
      gen_cast_s(dbt == VT_BOOL ? VT_BYTE|VT_UNSIGNED : dbt);
      vtop->type.t = dbt;

}

static void gen_cast_s(int t)  {
      CType type;
      type.t = t;
      type.ref = NULL;
      gen_cast(&type);

}

static void gen_cast(CType *type)  {
      int sbt, dbt, sf, df, c;
      int dbt_bt, sbt_bt, ds, ss, bits, trunc;
        /* special delayed cast for char/short */      if (vtop->r & VT_MUSTCAST)          force_charshort_cast();
