        dbt = type->t & (VT_BTYPE | VT_UNSIGNED);
      sbt = vtop->type.t & (VT_BTYPE | VT_UNSIGNED);
      if (sbt == VT_FUNC)          sbt = VT_PTR;
    again:      if (sbt != dbt) {
          sf = is_float(sbt);
          df = is_float(dbt);
          dbt_bt = dbt & VT_BTYPE;
          sbt_bt = sbt & VT_BTYPE;
          if (dbt_bt == VT_VOID)              goto done;
          if (sbt_bt == VT_VOID) {
  error:              cast_error(&vtop->type, type);

}            c = (vtop->r & (VT_VALMASK | VT_LVAL | VT_SYM)) == VT_CONST;
