                  else                      vtop->c.i = ((uint32_t)vtop->c.i | -(vtop->c.i & 0x80000000));
                    if (dbt_bt == VT_LLONG || (PTR_SIZE == 8 && dbt == VT_PTR))                     ;
                  else if (dbt == VT_BOOL)                      vtop->c.i = (vtop->c.i != 0);
