 int a = 0, b = *(char*)&a;

}             That means that if we cast to less width, we can just             change the type and read it still later. */          #define ALLOW_SUBTYPE_ACCESS 1            if (ALLOW_SUBTYPE_ACCESS && (vtop->r & VT_LVAL)) {
