    //#define BF_DEBUG        for (f = type->ref->next;
 f;
 f = f->next) {
          if (f->type.t & VT_BITFIELD)              bit_size = BIT_SIZE(f->type.t);
          else              bit_size = -1;
          size = type_size(&f->type, &align);
          a = f->a.aligned ? 1 << (f->a.aligned - 1) : 0;
          packed = 0;
            if (pcc && bit_size == 0) {
              /* in pcc mode, packing does not affect zero-width bitfields */            
} else {
              /* in pcc mode, attribute packed overrides if set. */              if (pcc && (f->a.packed || ad->a.packed))                  align = packed = 1;
                /* pragma pack overrides align if lesser and packs bitfields always */              if (pragma_pack) {
