       if (pcc && bit_size >= 0)           size = (bit_size + 7) >> 3;
       offset = 0;
       if (size > c)           c = size;

} else if (bit_size < 0) {
              if (pcc)                  c += (bit_pos + 7) >> 3;
       c = (c + align - 1) & -align;
       offset = c;
       if (size > 0)           c += size;
       bit_pos = 0;
       prevbt = VT_STRUCT;
       prev_bit_size = 0;

