static void sym_to_attr(AttributeDef *ad, Sym *s)  {
      merge_symattr(&ad->a, &s->a);
      merge_funcattr(&ad->f, &s->f);

}

static void parse_btype_qualify(CType *type, int qualifiers)  {
      while (type->t & VT_ARRAY) {
          type->ref = sym_push(SYM_FIELD, &type->ref->type, 0, type->ref->c);
          type = &type->ref->type;

}      type->t |= qualifiers;

}

static int parse_btype(CType *type, AttributeDef *ad, int ignore_label)  {
      int t, u, bt, st, type_found, typespec_found, g, n;
      Sym *s;
      CType type1;
        memset(ad, 0, sizeof(AttributeDef));
      type_found = 0;
      typespec_found = 0;
      t = VT_INT;
      bt = st = -1;
      type->ref = NULL;
        while(1) {
          switch(tok) {
          case TOK_EXTENSION:              /* currently, we really ignore extension */              next();
              continue;
                /* basic types */          case TOK_CHAR:              u = VT_BYTE;
          basic_type:              next();
          basic_type1:              if (u == VT_SHORT || u == VT_LONG) {
                  if (st != -1 || (bt != -1 && bt != VT_INT))                      tmbt: tcc_error("too many basic types");
                  st = u;

} else {
                  if (bt != -1 || (st != -1 && u != VT_INT))                      goto tmbt;
                  bt = u;

}              if (u != VT_INT)                  t = (t & ~(VT_BTYPE|VT_LONG)) | u;
              typespec_found = 1;
              break;
          case TOK_VOID:              u = VT_VOID;
              goto basic_type;
          case TOK_SHORT:              u = VT_SHORT;
              goto basic_type;
          case TOK_INT:              u = VT_INT;
              goto basic_type;
          case TOK_ALIGNAS:              {
 int n;
                AttributeDef ad1;
                next();
                skip('(');
                memset(&ad1, 0, sizeof(AttributeDef));
                if (parse_btype(&type1, &ad1, 0)) {
                    type_decl(&type1, &ad1, &n, TYPE_ABSTRACT);
                    if (ad1.a.aligned)                      n = 1 << (ad1.a.aligned - 1);
                    else                      type_size(&type1, &n);

} else {
                    n = expr_const();
                    if (n < 0 || (n & (n - 1)) != 0)                      tcc_error("alignment must be a positive power of two");

}                skip(')');
                ad->a.aligned = exact_log2p1(n);

}              continue;
          case TOK_LONG:              if ((t & VT_BTYPE) == VT_DOUBLE) {
                  t = (t & ~(VT_BTYPE|VT_LONG)) | VT_LDOUBLE;

} else if ((t & (VT_BTYPE|VT_LONG)) == VT_LONG) {
                  t = (t & ~(VT_BTYPE|VT_LONG)) | VT_LLONG;

} else {
                  u = VT_LONG;
                  goto basic_type;

}              next();
              break;
  #ifdef TCC_TARGET_ARM64          case TOK_UINT128:              /* GCC's __uint128_t appears in some Linux header files. Make it a                 synonym for long double to get the size and alignment right. */              u = VT_LDOUBLE;
              goto basic_type;
  #endif          case TOK_BOOL:              u = VT_BOOL;
              goto basic_type;
          case TOK_COMPLEX:              tcc_error("_Complex is not yet supported");
          case TOK_FLOAT:              u = VT_FLOAT;
              goto basic_type;
          case TOK_DOUBLE:              if ((t & (VT_BTYPE|VT_LONG)) == VT_LONG) {
                  t = (t & ~(VT_BTYPE|VT_LONG)) | VT_LDOUBLE;

} else {
                  u = VT_DOUBLE;
                  goto basic_type;

}              next();
              break;
          case TOK_ENUM:              struct_decl(&type1, VT_ENUM);
          basic_type2:              u = type1.t;
              type->ref = type1.ref;
              goto basic_type1;
          case TOK_STRUCT:              struct_decl(&type1, VT_STRUCT);
              goto basic_type2;
          case TOK_UNION:              struct_decl(&type1, VT_UNION);
              goto basic_type2;
                /* type modifiers */          case TOK__Atomic:              next();
              type->t = t;
              parse_btype_qualify(type, VT_ATOMIC);
              t = type->t;
              if (tok == '(') {
                  parse_expr_type(&type1);
                  /* remove all storage modifiers except typedef */                  type1.t &= ~(VT_STORAGE&~VT_TYPEDEF);
                  if (type1.ref)                      sym_to_attr(ad, type1.ref);
                  goto basic_type2;

}              break;
          case TOK_CONST1:          case TOK_CONST2:          case TOK_CONST3:              type->t = t;
              parse_btype_qualify(type, VT_CONSTANT);
              t = type->t;
              next();
              break;
          case TOK_VOLATILE1:          case TOK_VOLATILE2:          case TOK_VOLATILE3:              type->t = t;
              parse_btype_qualify(type, VT_VOLATILE);
              t = type->t;
              next();
              break;
          case TOK_SIGNED1:          case TOK_SIGNED2:          case TOK_SIGNED3:              if ((t & (VT_DEFSIGN|VT_UNSIGNED)) == (VT_DEFSIGN|VT_UNSIGNED))                  tcc_error("signed and unsigned modifier");
              t |= VT_DEFSIGN;
              next();
              typespec_found = 1;
              break;
          case TOK_REGISTER:          case TOK_AUTO:          case TOK_RESTRICT1:          case TOK_RESTRICT2:          case TOK_RESTRICT3:              next();
              break;
          case TOK_UNSIGNED:              if ((t & (VT_DEFSIGN|VT_UNSIGNED)) == VT_DEFSIGN)                  tcc_error("signed and unsigned modifier");
              t |= VT_DEFSIGN | VT_UNSIGNED;
              next();
              typespec_found = 1;
              break;
                /* storage */          case TOK_EXTERN:              g = VT_EXTERN;
              goto storage;
          case TOK_STATIC:              g = VT_STATIC;
              goto storage;
          case TOK_TYPEDEF:              g = VT_TYPEDEF;
              goto storage;
         storage:              if (t & (VT_EXTERN|VT_STATIC|VT_TYPEDEF) & ~g)                  tcc_error("multiple storage classes");
              t |= g;
              next();
              break;
          case TOK_INLINE1:          case TOK_INLINE2:          case TOK_INLINE3:              t |= VT_INLINE;
              next();
              break;
          case TOK_NORETURN3:              next();
              ad->f.func_noreturn = 1;
              break;
              /* GNUC attribute */          case TOK_ATTRIBUTE1:          case TOK_ATTRIBUTE2:              parse_attribute(ad);
              if (ad->attr_mode) {
