}              continue;
              /* GNUC typeof */          case TOK_TYPEOF1:          case TOK_TYPEOF2:          case TOK_TYPEOF3:              next();
              parse_expr_type(&type1);
              /* remove all storage modifiers except typedef */              type1.t &= ~(VT_STORAGE&~VT_TYPEDEF);
       if (type1.ref)                  sym_to_attr(ad, type1.ref);
              goto basic_type2;
          case TOK_THREAD_LOCAL:              tcc_error("_Thread_local is not implemented");
          default:              if (typespec_found)                  goto the_end;
              s = sym_find(tok);
              if (!s || !(s->type.t & VT_TYPEDEF))                  goto the_end;
                n = tok, next();
              if (tok == ':' && ignore_label) {
                  /* ignore if it's a label */                  unget_tok(n);
                  goto the_end;

}                t &= ~(VT_BTYPE|VT_LONG);
              u = t & ~(VT_CONSTANT | VT_VOLATILE), t ^= u;
              type->t = (s->type.t & ~VT_TYPEDEF) | u;
              type->ref = s->type.ref;
              if (t)                  parse_btype_qualify(type, t);
              t = type->t;
              /* get attributes from typedef */              sym_to_attr(ad, s);
              typespec_found = 1;
              st = bt = -2;
              break;

}          type_found = 1;

}  the_end:      if (tcc_state->char_is_unsigned) {
          if ((t & (VT_DEFSIGN|VT_BTYPE)) == VT_BYTE)              t |= VT_UNSIGNED;

}      /* VT_LONG is used just as a modifier for VT_INT / VT_LLONG */      bt = t & (VT_BTYPE|VT_LONG);
      if (bt == VT_LONG)          t |= LONG_SIZE == 8 ? VT_LLONG : VT_INT;
  #ifdef TCC_USING_DOUBLE_FOR_LDOUBLE      if (bt == VT_LDOUBLE)          t = (t & ~(VT_BTYPE|VT_LONG)) | (VT_DOUBLE|VT_LONG);
  #endif      type->t = t;
      return type_found;

}

static inline void convert_parameter_type(CType *pt)  {
      /* remove const and volatile qualifiers (XXX: const could be used         to indicate a const function parameter */      pt->t &= ~(VT_CONSTANT | VT_VOLATILE);
      /* array must be transformed to pointer according to ANSI C */      pt->t &= ~(VT_ARRAY | VT_VLA);
      if ((pt->t & VT_BTYPE) == VT_FUNC) {
          mk_pointer(pt);

}  
}

ST_FUNC CString* parse_asm_str(void)  {
      skip('(');
      return parse_mult_str("string constant");

}

static int asm_label_instr(void)  {
      int v;
      char *astr;
        next();
      astr = parse_asm_str()->data;
      skip(')');
  #ifdef ASM_DEBUG      printf("asm_alias: \"%s\"\n", astr);
  #endif      v = tok_alloc_const(astr);
      return v;

}

static int post_type(CType *type, AttributeDef *ad, int storage, int td)  {
