          case TOK__Atomic:              qualifiers |= VT_ATOMIC;
              goto redo;
          case TOK_CONST1:          case TOK_CONST2:          case TOK_CONST3:              qualifiers |= VT_CONSTANT;
              goto redo;
          case TOK_VOLATILE1:          case TOK_VOLATILE2:          case TOK_VOLATILE3:              qualifiers |= VT_VOLATILE;
