static void parse_builtin_params(int nc, const char *args)  {
      char c, sep = '(';
      CType type;
      if (nc)          nocode_wanted++;
      next();
      if (*args == 0)   skip(sep);
      while ((c = *args++)) {
   skip(sep);
   sep = ',';
          if (c == 't') {
              parse_type(&type);
       vpush(&type);
       continue;

}          expr_eq();
          type.ref = NULL;
          type.t = 0;
