                  break;
       case 'S':                  type.t = VT_CONSTANT;
       case 's':                  type.t |= char_type.t;
                  mk_pointer (&type);
                  break;
       case 'i':                  type.t = VT_INT;
                  break;
       case 'l':                  type.t = VT_SIZE_T;
                  break;
       default:                  break;

