static int condition_3way(void)  {
      int c = -1;
      if ((vtop->r & (VT_VALMASK | VT_LVAL)) == VT_CONST &&   (!(vtop->r & VT_SYM) || !vtop->sym->a.weak)) {
   vdup();
          gen_cast_s(VT_BOOL);
   c = vtop->c.i;
   vpop();

}      return c;

}

static void expr_landor(int op)  {
      int t = 0, cc = 1, f = 0, i = op == TOK_LAND, c;
      for(;
;
) {
          c = f ? i : condition_3way();
          if (c < 0)              save_regs(1), cc = 0;
          else if (c != i)              nocode_wanted++, f = 1;
          if (tok != op)              break;
          if (c < 0)              t = gvtst(i, t);
          else              vpop();
          next();
          expr_landor_next(op);

}      if (cc || f) {
          vpop();
          vpushi(i ^ f);
          gsym(t);
          nocode_wanted -= f;

} else {
          gvtst_set(i, t);

}  
}

static int is_cond_bool(SValue *sv)  {
      if ((sv->r & (VT_VALMASK | VT_LVAL | VT_SYM)) == VT_CONST          && (sv->type.t & VT_BTYPE) == VT_INT)          return (unsigned)sv->c.i < 2;
      if (sv->r == VT_CMP)          return 1;
      return 0;

}

static void expr_cond(void)  {
