                  vpop();

}          
} else if (c < 0) {
              /* needed to avoid having different registers saved in                 each branch */              save_regs(1);
              gv_dup();
              tt = gvtst(0, 0);

}            if (c == 0)            nocode_wanted++;
          if (!g)            gexpr();
            if ((vtop->type.t & VT_BTYPE) == VT_FUNC)            mk_pointer(&vtop->type);
          sv = *vtop;
