              u = tt;

} else if (c < 0) {
              u = gjmp(0);
              gsym(tt);

} else            u = 0;
            if (c == 0)            nocode_wanted--;
          if (c == 1)            nocode_wanted++;
          skip(':');
          expr_cond();
