static void check_func_return(void)  {
      if ((func_vt.t & VT_BTYPE) == VT_VOID)          return;
      if (!strcmp (funcname, "main")          && (func_vt.t & VT_BTYPE) == VT_INT) {
          /* main returns 0 by default */          vpushi(0);
          gen_assign_cast(&func_vt);
          gfunc_return(&func_vt);

