          tcc_warning("function might return no value: '%s'", funcname);

}  
}

static int case_cmp(uint64_t a, uint64_t b)  {
      if (cur_switch->sv.type.t & VT_UNSIGNED)          return a < b ? -1 : a > b;
      else          return (int64_t)a < (int64_t)b ? -1 : (int64_t)a > (int64_t)b;

}

static int case_cmp_qs(const void *pa, const void *pb)  {
      return case_cmp((*(struct case_t**)pa)->v1, (*(struct case_t**)pb)->v1);

}

static void case_sort(struct switch_t *sw)  {
      struct case_t **p;
      if (sw->n < 2)          return;
      qsort(sw->p, sw->n, sizeof *sw->p, case_cmp_qs);
      p = sw->p;
      while (p < sw->p + sw->n - 1) {
          if (case_cmp(p[0]->v2, p[1]->v1) >= 0) {
              int l1 = p[0]->line, l2 = p[1]->line;
              /* using special format "%i:..." to show specific line */              tcc_error("%i:duplicate case value", l1 > l2 ? l1 : l2);

} else if (p[0]->v2 + 1 == p[1]->v1 && p[0]->ind == p[1]->ind) {
              /* treat "case 1: case 2: case 3:" like "case 1 ... 3: */              p[1]->v1 = p[0]->v1;
              tcc_free(p[0]);
              memmove(p, p + 1, (--sw->n - (p - sw->p)) * sizeof *p);

} else              ++p;

}  
}

static int gcase(struct case_t **base, int len, int dsym)  {
      struct case_t *p;
      int t, l2, e;
        t = vtop->type.t & VT_BTYPE;
      if (t != VT_LLONG)          t = VT_INT;
      while (len) {
          /* binary search while len > 8, else linear */          l2 = len > 8 ? len/2 : 0;
          p = base[l2];
          vdup(), vpush64(t, p->v2);
          if (l2 == 0 && p->v1 == p->v2) {
              gen_op(TOK_EQ);
 /* jmp to case when equal */              gsym_addr(gvtst(0, 0), p->ind);

} else {
              /* case v1 ... v2 */              gen_op(TOK_GT);
 /* jmp over when > V2 */              if (len == 1) /* last case test jumps to default when false */                  dsym = gvtst(0, dsym), e = 0;
              else                  e = gvtst(0, 0);
              vdup(), vpush64(t, p->v1);
              gen_op(TOK_GE);
 /* jmp to case when >= V1 */              gsym_addr(gvtst(0, 0), p->ind);
              dsym = gcase(base, l2, dsym);
              gsym(e);

}          ++l2, base += l2, len -= l2;

}      /* jump automagically will suppress more jumps */      return gjmp(dsym);

}

static void end_switch(void)  {
      struct switch_t *sw = cur_switch;
      dynarray_reset(&sw->p, &sw->n);
      cur_switch = sw->prev;
      tcc_free(sw);

}

static void try_call_scope_cleanup(Sym *stop)  {
      Sym *cls = cur_scope->cl.s;
        for (;
