static void skip_or_save_block(TokenString **str)  {
      int braces = tok == '{
';
      int level = 0;
      if (str)        *str = tok_str_alloc();
        while (1) {
   int t = tok;
          if (level == 0              && (t == ','               || t == ';
'               || t == '
}'               || t == ')'               || t == ']'))               break;
