static void gen_inline_functions(TCCState *s)  {
      Sym *sym;
      int inline_generated, i;
      struct InlineFunc *fn;
        tcc_open_bf(s, ":inline:", 0);
      /* iterate while inline function are referenced */      do {
          inline_generated = 0;
          for (i = 0;
 i < s->nb_inline_fns;
 ++i) {
              fn = s->inline_fns[i];
              sym = fn->sym;
              if (sym && (sym->c || !(sym->type.t & VT_INLINE))) {
                  /* the function was used or forced (and then not internal):                     generate its code and convert it to a normal function */                  fn->sym = NULL;
                  tccpp_putfile(fn->filename);
                  begin_macro(fn->func_str, 1);
                  next();
                  cur_text_section = text_section;
                  gen_function(sym);
                  end_macro();
                    inline_generated = 1;

}          
}      
} while (inline_generated);
      tcc_close();

}

static void free_inline_functions(TCCState *s)  {
      int i;
      /* free tokens of unused inline functions */      for (i = 0;
 i < s->nb_inline_fns;
 ++i) {
          struct InlineFunc *fn = s->inline_fns[i];
          if (fn->sym)              tok_str_free(fn->func_str);

}      dynarray_reset(&s->inline_fns, &s->nb_inline_fns);

}

