          put_elf_reloca(s1->symtab, text_section,           text_section->data_offset - 9,           R_X86_64_PC32, mh_execute_header, -4);
   ptr[21] = 0xe8;
 // call __cxa_atexit          put_elf_reloca(s1->symtab, text_section,           text_section->data_offset - 4,           R_X86_64_PLT32, at_exit_sym, -4);

}      ptr = section_ptr_add(text_section, 2);
      ptr[0] = 0x5d;
  // pop   %rbp      ptr[1] = 0xc3;
  // ret  #elif defined TCC_TARGET_ARM64      ptr = section_ptr_add(text_section, 8);
      write32le(ptr, 0xa9bf7bfd);
     // stp     x29, x30, [sp, #-16]!      write32le(ptr + 4, 0x910003fd);
 // mov     x29, sp      for_each_elem(s->reloc, 0, rel, ElfW_Rel) {
