  // add x0,x0,destructor@pageoff          write32le(ptr + 8, 0xd2800001);
  // mov x1, #0          put_elf_reloc(s1->symtab, text_section,           text_section->data_offset - 12,          R_AARCH64_ADR_PREL_PG_HI21, mh_execute_header);
