static int check_symbols(TCCState *s1, struct macho *mo)  {
      int sym_index, sym_end;
      int ret = 0;
        mo->ilocal = mo->iextdef = mo->iundef = -1;
      sym_end = symtab_section->data_offset / sizeof(ElfW(Sym));
      for (sym_index = 1;
 sym_index < sym_end;
 ++sym_index) {
          int elf_index = ((struct nlist_64 *)mo->symtab->data + sym_index - 1)->n_value;
          ElfW(Sym) *sym = (ElfW(Sym) *)symtab_section->data + elf_index;
          const char *name = (char*)symtab_section->link->data + sym->st_name;
          unsigned type = ELFW(ST_TYPE)(sym->st_info);
          unsigned bind = ELFW(ST_BIND)(sym->st_info);
          unsigned vis  = ELFW(ST_VISIBILITY)(sym->st_other);
            dprintf("%4d (%4d): %09lx %4d %4d %4d %3d %s\n",                  sym_index, elf_index, (long)sym->st_value,                  type, bind, vis, sym->st_shndx, name);
          if (bind == STB_LOCAL) {
              if (mo->ilocal == -1)                mo->ilocal = sym_index - 1;
              if (mo->iextdef != -1 || mo->iundef != -1)                tcc_error("local syms after global ones");

} else if (sym->st_shndx != SHN_UNDEF) {
              if (mo->iextdef == -1)                mo->iextdef = sym_index - 1;
              if (mo->iundef != -1)                tcc_error("external defined symbol after undefined");

} else if (sym->st_shndx == SHN_UNDEF) {
              if (mo->iundef == -1)                mo->iundef = sym_index - 1;
              if (ELFW(ST_BIND)(sym->st_info) == STB_WEAK    || s1->output_type != TCC_OUTPUT_EXE                  || find_elf_sym(s1->dynsymtab_section, name)) {
                  /* Mark the symbol as coming from a dylib so that                     relocate_syms doesn't complain.  Normally bind_exe_dynsyms                     would do this check, and place the symbol into dynsym                     which is checked by relocate_syms.  But Mach-O doesn't use                     bind_exe_dynsyms.  */                  sym->st_shndx = SHN_FROMDLL;
                  continue;

}              tcc_error_noabort("undefined symbol '%s'", name);
              ret = -1;

}      
}      return ret;

}

static void convert_symbol(TCCState *s1, struct macho *mo, struct nlist_64 *pn)  {
      struct nlist_64 n = *pn;
      ElfSym *sym = (ElfW(Sym) *)symtab_section->data + pn->n_value;
      const char *name = (char*)symtab_section->link->data + sym->st_name;
      switch(ELFW(ST_TYPE)(sym->st_info)) {
      case STT_NOTYPE:      case STT_OBJECT:      case STT_FUNC:      case STT_SECTION:          n.n_type = N_SECT;
          break;
      case STT_FILE:          n.n_type = N_ABS;
          break;
      default:          tcc_error("unhandled ELF symbol type %d %s",                    ELFW(ST_TYPE)(sym->st_info), name);

}      if (sym->st_shndx == SHN_UNDEF)        tcc_error("should have been rewritten to SHN_FROMDLL: %s", name);
      else if (sym->st_shndx == SHN_FROMDLL)        n.n_type = N_UNDF, n.n_sect = 0;
      else if (sym->st_shndx == SHN_ABS)        n.n_type = N_ABS, n.n_sect = 0;
      else if (sym->st_shndx >= SHN_LORESERVE)        tcc_error("unhandled ELF symbol section %d %s", sym->st_shndx, name);
      else if (!mo->elfsectomacho[sym->st_shndx]) {
        if (strncmp(s1->sections[sym->st_shndx]->name, ".debug_", 7))          tcc_error("ELF section %d(%s) not mapped into Mach-O for symbol %s",                    sym->st_shndx, s1->sections[sym->st_shndx]->name, name);

}      else        n.n_sect = mo->elfsectomacho[sym->st_shndx];
      if (ELFW(ST_BIND)(sym->st_info) == STB_GLOBAL)        n.n_type |=  N_EXT;
      else if (ELFW(ST_BIND)(sym->st_info) == STB_WEAK)        n.n_desc |= N_WEAK_REF | (n.n_type != N_UNDF ? N_WEAK_DEF : 0);
      n.n_strx = pn->n_strx;
      n.n_value = sym->st_value;
      *pn = n;

}

static void convert_symbols(TCCState *s1, struct macho *mo)  {
      struct nlist_64 *pn;
      for_each_elem(mo->symtab, 0, pn, struct nlist_64)          convert_symbol(s1, mo, pn);

}

static int machosymcmp(const void *_a, const void *_b, void *arg)  {
      TCCState *s1 = arg;
      int ea = ((struct nlist_64 *)_a)->n_value;
      int eb = ((struct nlist_64 *)_b)->n_value;
      ElfSym *sa = (ElfSym *)symtab_section->data + ea;
      ElfSym *sb = (ElfSym *)symtab_section->data + eb;
      int r;
      /* locals, then defined externals, then undefined externals, the         last two sections also by name, otherwise stable sort */      r = (ELFW(ST_BIND)(sb->st_info) == STB_LOCAL)          - (ELFW(ST_BIND)(sa->st_info) == STB_LOCAL);
      if (r)        return r;
      r = (sa->st_shndx == SHN_UNDEF) - (sb->st_shndx == SHN_UNDEF);
      if (r)        return r;
      if (ELFW(ST_BIND)(sa->st_info) != STB_LOCAL) {
          const char * na = (char*)symtab_section->link->data + sa->st_name;
          const char * nb = (char*)symtab_section->link->data + sb->st_name;
          r = strcmp(na, nb);
          if (r)            return r;

}      return ea - eb;

}

static void tcc_qsort (void  *base, size_t nel, size_t width,                         int (*comp)(const void *, const void *, void *), void *arg)  {
      size_t wnel, gap, wgap, i, j, k;
      char *a, *b, tmp;
        wnel = width * nel;
      for (gap = 0;
 ++gap < nel;
)          gap *= 3;
      while ( gap /= 3 ) {
          wgap = width * gap;
          for (i = wgap;
 i < wnel;
 i += width) {
              for (j = i - wgap;
;
j -= wgap) {
                  a = j + (char *)base;
                  b = a + wgap;
                  if ( (*comp)(a, b, arg) <= 0 )                      break;
                  k = width;
                  do {
                      tmp = *a;
                      *a++ = *b;
                      *b++ = tmp;

} while ( --k );
                  if (j < wgap)                      break;

}          
}      
}  
}

static void create_symtab(TCCState *s1, struct macho *mo)  {
      int sym_index, sym_end;
      struct nlist_64 *pn;
        /* Stub creation belongs to check_relocs, but we need to create         the symbol now, so its included in the sorting.  */      mo->stubs = new_section(s1, "__stubs", SHT_PROGBITS, SHF_ALLOC | SHF_EXECINSTR);
      s1->got = new_section(s1, ".got", SHT_PROGBITS, SHF_ALLOC | SHF_WRITE);
      mo->stubsym = put_elf_sym(s1->symtab, 0, 0,                                ELFW(ST_INFO)(STB_LOCAL, STT_SECTION), 0,                                mo->stubs->sh_num, ".__stubs");
  #ifdef CONFIG_NEW_MACHO      mo->chained_fixups = new_section(s1, "CHAINED_FIXUPS",           SHT_LINKEDIT, SHF_ALLOC | SHF_WRITE);
  #else      mo->stub_helper = new_section(s1, "__stub_helper", SHT_PROGBITS, SHF_ALLOC | SHF_EXECINSTR);
      mo->la_symbol_ptr = new_section(s1, "__la_symbol_ptr", SHT_PROGBITS, SHF_ALLOC | SHF_WRITE);
      mo->helpsym = put_elf_sym(s1->symtab, 0, 0,                                ELFW(ST_INFO)(STB_LOCAL, STT_SECTION), 0,                                mo->stub_helper->sh_num, ".__stub_helper");
      mo->lasym = put_elf_sym(s1->symtab, 0, 0,                              ELFW(ST_INFO)(STB_LOCAL, STT_SECTION), 0,                              mo->la_symbol_ptr->sh_num, ".__la_symbol_ptr");
      section_ptr_add(data_section, -data_section->data_offset & (PTR_SIZE - 1));
      mo->dyld_private = put_elf_sym(s1->symtab, data_section->data_offset, PTR_SIZE,                                     ELFW(ST_INFO)(STB_LOCAL, STT_OBJECT), 0,                                     data_section->sh_num, ".__dyld_private");
      section_ptr_add(data_section, PTR_SIZE);
      mo->dyld_stub_binder = put_elf_sym(s1->symtab, 0, 0,                           ELFW(ST_INFO)(STB_GLOBAL, STT_OBJECT), 0,             SHN_UNDEF, "dyld_stub_binder");
      mo->rebase = new_section(s1, "REBASE", SHT_LINKEDIT, SHF_ALLOC | SHF_WRITE);
      mo->binding = new_section(s1, "BINDING", SHT_LINKEDIT, SHF_ALLOC | SHF_WRITE);
      mo->weak_binding = new_section(s1, "WEAK_BINDING", SHT_LINKEDIT, SHF_ALLOC | SHF_WRITE);
      mo->lazy_binding = new_section(s1, "LAZY_BINDING", SHT_LINKEDIT, SHF_ALLOC | SHF_WRITE);
  #endif      mo->exports = new_section(s1, "EXPORT", SHT_LINKEDIT, SHF_ALLOC | SHF_WRITE);
      mo->indirsyms = new_section(s1, "LEINDIR", SHT_LINKEDIT, SHF_ALLOC | SHF_WRITE);
        mo->symtab = new_section(s1, "LESYMTAB", SHT_LINKEDIT, SHF_ALLOC | SHF_WRITE);
      mo->strtab = new_section(s1, "LESTRTAB", SHT_LINKEDIT, SHF_ALLOC | SHF_WRITE);
      put_elf_str(mo->strtab, " ");
 /* Mach-O starts strtab with a space */      sym_end = symtab_section->data_offset / sizeof(ElfW(Sym));
      pn = section_ptr_add(mo->symtab, sizeof(*pn) * (sym_end - 1));
      for (sym_index = 1;
 sym_index < sym_end;
 ++sym_index) {
          ElfW(Sym) *sym = (ElfW(Sym) *)symtab_section->data + sym_index;
          const char *name = (char*)symtab_section->link->data + sym->st_name;
          pn[sym_index - 1].n_strx = put_elf_str(mo->strtab, name);
          pn[sym_index - 1].n_value = sym_index;

}      section_ptr_add(mo->strtab, -mo->strtab->data_offset & (PTR_SIZE - 1));
      tcc_qsort(pn, sym_end - 1, sizeof(*pn), machosymcmp, s1);
      mo->e2msym = tcc_malloc(sym_end * sizeof(*mo->e2msym));
      mo->e2msym[0] = -1;
      for (sym_index = 1;
 sym_index < sym_end;
 ++sym_index) {
          mo->e2msym[pn[sym_index - 1].n_value] = sym_index - 1;

}  
}

static void create_trie(struct trie_node *node,                          int from, int to, int index_start,                          int n_trie, struct trie_info *trie)  {
      int i;
      int start, end, index_end;
      char cur;
      struct trie_node *child;
        for (i = from;
 i < to;
 i = end) {
          cur = trie[i].name[index_start];
          start = i++;
          for (;
 i < to;
 i++)              if (cur != trie[i].name[index_start])                  break;
          end = i;
          if (start == end - 1 ||              (trie[start].name[index_start] &&               trie[start].name[index_start + 1] == 0))              index_end = trie[start].str_size - 1;
          else {
              index_end = index_start + 1;
              for (;
;
) {
                  cur = trie[start].name[index_end];
                  for (i = start + 1;
 i < end;
 i++)                      if (cur != trie[i].name[index_end])                          break;
                  if (trie[start].name[index_end] &&                      trie[start].name[index_end + 1] == 0) {
                      end = start + 1;
                      index_end = trie[start].str_size - 1;
                      break;

}                  if (i != end)                      break;
                  index_end++;

}          
}          node->child = tcc_realloc(node->child,                                    (node->n_child + 1) *                                    sizeof(struct trie_node));
          child = &node->child[node->n_child];
          child->start = start;
          child->end = end;
          child->index_start = index_start;
          child->index_end = index_end;
          child->n_child = 0;
          child->child = NULL;
          node->n_child++;
          if (start != end - 1)              create_trie(child, start, end, index_end, n_trie, trie);

}  
}

static int create_seq(int *offset, int *n_seq, struct trie_seq **seq,                          struct trie_node *node,                          int n_trie, struct trie_info *trie)  {
      int i, nest_offset, last_seq = *n_seq, retval = *offset;
      struct trie_seq *p_seq;
      struct trie_node *p_nest;
        for (i = 0;
 i < node->n_child;
 i++) {
          p_nest = &node->child[i];
          *seq = tcc_realloc(*seq, (*n_seq + 1) * sizeof(struct trie_seq));
          p_seq = &(*seq)[(*n_seq)++];
          p_seq->n_child = i == 0 ? node->n_child : -1;
          p_seq->node = p_nest;
          p_seq->offset = *offset;
          p_seq->nest_offset = 0;
          *offset += (i == 0 ? 1 + 1 : 0) +                     p_nest->index_end - p_nest->index_start + 1 + 3;

}      for (i = 0;
 i < node->n_child;
 i++) {
          nest_offset =              create_seq(offset, n_seq, seq, &node->child[i], n_trie, trie);
          p_seq = &(*seq)[last_seq + i];
          p_seq->nest_offset = nest_offset;

}      return retval;

}

static void node_free(struct trie_node *node)  {
      int i;
        for (i = 0;
 i < node->n_child;
 i++)   node_free(&node->child[i]);
      tcc_free(node->child);

}

static int triecmp(const void *_a, const void *_b, void *arg)  {
      struct trie_info *a = (struct trie_info *) _a;
      struct trie_info *b = (struct trie_info *) _b;
      int len_a = strlen(a->name);
      int len_b = strlen(b->name);
        /* strange sorting needed. Name 'xx' should be after 'xx1' */      if (!strncmp(a->name, b->name, len_a < len_b ? len_a : len_b))   return len_a < len_b ? 1 : (len_a > len_b ? -1 : 0);
      return strcmp(a->name, b->name);

}

static void export_trie(TCCState *s1, struct macho *mo)  {
      int i, size, offset = 0, save_offset;
      uint8_t *ptr;
      int sym_index;
      int sym_end = symtab_section->data_offset / sizeof(ElfW(Sym));
      int n_trie = 0, n_seq = 0;
      struct trie_info *trie = NULL, *p_trie;
      struct trie_node node, *p_node;
      struct trie_seq *seq = NULL;
      addr_t vm_addr = get_segment(mo, s1->output_type == TCC_OUTPUT_EXE)->vmaddr;
        for (sym_index = 1;
 sym_index < sym_end;
 ++sym_index) {
   ElfW(Sym) *sym = (ElfW(Sym) *)symtab_section->data + sym_index;
   const char *name = (char*)symtab_section->link->data + sym->st_name;
     if (sym->st_shndx != SHN_UNDEF && sym->st_shndx < SHN_LORESERVE &&              (ELFW(ST_BIND)(sym->st_info) == STB_GLOBAL ||        ELFW(ST_BIND)(sym->st_info) == STB_WEAK)) {
       int flag = EXPORT_SYMBOL_FLAGS_KIND_REGULAR;
       addr_t addr =    sym->st_value + s1->sections[sym->st_shndx]->sh_addr - vm_addr;
         if (ELFW(ST_BIND)(sym->st_info) == STB_WEAK)    flag |= EXPORT_SYMBOL_FLAGS_WEAK_DEFINITION;
       dprintf ("%s %d %llx\n", name, flag, (long long)addr + vm_addr);
       trie = tcc_realloc(trie, (n_trie + 1) * sizeof(struct trie_info));
       trie[n_trie].name = name;
       trie[n_trie].flag = flag;
       trie[n_trie].addr = addr;
       trie[n_trie].str_size = strlen(name) + 1;
       trie[n_trie].term_size = uleb128_size(flag) + uleb128_size(addr);
       n_trie++;

}      
}      if (n_trie) {
          tcc_qsort(trie, n_trie, sizeof(struct trie_info), triecmp, NULL);
   memset(&node, 0, sizeof(node));
          create_trie(&node, 0, n_trie, 0, n_trie, trie);
   create_seq(&offset, &n_seq, &seq, &node, n_trie, trie);
          save_offset = offset;
          for (i = 0;
 i < n_seq;
 i++) {
              p_node = seq[i].node;
              if (p_node->n_child == 0) {
                  p_trie = &trie[p_node->start];
                  seq[i].nest_offset = offset;
                  offset += 1 + p_trie->term_size + 1;

}          
}          for (i = 0;
 i < n_seq;
 i++) {
              p_node = seq[i].node;
              p_trie = &trie[p_node->start];
              if (seq[i].n_child >= 0) {
                  section_ptr_add(mo->exports,      seq[i].offset - mo->exports->data_offset);
                  ptr = section_ptr_add(mo->exports, 2);
                  *ptr++ = 0;
                  *ptr = seq[i].n_child;

}              size = p_node->index_end - p_node->index_start;
              ptr = section_ptr_add(mo->exports, size + 1);
              memcpy(ptr, &p_trie->name[p_node->index_start], size);
              ptr[size] = 0;
              write_uleb128(mo->exports, seq[i].nest_offset);

}          section_ptr_add(mo->exports, save_offset - mo->exports->data_offset);
          for (i = 0;
 i < n_seq;
 i++) {
              p_node = seq[i].node;
              if (p_node->n_child == 0) {
                  p_trie = &trie[p_node->start];
                  write_uleb128(mo->exports, p_trie->term_size);
                  write_uleb128(mo->exports, p_trie->flag);
                  write_uleb128(mo->exports, p_trie->addr);
                  ptr = section_ptr_add(mo->exports, 1);
                  *ptr = 0;

}          
}          section_ptr_add(mo->exports, -mo->exports->data_offset & 7);
   node_free(&node);
          tcc_free(seq);

}      tcc_free(trie);

}

static void collect_sections(TCCState *s1, struct macho *mo, const char *filename)  {
      int i, sk, numsec;
      int used_segment[N_SEGMENT];
      uint64_t curaddr, fileofs;
      Section *s;
      struct segment_command_64 *seg;
      struct dylib_command *dylib;
  #ifdef CONFIG_NEW_MACHO      struct linkedit_data_command *chained_fixups_lc;
      struct linkedit_data_command *export_trie_lc;
  #endif      struct build_version_command *dyldbv;
      struct source_version_command *dyldsv;
      struct rpath_command *rpath;
      struct dylinker_command *dyldlc;
      struct symtab_command *symlc;
      struct dysymtab_command *dysymlc;
      char *str;
        for (i = 0;
 i < N_SEGMENT;
 i++)   used_segment[i] = all_segment[i].used;
        memset (mo->sk_to_sect, 0, sizeof(mo->sk_to_sect));
      for (i = s1->nb_sections;
 i-- > 1;
) {
          int type, flags;
          s = s1->sections[i];
          type = s->sh_type;
          flags = s->sh_flags;
          sk = sk_unknown;
   /* debug sections have sometimes no SHF_ALLOC */          if ((flags & SHF_ALLOC) || !strncmp(s->name, ".debug_", 7)) {
              switch (type) {
              default:           sk = sk_unknown;
 break;
              case SHT_INIT_ARRAY: sk = sk_init;
 break;
              case SHT_FINI_ARRAY: sk = sk_fini;
 break;
              case SHT_NOBITS:   sk = sk_bss;
 break;
              case SHT_SYMTAB:   sk = sk_discard;
 break;
              case SHT_STRTAB:    if (s == stabstr_section)      sk = sk_stab_str;
    else      sk = sk_discard;
    break;
              case SHT_RELX:     sk = sk_discard;
 break;
              case SHT_LINKEDIT: sk = sk_linkedit;
 break;
              case SHT_PROGBITS:                  if (s == mo->stubs)                    sk = sk_stubs;
  #ifndef CONFIG_NEW_MACHO                  else if (s == mo->stub_helper)                    sk = sk_stub_helper;
                  else if (s == mo->la_symbol_ptr)                    sk = sk_la_ptr;
  #endif                  else if (s == rodata_section)                    sk = sk_ro_data;
                  else if (s == s1->got)                    sk = sk_nl_ptr;
                  else if (s == stab_section)                    sk = sk_stab;
                  else if (s == dwarf_info_section)                    sk = sk_debug_info;
                  else if (s == dwarf_abbrev_section)                    sk = sk_debug_abbrev;
                  else if (s == dwarf_line_section)                    sk = sk_debug_line;
                  else if (s == dwarf_aranges_section)                    sk = sk_debug_aranges;
                  else if (s == dwarf_str_section)                    sk = sk_debug_str;
                  else if (s == dwarf_line_str_section)                    sk = sk_debug_line_str;
                  else if (flags & SHF_EXECINSTR)                    sk = sk_text;
                  else if (flags & SHF_WRITE)                    sk = sk_rw_data;
                  else                    sk = sk_ro_data;
                  break;

}          
} else            sk = sk_discard;
          s->prev = mo->sk_to_sect[sk].s;
          mo->sk_to_sect[sk].s = s;
   used_segment[skinfo[sk].seg_initial] = 1;

}        if (s1->output_type != TCC_OUTPUT_EXE)   used_segment[0] = 0;
        for (i = 0;
 i < N_SEGMENT;
 i++)   if (used_segment[i]) {
       seg = add_segment(mo, all_segment[i].name);
       if (i == 1 && s1->output_type != TCC_OUTPUT_EXE)           seg->vmaddr = 0;
       else           seg->vmaddr = all_segment[i].vmaddr;
       seg->vmsize = all_segment[i].vmsize;
       seg->maxprot = all_segment[i].maxprot;
       seg->initprot = all_segment[i].initprot;
       seg->flags = all_segment[i].flags;
              for (sk = sk_unknown;
 sk < sk_last;
 sk++)    if (skinfo[sk].seg_initial == i)               mo->segment[sk] = mo->nseg - 1;

}        if (s1->output_type != TCC_OUTPUT_EXE) {
   const char *name = s1->install_name ? s1->install_name : filename;
          i = (sizeof(*dylib) + strlen(name) + 1 + 7) &-8;
          dylib = add_lc(mo, LC_ID_DYLIB, i);
   dylib->name = sizeof(*dylib);
   dylib->timestamp = 1;
   dylib->current_version =       s1->current_version ? s1->current_version : 1 << 16;
   dylib->compatibility_version =       s1->compatibility_version ? s1->compatibility_version : 1 << 16;
          str = (char*)dylib + dylib->name;
          strcpy(str, name);

}    #ifdef CONFIG_NEW_MACHO      chained_fixups_lc = add_lc(mo, LC_DYLD_CHAINED_FIXUPS,            sizeof(struct linkedit_data_command));
      export_trie_lc = add_lc(mo, LC_DYLD_EXPORTS_TRIE,         sizeof(struct linkedit_data_command));
  #else      mo->dyldinfo = add_lc(mo, LC_DYLD_INFO_ONLY, sizeof(*mo->dyldinfo));
  #endif        symlc = add_lc(mo, LC_SYMTAB, sizeof(*symlc));
      dysymlc = add_lc(mo, LC_DYSYMTAB, sizeof(*dysymlc));
        if (s1->output_type == TCC_OUTPUT_EXE) {
          i = (sizeof(*dyldlc) + strlen("/usr/lib/dyld") + 1 + 7) &-8;
          dyldlc = add_lc(mo, LC_LOAD_DYLINKER, i);
          dyldlc->name = sizeof(*dyldlc);
          str = (char*)dyldlc + dyldlc->name;
          strcpy(str, "/usr/lib/dyld");

}        dyldbv = add_lc(mo, LC_BUILD_VERSION, sizeof(*dyldbv));
      dyldbv->platform = PLATFORM_MACOS;
      dyldbv->minos = (10 << 16) + (6 << 8);
      dyldbv->sdk = (10 << 16) + (6 << 8);
      dyldbv->ntools = 0;
        dyldsv = add_lc(mo, LC_SOURCE_VERSION, sizeof(*dyldsv));
      dyldsv->version = 0;
        if (s1->output_type == TCC_OUTPUT_EXE) {
          mo->ep = add_lc(mo, LC_MAIN, sizeof(*mo->ep));
          mo->ep->entryoff = 4096;

}        for(i = 0;
 i < s1->nb_loaded_dlls;
 i++) {
          DLLReference *dllref = s1->loaded_dlls[i];
          if (dllref->level == 0)            add_dylib(mo, dllref->name);

}        if (s1->rpath) {
   char *path = s1->rpath, *end;
   do {
       end = strchr(path, ':');
       if (!end)    end = strchr(path, 0);
              i = (sizeof(*rpath) + (end - path) + 1 + 7) &-8;
              rpath = add_lc(mo, LC_RPATH, i);
              rpath->path = sizeof(*rpath);
              str = (char*)rpath + rpath->path;
              memcpy(str, path, end - path);
       str[end - path] = 0;
       path = end + 1;

} while (*end);

}        fileofs = 4096;
  /* leave space for mach-o headers */      curaddr = get_segment(mo, s1->output_type == TCC_OUTPUT_EXE)->vmaddr;
      curaddr += 4096;
      seg = NULL;
      numsec = 0;
      mo->elfsectomacho = tcc_mallocz(sizeof(*mo->elfsectomacho) * s1->nb_sections);
      for (sk = sk_unknown;
 sk < sk_last;
 sk++) {
          struct section_64 *sec = NULL;
          if (seg) {
              seg->vmsize = curaddr - seg->vmaddr;
              seg->filesize = fileofs - seg->fileoff;

}  #ifdef CONFIG_NEW_MACHO   if (sk == sk_linkedit) {
       calc_fixup_size(s1, mo);
       export_trie(s1, mo);

}  #else   if (sk == sk_linkedit) {
       bind_rebase(s1, mo);
       export_trie(s1, mo);

}  #endif          if (skinfo[sk].seg_initial &&       (s1->output_type != TCC_OUTPUT_EXE || mo->segment[sk]) &&       mo->sk_to_sect[sk].s) {
              uint64_t al = 0;
              int si;
              seg = get_segment(mo, mo->segment[sk]);
              if (skinfo[sk].name) {
                  si = add_section(mo, &seg, skinfo[sk].name);
                  numsec++;
                  mo->lc[mo->seg2lc[mo->segment[sk]]] = (struct load_command*)seg;
                  mo->sk_to_sect[sk].machosect = si;
                  sec = get_section(seg, si);
                  sec->flags = skinfo[sk].flags;
    if (sk == sk_stubs)  #ifdef TCC_TARGET_X86_64            sec->reserved2 = 6;
  #elif defined TCC_TARGET_ARM64            sec->reserved2 = 12;
  #endif    if (sk == sk_nl_ptr)            sec->reserved1 = mo->nr_plt;
  #ifndef CONFIG_NEW_MACHO    if (sk == sk_la_ptr)            sec->reserved1 = mo->nr_plt + mo->n_got;
  #endif              
}              if (seg->vmaddr == -1) {
                  curaddr = (curaddr + SEG_PAGE_SIZE - 1) & -SEG_PAGE_SIZE;
                  seg->vmaddr = curaddr;
                  fileofs = (fileofs + SEG_PAGE_SIZE - 1) & -SEG_PAGE_SIZE;
                  seg->fileoff = fileofs;

}                for (s = mo->sk_to_sect[sk].s;
 s;
 s = s->prev) {
                  int a = exact_log2p1(s->sh_addralign);
                  if (a && al < (a - 1))                    al = a - 1;
                  s->sh_size = s->data_offset;

}              if (sec)                sec->align = al;
              al = 1ULL << al;
              if (al > 4096)                tcc_warning("alignment > 4096"), sec->align = 12, al = 4096;
              curaddr = (curaddr + al - 1) & -al;
              fileofs = (fileofs + al - 1) & -al;
              if (sec) {
                  sec->addr = curaddr;
                  sec->offset = fileofs;

}              for (s = mo->sk_to_sect[sk].s;
 s;
 s = s->prev) {
                  al = s->sh_addralign;
                  curaddr = (curaddr + al - 1) & -al;
                  dprintf("%s: curaddr now 0x%lx\n", s->name, (long)curaddr);
                  s->sh_addr = curaddr;
                  curaddr += s->sh_size;
                  if (s->sh_type != SHT_NOBITS) {
                      fileofs = (fileofs + al - 1) & -al;
                      s->sh_offset = fileofs;
                      fileofs += s->sh_size;
                      dprintf("%s: fileofs now %ld\n", s->name, (long)fileofs);

}                  if (sec)                    mo->elfsectomacho[s->sh_num] = numsec;

}              if (sec)                sec->size = curaddr - sec->addr;

}          if (DEBUG_MACHO)            for (s = mo->sk_to_sect[sk].s;
 s;
 s = s->prev) {
                int type = s->sh_type;
                int flags = s->sh_flags;
                printf("%d section %-16s %-10s %09lx %04x %02d %s,%s,%s\n",                       sk,                       s->name,                       type == SHT_PROGBITS ? "progbits" :                       type == SHT_NOBITS ? "nobits" :                       type == SHT_SYMTAB ? "symtab" :                       type == SHT_STRTAB ? "strtab" :                       type == SHT_INIT_ARRAY ? "init" :                       type == SHT_FINI_ARRAY ? "fini" :                       type == SHT_RELX ? "rel" : "???",                       (long)s->sh_addr,                       (unsigned)s->data_offset,                       s->sh_addralign,                       flags & SHF_ALLOC ? "alloc" : "",                       flags & SHF_WRITE ? "write" : "",                       flags & SHF_EXECINSTR ? "exec" : ""                      );

}      
}      if (seg) {
          seg->vmsize = curaddr - seg->vmaddr;
          seg->filesize = fileofs - seg->fileoff;

}        /* Fill symtab info */      symlc->symoff = mo->symtab->sh_offset;
      symlc->nsyms = mo->symtab->data_offset / sizeof(struct nlist_64);
      symlc->stroff = mo->strtab->sh_offset;
      symlc->strsize = mo->strtab->data_offset;
        dysymlc->iundefsym = mo->iundef == -1 ? symlc->nsyms : mo->iundef;
      dysymlc->iextdefsym = mo->iextdef == -1 ? dysymlc->iundefsym : mo->iextdef;
      dysymlc->ilocalsym = mo->ilocal == -1 ? dysymlc->iextdefsym : mo->ilocal;
      dysymlc->nlocalsym = dysymlc->iextdefsym - dysymlc->ilocalsym;
      dysymlc->nextdefsym = dysymlc->iundefsym - dysymlc->iextdefsym;
      dysymlc->nundefsym = symlc->nsyms - dysymlc->iundefsym;
      dysymlc->indirectsymoff = mo->indirsyms->sh_offset;
      dysymlc->nindirectsyms = mo->indirsyms->data_offset / sizeof(uint32_t);
    #ifdef CONFIG_NEW_MACHO      if (mo->chained_fixups->data_offset) {
          chained_fixups_lc->dataoff = mo->chained_fixups->sh_offset;
          chained_fixups_lc->datasize = mo->chained_fixups->data_offset;

}      if (mo->exports->data_offset) {
          export_trie_lc->dataoff = mo->exports->sh_offset;
          export_trie_lc->datasize = mo->exports->data_offset;

}  #else      if (mo->rebase->data_offset) {
          mo->dyldinfo->rebase_off = mo->rebase->sh_offset;
          mo->dyldinfo->rebase_size = mo->rebase->data_offset;

}      if (mo->binding->data_offset) {
          mo->dyldinfo->bind_off = mo->binding->sh_offset;
          mo->dyldinfo->bind_size = mo->binding->data_offset;

}      if (mo->weak_binding->data_offset) {
          mo->dyldinfo->weak_bind_off = mo->weak_binding->sh_offset;
          mo->dyldinfo->weak_bind_size = mo->weak_binding->data_offset;

}      if (mo->lazy_binding->data_offset) {
          mo->dyldinfo->lazy_bind_off = mo->lazy_binding->sh_offset;
          mo->dyldinfo->lazy_bind_size = mo->lazy_binding->data_offset;

}      if (mo->exports->data_offset) {
          mo->dyldinfo->export_off = mo->exports->sh_offset;
          mo->dyldinfo->export_size = mo->exports->data_offset;

}  #endif  
}

static void macho_write(TCCState *s1, struct macho *mo, FILE *fp)  {
      int i, sk;
      uint64_t fileofs = 0;
      Section *s;
      mo->mh.mh.magic = MH_MAGIC_64;
  #ifdef TCC_TARGET_X86_64      mo->mh.mh.cputype = CPU_TYPE_X86_64;
      mo->mh.mh.cpusubtype = CPU_SUBTYPE_LIB64 | CPU_SUBTYPE_X86_ALL;
  #elif defined TCC_TARGET_ARM64      mo->mh.mh.cputype = CPU_TYPE_ARM64;
      mo->mh.mh.cpusubtype = CPU_SUBTYPE_ARM64_ALL;
  #endif      if (s1->output_type == TCC_OUTPUT_EXE) {
          mo->mh.mh.filetype = MH_EXECUTE;
          mo->mh.mh.flags = MH_DYLDLINK | MH_PIE;

}      else {
          mo->mh.mh.filetype = MH_DYLIB;
          mo->mh.mh.flags = MH_DYLDLINK;

}      mo->mh.mh.ncmds = mo->nlc;
      mo->mh.mh.sizeofcmds = 0;
      for (i = 0;
 i < mo->nlc;
 i++)        mo->mh.mh.sizeofcmds += mo->lc[i]->cmdsize;
        fwrite(&mo->mh, 1, sizeof(mo->mh), fp);
      fileofs += sizeof(mo->mh);
      for (i = 0;
 i < mo->nlc;
 i++) {
          fwrite(mo->lc[i], 1, mo->lc[i]->cmdsize, fp);
          fileofs += mo->lc[i]->cmdsize;

}        for (sk = sk_unknown;
 sk < sk_last;
 sk++) {
          //struct segment_command_64 *seg;
          if (skinfo[sk].seg_initial == 0 ||       (s1->output_type == TCC_OUTPUT_EXE && !mo->segment[sk]) ||       !mo->sk_to_sect[sk].s)            continue;
          /*seg =*/ get_segment(mo, mo->segment[sk]);
          for (s = mo->sk_to_sect[sk].s;
 s;
 s = s->prev) {
              if (s->sh_type != SHT_NOBITS) {
                  while (fileofs < s->sh_offset)                    fputc(0, fp), fileofs++;
                  if (s->sh_size) {
                      fwrite(s->data, 1, s->sh_size, fp);
                      fileofs += s->sh_size;

}              
}          
}      
}  
}

ST_FUNC int macho_output_file(TCCState *s1, const char *filename)  {
      int fd, mode, file_type;
      FILE *fp;
      int i, ret = -1;
      struct macho mo;
        (void)memset(&mo, 0, sizeof(mo));
        file_type = s1->output_type;
      if (file_type == TCC_OUTPUT_OBJ)          mode = 0666;
      else          mode = 0777;
      unlink(filename);
      fd = open(filename, O_WRONLY | O_CREAT | O_TRUNC | O_BINARY, mode);
      if (fd < 0 || (fp = fdopen(fd, "wb")) == NULL) {
          tcc_error_noabort("could not write '%s: %s'", filename, strerror(errno));
          return -1;

}      if (s1->verbose)          printf("<- %s\n", filename);
        tcc_add_runtime(s1);
      tcc_macho_add_destructor(s1);
      resolve_common_syms(s1);
      create_symtab(s1, &mo);
      check_relocs(s1, &mo);
      ret = check_symbols(s1, &mo);
      if (!ret) {
   int save_output = s1->output_type;
            collect_sections(s1, &mo, filename);
          relocate_syms(s1, s1->symtab, 0);
   if (s1->output_type == TCC_OUTPUT_EXE)              mo.ep->entryoff = get_sym_addr(s1, "main", 1, 1)                              -     get_segment(&mo, 1)->vmaddr;
          if (s1->nb_errors)            goto do_ret;
   // Macho uses bind/rebase instead of dynsym   s1->output_type = TCC_OUTPUT_EXE;
          relocate_sections(s1);
   s1->output_type = save_output;
  #ifdef CONFIG_NEW_MACHO   bind_rebase_import(s1, &mo);
  #endif          convert_symbols(s1, &mo);
          macho_write(s1, &mo, fp);

}     do_ret:      for (i = 0;
 i < mo.nlc;
 i++)        tcc_free(mo.lc[i]);
      tcc_free(mo.seg2lc);
      tcc_free(mo.lc);
      tcc_free(mo.elfsectomacho);
      tcc_free(mo.e2msym);
        fclose(fp);
  #ifdef CONFIG_CODESIGN      if (!ret) {
   char command[1024];
   int retval;
     snprintf(command, sizeof(command), "codesign -f -s - %s", filename);
   retval = system (command);
   if (retval == -1 || !(WIFEXITED(retval) && WEXITSTATUS(retval) == 0))       tcc_error ("command failed '%s'", command);

}  #endif      return ret;

}

static uint32_t macho_swap32(uint32_t x)  {
    return (x >> 24) | (x << 24) | ((x >> 8) & 0xff00) | ((x & 0xff00) << 8);

}

ST_FUNC int macho_load_tbd(TCCState* s1, int fd, const char* filename, int lev)  {
      char *soname, *data, *pos;
      int ret = -1;
        pos = data = tcc_load_text(fd);
      if (!tbd_parse_movepast("install-name: ")) goto the_end;
      tbd_parse_skipws;
      tbd_parse_tramplequote;
      soname = pos;
      if (!tbd_parse_movetoany("\n \"'")) goto the_end;
      tbd_parse_trample;
      ret = 0;
      if (tcc_add_dllref(s1, soname, lev)->found)          goto the_end;
      while(pos) {
          char* sym = NULL;
          int cont = 1;
          if (!tbd_parse_movepast("symbols: ")) break;
          if (!tbd_parse_movepast("[")) break;
          while (cont) {
              tbd_parse_skipws;
              tbd_parse_tramplequote;
              sym = pos;
              if (!tbd_parse_movetoany(",] \"'")) break;
              tbd_parse_tramplequote;
              tbd_parse_tramplespace;
              tbd_parse_skipws;
              if (*pos==0||*pos==']') cont=0;
              tbd_parse_trample;
              set_elf_sym(s1->dynsymtab_section, 0, 0,                  ELFW(ST_INFO)(STB_GLOBAL, STT_NOTYPE), 0, SHN_UNDEF, sym);

}      
}    the_end:      tcc_free(data);
      return ret;

}

ST_FUNC int macho_load_dll(TCCState * s1, int fd, const char* filename, int lev)  {
      unsigned char buf[sizeof(struct mach_header_64)];
      void *buf2;
      uint32_t machofs = 0;
      struct fat_header fh;
      struct mach_header mh;
      struct load_command *lc;
      int i, swap = 0;
      const char *soname = filename;
      struct nlist_64 *symtab = 0;
      uint32_t nsyms = 0;
      char *strtab = 0;
      uint32_t strsize = 0;
      uint32_t iextdef = 0;
      uint32_t nextdef = 0;
      again:      if (full_read(fd, buf, sizeof(buf)) != sizeof(buf))        return -1;
      memcpy(&fh, buf, sizeof(fh));
      if (fh.magic == FAT_MAGIC || fh.magic == FAT_CIGAM) {
          struct fat_arch *fa = load_data(fd, sizeof(fh),                                          fh.nfat_arch * sizeof(*fa));
          swap = fh.magic == FAT_CIGAM;
          for (i = 0;
 i < SWAP(fh.nfat_arch);
 i++)  #ifdef TCC_TARGET_X86_64            if (SWAP(fa[i].cputype) == CPU_TYPE_X86_64                && SWAP(fa[i].cpusubtype) == CPU_SUBTYPE_X86_ALL)  #elif defined TCC_TARGET_ARM64            if (SWAP(fa[i].cputype) == CPU_TYPE_ARM64                && SWAP(fa[i].cpusubtype) == CPU_SUBTYPE_ARM64_ALL)  #endif              break;
          if (i == SWAP(fh.nfat_arch)) {
              tcc_free(fa);
              return -1;

}          machofs = SWAP(fa[i].offset);
          tcc_free(fa);
          lseek(fd, machofs, SEEK_SET);
          goto again;

} else if (fh.magic == FAT_MAGIC_64 || fh.magic == FAT_CIGAM_64) {
          tcc_warning("%s: Mach-O fat 64bit files of type 0x%x not handled",                      filename, fh.magic);
          return -1;

}        memcpy(&mh, buf, sizeof(mh));
      if (mh.magic != MH_MAGIC_64)        return -1;
      dprintf("found Mach-O at %d\n", machofs);
      buf2 = load_data(fd, machofs + sizeof(struct mach_header_64), mh.sizeofcmds);
      for (i = 0, lc = buf2;
 i < mh.ncmds;
 i++) {
          dprintf("lc %2d: 0x%08x\n", i, lc->cmd);
          switch (lc->cmd) {
          case LC_SYMTAB:          {
              struct symtab_command *sc = (struct symtab_command*)lc;
              nsyms = sc->nsyms;
              symtab = load_data(fd, machofs + sc->symoff, nsyms * sizeof(*symtab));
              strsize = sc->strsize;
              strtab = load_data(fd, machofs + sc->stroff, strsize);
              break;

}          case LC_ID_DYLIB:          {
              struct dylib_command *dc = (struct dylib_command*)lc;
              soname = (char*)lc + dc->name;
              dprintf(" ID_DYLIB %d 0x%x 0x%x %s\n",                      dc->timestamp, dc->current_version,                      dc->compatibility_version, soname);
              break;

}          case LC_REEXPORT_DYLIB:          {
              struct dylib_command *dc = (struct dylib_command*)lc;
              char *name = (char*)lc + dc->name;
              int subfd = open(name, O_RDONLY | O_BINARY);
              dprintf(" REEXPORT %s\n", name);
              if (subfd < 0)                tcc_warning("can't open %s (reexported from %s)", name, filename);
              else {
                  /* Hopefully the REEXPORTs never form a cycle, we don't check                     for that!  */                  macho_load_dll(s1, subfd, name, lev + 1);
                  close(subfd);

}              break;

}          case LC_DYSYMTAB:          {
              struct dysymtab_command *dc = (struct dysymtab_command*)lc;
              iextdef = dc->iextdefsym;
              nextdef = dc->nextdefsym;
              break;

}          
}          lc = (struct load_command*) ((char*)lc + lc->cmdsize);

}        if (tcc_add_dllref(s1, soname, lev)->found)          goto the_end;
        if (!nsyms || !nextdef)        tcc_warning("%s doesn't export any symbols?", filename);
        //dprintf("symbols (all):\n");
      dprintf("symbols (exported):\n");
      dprintf("    n: typ sec   desc              value name\n");
      //for (i = 0;
 i < nsyms;
 i++) {
      for (i = iextdef;
 i < iextdef + nextdef;
 i++) {
          struct nlist_64 *sym = symtab + i;
          dprintf("%5d: %3d %3d 0x%04x 0x%016lx %s\n",                  i, sym->n_type, sym->n_sect, sym->n_desc, (long)sym->n_value,                  strtab + sym->n_strx);
          set_elf_sym(s1->dynsymtab_section, 0, 0,                      ELFW(ST_INFO)(STB_GLOBAL, STT_NOTYPE),                      0, SHN_UNDEF, strtab + sym->n_strx);

}      the_end:      tcc_free(strtab);
      tcc_free(symtab);
      tcc_free(buf2);
      return 0;

}

static const char *pe_export_name(TCCState *s1, ElfW(Sym) *sym)  {
      const char *name = (char*)symtab_section->link->data + sym->st_name;
      if (s1->leading_underscore && name[0] == '_' && !(sym->st_other & ST_PE_STDCALL))          return name + 1;
      return name;

}

static int pe_find_import(TCCState * s1, ElfW(Sym) *sym)  {
      char buffer[200];
      const char *s, *p;
      int sym_index = 0, n = 0;
      int a, err = 0;
        do {
          s = pe_export_name(s1, sym);
          a = 0;
          if (n) {
              /* second try: */       if (sym->st_other & ST_PE_STDCALL) {
                  /* try w/0 stdcall deco (windows API convention) */           p = strrchr(s, '@');
           if (!p || s[0] != '_')               break;
           strcpy(buffer, s+1)[p-s-1] = 0;

} else if (s[0] != '_') {
 /* try non-ansi function */           buffer[0] = '_', strcpy(buffer + 1, s);

} else if (0 == memcmp(s, "__imp_", 6)) {
 /* mingw 2.0 */           strcpy(buffer, s + 6), a = 1;

} else if (0 == memcmp(s, "_imp__", 6)) {
 /* mingw 3.7 */           strcpy(buffer, s + 6), a = 1;

} else {
           continue;

}       s = buffer;

}          sym_index = find_elf_sym(s1->dynsymtab_section, s);
          // printf("find (%d) %d %s\n", n, sym_index, s);
          if (sym_index              && ELFW(ST_TYPE)(sym->st_info) == STT_OBJECT              && 0 == (sym->st_other & ST_PE_IMPORT)              && 0 == a              ) err = -1, sym_index = 0;

} while (0 == sym_index && ++n < 2);
      return n == 2 ? err : sym_index;

}

static int dynarray_assoc(void **pp, int n, int key)  {
      int i;
      for (i = 0;
 i < n;
 ++i, ++pp)      if (key == **(int **) pp)          return i;
      return -1;

}

static DWORD umin(DWORD a, DWORD b)  {
      return a < b ? a : b;

}

static DWORD umax(DWORD a, DWORD b)  {
      return a < b ? b : a;

}

static DWORD pe_file_align(struct pe_info *pe, DWORD n)  {
      return (n + (pe->file_align - 1)) & ~(pe->file_align - 1);

}

static ADDR3264 pe_virtual_align(struct pe_info *pe, ADDR3264 n)  {
      return (n + (pe->section_align - 1)) & ~(ADDR3264)(pe->section_align - 1);

}

static void pe_align_section(Section *s, int a)  {
      int i = s->data_offset & (a-1);
      if (i)          section_ptr_add(s, a - i);

}

static void pe_set_datadir(struct pe_header *hdr, int dir, DWORD addr, DWORD size)  {
      hdr->opthdr.DataDirectory[dir].VirtualAddress = addr;
      hdr->opthdr.DataDirectory[dir].Size = size;

}

static int pe_fwrite(const void *data, int len, struct pe_file *pf)  {
      const WORD *p = data;
      DWORD sum;
      int ret, i;
      pf->pos += (ret = fwrite(data, 1, len, pf->op));
      sum = pf->sum;
      for (i = len;
 i > 0;
 i -= 2) {
          sum += (i >= 2) ? *p++ : *(BYTE*)p;
          sum = (sum + (sum >> 16)) & 0xFFFF;

}      pf->sum = sum;
      return len == ret ? 0 : -1;

}

static void pe_fpad(struct pe_file *pf, DWORD new_pos)  {
      char buf[256];
      int n, diff = new_pos - pf->pos;
      memset(buf, 0, sizeof buf);
      while (diff > 0) {
          diff -= n = umin(diff, sizeof buf);
          fwrite(buf, n, 1, pf->op);

}      pf->pos = new_pos;

}

static int pe_put_long_secname(char *secname, const char *name)  {
      const char *d = dwarf_secs;
      do {
          if (0 == strcmp(d, name)) {
              snprintf(secname, 8, "/%d", (int)(d - dwarf_secs + 4));
              return 1;

}          d = strchr(d, 0) + 1;

} while (*d);
      return 0;

}

static void pe_create_pdb(TCCState *s1, const char *exename)  {
      char buf[300];
 int r;
      snprintf(buf, sizeof buf, "cv2pdb.exe %s", exename);
      r = system(buf);
      strcpy(tcc_fileextension(strcpy(buf, exename)), ".pdb");
      if (r) {
          tcc_error_noabort("could not create '%s'\n(need working cv2pdb from https://github.com/rainers/cv2pdb)", buf);

} else if (s1->verbose) {
          printf("<- %s\n", buf);

}  
}

