          if (sym->st_other & ST_PE_STDCALL)              printf("stdcall: %s\n", name);
  #endif      
}        if (0 == sym_count)          return;
        qsort (sorted, sym_count, sizeof *sorted, sym_cmp);
        pe_align_section(pe->thunk, 16);
      dllname = tcc_basename(pe->filename);
        base_o = pe->thunk->data_offset;
      func_o = base_o + sizeof(IMAGE_EXPORT_DIRECTORY);
      name_o = func_o + sym_count * sizeof (DWORD);
      ord_o = name_o + sym_count * sizeof (DWORD);
      str_o = ord_o + sym_count * sizeof(WORD);
        hdr = section_ptr_add(pe->thunk, str_o - base_o);
      hdr->Characteristics        = 0;
      hdr->Base                   = 1;
      hdr->NumberOfFunctions      = sym_count;
      hdr->NumberOfNames          = sym_count;
      hdr->AddressOfFunctions     = func_o + rva_base;
      hdr->AddressOfNames         = name_o + rva_base;
      hdr->AddressOfNameOrdinals  = ord_o + rva_base;
      hdr->Name                   = str_o + rva_base;
      put_elf_str(pe->thunk, dllname);
    #if 1      /* automatically write exports to <output-filename>.def */      pstrcpy(buf, sizeof buf, pe->filename);
      strcpy(tcc_fileextension(buf), ".def");
      op = fopen(buf, "wb");
      if (NULL == op) {
          tcc_error_noabort("could not create '%s': %s", buf, strerror(errno));

} else {
          fprintf(op, "LIBRARY %s\n\nEXPORTS\n", dllname);
          if (pe->s1->verbose)              printf("<- %s (%d symbol%s)\n", buf, sym_count, &"s"[sym_count < 2]);

}  #endif        for (ord = 0;
 ord < sym_count;
 ++ord)      {
          p = sorted[ord], sym_index = p->index, name = p->name;
          /* insert actual address later in relocate_sections() */          put_elf_reloc(symtab_section, pe->thunk,              func_o, R_XXX_RELATIVE, sym_index);
          *(DWORD*)(pe->thunk->data + name_o)              = pe->thunk->data_offset + rva_base;
          *(WORD*)(pe->thunk->data + ord_o)              = ord;
          put_elf_str(pe->thunk, name);
          func_o += sizeof (DWORD);
          name_o += sizeof (DWORD);
          ord_o += sizeof (WORD);
          if (op)              fprintf(op, "%s\n", name);

}        pe->exp_offs = base_o + rva_base;
      pe->exp_size = pe->thunk->data_offset - base_o;
      dynarray_reset(&sorted, &sym_count);
      if (op)          fclose(op);

}

static void pe_build_reloc (struct pe_info *pe)  {
      DWORD offset, block_ptr, sh_addr, addr;
      int count, i;
      ElfW_Rel *rel, *rel_end;
      Section *s = NULL, *sr;
      struct pe_reloc_header *hdr;
        sh_addr = offset = block_ptr = count = i = 0;
      rel = rel_end = NULL;
        for(;
;
) {
          if (rel < rel_end) {
              int type = ELFW(R_TYPE)(rel->r_info);
              addr = rel->r_offset + sh_addr;
              ++ rel;
              if (type != REL_TYPE_DIRECT)                  continue;
              if (count == 0) {
 /* new block */                  block_ptr = pe->reloc->data_offset;
                  section_ptr_add(pe->reloc, sizeof(struct pe_reloc_header));
                  offset = addr & 0xFFFFFFFF<<12;

}              if ((addr -= offset)  < (1<<12)) {
 /* one block spans 4k addresses */                  WORD *wp = section_ptr_add(pe->reloc, sizeof (WORD));
                  *wp = addr | PE_IMAGE_REL<<12;
                  ++count;
                  continue;

}              -- rel;

} else if (s) {
              sr = s->reloc;
              if (sr) {
                  rel = (ElfW_Rel *)sr->data;
                  rel_end = (ElfW_Rel *)(sr->data + sr->data_offset);
                  sh_addr = s->sh_addr;

}              s = s->prev;
              continue;

} else if (i < pe->sec_count) {
              s = pe->sec_info[i]->sec, ++i;
              continue;

} else if (!count)              break;
            /* fill the last block and ready for a new one */          if (count & 1) /* align for DWORDS */              section_ptr_add(pe->reloc, sizeof(WORD)), ++count;
          hdr = (struct pe_reloc_header *)(pe->reloc->data + block_ptr);
          hdr -> offset = offset - pe->imagebase;
          hdr -> size = count * sizeof(WORD) + sizeof(struct pe_reloc_header);
          count = 0;

}  
}

static int pe_section_class(Section *s)  {
      int type, flags;
      const char *name;
      type = s->sh_type;
      flags = s->sh_flags;
      name = s->name;
        if (0 == memcmp(name, ".stab", 5) || 0 == memcmp(name, ".debug_", 7)) {
          return sec_debug;

} else if (flags & SHF_ALLOC) {
          if (type == SHT_PROGBITS           || type == SHT_INIT_ARRAY           || type == SHT_FINI_ARRAY) {
              if (flags & SHF_EXECINSTR)                  return sec_text;
              if (flags & SHF_WRITE)                  return sec_data;
              if (0 == strcmp(name, ".rsrc"))                  return sec_rsrc;
              if (0 == strcmp(name, ".iedat"))                  return sec_idata;
              if (0 == strcmp(name, ".pdata"))                  return sec_pdata;
              return sec_rdata;

} else if (type == SHT_NOBITS) {
              return sec_bss;

}          return sec_other;

} else {
          if (0 == strcmp(name, ".reloc"))              return sec_reloc;

}      return sec_last;

}

static int pe_assign_addresses (struct pe_info *pe)  {
      int i, k, n, c, nbs;
      ADDR3264 addr;
      int *sec_order, *sec_cls;
      struct section_info *si;
      Section *s;
      TCCState *s1 = pe->s1;
        if (PE_DLL == pe->type)          pe->reloc = new_section(pe->s1, ".reloc", SHT_PROGBITS, 0);
      //pe->thunk = new_section(pe->s1, ".iedat", SHT_PROGBITS, SHF_ALLOC);
        nbs = s1->nb_sections;
      sec_order = tcc_mallocz(2 * sizeof (int) * nbs);
      sec_cls = sec_order + nbs;
      for (i = 1;
 i < nbs;
 ++i) {
          s = s1->sections[i];
          k = pe_section_class(s);
          for (n = i;
 n > 1 && k < (c = sec_cls[n - 1]);
 --n)              sec_cls[n] = c, sec_order[n] = sec_order[n - 1];
          sec_cls[n] = k, sec_order[n] = i;

}      si = NULL;
      addr = pe->imagebase + 1;
        for (i = 1;
 (c = sec_cls[i]) < sec_last;
 ++i) {
          s = s1->sections[sec_order[i]];
            if (PE_MERGE_DATA && c == sec_bss)              c = sec_data;
            if (si && c == si->cls && c != sec_debug) {
              /* merge with previous section */              s->sh_addr = addr = ((addr - 1) | (16 - 1)) + 1;

} else {
              si = NULL;
              s->sh_addr = addr = pe_virtual_align(pe, addr);

}            if (NULL == pe->thunk              && c == (data_section == rodata_section ? sec_data : sec_rdata))              pe->thunk = s;
            if (s == pe->thunk) {
              pe_build_imports(pe);
              pe_build_exports(pe);

}          if (s == pe->reloc)              pe_build_reloc (pe);
            if (0 == s->data_offset)              continue;
            if (si)              goto add_section;
            si = tcc_mallocz(sizeof *si);
          dynarray_add(&pe->sec_info, &pe->sec_count, si);
            strcpy(si->name, s->name);
          si->cls = c;
          si->sh_addr = addr;
            si->pe_flags = IMAGE_SCN_MEM_READ;
          if (s->sh_flags & SHF_EXECINSTR)              si->pe_flags |= IMAGE_SCN_MEM_EXECUTE | IMAGE_SCN_CNT_CODE;
          else if (s->sh_type == SHT_NOBITS)              si->pe_flags |= IMAGE_SCN_CNT_UNINITIALIZED_DATA;
          else              si->pe_flags |= IMAGE_SCN_CNT_INITIALIZED_DATA;
          if (s->sh_flags & SHF_WRITE)              si->pe_flags |= IMAGE_SCN_MEM_WRITE;
          if (0 == (s->sh_flags & SHF_ALLOC))              si->pe_flags |= IMAGE_SCN_MEM_DISCARDABLE;
    add_section:          addr += s->data_offset;
          si->sh_size = addr - si->sh_addr;
          if (s->sh_type != SHT_NOBITS) {
              Section **ps = &si->sec;
              while (*ps)                  ps = &(*ps)->prev;
              *ps = s, s->prev = NULL;
              si->data_size = si->sh_size;

}          //printf("%08x %05x %08x %s\n", si->sh_addr, si->sh_size, si->pe_flags, s->name);

}  #if 0      for (i = 1;
 i < nbs;
 ++i) {
          Section *s = s1->sections[sec_order[i]];
          int type = s->sh_type;
          int flags = s->sh_flags;
          printf("section %-16s %-10s %p %04x %s,%s,%s\n",              s->name,              type == SHT_PROGBITS ? "progbits" :              type == SHT_INIT_ARRAY ? "initarr" :              type == SHT_FINI_ARRAY ? "finiarr" :              type == SHT_NOBITS ? "nobits" :              type == SHT_SYMTAB ? "symtab" :              type == SHT_STRTAB ? "strtab" :              type == SHT_RELX ? "rel" : "???",              s->sh_addr,              (unsigned)s->data_offset,              flags & SHF_ALLOC ? "alloc" : "",              flags & SHF_WRITE ? "write" : "",              flags & SHF_EXECINSTR ? "exec" : ""              );
          fflush(stdout);

}      s1->verbose = 2;
  #endif      tcc_free(sec_order);
      return 0;

}

static int pe_isafunc(TCCState *s1, int sym_index)  {
      Section *sr = text_section->reloc;
      ElfW_Rel *rel, *rel_end;
      ElfW(Addr)info = ELFW(R_INFO)(sym_index, R_XXX_FUNCCALL);
  #ifdef R_XXX_FUNCCALL2      ElfW(Addr)info2 = ELFW(R_INFO)(sym_index, R_XXX_FUNCCALL2);
  #endif      if (!sr)          return 0;
      rel_end = (ElfW_Rel *)(sr->data + sr->data_offset);
      for (rel = (ElfW_Rel *)sr->data;
 rel < rel_end;
 rel++) {
          if (rel->r_info == info)              return 1;
  #ifdef R_XXX_FUNCCALL2          if (rel->r_info == info2)              return 1;
  #endif      
}      return 0;

}

static int pe_check_symbols(struct pe_info *pe)  {
      ElfW(Sym) *sym;
      int sym_index, sym_end;
      int ret = 0;
      TCCState *s1 = pe->s1;
        pe_align_section(text_section, 8);
        sym_end = symtab_section->data_offset / sizeof(ElfW(Sym));
      for (sym_index = 1;
 sym_index < sym_end;
 ++sym_index) {
            sym = (ElfW(Sym) *)symtab_section->data + sym_index;
          if (sym->st_shndx == SHN_UNDEF) {
                const char *name = (char*)symtab_section->link->data + sym->st_name;
              unsigned type = ELFW(ST_TYPE)(sym->st_info);
              int imp_sym = pe_find_import(pe->s1, sym);
              struct import_symbol *is;
                if (imp_sym <= 0)                  goto not_found;
                if (type == STT_NOTYPE) {
                  /* symbols from assembler have no type, find out which */                  if (pe_isafunc(s1, sym_index))                      type = STT_FUNC;
                  else                      type = STT_OBJECT;

}                is = pe_add_import(pe, imp_sym);
                if (type == STT_FUNC) {
                  unsigned offset = is->thk_offset;
                  if (offset) {
                      /* got aliased symbol, like stricmp and _stricmp */                  
} else {
                      char buffer[100];
                      unsigned char *p;
                        /* add a helper symbol, will be patched later in                         pe_build_imports */                      sprintf(buffer, "IAT.%s", name);
                      is->iat_index = put_elf_sym(                          symtab_section, 0, sizeof(DWORD),                          ELFW(ST_INFO)(STB_LOCAL, STT_OBJECT),                          0, SHN_UNDEF, buffer);
                        offset = text_section->data_offset;
                      is->thk_offset = offset;
                        /* add the 'jmp IAT[x]' instruction */  #ifdef TCC_TARGET_ARM                      p = section_ptr_add(text_section, 8+4);
 // room for code and address                      write32le(p + 0, 0xE59FC000);
 // arm code ldr ip, [pc];
 PC+8+0 = 0001xxxx                      write32le(p + 4, 0xE59CF000);
 // arm code ldr pc, [ip]                      put_elf_reloc(symtab_section, text_section,                          offset + 8, R_XXX_THUNKFIX, is->iat_index);
 // offset to IAT position  #else                      p = section_ptr_add(text_section, 8);
                      write16le(p, 0x25FF);
  #ifdef TCC_TARGET_X86_64                      write32le(p + 2, (DWORD)-4);
  #endif                      put_elf_reloc(symtab_section, text_section,                           offset + 2, R_XXX_THUNKFIX, is->iat_index);
  #endif                  
}                  /* tcc_realloc might have altered sym's address */                  sym = (ElfW(Sym) *)symtab_section->data + sym_index;
                    /* patch the original symbol */                  sym->st_value = offset;
                  sym->st_shndx = text_section->sh_num;
                  sym->st_other &= ~ST_PE_EXPORT;
 /* do not export */                  continue;

}                if (type == STT_OBJECT) {
 /* data, ptr to that should be */                  if (0 == is->iat_index) {
                      /* original symbol will be patched later in pe_build_imports */                      is->iat_index = sym_index;
                      continue;

}              
}            not_found:              if (ELFW(ST_BIND)(sym->st_info) == STB_WEAK)                  /* STB_WEAK undefined symbols are accepted */                  continue;
              ret = tcc_error_noabort("undefined symbol '%s'%s", name,                  imp_sym < 0 ? ", missing __declspec(dllimport)?":"");

} else if (pe->s1->rdynamic                     && ELFW(ST_BIND)(sym->st_info) != STB_LOCAL) {
              /* if -rdynamic option, then export all non local symbols */              sym->st_other |= ST_PE_EXPORT;

}      
}      return ret;

}

ST_FUNC int pe_putimport(TCCState *s1, int dllindex, const char *name, addr_t value)  {
      return set_elf_sym(          s1->dynsymtab_section,          value,          dllindex, /* st_size */          ELFW(ST_INFO)(STB_GLOBAL, STT_NOTYPE),          0,          value ? SHN_ABS : SHN_UNDEF,          name          );

}

static int read_mem(int fd, unsigned offset, void *buffer, unsigned len)  {
      lseek(fd, offset, SEEK_SET);
      return len == read(fd, buffer, len);

}

static int get_dllexports(int fd, char **pp)  {
      int i, k, l, n, n0, ret;
      char *p;
        IMAGE_SECTION_HEADER ish;
      IMAGE_EXPORT_DIRECTORY ied;
      IMAGE_DOS_HEADER dh;
      IMAGE_FILE_HEADER ih;
      DWORD sig, ref, addr;
      DWORD *namep = NULL, p0 = 0, p1;
        int pef_hdroffset, opt_hdroffset, sec_hdroffset;
        n = n0 = 0;
      p = NULL;
      ret = 1;
      if (!read_mem(fd, 0, &dh, sizeof dh))          goto the_end;
      if (!read_mem(fd, dh.e_lfanew, &sig, sizeof sig))          goto the_end;
      if (sig != 0x00004550)          goto the_end;
      pef_hdroffset = dh.e_lfanew + sizeof sig;
      if (!read_mem(fd, pef_hdroffset, &ih, sizeof ih))          goto the_end;
      opt_hdroffset = pef_hdroffset + sizeof ih;
      if (ih.Machine == 0x014C) {
          IMAGE_OPTIONAL_HEADER32 oh;
          sec_hdroffset = opt_hdroffset + sizeof oh;
          if (!read_mem(fd, opt_hdroffset, &oh, sizeof oh))              goto the_end;
          if (IMAGE_DIRECTORY_ENTRY_EXPORT >= oh.NumberOfRvaAndSizes)              goto the_end_0;
          addr = oh.DataDirectory[IMAGE_DIRECTORY_ENTRY_EXPORT].VirtualAddress;

} else if (ih.Machine == 0x8664) {
          IMAGE_OPTIONAL_HEADER64 oh;
          sec_hdroffset = opt_hdroffset + sizeof oh;
          if (!read_mem(fd, opt_hdroffset, &oh, sizeof oh))              goto the_end;
          if (IMAGE_DIRECTORY_ENTRY_EXPORT >= oh.NumberOfRvaAndSizes)              goto the_end_0;
          addr = oh.DataDirectory[IMAGE_DIRECTORY_ENTRY_EXPORT].VirtualAddress;

} else          goto the_end;
        //printf("addr: %08x\n", addr);
      for (i = 0;
 i < ih.NumberOfSections;
 ++i) {
          if (!read_mem(fd, sec_hdroffset + i * sizeof ish, &ish, sizeof ish))              goto the_end;
          //printf("vaddr: %08x\n", ish.VirtualAddress);
          if (addr >= ish.VirtualAddress && addr < ish.VirtualAddress + ish.SizeOfRawData)              goto found;

}      goto the_end_0;
  found:      ref = ish.VirtualAddress - ish.PointerToRawData;
      if (!read_mem(fd, addr - ref, &ied, sizeof ied))          goto the_end;
      k = ied.NumberOfNames;
      if (k) {
          namep = tcc_malloc(l = k * sizeof *namep);
          if (!read_mem(fd, ied.AddressOfNames - ref, namep, l))              goto the_end;
          for (i = l = 0;
 i < k;
 ++i) {
              p1 = namep[i] - ref;
              if (p1 != p0)                  lseek(fd, p0 = p1, SEEK_SET), l = 0;
              do {
                  if (0 == l) {
                      if (n + 1000 >= n0)                          p = tcc_realloc(p, n0 += 1000);
                      if ((l = read(fd, p + n, 1000 - 1)) <= 0)                          goto the_end;

}                  --l, ++p0;

} while (p[n++]);

}          p[n] = 0;

}  the_end_0:      ret = 0;
  the_end:      tcc_free(namep);
      if (ret && p)          tcc_free(p), p = NULL;
      *pp = p;
      return ret;

}

static int pe_load_res(TCCState *s1, int fd)  {
      struct pe_rsrc_header hdr;
      Section *rsrc_section;
      int i, ret = -1, sym_index;
      BYTE *ptr;
      unsigned offs;
        if (!read_mem(fd, 0, &hdr, sizeof hdr))          goto quit;
        if (hdr.filehdr.Machine != IMAGE_FILE_MACHINE          || hdr.filehdr.NumberOfSections != 1          || strcmp((char*)hdr.sectionhdr.Name, ".rsrc") != 0)          goto quit;
        rsrc_section = new_section(s1, ".rsrc", SHT_PROGBITS, SHF_ALLOC);
      ptr = section_ptr_add(rsrc_section, hdr.sectionhdr.SizeOfRawData);
      offs = hdr.sectionhdr.PointerToRawData;
      if (!read_mem(fd, offs, ptr, hdr.sectionhdr.SizeOfRawData))          goto quit;
      offs = hdr.sectionhdr.PointerToRelocations;
      sym_index = put_elf_sym(symtab_section, 0, 0, 0, 0, rsrc_section->sh_num, ".rsrc");
      for (i = 0;
 i < hdr.sectionhdr.NumberOfRelocations;
 ++i) {
          struct pe_rsrc_reloc rel;
          if (!read_mem(fd, offs, &rel, sizeof rel))              goto quit;
          // printf("rsrc_reloc: %x %x %x\n", rel.offset, rel.size, rel.type);
          if (rel.type != RSRC_RELTYPE)              goto quit;
          put_elf_reloc(symtab_section, rsrc_section,              rel.offset, R_XXX_RELATIVE, sym_index);
          offs += sizeof rel;

}      ret = 0;
  quit:      return ret;

}

static char *trimfront(char *p)  {
      while ((unsigned char)*p <= ' ' && *p && *p != '\n')   ++p;
      return p;

}

static char *get_token(char **s, char *f)  {
      char *p = *s, *e;
      p = e = trimfront(p);
      while ((unsigned char)*e > ' ')          ++e;
      *s = trimfront(e);
      *f = **s;
 *e = 0;
      return p;

}

static int pe_load_def(TCCState *s1, int fd)  {
      int state = 0, ret = -1, dllindex = 0, ord;
      char dllname[80], *buf, *line, *p, *x, next;
        buf = tcc_load_text(fd);
      if (!buf)          return ret;
        for (line = buf;
;
 ++line)  {
          p = get_token(&line, &next);
          if (!(*p && *p != ';
'))              goto skip;
          switch (state) {
          case 0:              if (0 != stricmp(p, "LIBRARY") || next == '\n')                  goto quit;
              pstrcpy(dllname, sizeof dllname, get_token(&line, &next));
              ++state;
              break;
          case 1:              if (0 != stricmp(p, "EXPORTS"))                  goto quit;
              ++state;
              break;
          case 2:              dllindex = tcc_add_dllref(s1, dllname, 0)->index;
              ++state;
              /* fall through */          default:              /* get ordinal and will store in sym->st_value */              ord = 0;
              if (next == '@') {
                  x = get_token(&line, &next);
                  ord = (int)strtol(x + 1, &x, 10);

}              //printf("token %s;
 %s : %d\n", dllname, p, ord);
              pe_putimport(s1, dllindex, p, ord);
              break;

}  skip:          while ((unsigned char)next > ' ')              get_token(&line, &next);
          if (next != '\n')              break;

}      ret = 0;
  quit:      tcc_free(buf);
      return ret;

}

static int pe_load_dll(TCCState *s1, int fd, const char *filename)  {
      char *p, *q;
      DLLReference *ref = tcc_add_dllref(s1, tcc_basename(filename), 0);
      if (ref->found)          return 0;
      if (get_dllexports(fd, &p))          return -1;
      if (p) {
          for (q = p;
 *q;
 q += 1 + strlen(q))              pe_putimport(s1, ref->index, q, 0);
          tcc_free(p);

}      return 0;

}

ST_FUNC int pe_load_file(struct TCCState *s1, int fd, const char *filename)  {
      int ret = -1;
      char buf[10];
      if (0 == strcmp(tcc_fileextension(filename), ".def"))          ret = pe_load_def(s1, fd);
      else if (pe_load_res(s1, fd) == 0)          ret = 0;
      else if (read_mem(fd, 0, buf, 4) && 0 == memcmp(buf, "MZ", 2))          ret = pe_load_dll(s1, fd, filename);
      return ret;

}

PUB_FUNC int tcc_get_dllexports(const char *filename, char **pp)  {
      int ret, fd = open(filename, O_RDONLY | O_BINARY);
      if (fd < 0)          return -1;
      ret = get_dllexports(fd, pp);
      close(fd);
      return ret;

}

static void pe_add_runtime(TCCState *s1, struct pe_info *pe)  {
      const char *start_symbol;
      int pe_type;
        if (TCC_OUTPUT_DLL == s1->output_type) {
          pe_type = PE_DLL;
          start_symbol = PE_STDSYM("__dllstart","@12");

} else {
          const char *run_symbol;
          if (find_elf_sym(symtab_section, PE_STDSYM("WinMain","@16"))) {
              start_symbol = "__winstart";
              run_symbol = "__runwinmain";
              pe_type = PE_GUI;

} else if (find_elf_sym(symtab_section, PE_STDSYM("wWinMain","@16"))) {
              start_symbol = "__wwinstart";
              run_symbol = "__runwwinmain";
              pe_type = PE_GUI;

} else if (find_elf_sym(symtab_section, "wmain")) {
              start_symbol = "__wstart";
              run_symbol = "__runwmain";
              pe_type = PE_EXE;

} else {
              start_symbol =  "__start";
              run_symbol = "__runmain";
              pe_type = PE_EXE;
              if (s1->pe_subsystem == 2)                  pe_type = PE_GUI;

}            if (TCC_OUTPUT_MEMORY == s1->output_type && !s1->nostdlib)              start_symbol = run_symbol;

}      if (s1->elf_entryname) {
          pe->start_symbol = start_symbol = s1->elf_entryname;

} else {
          pe->start_symbol = start_symbol + 1;
          if (!s1->leading_underscore || strchr(start_symbol, '@'))              ++start_symbol;

}    #ifdef CONFIG_TCC_BACKTRACE      if (s1->do_backtrace) {
  #ifdef CONFIG_TCC_BCHECK          if (s1->do_bounds_check && s1->output_type != TCC_OUTPUT_DLL)              tcc_add_support(s1, "bcheck.o");
  #endif          if (s1->output_type == TCC_OUTPUT_EXE)              tcc_add_support(s1, "bt-exe.o");
          if (s1->output_type == TCC_OUTPUT_DLL)              tcc_add_support(s1, "bt-dll.o");
          if (s1->output_type != TCC_OUTPUT_DLL)              tcc_add_support(s1, "bt-log.o");
          tcc_add_btstub(s1);

