static void cstr_realloc(CString *cstr, int new_size)  {
      int size;
        size = cstr->size_allocated;
      if (size < 8)          size = 8;
 /* no need to allocate a too small first string */      while (size < new_size)          size = size * 2;
      cstr->data = tcc_realloc(cstr->data, size);
      cstr->size_allocated = size;

}

ST_INLN void cstr_ccat(CString *cstr, int ch)  {
      int size;
      size = cstr->size + 1;
      if (size > cstr->size_allocated)          cstr_realloc(cstr, size);
      cstr->data[size - 1] = ch;
      cstr->size = size;

}

ST_INLN char *unicode_to_utf8 (char *b, uint32_t Uc)  {
      if (Uc<0x80) *b++=Uc;
      else if (Uc<0x800) *b++=192+Uc/64, *b++=128+Uc%64;
      else if (Uc-0xd800u<0x800) goto error;
      else if (Uc<0x10000) *b++=224+Uc/4096, *b++=128+Uc/64%64, *b++=128+Uc%64;
      else if (Uc<0x110000) *b++=240+Uc/262144, *b++=128+Uc/4096%64, *b++=128+Uc/64%64, *b++=128+Uc%64;
      else error: tcc_error("0x%x is not a valid universal character", Uc);
      return b;

}

ST_INLN void cstr_u8cat(CString *cstr, int ch)  {
      char buf[4], *e;
      e = unicode_to_utf8(buf, (uint32_t)ch);
      cstr_cat(cstr, buf, e - buf);

}

ST_FUNC void cstr_cat(CString *cstr, const char *str, int len)  {
      int size;
      if (len <= 0)          len = strlen(str) + 1 + len;
      size = cstr->size + len;
      if (size > cstr->size_allocated)          cstr_realloc(cstr, size);
      memmove(cstr->data + cstr->size, str, len);
      cstr->size = size;

}

ST_FUNC void cstr_wccat(CString *cstr, int ch)  {
      int size;
      size = cstr->size + sizeof(nwchar_t);
      if (size > cstr->size_allocated)          cstr_realloc(cstr, size);
      *(nwchar_t *)(cstr->data + size - sizeof(nwchar_t)) = ch;
      cstr->size = size;

}

ST_FUNC void cstr_new(CString *cstr)  {
      memset(cstr, 0, sizeof(CString));

}

ST_FUNC void cstr_free(CString *cstr)  {
      tcc_free(cstr->data);

}

ST_FUNC void cstr_reset(CString *cstr)  {
      cstr->size = 0;

}

ST_FUNC int cstr_vprintf(CString *cstr, const char *fmt, va_list ap)  {
      va_list v;
      int len, size = 80;
      for (;
;
) {
          size += cstr->size;
          if (size > cstr->size_allocated)              cstr_realloc(cstr, size);
          size = cstr->size_allocated - cstr->size;
          va_copy(v, ap);
          len = vsnprintf(cstr->data + cstr->size, size, fmt, v);
          va_end(v);
          if (len >= 0 && len < size)              break;
          size *= 2;

}      cstr->size += len;
      return len;

}

ST_FUNC int cstr_printf(CString *cstr, const char *fmt, ...)  {
      va_list ap;
 int len;
      va_start(ap, fmt);
      len = cstr_vprintf(cstr, fmt, ap);
      va_end(ap);
      return len;

}

static void add_char(CString *cstr, int c)  {
      if (c == '\'' || c == '\"' || c == '\\') {
          /* XXX: could be more precise if char or string */          cstr_ccat(cstr, '\\');

}      if (c >= 32 && c <= 126) {
          cstr_ccat(cstr, c);

} else {
          cstr_ccat(cstr, '\\');
          if (c == '\n') {
              cstr_ccat(cstr, 'n');

} else {
              cstr_ccat(cstr, '0' + ((c >> 6) & 7));
              cstr_ccat(cstr, '0' + ((c >> 3) & 7));
              cstr_ccat(cstr, '0' + (c & 7));

}      
}  
}

static TokenSym *tok_alloc_new(TokenSym **pts, const char *str, int len)  {
      TokenSym *ts, **ptable;
      int i;
        if (tok_ident >= SYM_FIRST_ANOM)           tcc_error("memory full (symbols)");
        /* expand token table if needed */      i = tok_ident - TOK_IDENT;
      if ((i % TOK_ALLOC_INCR) == 0) {
          ptable = tcc_realloc(table_ident, (i + TOK_ALLOC_INCR) * sizeof(TokenSym *));
          table_ident = ptable;

}        ts = tal_realloc(toksym_alloc, 0, sizeof(TokenSym) + len);
      table_ident[i] = ts;
      ts->tok = tok_ident++;
      ts->sym_define = NULL;
      ts->sym_label = NULL;
      ts->sym_struct = NULL;
      ts->sym_identifier = NULL;
      ts->len = len;
      ts->hash_next = NULL;
      memcpy(ts->str, str, len);
      ts->str[len] = '\0';
      *pts = ts;
      return ts;

}

ST_FUNC TokenSym *tok_alloc(const char *str, int len)  {
      TokenSym *ts, **pts;
      int i;
      unsigned int h;
            h = TOK_HASH_INIT;
      for(i=0;
i<len;
i++)          h = TOK_HASH_FUNC(h, ((unsigned char *)str)[i]);
      h &= (TOK_HASH_SIZE - 1);
        pts = &hash_ident[h];
      for(;
;
) {
          ts = *pts;
          if (!ts)              break;
          if (ts->len == len && !memcmp(ts->str, str, len))              return ts;
          pts = &(ts->hash_next);

}      return tok_alloc_new(pts, str, len);

}

ST_FUNC int tok_alloc_const(const char *str)  {
      return tok_alloc(str, strlen(str))->tok;

}

ST_FUNC const char *get_tok_str(int v, CValue *cv)  {
      char *p;
      int i, len;
        cstr_reset(&cstr_buf);
      p = cstr_buf.data;
        switch(v) {
      case TOK_CINT:      case TOK_CUINT:      case TOK_CLONG:      case TOK_CULONG:      case TOK_CLLONG:      case TOK_CULLONG:          /* XXX: not quite exact, but only useful for testing  */  #ifdef _WIN32          sprintf(p, "%u", (unsigned)cv->i);
  #else          sprintf(p, "%llu", (unsigned long long)cv->i);
  #endif          break;
      case TOK_LCHAR:          cstr_ccat(&cstr_buf, 'L');
      case TOK_CCHAR:          cstr_ccat(&cstr_buf, '\'');
          add_char(&cstr_buf, cv->i);
          cstr_ccat(&cstr_buf, '\'');
          cstr_ccat(&cstr_buf, '\0');
          break;
      case TOK_PPNUM:      case TOK_PPSTR:          return (char*)cv->str.data;
      case TOK_LSTR:          cstr_ccat(&cstr_buf, 'L');
      case TOK_STR:          cstr_ccat(&cstr_buf, '\"');
          if (v == TOK_STR) {
              len = cv->str.size - 1;
              for(i=0;
i<len;
i++)                  add_char(&cstr_buf, ((unsigned char *)cv->str.data)[i]);

} else {
              len = (cv->str.size / sizeof(nwchar_t)) - 1;
              for(i=0;
i<len;
i++)                  add_char(&cstr_buf, ((nwchar_t *)cv->str.data)[i]);

}          cstr_ccat(&cstr_buf, '\"');
          cstr_ccat(&cstr_buf, '\0');
          break;
        case TOK_CFLOAT:          return strcpy(p, "<float>");
      case TOK_CDOUBLE:          return strcpy(p, "<double>");
      case TOK_CLDOUBLE:          return strcpy(p, "<long double>");
      case TOK_LINENUM:          return strcpy(p, "<linenumber>");
        /* above tokens have value, the ones below don't */      case TOK_LT:          v = '<';
          goto addv;
      case TOK_GT:          v = '>';
          goto addv;
      case TOK_DOTS:          return strcpy(p, "...");
      case TOK_A_SHL:          return strcpy(p, "<<=");
      case TOK_A_SAR:          return strcpy(p, ">>=");
      case TOK_EOF:          return strcpy(p, "<eof>");
      case 0: /* anonymous nameless symbols */          return strcpy(p, "<no name>");
      default:          v &= ~(SYM_FIELD | SYM_STRUCT);
          if (v < TOK_IDENT) {
              /* search in two bytes table */              const unsigned char *q = tok_two_chars;
              while (*q) {
                  if (q[2] == v) {
                      *p++ = q[0];
                      *p++ = q[1];
                      *p = '\0';
                      return cstr_buf.data;

}                  q += 3;

}              if (v >= 127 || (v < 32 && !is_space(v) && v != '\n')) {
                  sprintf(p, "<\\x%02x>", v);
                  break;

}      addv:              *p++ = v;
              *p = '\0';

} else if (v < tok_ident) {
              return table_ident[v - TOK_IDENT]->str;

} else if (v >= SYM_FIRST_ANOM) {
              /* special name for anonymous symbol */              sprintf(p, "L.%u", v - SYM_FIRST_ANOM);

} else {
              /* should never happen */              return NULL;

}          break;

}      return cstr_buf.data;

}

static int handle_eob(void)  {
      BufferedFile *bf = file;
      int len;
        /* only tries to read if really end of buffer */      if (bf->buf_ptr >= bf->buf_end) {
          if (bf->fd >= 0) {
  #if defined(PARSE_DEBUG)              len = 1;
  #else              len = IO_BUF_SIZE;
  #endif              len = read(bf->fd, bf->buffer, len);
              if (len < 0)                  len = 0;

} else {
              len = 0;

}          total_bytes += len;
          bf->buf_ptr = bf->buffer;
          bf->buf_end = bf->buffer + len;
          *bf->buf_end = CH_EOB;

}      if (bf->buf_ptr < bf->buf_end) {
          return bf->buf_ptr[0];

} else {
          bf->buf_ptr = bf->buf_end;
          return CH_EOF;

}  
}

static int next_c(void)  {
      int ch = *++file->buf_ptr;
      /* end of buffer/file handling */      if (ch == CH_EOB && file->buf_ptr >= file->buf_end)          ch = handle_eob();
      return ch;

}

static int handle_stray_noerror(int err)  {
      int ch;
      while ((ch = next_c()) == '\\') {
          ch = next_c();
          if (ch == '\n') {
      newl:              file->line_num++;

} else {
              if (ch == '\r') {
                  ch = next_c();
                  if (ch == '\n')                      goto newl;
                  *--file->buf_ptr = '\r';

}              if (err)                  tcc_error("stray '\\' in program");
              /* may take advantage of 'BufferedFile.unget[4
}' */              return *--file->buf_ptr = '\\';

}      
}      return ch;

}

static int handle_bs(uint8_t **p)  {
      int c;
      file->buf_ptr = *p - 1;
      c = ninp();
      *p = file->buf_ptr;
      return c;

}

static int handle_stray(uint8_t **p)  {
      int c;
      file->buf_ptr = *p - 1;
      c = handle_stray_noerror(!(parse_flags & PARSE_FLAG_ACCEPT_STRAYS));
      *p = file->buf_ptr;
      return c;

}

static int skip_spaces(void)  {
      int ch;
      --file->buf_ptr;
      do {
          ch = ninp();

} while (isidnum_table[ch - CH_EOF] & IS_SPC);
      return ch;

}

static uint8_t *parse_line_comment(uint8_t *p)  {
      int c;
      for(;
;
) {
          for (;
;
) {
              c = *++p;
      redo:              if (c == '\n' || c == '\\')                  break;
              c = *++p;
              if (c == '\n' || c == '\\')                  break;

}          if (c == '\n')              break;
          c = handle_bs(&p);
          if (c == CH_EOF)              break;
          if (c != '\\')              goto redo;

}      return p;

}

static uint8_t *parse_comment(uint8_t *p)  {
      int c;
      for(;
;
) {
          /* fast skip loop */          for(;
;
) {
              c = *++p;
          redo:              if (c == '\n' || c == '*' || c == '\\')                  break;
              c = *++p;
              if (c == '\n' || c == '*' || c == '\\')                  break;

}          /* now we can handle all the cases */          if (c == '\n') {
              file->line_num++;

} else if (c == '*') {
              do {
                  c = *++p;

} while (c == '*');
              if (c == '\\')                  c = handle_bs(&p);
              if (c == '/')                  break;
              goto check_eof;

} else {
              c = handle_bs(&p);
          check_eof:              if (c == CH_EOF)                  tcc_error("unexpected end of file in comment");
              if (c != '\\')                  goto redo;

}      
}      return p + 1;

}

static uint8_t *parse_pp_string(uint8_t *p, int sep, CString *str)  {
      int c;
      for(;
;
) {
          c = *++p;
      redo:          if (c == sep) {
              break;

} else if (c == '\\') {
              c = handle_bs(&p);
              if (c == CH_EOF) {
          unterminated_string:                  /* XXX: indicate line number of start of string */                  tok_flags &= ~TOK_FLAG_BOL;
                  tcc_error("missing terminating %c character", sep);

} else if (c == '\\') {
                  if (str)                      cstr_ccat(str, c);
                  c = *++p;
                  /* add char after '\\' unconditionally */                  if (c == '\\') {
                      c = handle_bs(&p);
                      if (c == CH_EOF)                          goto unterminated_string;

}                  goto add_char;

} else {
                  goto redo;

}          
} else if (c == '\n') {
          add_lf:              if (ACCEPT_LF_IN_STRINGS) {
                  file->line_num++;
                  goto add_char;

} else if (str) {
 /* not skipping */                  goto unterminated_string;

} else {
                  //tcc_warning("missing terminating %c character", sep);
                  return p;

}          
} else if (c == '\r') {
              c = *++p;
              if (c == '\\')                  c = handle_bs(&p);
              if (c == '\n')                  goto add_lf;
              if (c == CH_EOF)                  goto unterminated_string;
              if (str)                  cstr_ccat(str, '\r');
              goto redo;

} else {
          add_char:              if (str)                  cstr_ccat(str, c);

}      
}      p++;
      return p;

}

static void preprocess_skip(void)  {
      int a, start_of_line, c, in_warn_or_error;
      uint8_t *p;
        p = file->buf_ptr;
      a = 0;
  redo_start:      start_of_line = 1;
      in_warn_or_error = 0;
      for(;
;
) {
          c = *p;
          switch(c) {
          case ' ':          case '\t':          case '\f':          case '\v':          case '\r':              p++;
              continue;
          case '\n':              file->line_num++;
              p++;
              goto redo_start;
          case '\\':              c = handle_bs(&p);
              if (c == CH_EOF)                  expect("#endif");
              if (c == '\\')                  ++p;
              continue;
          /* skip strings */          case '\"':          case '\'':              if (in_warn_or_error)                  goto _default;
              tok_flags &= ~TOK_FLAG_BOL;
              p = parse_pp_string(p, c, NULL);
              break;
          /* skip comments */          case '/':              if (in_warn_or_error)                  goto _default;
              ++p;
              c = handle_bs(&p);
              if (c == '*') {
                  p = parse_comment(p);

} else if (c == '/') {
                  p = parse_line_comment(p);

}              continue;
          case '#':              p++;
