                  file->buf_ptr = p;
                  next_nomacro();
                  p = file->buf_ptr;
                  if (a == 0 &&                       (tok == TOK_ELSE || tok == TOK_ELIF || tok == TOK_ENDIF))                      goto the_end;
                  if (tok == TOK_IF || tok == TOK_IFDEF || tok == TOK_IFNDEF)                      a++;
                  else if (tok == TOK_ENDIF)                      a--;
                  else if( tok == TOK_ERROR || tok == TOK_WARNING)                      in_warn_or_error = 1;
                  else if (tok == TOK_LINEFEED)                      goto redo_start;
                  else if (parse_flags & PARSE_FLAG_ASM_FILE)                      p = parse_line_comment(p - 1);

}  #if !defined(TCC_TARGET_ARM)              else if (parse_flags & PARSE_FLAG_ASM_FILE)                  p = parse_line_comment(p - 1);
  #else              /* ARM assembly uses '#' for constants */  #endif              break;
  _default:          default:              p++;
              break;

}          start_of_line = 0;

}   the_end:;
      file->buf_ptr = p;

}

ST_INLN void tok_str_new(TokenString *s)  {
      s->str = NULL;
      s->len = s->need_spc = 0;
      s->allocated_len = 0;
      s->last_line_num = -1;

}

ST_FUNC TokenString *tok_str_alloc(void)  {
      TokenString *str = tal_realloc(tokstr_alloc, 0, sizeof *str);
      tok_str_new(str);
      return str;

}

ST_FUNC void tok_str_free_str(int *str)  {
      tal_free(tokstr_alloc, str);

}

ST_FUNC void tok_str_free(TokenString *str)  {
      tok_str_free_str(str->str);
      tal_free(tokstr_alloc, str);

}

ST_FUNC int *tok_str_realloc(TokenString *s, int new_size)  {
      int *str, size;
        size = s->allocated_len;
      if (size < 16)          size = 16;
      while (size < new_size)          size = size * 2;
      if (size > s->allocated_len) {
          str = tal_realloc(tokstr_alloc, s->str, size * sizeof(int));
          s->allocated_len = size;
          s->str = str;

}      return s->str;

}

ST_FUNC void tok_str_add(TokenString *s, int t)  {
      int len, *str;
        len = s->len;
      str = s->str;
      if (len >= s->allocated_len)          str = tok_str_realloc(s, len + 1);
      str[len++] = t;
      s->len = len;

}

ST_FUNC void begin_macro(TokenString *str, int alloc)  {
      str->alloc = alloc;
      str->prev = macro_stack;
      str->prev_ptr = macro_ptr;
      str->save_line_num = file->line_num;
      macro_ptr = str->str;
      macro_stack = str;

}

ST_FUNC void end_macro(void)  {
      TokenString *str = macro_stack;
      macro_stack = str->prev;
      macro_ptr = str->prev_ptr;
      file->line_num = str->save_line_num;
      if (str->alloc == 0) {
          /* matters if str not alloced, may be tokstr_buf */          str->len = str->need_spc = 0;

} else {
          if (str->alloc == 2)              str->str = NULL;
 /* don't free */          tok_str_free(str);

}  
}

static void tok_str_add2(TokenString *s, int t, CValue *cv)  {
      int len, *str;
        len = s->len;
      str = s->str;
        /* allocate space for worst case */      if (len + TOK_MAX_SIZE >= s->allocated_len)          str = tok_str_realloc(s, len + TOK_MAX_SIZE + 1);
      str[len++] = t;
      switch(t) {
      case TOK_CINT:      case TOK_CUINT:      case TOK_CCHAR:      case TOK_LCHAR:      case TOK_CFLOAT:      case TOK_LINENUM:  #if LONG_SIZE == 4      case TOK_CLONG:      case TOK_CULONG:  #endif          str[len++] = cv->tab[0];
          break;
      case TOK_PPNUM:      case TOK_PPSTR:      case TOK_STR:      case TOK_LSTR:          {
              /* Insert the string into the int array. */              size_t nb_words =                  1 + (cv->str.size + sizeof(int) - 1) / sizeof(int);
              if (len + nb_words >= s->allocated_len)                  str = tok_str_realloc(s, len + nb_words + 1);
              str[len] = cv->str.size;
              memcpy(&str[len + 1], cv->str.data, cv->str.size);
              len += nb_words;

}          break;
      case TOK_CDOUBLE:      case TOK_CLLONG:      case TOK_CULLONG:  #if LONG_SIZE == 8      case TOK_CLONG:      case TOK_CULONG:  #endif          str[len++] = cv->tab[0];
          str[len++] = cv->tab[1];
          break;
      case TOK_CLDOUBLE:  #if LDOUBLE_SIZE == 8 || defined TCC_USING_DOUBLE_FOR_LDOUBLE          str[len++] = cv->tab[0];
          str[len++] = cv->tab[1];
  #elif LDOUBLE_SIZE == 12          str[len++] = cv->tab[0];
          str[len++] = cv->tab[1];
          str[len++] = cv->tab[2];
  #elif LDOUBLE_SIZE == 16          str[len++] = cv->tab[0];
          str[len++] = cv->tab[1];
          str[len++] = cv->tab[2];
          str[len++] = cv->tab[3];
  #else  #error add long double size support  #endif          break;
      default:          break;

}      s->len = len;

}

ST_FUNC void tok_str_add_tok(TokenString *s)  {
      CValue cval;
        /* save line number info */      if (file->line_num != s->last_line_num) {
          s->last_line_num = file->line_num;
          cval.i = s->last_line_num;
          tok_str_add2(s, TOK_LINENUM, &cval);

}      tok_str_add2(s, tok, &tokc);

}

static void tok_str_add2_spc(TokenString *s, int t, CValue *cv)  {
      if (s->need_spc == 3)          tok_str_add(s, ' ');
      s->need_spc = 2;
      tok_str_add2(s, t, cv);

}

static inline void tok_get(int *t, const int **pp, CValue *cv)  {
      const int *p = *pp;
      int n, *tab;
        tab = cv->tab;
      switch(*t = *p++) {
  #if LONG_SIZE == 4      case TOK_CLONG:  #endif      case TOK_CINT:      case TOK_CCHAR:      case TOK_LCHAR:      case TOK_LINENUM:          cv->i = *p++;
          break;
  #if LONG_SIZE == 4      case TOK_CULONG:  #endif      case TOK_CUINT:          cv->i = (unsigned)*p++;
          break;
      case TOK_CFLOAT:   tab[0] = *p++;
   break;
      case TOK_STR:      case TOK_LSTR:      case TOK_PPNUM:      case TOK_PPSTR:          cv->str.size = *p++;
          cv->str.data = (char*)p;
          p += (cv->str.size + sizeof(int) - 1) / sizeof(int);
          break;
      case TOK_CDOUBLE:      case TOK_CLLONG:      case TOK_CULLONG:  #if LONG_SIZE == 8      case TOK_CLONG:      case TOK_CULONG:  #endif          n = 2;
          goto copy;
      case TOK_CLDOUBLE:  #if LDOUBLE_SIZE == 8 || defined TCC_USING_DOUBLE_FOR_LDOUBLE          n = 2;
  #elif LDOUBLE_SIZE == 12          n = 3;
  #elif LDOUBLE_SIZE == 16          n = 4;
  #else  # error add long double size support  #endif      copy:          do              *tab++ = *p++;
          while (--n);
          break;
      default:          break;

}      *pp = p;

}

static int macro_is_equal(const int *a, const int *b)  {
      CValue cv;
      int t;
        if (!a || !b)          return 1;
        while (*a && *b) {
          cstr_reset(&tokcstr);
          TOK_GET(&t, &a, &cv);
          cstr_cat(&tokcstr, get_tok_str(t, &cv), 0);
          TOK_GET(&t, &b, &cv);
          if (strcmp(tokcstr.data, get_tok_str(t, &cv)))              return 0;

}      return !(*a || *b);

}

ST_INLN void define_push(int v, int macro_type, int *str, Sym *first_arg)  {
      Sym *s, *o;
        o = define_find(v);
      s = sym_push2(&define_stack, v, macro_type, 0);
      s->d = str;
      s->next = first_arg;
      table_ident[v - TOK_IDENT]->sym_define = s;
        if (o && !macro_is_equal(o->d, s->d))   tcc_warning("%s redefined", get_tok_str(v, NULL));

}

ST_FUNC void define_undef(Sym *s)  {
      int v = s->v;
      if (v >= TOK_IDENT && v < tok_ident)          table_ident[v - TOK_IDENT]->sym_define = NULL;

}

ST_INLN Sym *define_find(int v)  {
      v -= TOK_IDENT;
      if ((unsigned)v >= (unsigned)(tok_ident - TOK_IDENT))          return NULL;
      return table_ident[v]->sym_define;

}

ST_FUNC void free_defines(Sym *b)  {
      while (define_stack != b) {
          Sym *top = define_stack;
          define_stack = top->prev;
          tok_str_free_str(top->d);
          define_undef(top);
          sym_free(top);

}  
}

static void maybe_run_test(TCCState *s)  {
      const char *p;
      if (s->include_stack_ptr != s->include_stack)          return;
      p = get_tok_str(tok, NULL);
      if (0 != memcmp(p, "test_", 5))          return;
      if (0 != --s->run_test)          return;
      fprintf(s->ppfp, &"\n[%s]\n"[!(s->dflag & 32)], p), fflush(s->ppfp);
      define_push(tok, MACRO_OBJ, NULL, NULL);

}

ST_FUNC void skip_to_eol(int warn)  {
      if (tok == TOK_LINEFEED)          return;
      if (warn)          tcc_warning("extra tokens after directive");
      file->buf_ptr = parse_line_comment(file->buf_ptr - 1);
      tok = TOK_LINEFEED;

}

static int parse_include(TCCState *s1, int do_next, int test)  {
      int c, i;
      char name[1024], buf[1024], *p;
      CachedInclude *e;
        c = skip_spaces();
      if (c == '<' || c == '\"') {
          cstr_reset(&tokcstr);
          file->buf_ptr = parse_pp_string(file->buf_ptr, c == '<' ? '>' : c, &tokcstr);
          i = tokcstr.size;
          pstrncpy(name, tokcstr.data, i >= sizeof name ? sizeof name - 1 : i);
          next_nomacro();

} else {
          /* computed #include : concatenate tokens until result is one of             the two accepted forms.  Don't convert pp-tokens to tokens here. */   parse_flags = PARSE_FLAG_PREPROCESS                      | PARSE_FLAG_LINEFEED                      | (parse_flags & PARSE_FLAG_ASM_FILE);
          name[0] = 0;
          for (;
;
) {
              next();
              p = name, i = strlen(p) - 1;
              if (i > 0                  && ((p[0] == '"' && p[i] == '"')                   || (p[0] == '<' && p[i] == '>')))                  break;
              if (tok == TOK_LINEFEED)                  tcc_error("'#include' expects \"FILENAME\" or <FILENAME>");
              pstrcat(name, sizeof name, get_tok_str(tok, &tokc));

}          c = p[0];
          /* remove '<>|""' */          memmove(p, p + 1, i - 1), p[i - 1] = 0;

}        if (!test)          skip_to_eol(1);
        i = do_next ? file->include_next_index : -1;
      for (;
;
) {
          ++i;
          if (i == 0) {
              /* check absolute include path */              if (!IS_ABSPATH(name))                  continue;
              buf[0] = '\0';

} else if (i == 1) {
              /* search in file's dir if "header.h" */              if (c != '\"')                  continue;
              p = file->true_filename;
              pstrncpy(buf, p, tcc_basename(p) - p);

} else {
              int j = i - 2, k = j - s1->nb_include_paths;
              if (k < 0)                  p = s1->include_paths[j];
              else if (k < s1->nb_sysinclude_paths)                  p = s1->sysinclude_paths[k];
              else if (test)                  return 0;
              else                  tcc_error("include file '%s' not found", name);
              pstrcpy(buf, sizeof buf, p);
              pstrcat(buf, sizeof buf, "/");

}          pstrcat(buf, sizeof buf, name);
          e = search_cached_include(s1, buf, 0);
          if (e && (define_find(e->ifndef_macro) || e->once)) {
              /* no need to parse the include because the 'ifndef macro'                 is defined (or had #pragma once) */  #ifdef INC_DEBUG              printf("%s: skipping cached %s\n", file->filename, buf);
  #endif              return 1;

}          if (tcc_open(s1, buf) >= 0)              break;

}        if (test) {
          tcc_close();

} else {
          if (s1->include_stack_ptr >= s1->include_stack + INCLUDE_STACK_SIZE)              tcc_error("#include recursion too deep");
          /* push previous file on stack */          *s1->include_stack_ptr++ = file->prev;
          file->include_next_index = i;
  #ifdef INC_DEBUG          printf("%s: including %s\n", file->prev->filename, file->filename);
  #endif          /* update target deps */          if (s1->gen_deps) {
              BufferedFile *bf = file;
              while (i == 1 && (bf = bf->prev))                  i = bf->include_next_index;
              /* skip system include files */              if (s1->include_sys_deps || i - 2 < s1->nb_include_paths)                  dynarray_add(&s1->target_deps, &s1->nb_target_deps,                      tcc_strdup(buf));

}          /* add include file debug info */          tcc_debug_bincl(s1);

}      return 1;

}

static int expr_preprocess(TCCState *s1)  {
      int c, t;
      int t0 = tok;
      TokenString *str;
            str = tok_str_alloc();
      pp_expr = 1;
      while (1) {
          next();
 /* do macro subst */          t = tok;
          if (tok < TOK_IDENT) {
              if (tok == TOK_LINEFEED || tok == TOK_EOF)                  break;
              if (tok >= TOK_STR && tok <= TOK_CLDOUBLE)                  tcc_error("invalid constant in preprocessor expression");

} else if (tok == TOK_DEFINED) {
              parse_flags &= ~PARSE_FLAG_PREPROCESS;
 /* no macro subst */              next();
              t = tok;
              if (t == '(')                   next();
              parse_flags |= PARSE_FLAG_PREPROCESS;
              if (tok < TOK_IDENT)                  expect("identifier after 'defined'");
              if (s1->run_test)                  maybe_run_test(s1);
              c = 0;
              if (define_find(tok)                  || tok == TOK___HAS_INCLUDE                  || tok == TOK___HAS_INCLUDE_NEXT)                  c = 1;
              if (t == '(') {
                  next();
                  if (tok != ')')                      expect("')'");

}              tok = TOK_CINT;
              tokc.i = c;

} else if (tok == TOK___HAS_INCLUDE ||                     tok == TOK___HAS_INCLUDE_NEXT) {
              t = tok;
              next();
       if (tok != '(')    expect("'('");
              c = parse_include(s1, t - TOK___HAS_INCLUDE, 1);
              if (tok != ')')                  expect("')'");
              tok = TOK_CINT;
              tokc.i = c;

} else {
              /* if undefined macro, replace with zero */              tok = TOK_CINT;
              tokc.i = 0;

}          tok_str_add_tok(str);

}      if (0 == str->len)          tcc_error("#%s with no expression", get_tok_str(t0, 0));
      tok_str_add(str, TOK_EOF);
 /* simulate end of file */      pp_expr = t0;
 /* redirect pre-processor expression error messages */      t = tok;
      /* now evaluate C constant expression */      begin_macro(str, 1);
      next();
      c = expr_const();
      if (tok != TOK_EOF)          tcc_error("...");
      pp_expr = 0;
      end_macro();
      tok = t;
 /* restore LF or EOF */      return c != 0;

}

ST_FUNC void pp_error(CString *cs)  {
      cstr_printf(cs, "bad preprocessor expression: #%s", get_tok_str(pp_expr, 0));
      macro_ptr = macro_stack->str;
      while (next(), tok != TOK_EOF)          cstr_printf(cs, " %s", get_tok_str(tok, &tokc));

}

ST_FUNC void parse_define(void)  {
      Sym *s, *first, **ps;
      int v, t, varg, is_vaargs, t0;
      int saved_parse_flags = parse_flags;
      TokenString str;
        v = tok;
      if (v < TOK_IDENT || v == TOK_DEFINED)          tcc_error("invalid macro name '%s'", get_tok_str(tok, &tokc));
      first = NULL;
      t = MACRO_OBJ;
      /* We have to parse the whole define as if not in asm mode, in particular         no line comment with '#' must be ignored.  Also for function         macros the argument list must be parsed without '.' being an ID         character.  */      parse_flags = ((parse_flags & ~PARSE_FLAG_ASM_FILE) | PARSE_FLAG_SPACES);
      /* '(' must be just after macro definition for MACRO_FUNC */      next_nomacro();
      parse_flags &= ~PARSE_FLAG_SPACES;
      is_vaargs = 0;
      if (tok == '(') {
          int dotid = set_idnum('.', 0);
          next_nomacro();
          ps = &first;
          if (tok != ')') for (;
;
) {
              varg = tok;
              next_nomacro();
              is_vaargs = 0;
              if (varg == TOK_DOTS) {
                  varg = TOK___VA_ARGS__;
                  is_vaargs = 1;

} else if (tok == TOK_DOTS && gnu_ext) {
                  is_vaargs = 1;
                  next_nomacro();

}              if (varg < TOK_IDENT)          bad_list:                  tcc_error("bad macro parameter list");
              s = sym_push2(&define_stack, varg | SYM_FIELD, is_vaargs, 0);
              *ps = s;
              ps = &s->next;
              if (tok == ')')                  break;
              if (tok != ',' || is_vaargs)                  goto bad_list;
              next_nomacro();

}          parse_flags |= PARSE_FLAG_SPACES;
          next_nomacro();
          t = MACRO_FUNC;
          set_idnum('.', dotid);

}        /* The body of a macro definition should be parsed such that identifiers         are parsed like the file mode determines (i.e. with '.' being an         ID character in asm mode).  But '#' should be retained instead of         regarded as line comment leader, so still don't set ASM_FILE         in parse_flags. */      parse_flags |= PARSE_FLAG_ACCEPT_STRAYS | PARSE_FLAG_SPACES | PARSE_FLAG_LINEFEED;
      tok_str_new(&str);
      t0 = 0;
      while (tok != TOK_LINEFEED && tok != TOK_EOF) {
          if (is_space(tok)) {
              str.need_spc |= 1;

} else {
              if (TOK_TWOSHARPS == tok) {
                  if (0 == t0)                      goto bad_twosharp;
                  tok = TOK_PPJOIN;
                  t |= MACRO_JOIN;

}              tok_str_add2_spc(&str, tok, &tokc);
              t0 = tok;

}          next_nomacro();

}      parse_flags = saved_parse_flags;
      tok_str_add(&str, 0);
      if (t0 == TOK_PPJOIN)  bad_twosharp:          tcc_error("'##' cannot appear at either end of macro");
      define_push(v, t, str.str, first);
      //tok_print(str.str, "#define (%d) %s %d:", t | is_vaargs * 4, get_tok_str(v, 0));

}

static CachedInclude *search_cached_include(TCCState *s1, const char *filename, int add)  {
      const char *s, *basename;
      unsigned int h;
      CachedInclude *e;
      int c, i, len;
        s = basename = tcc_basename(filename);
      h = TOK_HASH_INIT;
      while ((c = (unsigned char)*s) != 0) {
  #ifdef _WIN32          h = TOK_HASH_FUNC(h, toup(c));
  #else          h = TOK_HASH_FUNC(h, c);
  #endif          s++;

}      h &= (CACHED_INCLUDES_HASH_SIZE - 1);
        i = s1->cached_includes_hash[h];
      for(;
;
) {
          if (i == 0)              break;
          e = s1->cached_includes[i - 1];
          if (0 == PATHCMP(filename, e->filename))              return e;
          if (e->once              && 0 == PATHCMP(basename, tcc_basename(e->filename))              && 0 == normalized_PATHCMP(filename, e->filename)              )              return e;
          i = e->hash_next;

}      if (!add)          return NULL;
        e = tcc_malloc(sizeof(CachedInclude) + (len = strlen(filename)));
      memcpy(e->filename, filename, len + 1);
      e->ifndef_macro = e->once = 0;
      dynarray_add(&s1->cached_includes, &s1->nb_cached_includes, e);
      /* add in hash table */      e->hash_next = s1->cached_includes_hash[h];
      s1->cached_includes_hash[h] = s1->nb_cached_includes;
  #ifdef INC_DEBUG      printf("adding cached '%s'\n", filename);
  #endif      return e;

}

static int pragma_parse(TCCState *s1)  {
      next_nomacro();
      if (tok == TOK_push_macro || tok == TOK_pop_macro) {
          int t = tok, v;
          Sym *s;
            if (next(), tok != '(')              goto pragma_err;
          if (next(), tok != TOK_STR)              goto pragma_err;
          v = tok_alloc(tokc.str.data, tokc.str.size - 1)->tok;
          if (next(), tok != ')')              goto pragma_err;
          if (t == TOK_push_macro) {
              while (NULL == (s = define_find(v)))                  define_push(v, 0, NULL, NULL);
              s->type.ref = s;
 /* set push boundary */          
} else {
              for (s = define_stack;
 s;
 s = s->prev)                  if (s->v == v && s->type.ref == s) {
                      s->type.ref = NULL;
                      break;

}          
}          if (s)              table_ident[v - TOK_IDENT]->sym_define = s->d ? s : NULL;
          else              tcc_warning("unbalanced #pragma pop_macro");
          pp_debug_tok = t, pp_debug_symv = v;

} else if (tok == TOK_once) {
          search_cached_include(s1, file->true_filename, 1)->once = 1;

} else if (s1->output_type == TCC_OUTPUT_PREPROCESS) {
          /* tcc -E: keep pragmas below unchanged */          unget_tok(' ');
          unget_tok(TOK_PRAGMA);
          unget_tok('#');
          unget_tok(TOK_LINEFEED);
          return 1;

} else if (tok == TOK_pack) {
          /* This may be:             #pragma pack(1) // set             #pragma pack() // reset to default             #pragma pack(push) // push current             #pragma pack(push,1) // push & set             #pragma pack(pop) // restore previous */          next();
          skip('(');
          if (tok == TOK_ASM_pop) {
              next();
              if (s1->pack_stack_ptr <= s1->pack_stack) {
              stk_error:                  tcc_error("out of pack stack");

}              s1->pack_stack_ptr--;

} else {
              int val = 0;
              if (tok != ')') {
                  if (tok == TOK_ASM_push) {
                      next();
                      if (s1->pack_stack_ptr >= s1->pack_stack + PACK_STACK_SIZE - 1)                          goto stk_error;
                      val = *s1->pack_stack_ptr++;
                      if (tok != ',')                          goto pack_set;
                      next();

}                  if (tok != TOK_CINT)                      goto pragma_err;
                  val = tokc.i;
                  if (val < 1 || val > 16 || (val & (val - 1)) != 0)                      goto pragma_err;
                  next();

}          pack_set:              *s1->pack_stack_ptr = val;

}          if (tok != ')')              goto pragma_err;

} else if (tok == TOK_comment) {
          char *p;
 int t;
          next();
          skip('(');
          t = tok;
          next();
          skip(',');
          if (tok != TOK_STR)              goto pragma_err;
          p = tcc_strdup(tokc.str.data);
          next();
          if (tok != ')')              goto pragma_err;
          if (t == TOK_lib) {
              dynarray_add(&s1->pragma_libs, &s1->nb_pragma_libs, p);

} else {
              if (t == TOK_option)                  tcc_set_options(s1, p);
              tcc_free(p);

}        
} else {
          tcc_warning_c(warn_all)("#pragma %s ignored", get_tok_str(tok, &tokc));
          return 0;

}      next();
      return 1;
  pragma_err:      tcc_error("malformed #pragma directive");

}

ST_FUNC void tccpp_putfile(const char *filename)  {
      char buf[1024];
      buf[0] = 0;
      if (!IS_ABSPATH(filename)) {
          /* prepend directory from real file */          pstrcpy(buf, sizeof buf, file->true_filename);
          *tcc_basename(buf) = 0;

}      pstrcat(buf, sizeof buf, filename);
  #ifdef _WIN32      normalize_slashes(buf);
  #endif      if (0 == strcmp(file->filename, buf))          return;
      //printf("new file '%s'\n", buf);
      if (file->true_filename == file->filename)          file->true_filename = tcc_strdup(file->filename);
      pstrcpy(file->filename, sizeof file->filename, buf);
      tcc_debug_newfile(tcc_state);

}

ST_FUNC void preprocess(int is_bof)  {
      TCCState *s1 = tcc_state;
      int c, n, saved_parse_flags;
      char buf[1024], *q;
      Sym *s;
        saved_parse_flags = parse_flags;
      parse_flags = PARSE_FLAG_PREPROCESS          | PARSE_FLAG_TOK_NUM          | PARSE_FLAG_TOK_STR          | PARSE_FLAG_LINEFEED          | (parse_flags & PARSE_FLAG_ASM_FILE)         ;
        next_nomacro();
   redo:      switch(tok) {
      case TOK_DEFINE:          pp_debug_tok = tok;
          next_nomacro();
          pp_debug_symv = tok;
          parse_define();
          break;
      case TOK_UNDEF:          pp_debug_tok = tok;
          next_nomacro();
          pp_debug_symv = tok;
          s = define_find(tok);
          /* undefine symbol by putting an invalid name */          if (s)              define_undef(s);
          next_nomacro();
          break;
      case TOK_INCLUDE:      case TOK_INCLUDE_NEXT:          parse_include(s1, tok - TOK_INCLUDE, 0);
          goto the_end;
      case TOK_IFNDEF:          c = 1;
          goto do_ifdef;
      case TOK_IF:          c = expr_preprocess(s1);
          goto do_if;
      case TOK_IFDEF:          c = 0;
      do_ifdef:          next_nomacro();
          if (tok < TOK_IDENT)              tcc_error("invalid argument for '#if%sdef'", c ? "n" : "");
          if (is_bof) {
              if (c) {
  #ifdef INC_DEBUG                  printf("#ifndef %s\n", get_tok_str(tok, NULL));
  #endif                  file->ifndef_macro = tok;

}          
}          if (define_find(tok)              || tok == TOK___HAS_INCLUDE              || tok == TOK___HAS_INCLUDE_NEXT)              c ^= 1;
          next_nomacro();
      do_if:          if (s1->ifdef_stack_ptr >= s1->ifdef_stack + IFDEF_STACK_SIZE)              tcc_error("memory full (ifdef)");
          *s1->ifdef_stack_ptr++ = c;
          goto test_skip;
      case TOK_ELSE:          next_nomacro();
          if (s1->ifdef_stack_ptr == s1->ifdef_stack)              tcc_error("#else without matching #if");
          if (s1->ifdef_stack_ptr[-1] & 2)              tcc_error("#else after #else");
          c = (s1->ifdef_stack_ptr[-1] ^= 3);
          goto test_else;
      case TOK_ELIF:          if (s1->ifdef_stack_ptr == s1->ifdef_stack)              tcc_error("#elif without matching #if");
          c = s1->ifdef_stack_ptr[-1];
          if (c > 1)              tcc_error("#elif after #else");
          /* last #if/#elif expression was true: we skip */          if (c == 1) {
              skip_to_eol(0);
              c = 0;

} else {
              c = expr_preprocess(s1);
              s1->ifdef_stack_ptr[-1] = c;

}      test_else:          if (s1->ifdef_stack_ptr == file->ifdef_stack_ptr + 1)              file->ifndef_macro = 0;
      test_skip:          if (!(c & 1)) {
              skip_to_eol(1);
              preprocess_skip();
              is_bof = 0;
              goto redo;

}          break;
      case TOK_ENDIF:          next_nomacro();
          if (s1->ifdef_stack_ptr <= file->ifdef_stack_ptr)              tcc_error("#endif without matching #if");
          s1->ifdef_stack_ptr--;
          /* '#ifndef macro' was at the start of file. Now we check if             an '#endif' is exactly at the end of file */          if (file->ifndef_macro &&              s1->ifdef_stack_ptr == file->ifdef_stack_ptr) {
              file->ifndef_macro_saved = file->ifndef_macro;
              /* need to set to zero to avoid false matches if another                 #ifndef at middle of file */              file->ifndef_macro = 0;
              tok_flags |= TOK_FLAG_ENDIF;

}          break;
      case TOK_LINE:          next_nomacro();
          if (tok != TOK_PPNUM) {
      _line_err:              if (parse_flags & PARSE_FLAG_ASM_FILE)                  goto ignore;
              tcc_error("wrong #line format");

