                  break;
              case 'b':                  c = '\b';
                  break;
              case 'f':                  c = '\f';
                  break;
              case 'n':                  c = '\n';
                  break;
              case 'r':                  c = '\r';
                  break;
              case 't':                  c = '\t';
                  break;
              case 'v':                  c = '\v';
