static void parse_string(const char *s, int len)  {
      uint8_t buf[1000], *p = buf;
      int is_long, sep;
        if ((is_long = *s == 'L'))          ++s, --len;
      sep = *s++;
      len -= 2;
      if (len >= sizeof buf)          p = tcc_malloc(len + 1);
