          int char_size, i, n, c;
          /* XXX: make it portable */          if (!is_long)              tok = TOK_CCHAR, char_size = 1;
          else              tok = TOK_LCHAR, char_size = sizeof(nwchar_t);
          n = tokcstr.size / char_size - 1;
          if (n < 1)              tcc_error("empty character constant");
          if (n > 1)              tcc_warning_c(warn_all)("multi-character character constant");
