static void bn_lshift(unsigned int *bn, int shift, int or_val)  {
      int i;
      unsigned int v;
      for(i=0;
i<BN_SIZE;
i++) {
          v = bn[i];
          bn[i] = (v << shift) | or_val;
          or_val = v >> (32 - shift);

}  
}

static void bn_zero(unsigned int *bn)  {
      int i;
      for(i=0;
i<BN_SIZE;
i++) {
          bn[i] = 0;

}  
}

