          p = parse_pp_string(p, c, &tokcstr);
          cstr_ccat(&tokcstr, c);
          cstr_ccat(&tokcstr, '\0');
          tokc.str.size = tokcstr.size;
          tokc.str.data = tokcstr.data;
          tok = TOK_PPSTR;
          break;
        case '<':          PEEKC(c, p);
          if (c == '=') {
              p++;
              tok = TOK_LE;

} else if (c == '<') {
              PEEKC(c, p);
              if (c == '=') {
                  p++;
                  tok = TOK_A_SHL;

} else {
                  tok = TOK_SHL;

}          
} else {
              tok = TOK_LT;

}          break;
      case '>':          PEEKC(c, p);
          if (c == '=') {
              p++;
              tok = TOK_GE;

} else if (c == '>') {
              PEEKC(c, p);
              if (c == '=') {
                  p++;
                  tok = TOK_A_SAR;

} else {
                  tok = TOK_SAR;

}          
} else {
              tok = TOK_GT;

}          break;
                case '&':          PEEKC(c, p);
          if (c == '&') {
              p++;
              tok = TOK_LAND;

} else if (c == '=') {
              p++;
              tok = TOK_A_AND;

} else {
              tok = '&';

}          break;
                case '|':          PEEKC(c, p);
          if (c == '|') {
              p++;
              tok = TOK_LOR;

} else if (c == '=') {
              p++;
              tok = TOK_A_OR;

} else {
              tok = '|';

}          break;
        case '+':          PEEKC(c, p);
          if (c == '+') {
              p++;
              tok = TOK_INC;

} else if (c == '=') {
              p++;
              tok = TOK_A_ADD;

} else {
              tok = '+';

}          break;
                case '-':          PEEKC(c, p);
          if (c == '-') {
              p++;
              tok = TOK_DEC;

} else if (c == '=') {
              p++;
              tok = TOK_A_SUB;

} else if (c == '>') {
              p++;
              tok = TOK_ARROW;

} else {
              tok = '-';

}          break;
        PARSE2('!', '!', '=', TOK_NE)      PARSE2('=', '=', '=', TOK_EQ)      PARSE2('*', '*', '=', TOK_A_MUL)      PARSE2('%', '%', '=', TOK_A_MOD)      PARSE2('^', '^', '=', TOK_A_XOR)                    /* comments or operator */      case '/':          PEEKC(c, p);
          if (c == '*') {
              p = parse_comment(p);
              /* comments replaced by a blank */              tok = ' ';
              goto maybe_space;

} else if (c == '/') {
              p = parse_line_comment(p);
              tok = ' ';
              goto maybe_space;

} else if (c == '=') {
              p++;
              tok = TOK_A_DIV;

} else {
              tok = '/';

}          break;
                    /* simple tokens */      case '(':      case ')':      case '[':      case ']':      case '{
':      case '
}':      case ',':      case ';
':      case ':':      case '?':      case '~':      case '@': /* only used in assembler */      parse_simple:          tok = c;
          p++;
          break;
      default:          if (c >= 0x80 && c <= 0xFF) /* utf8 identifiers */       goto parse_ident_fast;
          if (parse_flags & PARSE_FLAG_ASM_FILE)              goto parse_simple;
          tcc_error("unrecognized character \\x%02x", c);
          break;

}      tok_flags = 0;
  keep_tok_flags:      file->buf_ptr = p;
  #if defined(PARSE_DEBUG)      printf("token = %d %s\n", tok, get_tok_str(tok, &tokc));
  #endif  
}

static int *macro_arg_subst(Sym **nested_list, const int *macro_str, Sym *args)  {
      int t, t0, t1, t2, n;
      const int *st;
      Sym *s;
      CValue cval;
      TokenString str;
    #ifdef PP_DEBUG      PP_PRINT(("asubst:", 0, macro_str));
      for (s = args, n = 0;
 s;
 s = s->prev, ++n);
      while (n--) {
          for (s = args, t = 0;
 t < n;
 s = s->prev, ++t);
          tok_print(s->d, "%*s - arg: %s:", indent, "", get_tok_str(s->v, 0));

}  #endif        tok_str_new(&str);
      t0 = t1 = 0;
      while(1) {
          TOK_GET(&t, &macro_str, &cval);
          if (!t)              break;
          if (t == '#') {
              /* stringize */              do t = *macro_str++;
 while (t == ' ');
              s = sym_find2(args, t);
              if (s) {
                  cstr_reset(&tokcstr);
                  cstr_ccat(&tokcstr, '\"');
                  st = s->d;
                  while (*st != TOK_EOF) {
                      const char *s;
                      TOK_GET(&t, &st, &cval);
                      s = get_tok_str(t, &cval);
                      while (*s) {
                          if (t == TOK_PPSTR && *s != '\'')                              add_char(&tokcstr, *s);
                          else                              cstr_ccat(&tokcstr, *s);
                          ++s;

}                  
}                  cstr_ccat(&tokcstr, '\"');
                  cstr_ccat(&tokcstr, '\0');
                  //printf("\nstringize: <%s>\n", (char *)tokcstr.data);
                  /* add string */                  cval.str.size = tokcstr.size;
                  cval.str.data = tokcstr.data;
                  tok_str_add2(&str, TOK_PPSTR, &cval);

} else {
                  expect("macro parameter after '#'");

}          
} else if (t >= TOK_IDENT) {
              s = sym_find2(args, t);
              if (s) {
                  st = s->d;
                  n = 0;
                  while ((t2 = macro_str[n]) == ' ')                      ++n;
                  /* if '##' is present before or after, no arg substitution */                  if (t2 == TOK_PPJOIN || t1 == TOK_PPJOIN) {
                      /* special case for var arg macros : ## eats the ','                         if empty VA_ARGS variable. */                      if (t1 == TOK_PPJOIN && t0 == ',' && gnu_ext && s->type.t) {
                          int c = str.str[str.len - 1];
                          while (str.str[--str.len] != ',')                             ;
                          if (*st == TOK_EOF) {
                              /* suppress ',' '##' */                          
} else {
                              /* suppress '##' and add variable */                              str.len++;
                              if (c == ' ')                                  str.str[str.len++] = c;
                              goto add_var;

}                      
} else {
                          if (*st == TOK_EOF)                              tok_str_add(&str, TOK_PLCHLDR);

}                  
} else {
              add_var:        if (!s->e) {
     /* Expand arguments tokens and store them.  In most        cases we could also re-expand each argument if        used multiple times, but not if the argument        contains the __COUNTER__ macro.  */     TokenString str2;
     tok_str_new(&str2);
     macro_subst(&str2, nested_list, st);
     tok_str_add(&str2, TOK_EOF);
     s->e = str2.str;

}        st = s->e;

}                  while (*st != TOK_EOF) {
                      TOK_GET(&t2, &st, &cval);
                      tok_str_add2(&str, t2, &cval);

}              
} else {
                  tok_str_add(&str, t);

}          
} else {
              tok_str_add2(&str, t, &cval);

}          if (t != ' ')              t0 = t1, t1 = t;

}      tok_str_add(&str, 0);
      PP_PRINT(("areslt:", 0, str.str));
      return str.str;

}

static inline int *macro_twosharps(const int *ptr0)  {
      int t1, t2, n, l;
      CValue cv1, cv2;
      TokenString macro_str1;
      const int *ptr;
        tok_str_new(&macro_str1);
      cstr_reset(&tokcstr);
      for (ptr = ptr0;
;
) {
          TOK_GET(&t1, &ptr, &cv1);
          if (t1 == 0)              break;
          for (;
;
) {
              n = 0;
              while ((t2 = ptr[n]) == ' ')                  ++n;
              if (t2 != TOK_PPJOIN)                  break;
              ptr += n;
              while ((t2 = *++ptr) == ' ' || t2 == TOK_PPJOIN)                 ;
              TOK_GET(&t2, &ptr, &cv2);
              if (t2 == TOK_PLCHLDR)                  continue;
              if (t1 != TOK_PLCHLDR) {
                  cstr_cat(&tokcstr, get_tok_str(t1, &cv1), -1);
                  t1 = TOK_PLCHLDR;

}              cstr_cat(&tokcstr, get_tok_str(t2, &cv2), -1);

}          if (tokcstr.size) {
              cstr_ccat(&tokcstr, 0);
              tcc_open_bf(tcc_state, ":paste:", tokcstr.size);
              memcpy(file->buffer, tokcstr.data, tokcstr.size);
              tok_flags = 0;
 /* don't interpret '#' */              for (n = 0;
;
n = l) {
                  next_nomacro();
                  tok_str_add2(&macro_str1, tok, &tokc);
                  if (*file->buf_ptr == 0)                      break;
                  tok_str_add(&macro_str1, ' ');
                  l = file->buf_ptr - file->buffer;
                  tcc_warning("pasting \"%.*s\" and \"%s\" does not give a valid"                      " preprocessing token", l - n, file->buffer + n, file->buf_ptr);

}              tcc_close();
              cstr_reset(&tokcstr);

}          if (t1 != TOK_PLCHLDR)              tok_str_add2(&macro_str1, t1, &cv1);

}      tok_str_add(&macro_str1, 0);
      PP_PRINT(("pasted:", 0, macro_str1.str));
      return macro_str1.str;

}

static int peek_file (TokenString *ws_str)  {
      uint8_t *p = file->buf_ptr - 1;
      int c;
      for (;
;
) {
          PEEKC(c, p);
          switch (c) {
          case '/':              PEEKC(c, p);
              if (c == '*')                  p = parse_comment(p);
              else if (c == '/')                  p = parse_line_comment(p);
              else {
                  c = *--p = '/';
                  goto leave;

}              --p, c = ' ';
              break;
          case ' ': case '\t':              break;
          case '\f': case '\v': case '\r':              continue;
          case '\n':              file->line_num++, tok_flags |= TOK_FLAG_BOL;
              break;
          default: leave:              file->buf_ptr = p;
              return c;

}          if (ws_str)              tok_str_add(ws_str, c);

}  
}

static int next_argstream(Sym **nested_list, TokenString *ws_str)  {
      int t;
      Sym *sa;
        while (macro_ptr) {
          const int *m = macro_ptr;
          while ((t = *m) != 0) {
              if (ws_str) {
                  if (t != ' ')                      return t;
                  ++m;

} else {
                  TOK_GET(&tok, &macro_ptr, &tokc);
                  return tok;

}          
}          end_macro();
          /* also, end of scope for nested defined symbol */          sa = *nested_list;
          if (sa)              *nested_list = sa->prev, sym_free(sa);

}      if (ws_str) {
          return peek_file(ws_str);

} else {
          next_nomacro();
          if (tok == '\t' || tok == TOK_LINEFEED)              tok = ' ';
          return tok;

}  
}

static int macro_subst_tok(      TokenString *tok_str,      Sym **nested_list,      Sym *s)  {
      int t;
      int v = s->v;
        PP_PRINT(("#", v, s->d));
      if (s->d) {
          int *mstr = s->d;
          int *jstr;
          Sym *sa;
          int ret;
            if (s->type.t & MACRO_FUNC) {
              int saved_parse_flags = parse_flags;
              TokenString str;
              int parlevel, i;
              Sym *sa1, *args;
                parse_flags |= PARSE_FLAG_SPACES | PARSE_FLAG_LINEFEED                  | PARSE_FLAG_ACCEPT_STRAYS;
                tok_str_new(&str);
              /* peek next token from argument stream */              t = next_argstream(nested_list, &str);
              if (t != '(') {
                  /* not a macro substitution after all, restore the                   * macro token plus all whitespace we've read.                   * whitespace is intentionally not merged to preserve                   * newlines. */                  parse_flags = saved_parse_flags;
                  tok_str_add2_spc(tok_str, v, 0);
                  if (parse_flags & PARSE_FLAG_SPACES)                      for (i = 0;
 i < str.len;
 i++)                          tok_str_add(tok_str, str.str[i]);
                  tok_str_free_str(str.str);
                  return 0;

} else {
                  tok_str_free_str(str.str);

}                /* argument macro */              args = NULL;
              sa = s->next;
              /* NOTE: empty args are allowed, except if no args */              i = 2;
 /* eat '(' */              for(;
;
) {
                  do {
                      t = next_argstream(nested_list, NULL);

} while (t == ' ' || --i);
                    if (!sa) {
                      if (t == ')') /* handle '()' case */                          break;
                      tcc_error("macro '%s' used with too many args",                          get_tok_str(v, 0));

}              empty_arg:                  tok_str_new(&str);
                  parlevel = 0;
                  /* NOTE: non zero sa->type.t indicates VA_ARGS */                  while (parlevel > 0                          || (t != ')' && (t != ',' || sa->type.t))) {
                      if (t == TOK_EOF)                          tcc_error("EOF in invocation of macro '%s'",                              get_tok_str(v, 0));
                      if (t == '(')                          parlevel++;
                      if (t == ')')                          parlevel--;
                      if (t == ' ')                          str.need_spc |= 1;
                      else                          tok_str_add2_spc(&str, t, &tokc);
                      t = next_argstream(nested_list, NULL);

}                  tok_str_add(&str, TOK_EOF);
                  sa1 = sym_push2(&args, sa->v & ~SYM_FIELD, sa->type.t, 0);
                  sa1->d = str.str;
                  sa = sa->next;
                  if (t == ')') {
                      if (!sa)                          break;
                      /* special case for gcc var args: add an empty                         var arg argument if it is omitted */                      if (sa->type.t && gnu_ext)                          goto empty_arg;
                      tcc_error("macro '%s' used with too few args",                          get_tok_str(v, 0));

}                  i = 1;

}                /* now subst each arg */              mstr = macro_arg_subst(nested_list, mstr, args);
              /* free memory */              sa = args;
              while (sa) {
                  sa1 = sa->prev;
                  tok_str_free_str(sa->d);
                  tok_str_free_str(sa->e);
                  sym_free(sa);
                  sa = sa1;

}              parse_flags = saved_parse_flags;

}            /* process '##'s (if present) */          jstr = mstr;
          if (s->type.t & MACRO_JOIN)              jstr = macro_twosharps(mstr);
            sa = sym_push2(nested_list, v, 0, 0);
          ret = macro_subst(tok_str, nested_list, jstr);
          /* pop nested defined symbol */          if (sa == *nested_list)              *nested_list = sa->prev, sym_free(sa);
            if (jstr != mstr)              tok_str_free_str(jstr);
          if (mstr != s->d)              tok_str_free_str(mstr);
          return ret;

} else {
          CValue cval;
          char buf[32], *cstrval = buf;
            /* special macros */          if (v == TOK___LINE__ || v == TOK___COUNTER__) {
              t = v == TOK___LINE__ ? file->line_num : pp_counter++;
              snprintf(buf, sizeof(buf), "%d", t);
              t = TOK_PPNUM;
              goto add_cstr1;

} else if (v == TOK___FILE__) {
              cstrval = file->filename;
              goto add_cstr;

} else if (v == TOK___DATE__ || v == TOK___TIME__) {
              time_t ti;
              struct tm *tm;
              time(&ti);
              tm = localtime(&ti);
              if (v == TOK___DATE__) {
                  static char const ab_month_name[12][4] = {
                      "Jan", "Feb", "Mar", "Apr", "May", "Jun",                      "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"                  
};
                  snprintf(buf, sizeof(buf), "%s %2d %d",                      ab_month_name[tm->tm_mon], tm->tm_mday, tm->tm_year + 1900);

} else {
                  snprintf(buf, sizeof(buf), "%02d:%02d:%02d",                      tm->tm_hour, tm->tm_min, tm->tm_sec);

}          add_cstr:              t = TOK_STR;
          add_cstr1:              cval.str.size = strlen(cstrval) + 1;
              cval.str.data = cstrval;
              tok_str_add2_spc(tok_str, t, &cval);

}          return 0;

}  
}

static int macro_subst(      TokenString *tok_str,      Sym **nested_list,      const int *macro_str      )  {
      Sym *s;
      int t, nosubst = 0;
      CValue cval;
      TokenString *str;
    #ifdef PP_DEBUG      int tlen = tok_str->len;
      PP_PRINT(("+expand:", 0, macro_str));
  #endif        while (1) {
          TOK_GET(&t, &macro_str, &cval);
          if (t == 0 || t == TOK_EOF)              break;
          if (t >= TOK_IDENT) {
              s = define_find(t);
              if (s == NULL || nosubst)                  goto no_subst;
              /* if nested substitution, do nothing */              if (sym_find2(*nested_list, t)) {
                  /* and mark so it doesn't get subst'd again */                  t |= SYM_FIELD;
                  goto no_subst;

}              str = tok_str_alloc();
              str->str = (int*)macro_str;
 /* setup stream for possible arguments */              begin_macro(str, 2);
              nosubst = macro_subst_tok(tok_str, nested_list, s);
              if (macro_stack != str) {
                  /* already finished by reading function macro arguments */                  break;

}              macro_str = macro_ptr;
              end_macro ();

} else if (t == ' ') {
              if (parse_flags & PARSE_FLAG_SPACES)                  tok_str->need_spc |= 1;

} else {
      no_subst:              tok_str_add2_spc(tok_str, t, &cval);
              if (nosubst && t != '(')                  nosubst = 0;
              /* GCC supports 'defined' as result of a macro substitution */              if (t == TOK_DEFINED && pp_expr)                  nosubst = 1;

}      
}    #ifdef PP_DEBUG      tok_str_add(tok_str, 0), --tok_str->len;
      PP_PRINT(("-result:", 0, tok_str->str + tlen));
  #endif      return nosubst;

}

ST_FUNC void next(void)  {
      int t;
      while (macro_ptr) {
  redo:          t = *macro_ptr;
          if (TOK_HAS_VALUE(t)) {
              tok_get(&tok, &macro_ptr, &tokc);
              if (t == TOK_LINENUM) {
                  file->line_num = tokc.i;
                  goto redo;

}              goto convert;

} else if (t == 0) {
              /* end of macro or unget token string */              end_macro();
              continue;

} else if (t == TOK_EOF) {
              /* do nothing */          
} else {
              ++macro_ptr;
              t &= ~SYM_FIELD;
 /* remove 'nosubst' marker */              if (t == '\\') {
                  if (!(parse_flags & PARSE_FLAG_ACCEPT_STRAYS))                      tcc_error("stray '\\' in program");

}          
}          tok = t;
          return;

}        next_nomacro();
      t = tok;
      if (t >= TOK_IDENT && (parse_flags & PARSE_FLAG_PREPROCESS)) {
          /* if reading from file, try to substitute macros */          Sym *s = define_find(t);
          if (s) {
              Sym *nested_list = NULL;
              macro_subst_tok(&tokstr_buf, &nested_list, s);
              tok_str_add(&tokstr_buf, 0);
              begin_macro(&tokstr_buf, 0);
              goto redo;

}          return;

}    convert:      /* convert preprocessor tokens into C tokens */      if (t == TOK_PPNUM) {
          if  (parse_flags & PARSE_FLAG_TOK_NUM)              parse_number(tokc.str.data);

} else if (t == TOK_PPSTR) {
          if (parse_flags & PARSE_FLAG_TOK_STR)              parse_string(tokc.str.data, tokc.str.size - 1);

}  
}

ST_INLN void unget_tok(int last_tok)  {
      TokenString *str = &unget_buf;
      int alloc = 0;
      if (str->len) /* use static buffer except if already in use */          str = tok_str_alloc(), alloc = 1;
      if (tok != TOK_EOF)          tok_str_add2(str, tok, &tokc);
      tok_str_add(str, 0);
      begin_macro(str, alloc);
      tok = last_tok;

}

static void putdef(CString *cs, const char *p)  {
      cstr_printf(cs, "#define %s%s\n", p, &" 1"[!!strchr(p, ' ')*2]);

}

static void putdefs(CString *cs, const char *p)  {
      while (*p)          putdef(cs, p), p = strchr(p, 0) + 1;

}

static void tcc_predefs(TCCState *s1, CString *cs, int is_asm)  {
      cstr_printf(cs, "#define __TINYC__ 9%.2s\n", TCC_VERSION + 4);
      putdefs(cs, target_machine_defs);
      putdefs(cs, target_os_defs);
    #ifdef TCC_TARGET_ARM      if (s1->float_abi == ARM_HARD_FLOAT)        putdef(cs, "__ARM_PCS_VFP");
  #endif      if (is_asm)        putdef(cs, "__ASSEMBLER__");
      if (s1->output_type == TCC_OUTPUT_PREPROCESS)        putdef(cs, "__TCC_PP__");
      if (s1->output_type == TCC_OUTPUT_MEMORY)        putdef(cs, "__TCC_RUN__");
  #ifdef CONFIG_TCC_BACKTRACE      if (s1->do_backtrace)        putdef(cs, "__TCC_BACKTRACE__");
  #endif  #ifdef CONFIG_TCC_BCHECK      if (s1->do_bounds_check)        putdef(cs, "__TCC_BCHECK__");
  #endif      if (s1->char_is_unsigned)        putdef(cs, "__CHAR_UNSIGNED__");
      if (s1->optimize > 0)        putdef(cs, "__OPTIMIZE__");
      if (s1->option_pthread)        putdef(cs, "_REENTRANT");
      if (s1->leading_underscore)        putdef(cs, "__leading_underscore");
      cstr_printf(cs, "#define __SIZEOF_POINTER__ %d\n", PTR_SIZE);
      cstr_printf(cs, "#define __SIZEOF_LONG__ %d\n", LONG_SIZE);
      if (!is_asm) {
        putdef(cs, "__STDC__");
        cstr_printf(cs, "#define __STDC_VERSION__ %dL\n", s1->cversion);
        cstr_cat(cs,          /* load more predefs and __builtins */  #if CONFIG_TCC_PREDEFS          #include "tccdefs_.h" /* include as strings */  #else          "#include <tccdefs.h>\n" /* load at runtime */  #endif          , -1);

}      cstr_printf(cs, "#define __BASE_FILE__ \"%s\"\n", file->filename);

}

ST_FUNC void preprocess_start(TCCState *s1, int filetype)  {
      int is_asm = !!(filetype & (AFF_TYPE_ASM|AFF_TYPE_ASMPP));
        tccpp_new(s1);
        s1->include_stack_ptr = s1->include_stack;
      s1->ifdef_stack_ptr = s1->ifdef_stack;
      file->ifdef_stack_ptr = s1->ifdef_stack_ptr;
      pp_expr = 0;
      pp_counter = 0;
      pp_debug_tok = pp_debug_symv = 0;
      s1->pack_stack[0] = 0;
      s1->pack_stack_ptr = s1->pack_stack;
        set_idnum('$', !is_asm && s1->dollars_in_identifiers ? IS_ID : 0);
      set_idnum('.', is_asm ? IS_ID : 0);
        if (!(filetype & AFF_TYPE_ASM)) {
          CString cstr;
          cstr_new(&cstr);
          tcc_predefs(s1, &cstr, is_asm);
          if (s1->cmdline_defs.size)            cstr_cat(&cstr, s1->cmdline_defs.data, s1->cmdline_defs.size);
          if (s1->cmdline_incl.size)            cstr_cat(&cstr, s1->cmdline_incl.data, s1->cmdline_incl.size);
          //printf("%.*s\n", cstr.size, (char*)cstr.data);
          *s1->include_stack_ptr++ = file;
          tcc_open_bf(s1, "<command line>", cstr.size);
          memcpy(file->buffer, cstr.data, cstr.size);
          cstr_free(&cstr);

}      parse_flags = is_asm ? PARSE_FLAG_ASM_FILE : 0;

}

ST_FUNC void preprocess_end(TCCState *s1)  {
      while (macro_stack)          end_macro();
      macro_ptr = NULL;
      while (file)          tcc_close();
      tccpp_delete(s1);

}

ST_FUNC int set_idnum(int c, int val)  {
      int prev = isidnum_table[c - CH_EOF];
      isidnum_table[c - CH_EOF] = val;
      return prev;

}

ST_FUNC void tccpp_new(TCCState *s)  {
      int i, c;
      const char *p, *r;
