static int pp_need_space(int a, int b)  {
      return 'E' == a ? '+' == b || '-' == b          : '+' == a ? TOK_INC == b || '+' == b          : '-' == a ? TOK_DEC == b || '-' == b          : a >= TOK_IDENT || a == TOK_PPNUM ? b >= TOK_IDENT || b == TOK_PPNUM          : 0;

}

static int pp_check_he0xE(int t, const char *p)  {
      if (t == TOK_PPNUM && toup(strchr(p, 0)[-1]) == 'E')          return 'E';
      return t;

}

