 // 250 func      memcpy(&arhdro.ar_mode, "100644", 6);
        // i_obj = first input object file      while (i_obj < argc)      {
          if (*argv[i_obj] == '-') {
  // by now, all options start with '-'              i_obj++;
              continue;

}          if ((fi = fopen(argv[i_obj], "rb")) == NULL) {
              fprintf(stderr, "tcc: ar: can't open file %s \n", argv[i_obj]);
              goto the_end;

}          if (verbose)              printf("a - %s\n", argv[i_obj]);
            fseek(fi, 0, SEEK_END);
          fsize = ftell(fi);
          fseek(fi, 0, SEEK_SET);
          buf = tcc_malloc(fsize + 1);
          fread(buf, fsize, 1, fi);
          fclose(fi);
            // elf header          ehdr = (ElfW(Ehdr) *)buf;
          if (ehdr->e_ident[4] != ELFCLASSW)          {
              fprintf(stderr, "tcc: ar: Unsupported Elf Class: %s\n", argv[i_obj]);
              goto the_end;

}            shdr = (ElfW(Shdr) *) (buf + ehdr->e_shoff + ehdr->e_shstrndx * ehdr->e_shentsize);
          shstr = (char *)(buf + shdr->sh_offset);
          symtab = strtab = NULL;
          for (i = 0;
 i < ehdr->e_shnum;
 i++)          {
              shdr = (ElfW(Shdr) *) (buf + ehdr->e_shoff + i * ehdr->e_shentsize);
              if (!shdr->sh_offset)                  continue;
              if (shdr->sh_type == SHT_SYMTAB)              {
                  symtab = (char *)(buf + shdr->sh_offset);
                  symtabsize = shdr->sh_size;

}              if (shdr->sh_type == SHT_STRTAB)              {
                  if (!strcmp(shstr + shdr->sh_name, ".strtab"))                  {
                      strtab = (char *)(buf + shdr->sh_offset);
                      //strtabsize = shdr->sh_size;

}              
}          
}            if (symtab && strtab)          {
              int nsym = symtabsize / sizeof(ElfW(Sym));
              //printf("symtab: info size shndx name\n");
              for (i = 1;
 i < nsym;
 i++)              {
                  sym = (ElfW(Sym) *) (symtab + i * sizeof(ElfW(Sym)));
                  if (sym->st_shndx &&                      (sym->st_info == 0x10                      || sym->st_info == 0x11                      || sym->st_info == 0x12                      || sym->st_info == 0x20                      || sym->st_info == 0x21                      || sym->st_info == 0x22                      )) {
                      //printf("symtab: %2Xh %4Xh %2Xh %s\n", sym->st_info, sym->st_size, sym->st_shndx, strtab + sym->st_name);
                      istrlen = strlen(strtab + sym->st_name)+1;
                      anames = tcc_realloc(anames, strpos+istrlen);
                      strcpy(anames + strpos, strtab + sym->st_name);
                      strpos += istrlen;
                      if (++funccnt >= funcmax) {
                          funcmax += 250;
                          afpos = tcc_realloc(afpos, funcmax * sizeof *afpos);
 // 250 func more                      
}                      afpos[funccnt] = fpos;

}              
}          
}            file = argv[i_obj];
          for (name = strchr(file, 0);
               name > file && name[-1] != '/' && name[-1] != '\\';
               --name);
          istrlen = strlen(name);
          if (istrlen >= sizeof(arhdro.ar_name))              istrlen = sizeof(arhdro.ar_name) - 1;
          memset(arhdro.ar_name, ' ', sizeof(arhdro.ar_name));
          memcpy(arhdro.ar_name, name, istrlen);
          arhdro.ar_name[istrlen] = '/';
          sprintf(stmp, "%-10d", fsize);
          memcpy(&arhdro.ar_size, stmp, 10);
          fwrite(&arhdro, sizeof(arhdro), 1, fo);
          fwrite(buf, fsize, 1, fo);
          tcc_free(buf);
          i_obj++;
          fpos += (fsize + sizeof(arhdro));
          if (fpos & 1)              fputc(0, fo), ++fpos;

}      hofs = 8 + sizeof(arhdr) + strpos + (funccnt+1) * sizeof(int);
      fpos = 0;
      if ((hofs & 1)) // align          hofs++, fpos = 1;
      // write header      fwrite(ARMAG, 8, 1, fh);
      // create an empty archive      if (!funccnt) {
          ret = 0;
          goto the_end;

}      sprintf(stmp, "%-10d", (int)(strpos + (funccnt+1) * sizeof(int)) + fpos);
      memcpy(&arhdr.ar_size, stmp, 10);
      fwrite(&arhdr, sizeof(arhdr), 1, fh);
      afpos[0] = le2belong(funccnt);
      for (i=1;
 i<=funccnt;
 i++)          afpos[i] = le2belong(afpos[i] + hofs);
      fwrite(afpos, (funccnt+1) * sizeof(int), 1, fh);
      fwrite(anames, strpos, 1, fh);
      if (fpos)          fwrite("", 1, 1, fh);
