      if (fo)          fclose(fo), remove(tfile);
      return ret;

}

static char *escape_target_dep(const char *s) {
      char *res = tcc_malloc(strlen(s) * 2 + 1);
      int j;
      for (j = 0;
 *s;
 s++, j++) {
          if (is_space(*s)) {
              res[j++] = '\\';

}          res[j] = *s;

}      res[j] = '\0';
      return res;

}

ST_FUNC int gen_makedeps(TCCState *s1, const char *target, const char *filename)  {
      FILE *depout;
      char buf[1024];
      char **escaped_targets;
      int i, k, num_targets;
        if (!filename) {
          /* compute filename automatically: dir/file.o -> dir/file.d */          snprintf(buf, sizeof buf, "%.*s.d",              (int)(tcc_fileextension(target) - target), target);
          filename = buf;

}        if(!strcmp(filename, "-"))          depout = fdopen(1, "w");
      else          /* XXX return err codes instead of error() ? */          depout = fopen(filename, "w");
      if (!depout)          return tcc_error_noabort("could not open '%s'", filename);
      if (s1->verbose)          printf("<- %s\n", filename);
        escaped_targets = tcc_malloc(s1->nb_target_deps * sizeof(*escaped_targets));
      num_targets = 0;
      for (i = 0;
 i<s1->nb_target_deps;
 ++i) {
          for (k = 0;
 k < i;
 ++k)              if (0 == strcmp(s1->target_deps[i], s1->target_deps[k]))                  goto next;
          escaped_targets[num_targets++] = escape_target_dep(s1->target_deps[i]);
      next:;

}        fprintf(depout, "%s:", target);
      for (i = 0;
 i < num_targets;
 ++i)          fprintf(depout, " \\\n  %s", escaped_targets[i]);
      fprintf(depout, "\n");
      if (s1->gen_phony_deps) {
          /* Skip first file, which is the c file.           * Only works for single file give on command-line,           * but other compilers have the same limitation */          for (i = 1;
 i < num_targets;
 ++i)              fprintf(depout, "%s:\n", escaped_targets[i]);

}      for (i = 0;
 i < num_targets;
 ++i)          tcc_free(escaped_targets[i]);
      tcc_free(escaped_targets);
      fclose(depout);
      return 0;

}

