int main(int argc, char **argv)  {
      TCCState *s;
      int i;
      int (*func)(int);
        s = tcc_new();
      if (!s) {
          fprintf(stderr, "Could not create tcc state\n");
          exit(1);

}        /* set custom error/warning printer */      tcc_set_error_func(s, stderr, handle_error);
        /* if tcclib.h and libtcc1.a are not installed, where can we find them */      for (i = 1;
 i < argc;
 ++i) {
          char *a = argv[i];
          if (a[0] == '-') {
              if (a[1] == 'B')                  tcc_set_lib_path(s, a+2);
              else if (a[1] == 'I')                  tcc_add_include_path(s, a+2);
              else if (a[1] == 'L')                  tcc_add_library_path(s, a+2);

}      
}        /* MUST BE CALLED before any compilation */      tcc_set_output_type(s, TCC_OUTPUT_MEMORY);
        if (tcc_compile_string(s, my_program) == -1)          return 1;
        /* as a test, we add symbols that the compiled program can use.         You may also open a dll with tcc_add_dll() and use symbols from that */      tcc_add_symbol(s, "add", add);
      tcc_add_symbol(s, "hello", hello);
        /* relocate the code */      if (tcc_relocate(s) < 0)          return 1;
        /* get entry symbol */      func = tcc_get_symbol(s, "foo");
      if (!func)          return 1;
        /* run the code */      func(32);
        /* delete the state */      tcc_delete(s);
