void math_cmp_test(void)  {
    double nan = 0.0/0.0;
    double one = 1.0;
    double two = 2.0;
    int comp = 0;
    int v;
  #define bug(a,b,op,iop,part) printf("Test broken: %s %s %s %s %d\n", #a, #b, #op, #iop, part)      /* This asserts that "a op b" is _not_ true, but "a iop b" is true.       And it does this in various ways so that all code generation paths       are checked (generating inverted tests, or non-inverted tests, or       producing a 0/1 value without jumps (that's done in the fcompare       function).  */  #define FCMP(a,b,op,iop,code) \    if (fcompare (a,b,code))    \      bug (a,b,op,iop,1);
 \    if (a op b) \      bug (a,b,op,iop,2);
 \    if (a iop b) \     ;
 \    else \      bug (a,b,op,iop,3);
 \    if ((a op b) || comp) \      bug (a,b,op,iop,4);
 \    if ((a iop b) || comp) \     ;
 \    else \      bug (a,b,op,iop,5);
 \    if (v = !(a op b), !v) bug(a,b,op,iop,7);
      /* Equality tests.  */    FCMP(nan, nan, ==, !=, 0);
    FCMP(one, two, ==, !=, 0);
    FCMP(one, one, !=, ==, 1);
    /* Non-equality is a bit special.  */    if (!fcompare (nan, nan, 1))      bug (nan, nan, !=, ==, 6);
      /* Relational tests on numbers.  */    FCMP(two, one, <, >=, 2);
    FCMP(one, two, >=, <, 3);
    FCMP(one, two, >, <=, 4);
    FCMP(two, one, <=, >, 5);
      /* Relational tests on NaNs.  Note that the inverse op here is       always !=, there's no operator in C that is equivalent to !(a < b),       when NaNs are involved, same for the other relational ops.  */    FCMP(nan, nan, <, !=, 2);
    FCMP(nan, nan, >=, !=, 3);
    FCMP(nan, nan, >, !=, 4);
    FCMP(nan, nan, <=, !=, 5);

}

