      pthread_t thread[NR_THREADS];
        atomic_flag_clear(&counter.flag);
      atomic_init(&counter.uc, 0);
      atomic_init(&counter.us, 0);
      atomic_init(&counter.ui, 0);
  #ifdef HAS_64BITS      atomic_init(&counter.ul, 0);
  #endif        for (index = 0;
 index < NR_THREADS;
 ++index)          BUG_ON(pthread_create(&thread[index], NULL, adder, (void *)&counter));
        for (index = 0;
 index < NR_THREADS;
 ++index)          BUG_ON(pthread_join(thread[index], NULL));
        if (atomic_load(&counter.uc) == ((NR_THREADS * NR_STEPS) & 0xffu)          && atomic_load(&counter.us) == ((NR_THREADS * NR_STEPS) & 0xffffu)          && atomic_load(&counter.ui) == (NR_THREADS * NR_STEPS)  #ifdef HAS_64BITS          && atomic_load(&counter.ul) == (NR_THREADS * NR_STEPS)  #endif          )          printf("SUCCESS\n");
