    if (another_jump () == 71)      printf ("another_jump: okay\n");
    else      printf ("another_jump: wrong\n");
    if (three_way_jump(0, &i) == 1 && i == 43)      printf ("three_way_jump(0): okay\n");
    else      printf ("three_way_jump(0): wrong (i=%d)\n", i);
    if (three_way_jump(1, &i) == 3 && i == 42)      printf ("three_way_jump(1): okay\n");
    else      printf ("three_way_jump(1): wrong (i=%d)\n", i);
    if (three_way_jump(-1, &i) == 2 && i == 42)      printf ("three_way_jump(-1): okay\n");
    else      printf ("three_way_jump(-1): wrong (i=%d)\n", i);
    return 0;

}

