void SortSymbolTable(TCCState *s1)  {
      int i, j, k, n = 0;
      Elf32_Sym *p, *p2, *NewTable;
      char *name, *name2;
        NewTable = (Elf32_Sym *) tcc_malloc(nb_syms * sizeof(Elf32_Sym));
        p = (Elf32_Sym *) symtab_section->data;
          // find a file symbol, copy it over      // then scan the whole symbol list and copy any function      // symbols that match the file association        for (i = 0;
 i < nb_syms;
 i++) {
   if (p->st_info == 4) {
       name = (char *) symtab_section->link->data + p->st_name;
         // this is a file symbol, copy it over         NewTable[n++] = *p;
         p2 = (Elf32_Sym *) symtab_section->data;
         for (j = 0;
 j < nb_syms;
 j++) {
    if (p2->st_info == 0x12) {
        // this is a func symbol          name2 =     (char *) symtab_section->link->data + p2->st_name;
          // find the function data index          for (k = 0;
 k < nFuncs;
 k++) {
     if (strcmp(name2, Func[k]) == 0)         break;

}          if (k >= nFuncs) {
                          tcc_error("debug (sort) info can't find function: %s", name2);

}          if (strcmp(AssociatedFile[k], name) == 0) {
     // yes they match copy it over       NewTable[n++] = *p2;

}    
}    p2++;

}   
}   p++;

}        // now all the filename and func symbols should have been copied over      // copy all the rest over (all except file and funcs)        p = (Elf32_Sym *) symtab_section->data;
      for (i = 0;
 i < nb_syms;
 i++) {
   if (p->st_info != 4 && p->st_info != 0x12) {
       NewTable[n++] = *p;

}   p++;

}        if (n != nb_syms)   tcc_error("Internal Compiler error, debug info");
        // copy it all back        p = (Elf32_Sym *) symtab_section->data;
      for (i = 0;
 i < nb_syms;
 i++) {
   *p++ = NewTable[i];

}        tcc_free(NewTable);

}

int FindCoffSymbolIndex(TCCState *s1, const char *func_name)  {
      int i, n = 0;
      Elf32_Sym *p;
      char *name;
        p = (Elf32_Sym *) symtab_section->data;
        for (i = 0;
 i < nb_syms;
 i++) {
     name = (char *) symtab_section->link->data + p->st_name;
     if (p->st_info == 4) {
       // put a filename symbol       n++;

} else if (p->st_info == 0x12) {
         if (strcmp(func_name, name) == 0)    return n;
         n += 6;
         // put a Function Name         // now put aux info         // put a .bf         // now put aux info         // put a .ef         // now put aux info     
} else {
       n += 2;

}     p++;

}        return n;
   // total number of symbols  
}

int OutputTheSection(Section * sect)  {
      const char *s = sect->name;
        if (!strcmp(s, ".text"))   return 1;
      else if (!strcmp(s, ".data"))   return 1;
      else   return 0;

}

short int GetCoffFlags(const char *s)  {
      if (!strcmp(s, ".text"))   return STYP_TEXT | STYP_DATA | STYP_ALIGN | 0x400;
      else if (!strcmp(s, ".data"))   return STYP_DATA;
      else if (!strcmp(s, ".bss"))   return STYP_BSS;
      else if (!strcmp(s, ".stack"))   return STYP_BSS | STYP_ALIGN | 0x200;
      else if (!strcmp(s, ".cinit"))   return STYP_COPY | STYP_DATA | STYP_ALIGN | 0x200;
      else   return 0;

}

Section *FindSection(TCCState * s1, const char *sname)  {
      Section *s;
      int i;
        for (i = 1;
 i < s1->nb_sections;
 i++) {
   s = s1->sections[i];
     if (!strcmp(sname, s->name))       return s;

}        tcc_error("could not find section %s", sname);
      return 0;

}

