}  //              if (strcmp("_DAC_Buffer",name)==0)  // tktk  //                      name[0]=0;
     if (((csym.n_type & 0x30) == 0x20 && csym.n_sclass == 0x2) || ((csym.n_type & 0x30) == 0x30 && csym.n_sclass == 0x2) || (csym.n_type == 0x4 && csym.n_sclass == 0x2) || (csym.n_type == 0x8 && csym.n_sclass == 0x2) || // structures       (csym.n_type == 0x18 && csym.n_sclass == 0x2) || // pointer to structure       (csym.n_type == 0x7 && csym.n_sclass == 0x2) || // doubles       (csym.n_type == 0x6 && csym.n_sclass == 0x2)) // floats   {
       // strip off any leading underscore (except for other main routine)         if (name[0] == '_' && strcmp(name, "_main") != 0)    name++;
