static void put_stabs(TCCState *s1, const char *str, int type, int other, int desc,                        unsigned long value)  {
      Stab_Sym *sym;
        unsigned offset;
      if (type == N_SLINE          && (offset = stab_section->data_offset)          && (sym = (Stab_Sym*)(stab_section->data + offset) - 1)          && sym->n_type == type          && sym->n_value == value) {
          /* just update line_number in previous entry */          sym->n_desc = desc;
          return;

}        sym = section_ptr_add(stab_section, sizeof(Stab_Sym));
      if (str) {
          sym->n_strx = put_elf_str(stab_section->link, str);

} else {
          sym->n_strx = 0;

}      sym->n_type = type;
      sym->n_other = other;
      sym->n_desc = desc;
      sym->n_value = value;

}

static void put_stabs_r(TCCState *s1, const char *str, int type, int other, int desc,                          unsigned long value, Section *sec, int sym_index)  {
      put_elf_reloc(symtab_section, stab_section,                    stab_section->data_offset + 8,                    sizeof ((Stab_Sym*)0)->n_value == PTR_SIZE ? R_DATA_PTR : R_DATA_32,                    sym_index);
      put_stabs(s1, str, type, other, desc, value);

}

static void put_stabn(TCCState *s1, int type, int other, int desc, int value)  {
      put_stabs(s1, NULL, type, other, desc, value);

}

static int dwarf_get_section_sym(Section *s)  {
      TCCState *s1 = s->s1;
      return put_elf_sym(symtab_section, 0, 0,                         ELFW(ST_INFO)(STB_LOCAL, STT_SECTION), 0,                         s->sh_num, NULL);

}

static void dwarf_reloc(Section *s, int sym, int rel)  {
      TCCState *s1 = s->s1;
      put_elf_reloca(symtab_section, s, s->data_offset, rel, sym, 0);

}

static void dwarf_string(Section *s, Section *dw, int sym, const char *str)  {
      TCCState *s1 = s->s1;
      int offset, len;
      char *ptr;
        len = strlen(str) + 1;
      offset = dw->data_offset;
      ptr = section_ptr_add(dw, len);
      memmove(ptr, str, len);
      put_elf_reloca(symtab_section, s, s->data_offset, R_DATA_32DW, sym,                     PTR_SIZE == 4 ? 0 : offset);
      dwarf_data4(s, PTR_SIZE == 4 ? offset : 0);

}

static void dwarf_strp(Section *s, const char *str)  {
      TCCState *s1 = s->s1;
      dwarf_string(s, dwarf_str_section, dwarf_sym.str, str);

}

static void dwarf_line_strp(Section *s, const char *str)  {
      TCCState *s1 = s->s1;
      dwarf_string(s, dwarf_line_str_section, dwarf_sym.line_str, str);

}

static void dwarf_line_op(TCCState *s1, unsigned char op)  {
      if (dwarf_line.line_size >= dwarf_line.line_max_size) {
   dwarf_line.line_max_size += 1024;
   dwarf_line.line_data =       (unsigned char *)tcc_realloc(dwarf_line.line_data,        dwarf_line.line_max_size);

}      dwarf_line.line_data[dwarf_line.line_size++] = op;

}

static void dwarf_file(TCCState *s1)  {
      int i, j;
      char *filename;
      int index_offset = s1->dwarf < 5;
        if (!strcmp(file->filename, "<command line>")) {
          dwarf_line.cur_file = 1;
   return;

}      filename = strrchr(file->filename, '/');
      if (filename == NULL) {
          for (i = 1;
 i < dwarf_line.filename_size;
 i++)              if (dwarf_line.filename_table[i].dir_entry == 0 &&    strcmp(dwarf_line.filename_table[i].name,           file->filename) == 0) {
        dwarf_line.cur_file = i + index_offset;
               return;

}   i = -index_offset;
   filename = file->filename;

}      else {
   char *undo = filename;
   char *dir = file->filename;
     *filename++ = '\0';
          for (i = 0;
 i < dwarf_line.dir_size;
 i++)       if (strcmp(dwarf_line.dir_table[i], dir) == 0) {
    for (j = 1;
 j < dwarf_line.filename_size;
 j++)        if (dwarf_line.filename_table[j].dir_entry - index_offset     == i &&     strcmp(dwarf_line.filename_table[j].name,            filename) == 0) {
     *undo = '/';
            dwarf_line.cur_file = j + index_offset;
     return;

}    break;

}   if (i == dwarf_line.dir_size) {
       dwarf_line.dir_size++;
       dwarf_line.dir_table =                  (char **) tcc_realloc(dwarf_line.dir_table,                                        dwarf_line.dir_size *                                        sizeof (char *));
              dwarf_line.dir_table[i] = tcc_strdup(dir);

}   *undo = '/';

}      dwarf_line.filename_table =          (struct dwarf_filename_struct *)          tcc_realloc(dwarf_line.filename_table,                      (dwarf_line.filename_size + 1) *                      sizeof (struct dwarf_filename_struct));
      dwarf_line.filename_table[dwarf_line.filename_size].dir_entry =   i + index_offset;
      dwarf_line.filename_table[dwarf_line.filename_size].name =          tcc_strdup(filename);
      dwarf_line.cur_file = dwarf_line.filename_size++ + index_offset;
      return;

}

static int dwarf_sleb128_size (long long value)  {
      int size =  0;
      long long end = value >> 63;
      unsigned char last = end & 0x40;
      unsigned char byte;
        do {
          byte = value & 0x7f;
          value >>= 7;
          size++;

} while (value != end || (byte & 0x40) != last);
      return size;

}

static void dwarf_uleb128 (Section *s, unsigned long long value)  {
      do {
          unsigned char byte = value & 0x7f;
            value >>= 7;
          dwarf_data1(s, byte | (value ? 0x80 : 0));

} while (value != 0);

}

static void dwarf_sleb128 (Section *s, long long value)  {
      int more;
      long long end = value >> 63;
      unsigned char last = end & 0x40;
        do {
          unsigned char byte = value & 0x7f;
            value >>= 7;
   more = value != end || (byte & 0x40) != last;
          dwarf_data1(s, byte | (0x80 * more));

} while (more);

}

static void dwarf_uleb128_op (TCCState *s1, unsigned long long value)  {
      do {
          unsigned char byte = value & 0x7f;
            value >>= 7;
          dwarf_line_op(s1, byte | (value ? 0x80 : 0));

} while (value != 0);

}

static void dwarf_sleb128_op (TCCState *s1, long long value)  {
      int more;
      long long end = value >> 63;
      unsigned char last = end & 0x40;
        do {
          unsigned char byte = value & 0x7f;
            value >>= 7;
          more = value != end || (byte & 0x40) != last;
          dwarf_line_op(s1, byte | (0x80 * more));

} while (more);

}

ST_FUNC void tcc_debug_start(TCCState *s1)  {
      int i;
      char buf[512];
      char *filename;
        /* we might currently #include the <command-line> */      filename = file->prev ? file->prev->filename : file->filename;
        /* an elf symbol of type STT_FILE must be put so that STB_LOCAL         symbols can be safely used */      put_elf_sym(symtab_section, 0, 0,                  ELFW(ST_INFO)(STB_LOCAL, STT_FILE), 0,                  SHN_ABS, filename);
        if (s1->do_debug) {
            new_file = last_line_num = 0;
          debug_next_type = N_DEFAULT_DEBUG;
          debug_hash = NULL;
          debug_anon_hash = NULL;
          n_debug_hash = 0;
          n_debug_anon_hash = 0;
            getcwd(buf, sizeof(buf));
  #ifdef _WIN32          normalize_slashes(buf);
  #endif            if (s1->dwarf) {
              int start_abbrev;
              unsigned char *ptr;
       char *undo;
                /* dwarf_abbrev */              start_abbrev = dwarf_abbrev_section->data_offset;
              ptr = section_ptr_add(dwarf_abbrev_section, sizeof(dwarf_abbrev_init));
              memcpy(ptr, dwarf_abbrev_init, sizeof(dwarf_abbrev_init));
                if (s1->dwarf < 5) {
               while (*ptr) {
                   ptr += 3;
                   while (*ptr) {
                       if (ptr[1] == DW_FORM_line_strp)                    ptr[1] = DW_FORM_strp;
            if (s1->dwarf < 4) {
         /* These are compatable for DW_TAG_compile_unit            DW_AT_stmt_list. */         if  (ptr[1] == DW_FORM_sec_offset)              ptr[1] = DW_FORM_data4;
         /* This code uses only size < 0x80 so these are            compatible. */         if  (ptr[1] == DW_FORM_exprloc)              ptr[1] = DW_FORM_block1;

}                       ptr += 2;

}        ptr += 2;

}              
}                dwarf_sym.info = dwarf_get_section_sym(dwarf_info_section);
              dwarf_sym.abbrev = dwarf_get_section_sym(dwarf_abbrev_section);
              dwarf_sym.line = dwarf_get_section_sym(dwarf_line_section);
              dwarf_sym.str = dwarf_get_section_sym(dwarf_str_section);
              if (tcc_state->dwarf >= 5)               dwarf_sym.line_str = dwarf_get_section_sym(dwarf_line_str_section);
              else {
               dwarf_line_str_section = dwarf_str_section;
                  dwarf_sym.line_str = dwarf_sym.str;

}              section_sym = dwarf_get_section_sym(text_section);
                /* dwarf_info */              dwarf_info.start = dwarf_info_section->data_offset;
              dwarf_data4(dwarf_info_section, 0);
 // size              dwarf_data2(dwarf_info_section, s1->dwarf);
 // version              if (s1->dwarf >= 5) {
                  dwarf_data1(dwarf_info_section, DW_UT_compile);
 // unit type                  dwarf_data1(dwarf_info_section, PTR_SIZE);
                  dwarf_reloc(dwarf_info_section, dwarf_sym.abbrev, R_DATA_32DW);
                  dwarf_data4(dwarf_info_section, start_abbrev);

}              else {
                  dwarf_reloc(dwarf_info_section, dwarf_sym.abbrev, R_DATA_32DW);
                  dwarf_data4(dwarf_info_section, start_abbrev);
                  dwarf_data1(dwarf_info_section, PTR_SIZE);

}                dwarf_data1(dwarf_info_section, DWARF_ABBREV_COMPILE_UNIT);
              dwarf_strp(dwarf_info_section, "tcc " TCC_VERSION);
              dwarf_data1(dwarf_info_section, s1->cversion == 201112 ? DW_LANG_C11 : DW_LANG_C99);
              dwarf_line_strp(dwarf_info_section, filename);
              dwarf_line_strp(dwarf_info_section, buf);
              dwarf_reloc(dwarf_info_section, section_sym, R_DATA_PTR);
  #if PTR_SIZE == 4              dwarf_data4(dwarf_info_section, ind);
 // low pc              dwarf_data4(dwarf_info_section, 0);
 // high pc  #else              dwarf_data8(dwarf_info_section, ind);
 // low pc              dwarf_data8(dwarf_info_section, 0);
 // high pc  #endif              dwarf_reloc(dwarf_info_section, dwarf_sym.line, R_DATA_32DW);
              dwarf_data4(dwarf_info_section, dwarf_line_section->data_offset);
 // stmt_list                /* dwarf_line */              dwarf_line.start = dwarf_line_section->data_offset;
              dwarf_data4(dwarf_line_section, 0);
 // length              dwarf_data2(dwarf_line_section, s1->dwarf);
 // version              if (s1->dwarf >= 5) {
                  dwarf_data1(dwarf_line_section, PTR_SIZE);
 // address size                  dwarf_data1(dwarf_line_section, 0);
 // segment selector              
}              dwarf_data4(dwarf_line_section, 0);
 // prologue Length              dwarf_data1(dwarf_line_section, DWARF_MIN_INSTR_LEN);
              if (s1->dwarf >= 4)                  dwarf_data1(dwarf_line_section, 1);
 // maximum ops per instruction              dwarf_data1(dwarf_line_section, 1);
 // Initial value of 'is_stmt'              dwarf_data1(dwarf_line_section, DWARF_LINE_BASE);
              dwarf_data1(dwarf_line_section, DWARF_LINE_RANGE);
              dwarf_data1(dwarf_line_section, DWARF_OPCODE_BASE);
              ptr = section_ptr_add(dwarf_line_section, sizeof(dwarf_line_opcodes));
              memcpy(ptr, dwarf_line_opcodes, sizeof(dwarf_line_opcodes));
       undo = strrchr(filename, '/');
       if (undo)    *undo = 0;
              dwarf_line.dir_size = 1 + (undo != NULL);
              dwarf_line.dir_table = (char **) tcc_malloc(sizeof (char *) *         dwarf_line.dir_size);
              dwarf_line.dir_table[0] = tcc_strdup(buf);
       if (undo)                  dwarf_line.dir_table[1] = tcc_strdup(filename);
              dwarf_line.filename_size = 2;
              dwarf_line.filename_table =               (struct dwarf_filename_struct *)               tcc_malloc(2*sizeof (struct dwarf_filename_struct));
              dwarf_line.filename_table[0].dir_entry = 0;
       if (undo) {
                  dwarf_line.filename_table[0].name = tcc_strdup(undo + 1);
                  dwarf_line.filename_table[1].dir_entry = 1;
                  dwarf_line.filename_table[1].name = tcc_strdup(undo + 1);
    *undo = '/';

}       else {
                  dwarf_line.filename_table[0].name = tcc_strdup(filename);
                  dwarf_line.filename_table[1].dir_entry = 0;
                  dwarf_line.filename_table[1].name = tcc_strdup(filename);

}              dwarf_line.line_size = dwarf_line.line_max_size = 0;
              dwarf_line.line_data = NULL;
              dwarf_line.cur_file = 1;
              dwarf_line.last_file = 0;
              dwarf_line.last_pc = 0;
              dwarf_line.last_line = 1;
              dwarf_line_op(s1, 0);
 // extended              dwarf_uleb128_op(s1, 1 + PTR_SIZE);
 // extended size              dwarf_line_op(s1, DW_LNE_set_address);
              for (i = 0;
 i < PTR_SIZE;
 i++)               dwarf_line_op(s1, 0);
              memset(&dwarf_info.base_type_used, 0, sizeof(dwarf_info.base_type_used));

}          else          {
              /* file info: full path + filename */              pstrcat(buf, sizeof(buf), "/");
              section_sym = put_elf_sym(symtab_section, 0, 0,                                        ELFW(ST_INFO)(STB_LOCAL, STT_SECTION), 0,                                        text_section->sh_num, NULL);
              put_stabs_r(s1, buf, N_SO, 0, 0,                          text_section->data_offset, text_section, section_sym);
              put_stabs_r(s1, filename, N_SO, 0, 0,                          text_section->data_offset, text_section, section_sym);
              for (i = 0;
 i < N_DEFAULT_DEBUG;
 i++)                  put_stabs(s1, default_debug[i].name, N_LSYM, 0, 0, 0);

}          /* we're currently 'including' the <command line> */          tcc_debug_bincl(s1);

}  
}

ST_FUNC void tcc_debug_end(TCCState *s1)  {
      if (!s1->do_debug || debug_next_type == 0)          return;
        if (debug_info_root)          tcc_debug_funcend(s1, 0);
 /* free stuff in case of errors */        if (s1->dwarf) {
   int i, j;
   int start_aranges;
   unsigned char *ptr;
   int text_size = text_section->data_offset;
     /* dwarf_info */   for (i = 0;
 i < n_debug_anon_hash;
 i++) {
       Sym *t = debug_anon_hash[i].type;
       int pos = dwarf_info_section->data_offset;
         dwarf_data1(dwarf_info_section,                          IS_UNION (t->type.t) ? DWARF_ABBREV_UNION_EMPTY_TYPE                                               : DWARF_ABBREV_STRUCTURE_EMPTY_TYPE);
              dwarf_strp(dwarf_info_section,                         (t->v & ~SYM_STRUCT) >= SYM_FIRST_ANOM                         ? "" : get_tok_str(t->v, NULL));
              dwarf_uleb128(dwarf_info_section, 0);
              dwarf_uleb128(dwarf_info_section, dwarf_line.cur_file);
              dwarf_uleb128(dwarf_info_section, file->line_num);
       for (j = 0;
 j < debug_anon_hash[i].n_debug_type;
 j++)    write32le(dwarf_info_section->data +       debug_anon_hash[i].debug_type[j],       pos - dwarf_info.start);
       tcc_free (debug_anon_hash[i].debug_type);

}   tcc_free (debug_anon_hash);
   dwarf_data1(dwarf_info_section, 0);
   ptr = dwarf_info_section->data + dwarf_info.start;
   write32le(ptr, dwarf_info_section->data_offset - dwarf_info.start - 4);
   write32le(ptr + 25 + (s1->dwarf >= 5) + PTR_SIZE, text_size);
     /* dwarf_aranges */   start_aranges = dwarf_aranges_section->data_offset;
   dwarf_data4(dwarf_aranges_section, 0);
 // size   dwarf_data2(dwarf_aranges_section, 2);
 // version   dwarf_reloc(dwarf_aranges_section, dwarf_sym.info, R_DATA_32DW);
   dwarf_data4(dwarf_aranges_section, 0);
 // dwarf_info  #if PTR_SIZE == 4   dwarf_data1(dwarf_aranges_section, 4);
 // address size  #else   dwarf_data1(dwarf_aranges_section, 8);
 // address size  #endif   dwarf_data1(dwarf_aranges_section, 0);
 // segment selector size   dwarf_data4(dwarf_aranges_section, 0);
 // padding   dwarf_reloc(dwarf_aranges_section, section_sym, R_DATA_PTR);
  #if PTR_SIZE == 4   dwarf_data4(dwarf_aranges_section, 0);
 // Begin   dwarf_data4(dwarf_aranges_section, text_size);
 // End   dwarf_data4(dwarf_aranges_section, 0);
 // End list   dwarf_data4(dwarf_aranges_section, 0);
 // End list  #else   dwarf_data8(dwarf_aranges_section, 0);
 // Begin   dwarf_data8(dwarf_aranges_section, text_size);
 // End   dwarf_data8(dwarf_aranges_section, 0);
 // End list   dwarf_data8(dwarf_aranges_section, 0);
 // End list  #endif   ptr = dwarf_aranges_section->data + start_aranges;
   write32le(ptr, dwarf_aranges_section->data_offset - start_aranges - 4);
     /* dwarf_line */   if (s1->dwarf >= 5) {
       dwarf_data1(dwarf_line_section, 1);
 /* col */       dwarf_uleb128(dwarf_line_section, DW_LNCT_path);
       dwarf_uleb128(dwarf_line_section, DW_FORM_line_strp);
       dwarf_uleb128(dwarf_line_section, dwarf_line.dir_size);
       for (i = 0;
 i < dwarf_line.dir_size;
 i++)           dwarf_line_strp(dwarf_line_section, dwarf_line.dir_table[i]);
       dwarf_data1(dwarf_line_section, 2);
 /* col */       dwarf_uleb128(dwarf_line_section, DW_LNCT_path);
       dwarf_uleb128(dwarf_line_section, DW_FORM_line_strp);
       dwarf_uleb128(dwarf_line_section, DW_LNCT_directory_index);
       dwarf_uleb128(dwarf_line_section, DW_FORM_udata);
       dwarf_uleb128(dwarf_line_section, dwarf_line.filename_size);
       for (i = 0;
 i < dwarf_line.filename_size;
 i++) {
           dwarf_line_strp(dwarf_line_section,      dwarf_line.filename_table[i].name);
           dwarf_uleb128(dwarf_line_section,           dwarf_line.filename_table[i].dir_entry);

}   
}   else {
       int len;
         for (i = 0;
 i < dwarf_line.dir_size;
 i++) {
           len = strlen(dwarf_line.dir_table[i]) + 1;
           ptr = section_ptr_add(dwarf_line_section, len);
           memmove(ptr, dwarf_line.dir_table[i], len);

}       dwarf_data1(dwarf_line_section, 0);
 /* end dir */       for (i = 0;
 i < dwarf_line.filename_size;
 i++) {
           len = strlen(dwarf_line.filename_table[i].name) + 1;
           ptr = section_ptr_add(dwarf_line_section, len);
           memmove(ptr, dwarf_line.filename_table[i].name, len);
           dwarf_uleb128(dwarf_line_section,           dwarf_line.filename_table[i].dir_entry);
           dwarf_uleb128(dwarf_line_section, 0);
 /* time */           dwarf_uleb128(dwarf_line_section, 0);
 /* size */       
}       dwarf_data1(dwarf_line_section, 0);
 /* end file */   
}   for (i = 0;
 i < dwarf_line.dir_size;
 i++)       tcc_free(dwarf_line.dir_table[i]);
   tcc_free(dwarf_line.dir_table);
   for (i = 0;
 i < dwarf_line.filename_size;
 i++)       tcc_free(dwarf_line.filename_table[i].name);
   tcc_free(dwarf_line.filename_table);
     dwarf_line_op(s1, 0);
 // extended   dwarf_uleb128_op(s1, 1);
 // extended size   dwarf_line_op(s1, DW_LNE_end_sequence);
   i = (s1->dwarf >= 5) * 2;
   write32le(&dwarf_line_section->data[dwarf_line.start + 6 + i],      dwarf_line_section->data_offset - dwarf_line.start - (10 + i));
   section_ptr_add(dwarf_line_section, 3);
   dwarf_reloc(dwarf_line_section, section_sym, R_DATA_PTR);
   ptr = section_ptr_add(dwarf_line_section, dwarf_line.line_size - 3);
   memmove(ptr - 3, dwarf_line.line_data, dwarf_line.line_size);
   tcc_free(dwarf_line.line_data);
   write32le(dwarf_line_section->data + dwarf_line.start,      dwarf_line_section->data_offset - dwarf_line.start - 4);

}      else      {
          put_stabs_r(s1, NULL, N_SO, 0, 0,                      text_section->data_offset, text_section, section_sym);

}      tcc_free(debug_hash);
      debug_next_type = 0;

}

static BufferedFile* put_new_file(TCCState *s1)  {
      BufferedFile *f = file;
      /* use upper file if from inline ":asm:" */      if (f->filename[0] == ':')          f = f->prev;
      if (f && new_file) {
          new_file = last_line_num = 0;
          if (s1->dwarf)              dwarf_file(s1);
          else              put_stabs_r(s1, f->filename, N_SOL, 0, 0, ind, text_section, section_sym);

}      return f;

}

ST_FUNC void tcc_debug_newfile(TCCState *s1)  {
      if (!s1->do_debug)          return;
      if (s1->dwarf)          dwarf_file(s1);
      new_file = 1;

}

ST_FUNC void tcc_debug_bincl(TCCState *s1)  {
      if (!s1->do_debug)          return;
      if (s1->dwarf)          dwarf_file(s1);
      else          put_stabs(s1, file->filename, N_BINCL, 0, 0, 0);
      new_file = 1;

}

ST_FUNC void tcc_debug_eincl(TCCState *s1)  {
      if (!s1->do_debug)          return;
      if (s1->dwarf)          dwarf_file(s1);
      else          put_stabn(s1, N_EINCL, 0, 0, 0);
      new_file = 1;

}

ST_FUNC void tcc_debug_line(TCCState *s1)  {
      BufferedFile *f;
        if (!s1->do_debug)          return;
      if (cur_text_section != text_section || nocode_wanted)          return;
      f = put_new_file(s1);
      if (!f)          return;
      if (last_line_num == f->line_num)          return;
      last_line_num = f->line_num;
        if (s1->dwarf) {
   int len_pc = (ind - dwarf_line.last_pc) / DWARF_MIN_INSTR_LEN;
   int len_line = f->line_num - dwarf_line.last_line;
   int n = len_pc * DWARF_LINE_RANGE + len_line + DWARF_OPCODE_BASE - DWARF_LINE_BASE;
     if (dwarf_line.cur_file != dwarf_line.last_file) {
       dwarf_line.last_file = dwarf_line.cur_file;
       dwarf_line_op(s1, DW_LNS_set_file);
       dwarf_uleb128_op(s1, dwarf_line.cur_file);

}   if (len_pc &&       len_line >= DWARF_LINE_BASE && len_line <= (DWARF_OPCODE_BASE + DWARF_LINE_BASE) &&       n >= DWARF_OPCODE_BASE && n <= 255)              dwarf_line_op(s1, n);
   else {
       if (len_pc) {
           n = len_pc * DWARF_LINE_RANGE + 0 + DWARF_OPCODE_BASE - DWARF_LINE_BASE;
           if (n >= DWARF_OPCODE_BASE && n <= 255)                      dwarf_line_op(s1, n);
    else {
               dwarf_line_op(s1, DW_LNS_advance_pc);
        dwarf_uleb128_op(s1, len_pc);

}       
}       if (len_line) {
           n = 0 * DWARF_LINE_RANGE + len_line + DWARF_OPCODE_BASE - DWARF_LINE_BASE;
           if (len_line >= DWARF_LINE_BASE && len_line <= (DWARF_OPCODE_BASE + DWARF_LINE_BASE) &&        n >= DWARF_OPCODE_BASE && n <= 255)               dwarf_line_op(s1, n);
    else {
               dwarf_line_op(s1, DW_LNS_advance_line);
        dwarf_sleb128_op(s1, len_line);

}       
}   
}   dwarf_line.last_pc = ind;
   dwarf_line.last_line = f->line_num;

}      else      {
   if (func_ind != -1) {
              put_stabn(s1, N_SLINE, 0, f->line_num, ind - func_ind);

} else {
              /* from tcc_assemble */              put_stabs_r(s1, NULL, N_SLINE, 0, f->line_num, ind, text_section, section_sym);

}      
}  
}

static void tcc_debug_stabs (TCCState *s1, const char *str, int type, unsigned long value,                               Section *sec, int sym_index, int info)  {
      struct debug_sym *s;
        if (debug_info) {
          debug_info->sym =              (struct debug_sym *)tcc_realloc (debug_info->sym,                                               sizeof(struct debug_sym) *                                               (debug_info->n_sym + 1));
          s = debug_info->sym + debug_info->n_sym++;
          s->type = type;
          s->value = value;
          s->str = tcc_strdup(str);
          s->sec = sec;
          s->sym_index = sym_index;
          s->info = info;
          s->file = dwarf_line.cur_file;
          s->line = file->line_num;

}      else if (sec)          put_stabs_r (s1, str, type, 0, 0, value, sec, sym_index);
      else          put_stabs (s1, str, type, 0, 0, value);

}

ST_FUNC void tcc_debug_stabn(TCCState *s1, int type, int value)  {
      if (!s1->do_debug)          return;
      if (type == N_LBRAC) {
          struct _debug_info *info =              (struct _debug_info *) tcc_mallocz(sizeof (*info));
            info->start = value;
          info->parent = debug_info;
          if (debug_info) {
              if (debug_info->child) {
                  if (debug_info->child->last)                      debug_info->child->last->next = info;
                  else                      debug_info->child->next = info;
                  debug_info->child->last = info;

}              else                  debug_info->child = info;

}          else              debug_info_root = info;
          debug_info = info;

}      else {
          debug_info->end = value;
          debug_info = debug_info->parent;

}  
}

static int tcc_debug_find(TCCState *s1, Sym *t, int dwarf)  {
      int i;
        if (!debug_info && dwarf &&   (t->type.t & VT_BTYPE) == VT_STRUCT && t->c == -1) {
   for (i = 0;
 i < n_debug_anon_hash;
 i++)              if (t == debug_anon_hash[i].type)    return 0;
   debug_anon_hash = (struct _debug_anon_hash *)              tcc_realloc (debug_anon_hash,                           (n_debug_anon_hash + 1) * sizeof(*debug_anon_hash));
          debug_anon_hash[n_debug_anon_hash].n_debug_type = 0;
          debug_anon_hash[n_debug_anon_hash].debug_type = NULL;
          debug_anon_hash[n_debug_anon_hash++].type = t;
   return 0;

}      for (i = 0;
 i < n_debug_hash;
 i++)          if (t == debug_hash[i].type)       return debug_hash[i].debug_type;
      return -1;

}

static void tcc_debug_check_anon(TCCState *s1, Sym *t, int debug_type)  {
      int i;
        if (!debug_info && (t->type.t & VT_BTYPE) == VT_STRUCT && t->type.ref->c == -1)   for (i = 0;
 i < n_debug_anon_hash;
 i++)              if (t->type.ref == debug_anon_hash[i].type) {
    debug_anon_hash[i].debug_type =        tcc_realloc(debug_anon_hash[i].debug_type,      (debug_anon_hash[i].n_debug_type + 1) * sizeof(int));
    debug_anon_hash[i].debug_type[debug_anon_hash[i].n_debug_type++] =        debug_type;

}  
}

ST_FUNC void tcc_debug_fix_anon(TCCState *s1, CType *t)  {
      int i, j, debug_type;
        if (!(s1->do_debug & 2) || !s1->dwarf || debug_info)   return;
        if ((t->t & VT_BTYPE) == VT_STRUCT && t->ref->c != -1)   for (i = 0;
 i < n_debug_anon_hash;
 i++)       if (t->ref == debug_anon_hash[i].type) {
    Sym sym = {
0
};
 sym .type = *t;
      /* Trick to not hash this struct */    debug_info = (struct _debug_info *) t;
    debug_type = tcc_get_dwarf_info(s1, &sym);
    debug_info = NULL;
    for (j = 0;
 j < debug_anon_hash[i].n_debug_type;
 j++)        write32le(dwarf_info_section->data +           debug_anon_hash[i].debug_type[j],           debug_type - dwarf_info.start);
    tcc_free(debug_anon_hash[i].debug_type);
    n_debug_anon_hash--;
    for (;
 i < n_debug_anon_hash;
 i++)        debug_anon_hash[i] = debug_anon_hash[i + 1];

}  
}

static int tcc_debug_add(TCCState *s1, Sym *t, int dwarf)  {
      int offset = dwarf ? dwarf_info_section->data_offset : ++debug_next_type;
      debug_hash = (struct _debug_hash *)   tcc_realloc (debug_hash,         (n_debug_hash + 1) * sizeof(*debug_hash));
      debug_hash[n_debug_hash].debug_type = offset;
      debug_hash[n_debug_hash++].type = t;
      return offset;

}

static void tcc_debug_remove(TCCState *s1, Sym *t)  {
      int i;
        for (i = 0;
 i < n_debug_hash;
 i++)          if (t == debug_hash[i].type) {
       n_debug_hash--;
       for (;
 i < n_debug_hash;
 i++)    debug_hash[i] = debug_hash[i+1];

}  
}

static void tcc_get_debug_info(TCCState *s1, Sym *s, CString *result)  {
      int type;
