     debug_type = tcc_debug_find(s1, t, 0);
   if (debug_type == -1) {
       debug_type = tcc_debug_add(s1, t, 0);
              cstr_new (&str);
              cstr_printf (&str, "%s:T%d=e",                           (t->v & ~SYM_STRUCT) >= SYM_FIRST_ANOM                           ? "" : get_tok_str(t->v, NULL),                           debug_type);
              while (t->next) {
                  t = t->next;
                  cstr_printf (&str, "%s:",                               (t->v & ~SYM_FIELD) >= SYM_FIRST_ANOM                               ? "" : get_tok_str(t->v, NULL));
                  cstr_printf (&str, e->type.t & VT_UNSIGNED ? "%u," : "%d,",                               (int)t->enum_val);

}              cstr_printf (&str, ";
");
              tcc_debug_stabs(s1, str.data, N_LSYM, 0, NULL, 0, 0);
              cstr_free (&str);
              if (debug_info)                  tcc_debug_remove(s1, e);

}      
}      else if ((type & VT_BTYPE) != VT_FUNC) {
          type &= ~VT_STRUCT_MASK;
          for (debug_type = 1;
 debug_type <= N_DEFAULT_DEBUG;
 debug_type++)              if (default_debug[debug_type - 1].type == type)                  break;
          if (debug_type > N_DEFAULT_DEBUG)              return;

}      if (n > 0)          cstr_printf (result, "%d=", ++debug_next_type);
      t = s;
      for (;
;
) {
          type = t->type.t & ~(VT_STORAGE | VT_CONSTANT | VT_VOLATILE | VT_VLA);
          if ((type & VT_BTYPE) != VT_BYTE)              type &= ~VT_DEFSIGN;
          if (type == VT_PTR)              cstr_printf (result, "%d=*", ++debug_next_type);
          else if (type == (VT_PTR | VT_ARRAY))              cstr_printf (result, "%d=ar1;
0;
%d;
",                           ++debug_next_type, t->type.ref->c - 1);
          else if (type == VT_FUNC) {
