}          else              break;
          t = t->type.ref;

}      cstr_printf (result, "%d", debug_type);

}

static int tcc_get_dwarf_info(TCCState *s1, Sym *s)  {
      int type;
      int debug_type = -1;
      Sym *e, *t = s;
      int i;
      int last_pos = -1;
