}       tcc_free(pos_type);
       if (debug_info)    tcc_debug_remove(s1, t);

}      
}      else if (IS_ENUM(type)) {
          t = t->type.ref;
   debug_type = tcc_debug_find(s1, t, 1);
   if (debug_type == -1) {
