           dwarf_strp(dwarf_info_section,                             (e->v & ~SYM_FIELD) >= SYM_FIRST_ANOM                             ? "" : get_tok_str(e->v, NULL));
    if (type & VT_UNSIGNED)               dwarf_uleb128(dwarf_info_section, e->enum_val);
    else               dwarf_sleb128(dwarf_info_section, e->enum_val);

}       dwarf_data1(dwarf_info_section, 0);
       write32le(dwarf_info_section->data + pos_sib,          dwarf_info_section->data_offset - dwarf_info.start);
       if (debug_info)    tcc_debug_remove(s1, t);

}      
}      else if ((type & VT_BTYPE) != VT_FUNC) {
          type &= ~VT_STRUCT_MASK;
          for (i = 1;
 i <= N_DEFAULT_DEBUG;
 i++)              if (default_debug[i - 1].type == type)                  break;
          if (i > N_DEFAULT_DEBUG)              return 0;
   debug_type = dwarf_info.base_type_used[i - 1];
   if (debug_type == 0) {
       char name[100];
         debug_type = dwarf_info_section->data_offset;
       dwarf_data1(dwarf_info_section, DWARF_ABBREV_BASE_TYPE);
