static void tcc_debug_finish (TCCState *s1, struct _debug_info *cur)  {
      while (cur) {
          struct _debug_info *next = cur->next;
          int i;
            if (s1->dwarf) {
                for (i = cur->n_sym - 1;
 i >= 0;
 i--) {
                  struct debug_sym *s = &cur->sym[i];
      dwarf_data1(dwarf_info_section,                              s->type == N_PSYM         ? DWARF_ABBREV_FORMAL_PARAMETER         : s->type == N_GSYM                              ? DWARF_ABBREV_VARIABLE_EXTERNAL                              : s->type == N_STSYM         ? DWARF_ABBREV_VARIABLE_STATIC         : DWARF_ABBREV_VARIABLE_LOCAL);
                  dwarf_strp(dwarf_info_section, s->str);
    if (s->type == N_GSYM || s->type == N_STSYM) {
                      dwarf_uleb128(dwarf_info_section, s->file);
                      dwarf_uleb128(dwarf_info_section, s->line);

}                  dwarf_data4(dwarf_info_section, s->info - dwarf_info.start);
    if (s->type == N_GSYM || s->type == N_STSYM) {
        /* global/static */        if (s->type == N_GSYM)                          dwarf_data1(dwarf_info_section, 1);
                      dwarf_data1(dwarf_info_section, PTR_SIZE + 1);
                      dwarf_data1(dwarf_info_section, DW_OP_addr);
        if (s->type == N_STSYM)            dwarf_reloc(dwarf_info_section, section_sym, R_DATA_PTR);
  #if PTR_SIZE == 4                      dwarf_data4(dwarf_info_section, s->value);
  #else                      dwarf_data8(dwarf_info_section, s->value);
  #endif    
}    else {
        /* param/local */                      dwarf_data1(dwarf_info_section, dwarf_sleb128_size(s->value) + 1);
                      dwarf_data1(dwarf_info_section, DW_OP_fbreg);
                      dwarf_sleb128(dwarf_info_section, s->value);

}    tcc_free (s->str);

}              tcc_free (cur->sym);
              dwarf_data1(dwarf_info_section,     cur->child ? DWARF_ABBREV_LEXICAL_BLOCK                : DWARF_ABBREV_LEXICAL_EMPTY_BLOCK);
              dwarf_reloc(dwarf_info_section, section_sym, R_DATA_PTR);
  #if PTR_SIZE == 4              dwarf_data4(dwarf_info_section, func_ind + cur->start);
              dwarf_data4(dwarf_info_section, cur->end - cur->start);
  #else              dwarf_data8(dwarf_info_section, func_ind + cur->start);
              dwarf_data8(dwarf_info_section, cur->end - cur->start);
  #endif              tcc_debug_finish (s1, cur->child);
       if (cur->child)                  dwarf_data1(dwarf_info_section, 0);

}          else          {
              for (i = 0;
 i < cur->n_sym;
 i++) {
                  struct debug_sym *s = &cur->sym[i];
                    if (s->sec)                      put_stabs_r(s1, s->str, s->type, 0, 0, s->value,                                  s->sec, s->sym_index);
                  else                      put_stabs(s1, s->str, s->type, 0, 0, s->value);
                  tcc_free (s->str);

}              tcc_free (cur->sym);
              put_stabn(s1, N_LBRAC, 0, 0, cur->start);
              tcc_debug_finish (s1, cur->child);
              put_stabn(s1, N_RBRAC, 0, 0, cur->end);

}          tcc_free (cur);
          cur = next;

}  
}

ST_FUNC void tcc_add_debug_info(TCCState *s1, int param, Sym *s, Sym *e)  {
      CString debug_str;
        if (!(s1->do_debug & 2))          return;
        cstr_new (&debug_str);
      for (;
 s != e;
 s = s->prev) {
          if (!s->v || (s->r & VT_VALMASK) != VT_LOCAL)              continue;
   if (s1->dwarf) {
       tcc_debug_stabs(s1, get_tok_str(s->v, NULL),         param ? N_PSYM : N_LSYM, s->c, NULL, 0,         tcc_get_dwarf_info(s1, s));

}   else          {
              cstr_reset (&debug_str);
              cstr_printf (&debug_str, "%s:%s", get_tok_str(s->v, NULL),      param ? "p" : "");
              tcc_get_debug_info(s1, s, &debug_str);
              tcc_debug_stabs(s1, debug_str.data, param ? N_PSYM : N_LSYM,         s->c, NULL, 0, 0);

}      
}      cstr_free (&debug_str);

}

