   if (s1->do_backtrace) {
       int i, len;
         dwarf_line_op(s1, 0);
 // extended       dwarf_uleb128_op(s1, strlen(funcname) + 2);
       dwarf_line_op(s1, DW_LNE_hi_user - 1);
