ST_FUNC void tcc_debug_funcend(TCCState *s1, int size)  {
      /* lldb does not like function end and next function start at same pc */      int min_instr_len;
    #if TCC_EH_FRAME      tcc_debug_frame_end(s1, size);
  #endif      if (!s1->do_debug)          return;
      min_instr_len = dwarf_line.last_pc == ind ? 0 : DWARF_MIN_INSTR_LEN;
      ind -= min_instr_len;
      tcc_debug_line(s1);
      ind += min_instr_len;
      tcc_debug_stabn(s1, N_RBRAC, size);
      if (s1->dwarf) {
          int func_sib = 0;
   Sym *sym = dwarf_info.func;
   int n_debug_info = tcc_get_dwarf_info(s1, sym->type.ref);
            dwarf_data1(dwarf_info_section,       sym->type.t & VT_STATIC ? DWARF_ABBREV_SUBPROGRAM_STATIC          : DWARF_ABBREV_SUBPROGRAM_EXTERNAL);
          if ((sym->type.t & VT_STATIC) == 0)              dwarf_data1(dwarf_info_section, 1);
          dwarf_strp(dwarf_info_section, funcname);
          dwarf_uleb128(dwarf_info_section, dwarf_line.cur_file);
          dwarf_uleb128(dwarf_info_section, dwarf_info.line);
   tcc_debug_check_anon(s1, sym->type.ref, dwarf_info_section->data_offset);
          dwarf_data4(dwarf_info_section, n_debug_info - dwarf_info.start);
          dwarf_reloc(dwarf_info_section, section_sym, R_DATA_PTR);
  #if PTR_SIZE == 4          dwarf_data4(dwarf_info_section, func_ind);
 // low_pc          dwarf_data4(dwarf_info_section, size);
 // high_pc  #else          dwarf_data8(dwarf_info_section, func_ind);
 // low_pc          dwarf_data8(dwarf_info_section, size);
 // high_pc  #endif          func_sib = dwarf_info_section->data_offset;
          dwarf_data4(dwarf_info_section, 0);
 // sibling          dwarf_data1(dwarf_info_section, 1);
  #if defined(TCC_TARGET_I386)          dwarf_data1(dwarf_info_section, DW_OP_reg5);
 // ebp  #elif defined(TCC_TARGET_X86_64)          dwarf_data1(dwarf_info_section, DW_OP_reg6);
 // rbp  #elif defined TCC_TARGET_ARM          dwarf_data1(dwarf_info_section, DW_OP_reg13);
 // sp  #elif defined TCC_TARGET_ARM64          dwarf_data1(dwarf_info_section, DW_OP_reg29);
 // reg 29  #elif defined TCC_TARGET_RISCV64          dwarf_data1(dwarf_info_section, DW_OP_reg8);
 // r8(s0)  #else          dwarf_data1(dwarf_info_section, DW_OP_call_frame_cfa);
  #endif          tcc_debug_finish (s1, debug_info_root);
   dwarf_data1(dwarf_info_section, 0);
          write32le(dwarf_info_section->data + func_sib,                    dwarf_info_section->data_offset - dwarf_info.start);

}      else      {
          tcc_debug_finish (s1, debug_info_root);

}      debug_info_root = 0;

}

ST_FUNC void tcc_debug_extern_sym(TCCState *s1, Sym *sym, int sh_num, int sym_bind, int sym_type)  {
      if (!(s1->do_debug & 2))          return;
        if (sym_type == STT_FUNC || sym->v >= SYM_FIRST_ANOM)          return;
      if (s1->dwarf) {
          int debug_type;
            debug_type = tcc_get_dwarf_info(s1, sym);
   dwarf_data1(dwarf_info_section,        sym_bind == STB_GLOBAL        ? DWARF_ABBREV_VARIABLE_EXTERNAL        : DWARF_ABBREV_VARIABLE_STATIC);
   dwarf_strp(dwarf_info_section, get_tok_str(sym->v, NULL));
   dwarf_uleb128(dwarf_info_section, dwarf_line.cur_file);
   dwarf_uleb128(dwarf_info_section, file->line_num);
   tcc_debug_check_anon(s1, sym, dwarf_info_section->data_offset);
   dwarf_data4(dwarf_info_section, debug_type - dwarf_info.start);
   if (sym_bind == STB_GLOBAL)       dwarf_data1(dwarf_info_section, 1);
   dwarf_data1(dwarf_info_section, PTR_SIZE + 1);
   dwarf_data1(dwarf_info_section, DW_OP_addr);
   greloca(dwarf_info_section, sym, dwarf_info_section->data_offset,    R_DATA_PTR, 0);
  #if PTR_SIZE == 4   dwarf_data4(dwarf_info_section, 0);
  #else   dwarf_data8(dwarf_info_section, 0);
  #endif      
}      else      {
          Section *s = sh_num == SHN_COMMON ? common_section         : s1->sections[sh_num];
          CString str;
            cstr_new (&str);
          cstr_printf (&str, "%s:%c",                  get_tok_str(sym->v, NULL),                  sym_bind == STB_GLOBAL ? 'G' : func_ind != -1 ? 'V' : 'S'                  );
          tcc_get_debug_info(s1, sym, &str);
          if (sym_bind == STB_GLOBAL)              tcc_debug_stabs(s1, str.data, N_GSYM, 0, NULL, 0, 0);
          else              tcc_debug_stabs(s1, str.data,                  (sym->type.t & VT_STATIC) && data_section == s                  ? N_STSYM : N_LCSYM, 0, s, sym->c, 0);
          cstr_free (&str);

}  
}

ST_FUNC void tcc_debug_typedef(TCCState *s1, Sym *sym)  {
      if (!(s1->do_debug & 2))          return;
        if (s1->dwarf) {
   int debug_type;
            debug_type = tcc_get_dwarf_info(s1, sym);
   if (debug_type != -1) {
       dwarf_data1(dwarf_info_section, DWARF_ABBREV_TYPEDEF);
       dwarf_strp(dwarf_info_section, get_tok_str(sym->v, NULL));
       dwarf_uleb128(dwarf_info_section, dwarf_line.cur_file);
       dwarf_uleb128(dwarf_info_section, file->line_num);
       tcc_debug_check_anon(s1, sym, dwarf_info_section->data_offset);
       dwarf_data4(dwarf_info_section, debug_type - dwarf_info.start);

}      
}      else      {
          CString str;
          cstr_new (&str);
          cstr_printf (&str, "%s:t",                       (sym->v & ~SYM_FIELD) >= SYM_FIRST_ANOM                       ? "" : get_tok_str(sym->v, NULL));
          tcc_get_debug_info(s1, sym, &str);
          tcc_debug_stabs(s1, str.data, N_LSYM, 0, NULL, 0, 0);
          cstr_free (&str);

}  
}

ST_FUNC void tcc_tcov_block_begin(TCCState *s1)  {
      SValue sv;
      void *ptr;
      unsigned long last_offset = tcov_data.offset;
        tcc_tcov_block_end (tcc_state, 0);
      if (s1->test_coverage == 0 || nocode_wanted)   return;
        if (tcov_data.last_file_name == 0 ||   strcmp ((const char *)(tcov_section->data + tcov_data.last_file_name),    file->true_filename) != 0) {
   char wd[1024];
   CString cstr;
     if (tcov_data.last_func_name)       section_ptr_add(tcov_section, 1);
   if (tcov_data.last_file_name)       section_ptr_add(tcov_section, 1);
   tcov_data.last_func_name = 0;
   cstr_new (&cstr);
   if (file->true_filename[0] == '/') {
       tcov_data.last_file_name = tcov_section->data_offset;
       cstr_printf (&cstr, "%s", file->true_filename);

}   else {
       getcwd (wd, sizeof(wd));
       tcov_data.last_file_name = tcov_section->data_offset + strlen(wd) + 1;
       cstr_printf (&cstr, "%s/%s", wd, file->true_filename);

}   ptr = section_ptr_add(tcov_section, cstr.size + 1);
   strcpy((char *)ptr, cstr.data);
  #ifdef _WIN32          normalize_slashes((char *)ptr);
  #endif   cstr_free (&cstr);

}      if (tcov_data.last_func_name == 0 ||   strcmp ((const char *)(tcov_section->data + tcov_data.last_func_name),    funcname) != 0) {
   size_t len;
     if (tcov_data.last_func_name)       section_ptr_add(tcov_section, 1);
   tcov_data.last_func_name = tcov_section->data_offset;
   len = strlen (funcname);
   ptr = section_ptr_add(tcov_section, len + 1);
   strcpy((char *)ptr, funcname);
   section_ptr_add(tcov_section, -tcov_section->data_offset & 7);
   ptr = section_ptr_add(tcov_section, 8);
   write64le (ptr, file->line_num);

}      if (ind == tcov_data.ind && tcov_data.line == file->line_num)          tcov_data.offset = last_offset;
      else {
          Sym label = {
0
};
          label.type.t = VT_LLONG | VT_STATIC;
            ptr = section_ptr_add(tcov_section, 16);
          tcov_data.line = file->line_num;
          write64le (ptr, (tcov_data.line << 8) | 0xff);
          put_extern_sym(&label, tcov_section,           ((unsigned char *)ptr - tcov_section->data) + 8, 0);
          sv.type = label.type;
          sv.r = VT_SYM | VT_LVAL | VT_CONST;
          sv.r2 = VT_CONST;
          sv.c.i = 0;
          sv.sym = &label;
  #if defined TCC_TARGET_I386 || defined TCC_TARGET_X86_64 || \      defined TCC_TARGET_ARM || defined TCC_TARGET_ARM64 || \      defined TCC_TARGET_RISCV64          gen_increment_tcov (&sv);
  #else          vpushv(&sv);
          inc(0, TOK_INC);
          vpop();
  #endif          tcov_data.offset = (unsigned char *)ptr - tcov_section->data;
          tcov_data.ind = ind;

}  
}

ST_FUNC void tcc_tcov_block_end(TCCState *s1, int line)  {
      if (s1->test_coverage == 0)   return;
      if (line == -1)          line = tcov_data.line;
      if (tcov_data.offset) {
   void *ptr = tcov_section->data + tcov_data.offset;
   unsigned long long nline = line ? line : file->line_num;
     write64le (ptr, (read64le (ptr) & 0xfffffffffull) | (nline << 36));
   tcov_data.offset = 0;

}  
}

ST_FUNC void tcc_tcov_check_line(TCCState *s1, int start)  {
      if (s1->test_coverage == 0)   return;
      if (tcov_data.line != file->line_num) {
          if ((tcov_data.line + 1) != file->line_num) {
       tcc_tcov_block_end (s1, -1);
       if (start)                  tcc_tcov_block_begin (s1);

}   else       tcov_data.line = file->line_num;

}  
}

ST_FUNC void tcc_tcov_start(TCCState *s1)  {
      if (s1->test_coverage == 0)   return;
      if (!s1->dState)          s1->dState = tcc_mallocz(sizeof *s1->dState);
      memset (&tcov_data, 0, sizeof (tcov_data));
      if (tcov_section == NULL) {
          tcov_section = new_section(tcc_state, ".tcov", SHT_PROGBITS,         SHF_ALLOC | SHF_WRITE);
   section_ptr_add(tcov_section, 4);
 // pointer to executable name      
}  
}

ST_FUNC void tcc_tcov_end(TCCState *s1)  {
      if (s1->test_coverage == 0)   return;
      if (tcov_data.last_func_name)          section_ptr_add(tcov_section, 1);
      if (tcov_data.last_file_name)          section_ptr_add(tcov_section, 1);

}

ST_FUNC void tcc_tcov_reset_ind(TCCState *s1)  {
      tcov_data.ind = 0;

}

ST_FUNC void tccelf_new(TCCState *s)  {
      TCCState *s1 = s;
        /* no section zero */      dynarray_add(&s->sections, &s->nb_sections, NULL);
        /* create standard sections */      text_section = new_section(s, ".text", SHT_PROGBITS, SHF_ALLOC | SHF_EXECINSTR);
      data_section = new_section(s, ".data", SHT_PROGBITS, SHF_ALLOC | SHF_WRITE);
      /* create ro data section (make ro after relocation done with GNU_RELRO) */      rodata_section = new_section(s, rdata, SHT_PROGBITS, shf_RELRO);
      bss_section = new_section(s, ".bss", SHT_NOBITS, SHF_ALLOC | SHF_WRITE);
      common_section = new_section(s, ".common", SHT_NOBITS, SHF_PRIVATE);
      common_section->sh_num = SHN_COMMON;
        /* symbols are always generated for linking stage */      symtab_section = new_symtab(s, ".symtab", SHT_SYMTAB, 0,                                  ".strtab",                                  ".hashtab", SHF_PRIVATE);
        /* private symbol table for dynamic symbols */      s->dynsymtab_section = new_symtab(s, ".dynsymtab", SHT_SYMTAB, SHF_PRIVATE|SHF_DYNSYM,                                        ".dynstrtab",                                        ".dynhashtab", SHF_PRIVATE);
      get_sym_attr(s, 0, 1);
        if (s->do_debug) {
          /* add debug sections */          tcc_debug_new(s);

}    #if TCC_EH_FRAME      tcc_eh_frame_start(s);
  #endif    #ifdef CONFIG_TCC_BCHECK      if (s->do_bounds_check) {
          /* if bound checking, then add corresponding sections */          /* (make ro after relocation done with GNU_RELRO) */          bounds_section = new_section(s, ".bounds", SHT_PROGBITS, shf_RELRO);
          lbounds_section = new_section(s, ".lbounds", SHT_PROGBITS, shf_RELRO);

}  #endif  
}

ST_FUNC void free_section(Section *s)  {
      if (!s)          return;
      tcc_free(s->data);
      s->data = NULL;
      s->data_allocated = s->data_offset = 0;

}

ST_FUNC void tccelf_delete(TCCState *s1)  {
      int i;
    #ifndef ELF_OBJ_ONLY      /* free symbol versions */      for (i = 0;
 i < nb_sym_versions;
 i++) {
          tcc_free(sym_versions[i].version);
          tcc_free(sym_versions[i].lib);

}      tcc_free(sym_versions);
      tcc_free(sym_to_version);
  #endif        /* free all sections */      for(i = 1;
 i < s1->nb_sections;
 i++)          free_section(s1->sections[i]);
      dynarray_reset(&s1->sections, &s1->nb_sections);
        for(i = 0;
 i < s1->nb_priv_sections;
 i++)          free_section(s1->priv_sections[i]);
      dynarray_reset(&s1->priv_sections, &s1->nb_priv_sections);
        tcc_free(s1->sym_attrs);
      symtab_section = NULL;
 /* for tccrun.c:rt_printline() */  
}

ST_FUNC void tccelf_begin_file(TCCState *s1)  {
      Section *s;
 int i;
      for (i = 1;
 i < s1->nb_sections;
 i++) {
          s = s1->sections[i];
          s->sh_offset = s->data_offset;

}      /* disable symbol hashing during compilation */      s = s1->symtab, s->reloc = s->hash, s->hash = NULL;
  #if defined TCC_TARGET_X86_64 && defined TCC_TARGET_PE      s1->uw_sym = 0;
      s1->uw_offs = 0;
  #endif  
}

ST_FUNC void tccelf_end_file(TCCState *s1)  {
      Section *s = s1->symtab;
      int first_sym, nb_syms, *tr, i;
        first_sym = s->sh_offset / sizeof (ElfSym);
      nb_syms = s->data_offset / sizeof (ElfSym) - first_sym;
      s->data_offset = s->sh_offset;
      s->link->data_offset = s->link->sh_offset;
      s->hash = s->reloc, s->reloc = NULL;
      tr = tcc_mallocz(nb_syms * sizeof *tr);
        for (i = 0;
 i < nb_syms;
 ++i) {
          ElfSym *sym = (ElfSym*)s->data + first_sym + i;
          if (sym->st_shndx == SHN_UNDEF) {
              int sym_bind = ELFW(ST_BIND)(sym->st_info);
              int sym_type = ELFW(ST_TYPE)(sym->st_info);
              if (sym_bind == STB_LOCAL)                  sym_bind = STB_GLOBAL;
  #ifndef TCC_TARGET_PE              if (sym_bind == STB_GLOBAL && s1->output_type == TCC_OUTPUT_OBJ) {
                  /* undefined symbols with STT_FUNC are confusing gnu ld when                     linking statically to STT_GNU_IFUNC */                  sym_type = STT_NOTYPE;

}  #endif              sym->st_info = ELFW(ST_INFO)(sym_bind, sym_type);

}          tr[i] = set_elf_sym(s, sym->st_value, sym->st_size, sym->st_info,              sym->st_other, sym->st_shndx, (char*)s->link->data + sym->st_name);

}      /* now update relocations */      update_relocs(s1, s, tr, first_sym);
      tcc_free(tr);
      /* record text/data/bss output for -bench info */      for (i = 0;
 i < 4;
 ++i) {
          s = s1->sections[i + 1];
          s1->total_output[i] += s->data_offset - s->sh_offset;

}  
}

ST_FUNC Section *new_section(TCCState *s1, const char *name, int sh_type, int sh_flags)  {
      Section *sec;
        sec = tcc_mallocz(sizeof(Section) + strlen(name));
      sec->s1 = s1;
      strcpy(sec->name, name);
      sec->sh_type = sh_type;
      sec->sh_flags = sh_flags;
      switch(sh_type) {
      case SHT_GNU_versym:          sec->sh_addralign = 2;
          break;
      case SHT_HASH:      case SHT_GNU_HASH:      case SHT_REL:      case SHT_RELA:      case SHT_DYNSYM:      case SHT_SYMTAB:      case SHT_DYNAMIC:      case SHT_GNU_verneed:      case SHT_GNU_verdef:          sec->sh_addralign = PTR_SIZE;
          break;
      case SHT_STRTAB:          sec->sh_addralign = 1;
          break;
      default:          sec->sh_addralign =  PTR_SIZE;
 /* gcc/pcc default alignment */          break;

}        if (sh_flags & SHF_PRIVATE) {
          dynarray_add(&s1->priv_sections, &s1->nb_priv_sections, sec);

} else {
          sec->sh_num = s1->nb_sections;
          dynarray_add(&s1->sections, &s1->nb_sections, sec);

}        return sec;

}

ST_FUNC void init_symtab(Section *s)  {
      int *ptr, nb_buckets = 1;
      put_elf_str(s->link, "");
      section_ptr_add(s, sizeof (ElfW(Sym)));
      ptr = section_ptr_add(s->hash, (2 + nb_buckets + 1) * sizeof(int));
      ptr[0] = nb_buckets;
      ptr[1] = 1;
      memset(ptr + 2, 0, (nb_buckets + 1) * sizeof(int));

}

ST_FUNC Section *new_symtab(TCCState *s1,                             const char *symtab_name, int sh_type, int sh_flags,                             const char *strtab_name,                             const char *hash_name, int hash_sh_flags)  {
      Section *symtab, *strtab, *hash;
      symtab = new_section(s1, symtab_name, sh_type, sh_flags);
      symtab->sh_entsize = sizeof(ElfW(Sym));
      strtab = new_section(s1, strtab_name, SHT_STRTAB, sh_flags);
      symtab->link = strtab;
      hash = new_section(s1, hash_name, SHT_HASH, hash_sh_flags);
      hash->sh_entsize = sizeof(int);
      symtab->hash = hash;
      hash->link = symtab;
      init_symtab(symtab);
      return symtab;

}

ST_FUNC void section_realloc(Section *sec, unsigned long new_size)  {
      unsigned long size;
      unsigned char *data;
        size = sec->data_allocated;
      if (size == 0)          size = 1;
      while (size < new_size)          size = size * 2;
      data = tcc_realloc(sec->data, size);
      memset(data + sec->data_allocated, 0, size - sec->data_allocated);
      sec->data = data;
      sec->data_allocated = size;

}

ST_FUNC size_t section_add(Section *sec, addr_t size, int align)  {
      size_t offset, offset1;
        offset = (sec->data_offset + align - 1) & -align;
      offset1 = offset + size;
      if (sec->sh_type != SHT_NOBITS && offset1 > sec->data_allocated)          section_realloc(sec, offset1);
      sec->data_offset = offset1;
      if (align > sec->sh_addralign)          sec->sh_addralign = align;
      return offset;

}

ST_FUNC void *section_ptr_add(Section *sec, addr_t size)  {
      size_t offset = section_add(sec, size, 1);
      return sec->data + offset;

}

static Section *have_section(TCCState *s1, const char *name)  {
      Section *sec;
      int i;
      for(i = 1;
 i < s1->nb_sections;
 i++) {
          sec = s1->sections[i];
          if (!strcmp(name, sec->name))              return sec;

}      return NULL;

}

ST_FUNC Section *find_section(TCCState *s1, const char *name)  {
      Section *sec = have_section(s1, name);
      if (sec)          return sec;
      /* sections are created as PROGBITS */      return new_section(s1, name, SHT_PROGBITS, SHF_ALLOC);

}

ST_FUNC int put_elf_str(Section *s, const char *sym)  {
      int offset, len;
      char *ptr;
        len = strlen(sym) + 1;
      offset = s->data_offset;
      ptr = section_ptr_add(s, len);
      memmove(ptr, sym, len);
      return offset;

}

static ElfW(Word) elf_hash(const unsigned char *name)  {
      ElfW(Word) h = 0, g;
        while (*name) {
          h = (h << 4) + *name++;
          g = h & 0xf0000000;
          if (g)              h ^= g >> 24;
          h &= ~g;

}      return h;

}

static void rebuild_hash(Section *s, unsigned int nb_buckets)  {
      ElfW(Sym) *sym;
      int *ptr, *hash, nb_syms, sym_index, h;
      unsigned char *strtab;
        strtab = s->link->data;
      nb_syms = s->data_offset / sizeof(ElfW(Sym));
        if (!nb_buckets)          nb_buckets = ((int*)s->hash->data)[0];
        s->hash->data_offset = 0;
      ptr = section_ptr_add(s->hash, (2 + nb_buckets + nb_syms) * sizeof(int));
      ptr[0] = nb_buckets;
      ptr[1] = nb_syms;
      ptr += 2;
      hash = ptr;
      memset(hash, 0, (nb_buckets + 1) * sizeof(int));
      ptr += nb_buckets + 1;
        sym = (ElfW(Sym) *)s->data + 1;
      for(sym_index = 1;
 sym_index < nb_syms;
 sym_index++) {
          if (ELFW(ST_BIND)(sym->st_info) != STB_LOCAL) {
              h = elf_hash(strtab + sym->st_name) % nb_buckets;
              *ptr = hash[h];
              hash[h] = sym_index;

} else {
              *ptr = 0;

}          ptr++;
          sym++;

}  
}

ST_FUNC int put_elf_sym(Section *s, addr_t value, unsigned long size,      int info, int other, int shndx, const char *name)  {
      int name_offset, sym_index;
      int nbuckets, h;
      ElfW(Sym) *sym;
      Section *hs;
        sym = section_ptr_add(s, sizeof(ElfW(Sym)));
      if (name && name[0])          name_offset = put_elf_str(s->link, name);
      else          name_offset = 0;
      /* XXX: endianness */      sym->st_name = name_offset;
      sym->st_value = value;
      sym->st_size = size;
      sym->st_info = info;
      sym->st_other = other;
      sym->st_shndx = shndx;
      sym_index = sym - (ElfW(Sym) *)s->data;
      hs = s->hash;
      if (hs) {
          int *ptr, *base;
          ptr = section_ptr_add(hs, sizeof(int));
          base = (int *)hs->data;
          /* only add global or weak symbols. */          if (ELFW(ST_BIND)(info) != STB_LOCAL) {
              /* add another hashing entry */              nbuckets = base[0];
              h = elf_hash((unsigned char *)s->link->data + name_offset) % nbuckets;
              *ptr = base[2 + h];
              base[2 + h] = sym_index;
              base[1]++;
              /* we resize the hash table */              hs->nb_hashed_syms++;
              if (hs->nb_hashed_syms > 2 * nbuckets) {
                  rebuild_hash(s, 2 * nbuckets);

}          
} else {
              *ptr = 0;
              base[1]++;

}      
}      return sym_index;

}

ST_FUNC int find_elf_sym(Section *s, const char *name)  {
      ElfW(Sym) *sym;
      Section *hs;
      int nbuckets, sym_index, h;
      const char *name1;
        hs = s->hash;
      if (!hs)          return 0;
      nbuckets = ((int *)hs->data)[0];
      h = elf_hash((unsigned char *) name) % nbuckets;
      sym_index = ((int *)hs->data)[2 + h];
      while (sym_index != 0) {
          sym = &((ElfW(Sym) *)s->data)[sym_index];
          name1 = (char *) s->link->data + sym->st_name;
          if (!strcmp(name, name1))              return sym_index;
          sym_index = ((int *)hs->data)[2 + nbuckets + sym_index];

}      return 0;

}

ST_FUNC addr_t get_sym_addr(TCCState *s1, const char *name, int err, int forc)  {
      int sym_index;
      ElfW(Sym) *sym;
      char buf[256];
      if (forc && s1->leading_underscore  #ifdef TCC_TARGET_PE          /* win32-32bit stdcall symbols always have _ already */          && !strchr(name, '@')  #endif          ) {
          buf[0] = '_';
          pstrcpy(buf + 1, sizeof(buf) - 1, name);
          name = buf;

}      sym_index = find_elf_sym(s1->symtab, name);
      sym = &((ElfW(Sym) *)s1->symtab->data)[sym_index];
      if (!sym_index || sym->st_shndx == SHN_UNDEF) {
          if (err)              tcc_error_noabort("%s not defined", name);
          return (addr_t)-1;

}      return sym->st_value;

}

LIBTCCAPI void *tcc_get_symbol(TCCState *s, const char *name)  {
      addr_t addr = get_sym_addr(s, name, 0, 1);
      return addr == -1 ? NULL : (void*)(uintptr_t)addr;

}

ST_FUNC void list_elf_symbols(TCCState *s, void *ctx,      void (*symbol_cb)(void *ctx, const char *name, const void *val))  {
      ElfW(Sym) *sym;
      Section *symtab;
      int sym_index, end_sym;
      const char *name;
      unsigned char sym_vis, sym_bind;
        symtab = s->symtab;
      end_sym = symtab->data_offset / sizeof (ElfSym);
      for (sym_index = 0;
 sym_index < end_sym;
 ++sym_index) {
          sym = &((ElfW(Sym) *)symtab->data)[sym_index];
          if (sym->st_value) {
              name = (char *) symtab->link->data + sym->st_name;
              sym_bind = ELFW(ST_BIND)(sym->st_info);
              sym_vis = ELFW(ST_VISIBILITY)(sym->st_other);
              if (sym_bind == STB_GLOBAL && sym_vis == STV_DEFAULT)                  symbol_cb(ctx, name, (void*)(uintptr_t)sym->st_value);

}      
}  
}

LIBTCCAPI void tcc_list_symbols(TCCState *s, void *ctx,      void (*symbol_cb)(void *ctx, const char *name, const void *val))  {
      list_elf_symbols(s, ctx, symbol_cb);

}

ST_FUNC int set_elf_sym(Section *s, addr_t value, unsigned long size,                         int info, int other, int shndx, const char *name)  {
      TCCState *s1 = s->s1;
      ElfW(Sym) *esym;
      int sym_bind, sym_index, sym_type, esym_bind;
      unsigned char sym_vis, esym_vis, new_vis;
        sym_bind = ELFW(ST_BIND)(info);
      sym_type = ELFW(ST_TYPE)(info);
      sym_vis = ELFW(ST_VISIBILITY)(other);
        if (sym_bind != STB_LOCAL) {
          /* we search global or weak symbols */          sym_index = find_elf_sym(s, name);
          if (!sym_index)              goto do_def;
          esym = &((ElfW(Sym) *)s->data)[sym_index];
          if (esym->st_value == value && esym->st_size == size && esym->st_info == info              && esym->st_other == other && esym->st_shndx == shndx)              return sym_index;
          if (esym->st_shndx != SHN_UNDEF) {
              esym_bind = ELFW(ST_BIND)(esym->st_info);
              /* propagate the most constraining visibility */              /* STV_DEFAULT(0)<STV_PROTECTED(3)<STV_HIDDEN(2)<STV_INTERNAL(1) */              esym_vis = ELFW(ST_VISIBILITY)(esym->st_other);
              if (esym_vis == STV_DEFAULT) {
                  new_vis = sym_vis;

} else if (sym_vis == STV_DEFAULT) {
                  new_vis = esym_vis;

} else {
                  new_vis = (esym_vis < sym_vis) ? esym_vis : sym_vis;

}              esym->st_other = (esym->st_other & ~ELFW(ST_VISIBILITY)(-1))                               | new_vis;
              if (shndx == SHN_UNDEF) {
                  /* ignore adding of undefined symbol if the                     corresponding symbol is already defined */              
} else if (sym_bind == STB_GLOBAL && esym_bind == STB_WEAK) {
                  /* global overrides weak, so patch */                  goto do_patch;

} else if (sym_bind == STB_WEAK && esym_bind == STB_GLOBAL) {
                  /* weak is ignored if already global */              
} else if (sym_bind == STB_WEAK && esym_bind == STB_WEAK) {
                  /* keep first-found weak definition, ignore subsequents */              
} else if (sym_vis == STV_HIDDEN || sym_vis == STV_INTERNAL) {
                  /* ignore hidden symbols after */              
} else if ((esym->st_shndx == SHN_COMMON                              || esym->st_shndx == bss_section->sh_num)                          && (shndx < SHN_LORESERVE                              && shndx != bss_section->sh_num)) {
                  /* data symbol gets precedence over common/bss */                  goto do_patch;

} else if (shndx == SHN_COMMON || shndx == bss_section->sh_num) {
                  /* data symbol keeps precedence over common/bss */              
} else if (s->sh_flags & SHF_DYNSYM) {
                  /* we accept that two DLL define the same symbol */       
} else if (esym->st_other & ST_ASM_SET) {
    /* If the existing symbol came from an asm .set       we can override.  */    goto do_patch;

} else {
  #if 0                  printf("new_bind=%x new_shndx=%x new_vis=%x old_bind=%x old_shndx=%x old_vis=%x\n",                         sym_bind, shndx, new_vis, esym_bind, esym->st_shndx, esym_vis);
  #endif                  tcc_error_noabort("'%s' defined twice", name);

}          
} else {
              esym->st_other = other;
          do_patch:              esym->st_info = ELFW(ST_INFO)(sym_bind, sym_type);
              esym->st_shndx = shndx;
              s1->new_undef_sym = 1;
              esym->st_value = value;
              esym->st_size = size;

}      
} else {
      do_def:          sym_index = put_elf_sym(s, value, size,                                  ELFW(ST_INFO)(sym_bind, sym_type), other,                                  shndx, name);

}      return sym_index;

}

ST_FUNC void put_elf_reloca(Section *symtab, Section *s, unsigned long offset,                              int type, int symbol, addr_t addend)  {
      TCCState *s1 = s->s1;
      char buf[256];
      Section *sr;
      ElfW_Rel *rel;
        sr = s->reloc;
      if (!sr) {
          /* if no relocation section, create it */          snprintf(buf, sizeof(buf), REL_SECTION_FMT, s->name);
          /* if the symtab is allocated, then we consider the relocation             are also */          sr = new_section(s->s1, buf, SHT_RELX, symtab->sh_flags);
          sr->sh_entsize = sizeof(ElfW_Rel);
          sr->link = symtab;
          sr->sh_info = s->sh_num;
          s->reloc = sr;

}      rel = section_ptr_add(sr, sizeof(ElfW_Rel));
      rel->r_offset = offset;
      rel->r_info = ELFW(R_INFO)(symbol, type);
  #if SHT_RELX == SHT_RELA      rel->r_addend = addend;
  #endif      if (SHT_RELX != SHT_RELA && addend)          tcc_error_noabort("non-zero addend on REL architecture");

}

ST_FUNC void put_elf_reloc(Section *symtab, Section *s, unsigned long offset,                             int type, int symbol)  {
      put_elf_reloca(symtab, s, offset, type, symbol, 0);

}

ST_FUNC struct sym_attr *get_sym_attr(TCCState *s1, int index, int alloc)  {
      int n;
      struct sym_attr *tab;
        if (index >= s1->nb_sym_attrs) {
          if (!alloc)              return s1->sym_attrs;
          /* find immediately bigger power of 2 and reallocate array */          n = 1;
          while (index >= n)              n *= 2;
          tab = tcc_realloc(s1->sym_attrs, n * sizeof(*s1->sym_attrs));
          s1->sym_attrs = tab;
          memset(s1->sym_attrs + s1->nb_sym_attrs, 0,                 (n - s1->nb_sym_attrs) * sizeof(*s1->sym_attrs));
          s1->nb_sym_attrs = n;

}      return &s1->sym_attrs[index];

}

static void update_relocs(TCCState *s1, Section *s, int *old_to_new_syms, int first_sym)  {
      int i, type, sym_index;
      Section *sr;
      ElfW_Rel *rel;
        for(i = 1;
 i < s1->nb_sections;
 i++) {
          sr = s1->sections[i];
          if (sr->sh_type == SHT_RELX && sr->link == s) {
              for_each_elem(sr, 0, rel, ElfW_Rel) {
                  sym_index = ELFW(R_SYM)(rel->r_info);
                  type = ELFW(R_TYPE)(rel->r_info);
                  if ((sym_index -= first_sym) < 0)                      continue;
 /* zero sym_index in reloc (can happen with asm) */                  sym_index = old_to_new_syms[sym_index];
                  rel->r_info = ELFW(R_INFO)(sym_index, type);

}          
}      
}  
}

static void sort_syms(TCCState *s1, Section *s)  {
      int *old_to_new_syms;
      ElfW(Sym) *new_syms;
      int nb_syms, i;
      ElfW(Sym) *p, *q;
        nb_syms = s->data_offset / sizeof(ElfW(Sym));
      new_syms = tcc_malloc(nb_syms * sizeof(ElfW(Sym)));
      old_to_new_syms = tcc_malloc(nb_syms * sizeof(int));
        /* first pass for local symbols */      p = (ElfW(Sym) *)s->data;
      q = new_syms;
      for(i = 0;
 i < nb_syms;
 i++) {
          if (ELFW(ST_BIND)(p->st_info) == STB_LOCAL) {
              old_to_new_syms[i] = q - new_syms;
              *q++ = *p;

}          p++;

}      /* save the number of local symbols in section header */      if( s->sh_size )    /* this 'if' makes IDA happy */          s->sh_info = q - new_syms;
        /* then second pass for non local symbols */      p = (ElfW(Sym) *)s->data;
      for(i = 0;
 i < nb_syms;
 i++) {
          if (ELFW(ST_BIND)(p->st_info) != STB_LOCAL) {
              old_to_new_syms[i] = q - new_syms;
              *q++ = *p;

}          p++;

}        /* we copy the new symbols to the old */      memcpy(s->data, new_syms, nb_syms * sizeof(ElfW(Sym)));
      tcc_free(new_syms);
        update_relocs(s1, s, old_to_new_syms, 0);
      tcc_free(old_to_new_syms);

}

ST_FUNC void relocate_syms(TCCState *s1, Section *symtab, int do_resolve)  {
      ElfW(Sym) *sym;
      int sym_bind, sh_num;
      const char *name;
        for_each_elem(symtab, 1, sym, ElfW(Sym)) {
          sh_num = sym->st_shndx;
          if (sh_num == SHN_UNDEF) {
              if (do_resolve == 2) /* relocating dynsym */                  continue;
              name = (char *) s1->symtab->link->data + sym->st_name;
              /* Use ld.so to resolve symbol for us (for tcc -run) */              if (do_resolve) {
  #if defined TCC_IS_NATIVE && !defined TCC_TARGET_PE                  /* dlsym() needs the undecorated name.  */                  void *addr = dlsym(RTLD_DEFAULT, &name[s1->leading_underscore]);
  #if TARGETOS_OpenBSD || TARGETOS_FreeBSD || TARGETOS_NetBSD || TARGETOS_ANDROID    if (addr == NULL) {
        int i;
        for (i = 0;
 i < s1->nb_loaded_dlls;
 i++)                          if ((addr = dlsym(s1->loaded_dlls[i]->handle, name)))         break;

}  #endif                  if (addr) {
                      sym->st_value = (addr_t) addr;
  #ifdef DEBUG_RELOC        printf ("relocate_sym: %s -> 0x%lx\n", name, sym->st_value);
  #endif                      goto found;

}  #endif              /* if dynamic symbol exist, it will be used in relocate_section */              
} else if (s1->dynsym && find_elf_sym(s1->dynsym, name))                  goto found;
              /* XXX: _fp_hw seems to be part of the ABI, so we ignore                 it */              if (!strcmp(name, "_fp_hw"))                  goto found;
              /* only weak symbols are accepted to be undefined. Their                 value is zero */              sym_bind = ELFW(ST_BIND)(sym->st_info);
              if (sym_bind == STB_WEAK)                  sym->st_value = 0;
              else                  tcc_error_noabort("undefined symbol '%s'", name);

} else if (sh_num < SHN_LORESERVE) {
              /* add section base */              sym->st_value += s1->sections[sym->st_shndx]->sh_addr;

}      found:;

}  
}

static void relocate_section(TCCState *s1, Section *s, Section *sr)  {
      ElfW_Rel *rel;
      ElfW(Sym) *sym;
      int type, sym_index;
      unsigned char *ptr;
      addr_t tgt, addr;
      int is_dwarf = s->sh_num >= s1->dwlo && s->sh_num < s1->dwhi;
        qrel = (ElfW_Rel *)sr->data;
      for_each_elem(sr, 0, rel, ElfW_Rel) {
          ptr = s->data + rel->r_offset;
          sym_index = ELFW(R_SYM)(rel->r_info);
          sym = &((ElfW(Sym) *)symtab_section->data)[sym_index];
          type = ELFW(R_TYPE)(rel->r_info);
          tgt = sym->st_value;
  #if SHT_RELX == SHT_RELA          tgt += rel->r_addend;
  #endif          if (is_dwarf && type == R_DATA_32DW              && sym->st_shndx >= s1->dwlo && sym->st_shndx < s1->dwhi) {
              /* dwarf section relocation to each other */              add32le(ptr, tgt - s1->sections[sym->st_shndx]->sh_addr);
              continue;

}          addr = s->sh_addr + rel->r_offset;
          relocate(s1, rel, type, ptr, addr, tgt);

}  #ifndef ELF_OBJ_ONLY      /* if the relocation is allocated, we change its symbol table */      if (sr->sh_flags & SHF_ALLOC) {
          sr->link = s1->dynsym;
          if (s1->output_type & TCC_OUTPUT_DYN) {
              size_t r = (uint8_t*)qrel - sr->data;
              if (sizeof ((Stab_Sym*)0)->n_value < PTR_SIZE                  && 0 == strcmp(s->name, ".stab"))                  r = 0;
 /* cannot apply 64bit relocation to 32bit value */              sr->data_offset = sr->sh_size = r;
  #ifdef CONFIG_TCC_PIE              if (r && (s->sh_flags & SHF_EXECINSTR))                  tcc_warning("%d relocations to %s", (unsigned)(r / sizeof *qrel), s->name);
  #endif          
}      
}  #endif  
}

ST_FUNC void relocate_sections(TCCState *s1)  {
      int i;
      Section *s, *sr;
        for (i = 1;
 i < s1->nb_sections;
 ++i) {
          sr = s1->sections[i];
          if (sr->sh_type != SHT_RELX)              continue;
          s = s1->sections[sr->sh_info];
  #ifndef TCC_TARGET_MACHO          if (s != s1->got              || s1->static_link              || s1->output_type == TCC_OUTPUT_MEMORY)  #endif          {
              relocate_section(s1, s, sr);

}  #ifndef ELF_OBJ_ONLY          if (sr->sh_flags & SHF_ALLOC) {
              ElfW_Rel *rel;
              /* relocate relocation table in 'sr' */              for_each_elem(sr, 0, rel, ElfW_Rel)                  rel->r_offset += s->sh_addr;

}  #endif      
}  
}

ST_FUNC int set_global_sym(TCCState *s1, const char *name, Section *sec, addr_t offs)  {
      int shn = sec ? sec->sh_num : offs || !name ? SHN_ABS : SHN_UNDEF;
      if (sec && offs == -1)          offs = sec->data_offset;
      return set_elf_sym(symtab_section, offs, 0,          ELFW(ST_INFO)(name ? STB_GLOBAL : STB_LOCAL, STT_NOTYPE), 0, shn, name);

}

static void add_init_array_defines(TCCState *s1, const char *section_name)  {
      Section *s;
      addr_t end_offset;
      char buf[1024];
      s = have_section(s1, section_name);
      if (!s || !(s->sh_flags & SHF_ALLOC)) {
          end_offset = 0;
          s = text_section;

} else {
          end_offset = s->data_offset;

}      snprintf(buf, sizeof(buf), "__%s_start", section_name + 1);
      set_global_sym(s1, buf, s, 0);
      snprintf(buf, sizeof(buf), "__%s_end", section_name + 1);
      set_global_sym(s1, buf, s, end_offset);

}

ST_FUNC void add_array (TCCState *s1, const char *sec, int c)  {
      Section *s;
      s = find_section(s1, sec);
      s->sh_flags = shf_RELRO;
      s->sh_type = sec[1] == 'i' ? SHT_INIT_ARRAY : SHT_FINI_ARRAY;
      put_elf_reloc (s1->symtab, s, s->data_offset, R_DATA_PTR, c);
      section_ptr_add(s, PTR_SIZE);

}

static void set_local_sym(TCCState *s1, const char *name, Section *s, int offset)  {
      int c = find_elf_sym(s1->symtab, name);
      if (c) {
          ElfW(Sym) *esym = (ElfW(Sym)*)s1->symtab->data + c;
          esym->st_info = ELFW(ST_INFO)(STB_LOCAL, STT_NOTYPE);
          esym->st_value = offset;
          esym->st_shndx = s->sh_num;

}  
}

static void tcc_compile_string_no_debug(TCCState *s, const char *str)  {
      int save_do_debug = s->do_debug;
      int save_test_coverage = s->test_coverage;
        s->do_debug = 0;
      s->test_coverage = 0;
      tcc_compile_string(s, str);
      s->do_debug = save_do_debug;
      s->test_coverage = save_test_coverage;

}

static void tcc_tcov_add_file(TCCState *s1, const char *filename)  {
      CString cstr;
      void *ptr;
      char wd[1024];
        if (tcov_section == NULL)          return;
      section_ptr_add(tcov_section, 1);
      write32le (tcov_section->data, tcov_section->data_offset);
        cstr_new (&cstr);
      if (filename[0] == '/')          cstr_printf (&cstr, "%s.tcov", filename);
      else {
          getcwd (wd, sizeof(wd));
          cstr_printf (&cstr, "%s/%s.tcov", wd, filename);

}      ptr = section_ptr_add(tcov_section, cstr.size + 1);
      strcpy((char *)ptr, cstr.data);
      unlink((char *)ptr);
  #ifdef _WIN32      normalize_slashes((char *)ptr);
  #endif      cstr_free (&cstr);
        cstr_new(&cstr);
      cstr_printf(&cstr,          "extern char *__tcov_data[];
"          "extern void __store_test_coverage ();
"          "__attribute__((destructor)) static void __tcov_exit() {
"          "__store_test_coverage(__tcov_data);
"          "
}");
      tcc_compile_string_no_debug(s1, cstr.data);
      cstr_free(&cstr);
      set_local_sym(s1, &"___tcov_data"[!s1->leading_underscore], tcov_section, 0);

}

static void tcc_add_linker_symbols(TCCState *s1)  {
      char buf[1024];
      int i;
      Section *s;
        set_global_sym(s1, "_etext", text_section, -1);
      set_global_sym(s1, "_edata", data_section, -1);
      set_global_sym(s1, "_end", bss_section, -1);
  #if TARGETOS_OpenBSD      set_global_sym(s1, "__executable_start", NULL, ELF_START_ADDR);
  #endif  #ifdef TCC_TARGET_RISCV64      /* XXX should be .sdata+0x800, not .data+0x800 */      set_global_sym(s1, "__global_pointer$", data_section, 0x800);
  #endif      /* horrible new standard ldscript defines */      add_init_array_defines(s1, ".preinit_array");
      add_init_array_defines(s1, ".init_array");
      add_init_array_defines(s1, ".fini_array");
      /* add start and stop symbols for sections whose name can be         expressed in C */      for(i = 1;
 i < s1->nb_sections;
 i++) {
          s = s1->sections[i];
          if ((s->sh_flags & SHF_ALLOC)              && (s->sh_type == SHT_PROGBITS || s->sh_type == SHT_NOBITS                  || s->sh_type == SHT_STRTAB)) {
              /* check if section name can be expressed in C */              const char *p0, *p;
              p0 = s->name;
              if (*p0 == '.')                  ++p0;
              p = p0;
              for(;
;
) {
                  int c = *p;
                  if (!c)                      break;
                  if (!isid(c) && !isnum(c))                      goto next_sec;
                  p++;

}              snprintf(buf, sizeof(buf), "__start_%s", p0);
              set_global_sym(s1, buf, s, 0);
              snprintf(buf, sizeof(buf), "__stop_%s", p0);
              set_global_sym(s1, buf, s, -1);

}      next_sec:;

}  
}

ST_FUNC void resolve_common_syms(TCCState *s1)  {
      ElfW(Sym) *sym;
        /* Allocate common symbols in BSS.  */      for_each_elem(symtab_section, 1, sym, ElfW(Sym)) {
          if (sym->st_shndx == SHN_COMMON) {
              /* symbol alignment is in st_value for SHN_COMMONs */       sym->st_value = section_add(bss_section, sym->st_size,       sym->st_value);
              sym->st_shndx = bss_section->sh_num;

}      
}        /* Now assign linker provided symbols their value.  */      tcc_add_linker_symbols(s1);

}

static int tcc_output_elf(TCCState *s1, FILE *f, int phnum, ElfW(Phdr) *phdr)  {
      int i, shnum, offset, size, file_type;
      Section *s;
      ElfW(Ehdr) ehdr;
      ElfW(Shdr) shdr, *sh;
        file_type = s1->output_type;
      shnum = s1->nb_sections;
        memset(&ehdr, 0, sizeof(ehdr));
      if (phnum > 0) {
          ehdr.e_phentsize = sizeof(ElfW(Phdr));
          ehdr.e_phnum = phnum;
          ehdr.e_phoff = sizeof(ElfW(Ehdr));

}        /* fill header */      ehdr.e_ident[0] = ELFMAG0;
      ehdr.e_ident[1] = ELFMAG1;
      ehdr.e_ident[2] = ELFMAG2;
      ehdr.e_ident[3] = ELFMAG3;
      ehdr.e_ident[4] = ELFCLASSW;
      ehdr.e_ident[5] = ELFDATA2LSB;
      ehdr.e_ident[6] = EV_CURRENT;
    #if TARGETOS_FreeBSD || TARGETOS_FreeBSD_kernel      ehdr.e_ident[EI_OSABI] = ELFOSABI_FREEBSD;
  #elif defined TCC_TARGET_ARM && defined TCC_ARM_EABI      ehdr.e_flags = EF_ARM_EABI_VER5;
      ehdr.e_flags |= s1->float_abi == ARM_HARD_FLOAT          ? EF_ARM_VFP_FLOAT : EF_ARM_SOFT_FLOAT;
  #elif defined TCC_TARGET_ARM      ehdr.e_ident[EI_OSABI] = ELFOSABI_ARM;
  #elif defined TCC_TARGET_RISCV64      /* XXX should be configurable */      ehdr.e_flags = EF_RISCV_FLOAT_ABI_DOUBLE;
  #endif        if (file_type == TCC_OUTPUT_OBJ) {
          ehdr.e_type = ET_REL;

} else {
          if (file_type & TCC_OUTPUT_DYN)              ehdr.e_type = ET_DYN;
          else              ehdr.e_type = ET_EXEC;
          if (s1->elf_entryname)              ehdr.e_entry = get_sym_addr(s1, s1->elf_entryname, 1, 0);
          else              ehdr.e_entry = get_sym_addr(s1, "_start", !!(file_type & TCC_OUTPUT_EXE), 0);
          if (ehdr.e_entry == (addr_t)-1)              ehdr.e_entry = text_section->sh_addr;
          if (s1->nb_errors)              return -1;

}        sort_syms(s1, s1->symtab);
        ehdr.e_machine = EM_TCC_TARGET;
      ehdr.e_version = EV_CURRENT;
      ehdr.e_shoff = (sizeof(ElfW(Ehdr)) + phnum * sizeof(ElfW(Phdr)) + 3) & -4;
      ehdr.e_ehsize = sizeof(ElfW(Ehdr));
      ehdr.e_shentsize = sizeof(ElfW(Shdr));
      ehdr.e_shnum = shnum;
      ehdr.e_shstrndx = shnum - 1;
        offset = fwrite(&ehdr, 1, sizeof(ElfW(Ehdr)), f);
      if (phdr)          offset += fwrite(phdr, 1, phnum * sizeof(ElfW(Phdr)), f);
        /* output section headers */      while (offset < ehdr.e_shoff) {
          fputc(0, f);
          offset++;

}        for(i = 0;
 i < shnum;
 i++) {
          sh = &shdr;
          memset(sh, 0, sizeof(ElfW(Shdr)));
          if (i) {
              s = s1->sections[i];
              sh->sh_name = s->sh_name;
              sh->sh_type = s->sh_type;
              sh->sh_flags = s->sh_flags;
              sh->sh_entsize = s->sh_entsize;
              sh->sh_info = s->sh_info;
              if (s->link)                  sh->sh_link = s->link->sh_num;
              sh->sh_addralign = s->sh_addralign;
              sh->sh_addr = s->sh_addr;
              sh->sh_offset = s->sh_offset;
              sh->sh_size = s->sh_size;

}          offset += fwrite(sh, 1, sizeof(ElfW(Shdr)), f);

}        /* output sections */      for(i = 1;
 i < s1->nb_sections;
 i++) {
          s = s1->sections[i];
          if (s->sh_type != SHT_NOBITS) {
              while (offset < s->sh_offset) {
                  fputc(0, f);
                  offset++;

}              size = s->sh_size;
              if (size)                  offset += fwrite(s->data, 1, size, f);

}      
}      return 0;

}

static int tcc_output_binary(TCCState *s1, FILE *f)  {
      Section *s;
      int i, offset, size;
        offset = 0;
      for(i=1;
i<s1->nb_sections;
i++) {
          s = s1->sections[i];
          if (s->sh_type != SHT_NOBITS &&              (s->sh_flags & SHF_ALLOC)) {
              while (offset < s->sh_offset) {
                  fputc(0, f);
                  offset++;

}              size = s->sh_size;
              fwrite(s->data, 1, size, f);
              offset += size;

}      
}      return 0;

}

static int tcc_write_elf_file(TCCState *s1, const char *filename, int phnum,                                ElfW(Phdr) *phdr)  {
      int fd, mode, file_type, ret;
      FILE *f;
        file_type = s1->output_type;
      if (file_type == TCC_OUTPUT_OBJ)          mode = 0666;
      else          mode = 0777;
      unlink(filename);
      fd = open(filename, O_WRONLY | O_CREAT | O_TRUNC | O_BINARY, mode);
      if (fd < 0 || (f = fdopen(fd, "wb")) == NULL)          return tcc_error_noabort("could not write '%s: %s'", filename, strerror(errno));
      if (s1->verbose)          printf("<- %s\n", filename);
  #ifdef TCC_TARGET_COFF      if (s1->output_format == TCC_OUTPUT_FORMAT_COFF)          tcc_output_coff(s1, f);
      else  #endif      if (s1->output_format == TCC_OUTPUT_FORMAT_ELF)          ret = tcc_output_elf(s1, f, phnum, phdr);
      else          ret = tcc_output_binary(s1, f);
      fclose(f);
        return ret;

}

static void alloc_sec_names(TCCState *s1, int is_obj)  {
      int i;
      Section *s, *strsec;
        strsec = new_section(s1, ".shstrtab", SHT_STRTAB, 0);
      put_elf_str(strsec, "");
      for(i = 1;
 i < s1->nb_sections;
 i++) {
          s = s1->sections[i];
          if (is_obj)              s->sh_size = s->data_offset;
   if (s->sh_size || s == strsec || (s->sh_flags & SHF_ALLOC) || is_obj)              s->sh_name = put_elf_str(strsec, s->name);

}      strsec->sh_size = strsec->data_offset;

}

static int elf_output_obj(TCCState *s1, const char *filename)  {
      Section *s;
      int i, ret, file_offset;
      s1->nb_errors = 0;
      /* Allocate strings for section names */      alloc_sec_names(s1, 1);
      file_offset = (sizeof (ElfW(Ehdr)) + 3) & -4;
      file_offset += s1->nb_sections * sizeof(ElfW(Shdr));
      for(i = 1;
 i < s1->nb_sections;
 i++) {
          s = s1->sections[i];
          file_offset = (file_offset + 15) & -16;
          s->sh_offset = file_offset;
          if (s->sh_type != SHT_NOBITS)              file_offset += s->sh_size;

}      /* Create the ELF file with name 'filename' */      ret = tcc_write_elf_file(s1, filename, 0, NULL);
      return ret;

}

LIBTCCAPI int tcc_output_file(TCCState *s, const char *filename)  {
      if (s->test_coverage)          tcc_tcov_add_file(s, filename);
      if (s->output_type == TCC_OUTPUT_OBJ)          return elf_output_obj(s, filename);
  #ifdef TCC_TARGET_PE      return  pe_output_file(s, filename);
  #elif defined TCC_TARGET_MACHO      return macho_output_file(s, filename);
  #else      return elf_output_file(s, filename);
  #endif  
}

ST_FUNC ssize_t full_read(int fd, void *buf, size_t count) {
      char *cbuf = buf;
      size_t rnum = 0;
      while (1) {
          ssize_t num = read(fd, cbuf, count-rnum);
          if (num < 0) return num;
          if (num == 0) return rnum;
          rnum += num;
          cbuf += num;

}  
}

ST_FUNC void *load_data(int fd, unsigned long file_offset, unsigned long size)  {
      void *data;
        data = tcc_malloc(size);
      lseek(fd, file_offset, SEEK_SET);
      full_read(fd, data, size);
      return data;

}

ST_FUNC int tcc_object_type(int fd, ElfW(Ehdr) *h)  {
      int size = full_read(fd, h, sizeof *h);
      if (size == sizeof *h && 0 == memcmp(h, ELFMAG, 4)) {
          if (h->e_type == ET_REL)              return AFF_BINTYPE_REL;
          if (h->e_type == ET_DYN)              return AFF_BINTYPE_DYN;

} else if (size >= 8) {
          if (0 == memcmp(h, ARMAG, 8))              return AFF_BINTYPE_AR;
  #ifdef TCC_TARGET_COFF          if (((struct filehdr*)h)->f_magic == COFF_C67_MAGIC)              return AFF_BINTYPE_C67;
  #endif      
}      return 0;

}

ST_FUNC int tcc_load_object_file(TCCState *s1,                                  int fd, unsigned long file_offset)  {
      ElfW(Ehdr) ehdr;
      ElfW(Shdr) *shdr, *sh;
      unsigned long size, offset, offseti;
      int i, j, nb_syms, sym_index, ret, seencompressed;
      char *strsec, *strtab;
      int stab_index, stabstr_index;
      int *old_to_new_syms;
      char *sh_name, *name;
      SectionMergeInfo *sm_table, *sm;
      ElfW(Sym) *sym, *symtab;
      ElfW_Rel *rel;
      Section *s;
        lseek(fd, file_offset, SEEK_SET);
      if (tcc_object_type(fd, &ehdr) != AFF_BINTYPE_REL)          goto invalid;
      /* test CPU specific stuff */      if (ehdr.e_ident[5] != ELFDATA2LSB ||          ehdr.e_machine != EM_TCC_TARGET) {
  invalid:          return tcc_error_noabort("invalid object file");

}      /* read sections */      shdr = load_data(fd, file_offset + ehdr.e_shoff,                       sizeof(ElfW(Shdr)) * ehdr.e_shnum);
      sm_table = tcc_mallocz(sizeof(SectionMergeInfo) * ehdr.e_shnum);
        /* load section names */      sh = &shdr[ehdr.e_shstrndx];
      strsec = load_data(fd, file_offset + sh->sh_offset, sh->sh_size);
        /* load symtab and strtab */      old_to_new_syms = NULL;
      symtab = NULL;
      strtab = NULL;
      nb_syms = 0;
      seencompressed = 0;
      stab_index = stabstr_index = 0;
      ret = -1;
        for(i = 1;
 i < ehdr.e_shnum;
 i++) {
          sh = &shdr[i];
          if (sh->sh_type == SHT_SYMTAB) {
              if (symtab) {
                  tcc_error_noabort("object must contain only one symtab");
                  goto the_end;

}              nb_syms = sh->sh_size / sizeof(ElfW(Sym));
              symtab = load_data(fd, file_offset + sh->sh_offset, sh->sh_size);
              sm_table[i].s = symtab_section;
                /* now load strtab */              sh = &shdr[sh->sh_link];
              strtab = load_data(fd, file_offset + sh->sh_offset, sh->sh_size);

}   if (sh->sh_flags & SHF_COMPRESSED)       seencompressed = 1;

}        /* now examine each section and try to merge its content with the         ones in memory */      for(i = 1;
 i < ehdr.e_shnum;
 i++) {
          /* no need to examine section name strtab */          if (i == ehdr.e_shstrndx)              continue;
          sh = &shdr[i];
   if (sh->sh_type == SHT_RELX)     sh = &shdr[sh->sh_info];
          /* ignore sections types we do not handle (plus relocs to those) */          if (0 == strncmp(strsec + sh->sh_name, ".debug_", 7)           || 0 == strncmp(strsec + sh->sh_name, ".stab", 5)) {
       if (!s1->do_debug || seencompressed)           continue;

} else          if (sh->sh_type != SHT_PROGBITS &&  #ifdef TCC_ARM_EABI              sh->sh_type != SHT_ARM_EXIDX &&  #endif  #if TARGETOS_OpenBSD || TARGETOS_FreeBSD || TARGETOS_NetBSD              sh->sh_type != SHT_X86_64_UNWIND &&  #endif              sh->sh_type != SHT_NOTE &&              sh->sh_type != SHT_NOBITS &&              sh->sh_type != SHT_PREINIT_ARRAY &&              sh->sh_type != SHT_INIT_ARRAY &&              sh->sh_type != SHT_FINI_ARRAY              )              continue;
     sh = &shdr[i];
          sh_name = strsec + sh->sh_name;
          if (sh->sh_addralign < 1)              sh->sh_addralign = 1;
          /* find corresponding section, if any */          for(j = 1;
 j < s1->nb_sections;
j++) {
              s = s1->sections[j];
              if (!strcmp(s->name, sh_name)) {
                  if (!strncmp(sh_name, ".gnu.linkonce",                               sizeof(".gnu.linkonce") - 1)) {
                      /* if a 'linkonce' section is already present, we                         do not add it again. It is a little tricky as                         symbols can still be defined in                         it. */                      sm_table[i].link_once = 1;
                      goto next;

}                  if (stab_section) {
                      if (s == stab_section)                          stab_index = i;
                      if (s == stab_section->link)                          stabstr_index = i;

}                  goto found;

}          
}          /* not found: create new section */          s = new_section(s1, sh_name, sh->sh_type, sh->sh_flags & ~SHF_GROUP);
          /* take as much info as possible from the section. sh_link and             sh_info will be updated later */          s->sh_addralign = sh->sh_addralign;
          s->sh_entsize = sh->sh_entsize;
          sm_table[i].new_section = 1;
      found:          if (sh->sh_type != s->sh_type  #if TARGETOS_OpenBSD || TARGETOS_FreeBSD || TARGETOS_NetBSD              && strcmp (s->name, ".eh_frame")  #endif              ) {
              tcc_error_noabort("invalid section type");
              goto the_end;

}          /* align start of section */          s->data_offset += -s->data_offset & (sh->sh_addralign - 1);
          if (sh->sh_addralign > s->sh_addralign)              s->sh_addralign = sh->sh_addralign;
          sm_table[i].offset = s->data_offset;
          sm_table[i].s = s;
          /* concatenate sections */          size = sh->sh_size;
          if (sh->sh_type != SHT_NOBITS) {
              unsigned char *ptr;
              lseek(fd, file_offset + sh->sh_offset, SEEK_SET);
              ptr = section_ptr_add(s, size);
              full_read(fd, ptr, size);

} else {
              s->data_offset += size;

}      next:;

}        /* gr relocate stab strings */      if (stab_index && stabstr_index) {
          Stab_Sym *a, *b;
          unsigned o;
          s = sm_table[stab_index].s;
          a = (Stab_Sym *)(s->data + sm_table[stab_index].offset);
          b = (Stab_Sym *)(s->data + s->data_offset);
          o = sm_table[stabstr_index].offset;
          while (a < b) {
              if (a->n_strx)                  a->n_strx += o;
              a++;

}      
}        /* second short pass to update sh_link and sh_info fields of new         sections */      for(i = 1;
 i < ehdr.e_shnum;
 i++) {
          s = sm_table[i].s;
          if (!s || !sm_table[i].new_section)              continue;
          sh = &shdr[i];
          if (sh->sh_link > 0)              s->link = sm_table[sh->sh_link].s;
          if (sh->sh_type == SHT_RELX) {
              s->sh_info = sm_table[sh->sh_info].s->sh_num;
              /* update backward link */              s1->sections[s->sh_info]->reloc = s;

}      
}        /* resolve symbols */      old_to_new_syms = tcc_mallocz(nb_syms * sizeof(int));
        sym = symtab + 1;
      for(i = 1;
 i < nb_syms;
 i++, sym++) {
          if (sym->st_shndx != SHN_UNDEF &&              sym->st_shndx < SHN_LORESERVE) {
              sm = &sm_table[sym->st_shndx];
              if (sm->link_once) {
                  /* if a symbol is in a link once section, we use the                     already defined symbol. It is very important to get                     correct relocations */                  if (ELFW(ST_BIND)(sym->st_info) != STB_LOCAL) {
                      name = strtab + sym->st_name;
                      sym_index = find_elf_sym(symtab_section, name);
                      if (sym_index)                          old_to_new_syms[i] = sym_index;

}                  continue;

}              /* if no corresponding section added, no need to add symbol */              if (!sm->s)                  continue;
              /* convert section number */              sym->st_shndx = sm->s->sh_num;
              /* offset value */              sym->st_value += sm->offset;

}          /* add symbol */          name = strtab + sym->st_name;
          sym_index = set_elf_sym(symtab_section, sym->st_value, sym->st_size,                                  sym->st_info, sym->st_other,                                  sym->st_shndx, name);
          old_to_new_syms[i] = sym_index;

}        /* third pass to patch relocation entries */      for(i = 1;
 i < ehdr.e_shnum;
 i++) {
          s = sm_table[i].s;
          if (!s)              continue;
          sh = &shdr[i];
          offset = sm_table[i].offset;
          size = sh->sh_size;
          switch(s->sh_type) {
          case SHT_RELX:              /* take relocation offset information */              offseti = sm_table[sh->sh_info].offset;
       for (rel = (ElfW_Rel *) s->data + (offset / sizeof(*rel));
     rel < (ElfW_Rel *) s->data + ((offset + size) / sizeof(*rel));
     rel++) {
                  int type;
                  unsigned sym_index;
                  /* convert symbol index */                  type = ELFW(R_TYPE)(rel->r_info);
                  sym_index = ELFW(R_SYM)(rel->r_info);
                  /* NOTE: only one symtab assumed */                  if (sym_index >= nb_syms)                      goto invalid_reloc;
                  sym_index = old_to_new_syms[sym_index];
                  /* ignore link_once in rel section. */                  if (!sym_index && !sm_table[sh->sh_info].link_once  #ifdef TCC_TARGET_ARM                      && type != R_ARM_V4BX  #elif defined TCC_TARGET_RISCV64                      && type != R_RISCV_ALIGN                      && type != R_RISCV_RELAX  #endif                     ) {
                  invalid_reloc:                      tcc_error_noabort("Invalid relocation entry [%2d] '%s' @ %.8x",                          i, strsec + sh->sh_name, (int)rel->r_offset);
                      goto the_end;

}                  rel->r_info = ELFW(R_INFO)(sym_index, type);
                  /* offset the relocation offset */                  rel->r_offset += offseti;
  #ifdef TCC_TARGET_ARM                  /* Jumps and branches from a Thumb code to a PLT entry need                     special handling since PLT entries are ARM code.                     Unconditional bl instructions referencing PLT entries are                     handled by converting these instructions into blx                     instructions. Other case of instructions referencing a PLT                     entry require to add a Thumb stub before the PLT entry to                     switch to ARM mode. We set bit plt_thumb_stub of the                     attribute of a symbol to indicate such a case. */                  if (type == R_ARM_THM_JUMP24)                      get_sym_attr(s1, sym_index, 1)->plt_thumb_stub = 1;
  #endif              
}              break;
          default:              break;

}      
}        ret = 0;
   the_end:      tcc_free(symtab);
      tcc_free(strtab);
      tcc_free(old_to_new_syms);
      tcc_free(sm_table);
      tcc_free(strsec);
      tcc_free(shdr);
      return ret;

}

static unsigned long long get_be(const uint8_t *b, int n)  {
      unsigned long long ret = 0;
      while (n)          ret = (ret << 8) | *b++, --n;
      return ret;

}

static int read_ar_header(int fd, int offset, ArchiveHeader *hdr)  {
      char *p, *e;
      int len;
      lseek(fd, offset, SEEK_SET);
      len = full_read(fd, hdr, sizeof(ArchiveHeader));
      if (len != sizeof(ArchiveHeader))          return len ? -1 : 0;
      if (memcmp(hdr->ar_fmag, ARFMAG, sizeof hdr->ar_fmag))          return -1;
      p = hdr->ar_name;
      for (e = p + sizeof hdr->ar_name;
 e > p && e[-1] == ' ';
)          --e;
      *e = '\0';
      hdr->ar_size[sizeof hdr->ar_size-1] = 0;
      return len;

}

static int tcc_load_alacarte(TCCState *s1, int fd, int size, int entrysize)  {
      int i, bound, nsyms, sym_index, len, ret = -1;
      unsigned long long off;
      uint8_t *data;
      const char *ar_names, *p;
      const uint8_t *ar_index;
      ElfW(Sym) *sym;
      ArchiveHeader hdr;
        data = tcc_malloc(size);
      if (full_read(fd, data, size) != size)          goto invalid;
      nsyms = get_be(data, entrysize);
      ar_index = data + entrysize;
      ar_names = (char *) ar_index + nsyms * entrysize;
        do {
          bound = 0;
          for (p = ar_names, i = 0;
 i < nsyms;
 i++, p += strlen(p)+1) {
              Section *s = symtab_section;
              sym_index = find_elf_sym(s, p);
              if (!sym_index)                  continue;
              sym = &((ElfW(Sym) *)s->data)[sym_index];
              if(sym->st_shndx != SHN_UNDEF)                  continue;
              off = get_be(ar_index + i * entrysize, entrysize);
              len = read_ar_header(fd, off, &hdr);
              if (len <= 0 || memcmp(hdr.ar_fmag, ARFMAG, 2)) {
          invalid:                  tcc_error_noabort("invalid archive");
                  goto the_end;

}              off += len;
              if (s1->verbose == 2)                  printf("   -> %s\n", hdr.ar_name);
              if (tcc_load_object_file(s1, fd, off) < 0)                  goto the_end;
              ++bound;

}      
} while(bound);
      ret = 0;
   the_end:      tcc_free(data);
      return ret;

}

ST_FUNC int tcc_load_archive(TCCState *s1, int fd, int alacarte)  {
      ArchiveHeader hdr;
      /* char magic[8];
 */      int size, len;
      unsigned long file_offset;
      ElfW(Ehdr) ehdr;
        /* skip magic which was already checked */      /* full_read(fd, magic, sizeof(magic));
 */      file_offset = sizeof ARMAG - 1;
        for(;
;
) {
          len = read_ar_header(fd, file_offset, &hdr);
          if (len == 0)              return 0;
          if (len < 0)              return tcc_error_noabort("invalid archive");
          file_offset += len;
          size = strtol(hdr.ar_size, NULL, 0);
          if (alacarte) {
              /* coff symbol table : we handle it */              if (!strcmp(hdr.ar_name, "/"))                  return tcc_load_alacarte(s1, fd, size, 4);
              if (!strcmp(hdr.ar_name, "/SYM64/"))                  return tcc_load_alacarte(s1, fd, size, 8);

} else if (tcc_object_type(fd, &ehdr) == AFF_BINTYPE_REL) {
              if (s1->verbose == 2)                  printf("   -> %s\n", hdr.ar_name);
              if (tcc_load_object_file(s1, fd, file_offset) < 0)                  return -1;

}          /* align to even */          file_offset = (file_offset + size + 1) & ~1;

}  
}

ST_FUNC void gsym(int t)  {
    if (t) {
      gsym_addr(t, ind);
      CODE_ON();

}  
}

static int gind()  {
    int t = ind;
    CODE_ON();
    if (debug_modes)      tcc_tcov_block_begin(tcc_state);
    return t;

}

static void gjmp_addr_acs(int t)  {
    gjmp_addr(t);
    CODE_OFF();

}

static int gjmp_acs(int t)  {
    t = gjmp(t);
    CODE_OFF();
    return t;

}

ST_INLN int is_float(int t)  {
      int bt = t & VT_BTYPE;
      return bt == VT_LDOUBLE          || bt == VT_DOUBLE          || bt == VT_FLOAT          || bt == VT_QFLOAT;

}

static inline int is_integer_btype(int bt)  {
      return bt == VT_BYTE          || bt == VT_BOOL          || bt == VT_SHORT          || bt == VT_INT          || bt == VT_LLONG;

}

static int btype_size(int bt)  {
      return bt == VT_BYTE || bt == VT_BOOL ? 1 :          bt == VT_SHORT ? 2 :          bt == VT_INT ? 4 :          bt == VT_LLONG ? 8 :          bt == VT_PTR ? PTR_SIZE : 0;

}

static int R_RET(int t)  {
      if (!is_float(t))          return REG_IRET;
  #ifdef TCC_TARGET_X86_64      if ((t & VT_BTYPE) == VT_LDOUBLE)          return TREG_ST0;
  #elif defined TCC_TARGET_RISCV64      if ((t & VT_BTYPE) == VT_LDOUBLE)          return REG_IRET;
  #endif      return REG_FRET;

}

static int R2_RET(int t)  {
      t &= VT_BTYPE;
  #if PTR_SIZE == 4      if (t == VT_LLONG)          return REG_IRE2;
  #elif defined TCC_TARGET_X86_64      if (t == VT_QLONG)          return REG_IRE2;
      if (t == VT_QFLOAT)          return REG_FRE2;
  #elif defined TCC_TARGET_RISCV64      if (t == VT_LDOUBLE)          return REG_IRE2;
  #endif      return VT_CONST;

}

static void PUT_R_RET(SValue *sv, int t)  {
      sv->r = R_RET(t), sv->r2 = R2_RET(t);

}

static int RC_RET(int t)  {
      return reg_classes[R_RET(t)] & ~(RC_FLOAT | RC_INT);

}

static int RC_TYPE(int t)  {
      if (!is_float(t))          return RC_INT;
  #ifdef TCC_TARGET_X86_64      if ((t & VT_BTYPE) == VT_LDOUBLE)          return RC_ST0;
      if ((t & VT_BTYPE) == VT_QFLOAT)          return RC_FRET;
  #elif defined TCC_TARGET_RISCV64      if ((t & VT_BTYPE) == VT_LDOUBLE)          return RC_INT;
  #endif      return RC_FLOAT;

}

static int RC2_TYPE(int t, int rc)  {
      if (!USING_TWO_WORDS(t))          return 0;
  #ifdef RC_IRE2      if (rc == RC_IRET)          return RC_IRE2;
  #endif  #ifdef RC_FRE2      if (rc == RC_FRET)          return RC_FRE2;
  #endif      if (rc & RC_FLOAT)          return RC_FLOAT;
      return RC_INT;

}

ST_FUNC int ieee_finite(double d)  {
      int p[4];
      memcpy(p, &d, sizeof(double));
      return ((unsigned)((p[1] | 0x800fffff) + 1)) >> 31;

}

ST_FUNC void test_lvalue(void)  {
      if (!(vtop->r & VT_LVAL))          expect("lvalue");

}

ST_FUNC void check_vstack(void)  {
      if (vtop != vstack - 1)          tcc_error("internal compiler error: vstack leak (%d)",                    (int)(vtop - vstack + 1));

}

ST_FUNC void tccgen_init(TCCState *s1)  {
      vtop = vstack - 1;
      memset(vtop, 0, sizeof *vtop);
        /* define some often used types */      int_type.t = VT_INT;
        char_type.t = VT_BYTE;
      if (s1->char_is_unsigned)          char_type.t |= VT_UNSIGNED;
      char_pointer_type = char_type;
      mk_pointer(&char_pointer_type);
        func_old_type.t = VT_FUNC;
      func_old_type.ref = sym_push(SYM_FIELD, &int_type, 0, 0);
      func_old_type.ref->f.func_call = FUNC_CDECL;
      func_old_type.ref->f.func_type = FUNC_OLD;
  #ifdef precedence_parser      init_prec();
  #endif      cstr_new(&initstr);

}

ST_FUNC int tccgen_compile(TCCState *s1)  {
      funcname = "";
      func_ind = -1;
      anon_sym = SYM_FIRST_ANOM;
      nocode_wanted = DATA_ONLY_WANTED;
 /* no code outside of functions */      debug_modes = (s1->do_debug ? 1 : 0) | s1->test_coverage << 1;
        tcc_debug_start(s1);
      tcc_tcov_start (s1);
  #ifdef TCC_TARGET_ARM      arm_init(s1);
  #endif  #ifdef INC_DEBUG      printf("%s: **** new file\n", file->filename);
  #endif      parse_flags = PARSE_FLAG_PREPROCESS | PARSE_FLAG_TOK_NUM | PARSE_FLAG_TOK_STR;
      next();
      decl(VT_CONST);
      gen_inline_functions(s1);
      check_vstack();
      /* end of translation unit info */  #if TCC_EH_FRAME      tcc_eh_frame_end(s1);
  #endif      tcc_debug_end(s1);
      tcc_tcov_end(s1);
      return 0;

}

ST_FUNC void tccgen_finish(TCCState *s1)  {
      tcc_debug_end(s1);
 /* just in case of errors: free memory */      free_inline_functions(s1);
      sym_pop(&global_stack, NULL, 0);
      sym_pop(&local_stack, NULL, 0);
      /* free preprocessor macros */      free_defines(NULL);
      /* free sym_pools */      dynarray_reset(&sym_pools, &nb_sym_pools);
      cstr_free(&initstr);
      dynarray_reset(&stk_data, &nb_stk_data);
      while (cur_switch)          end_switch();
      local_scope = 0;
      loop_scope = NULL;
      all_cleanups = NULL;
      pending_gotos = NULL;
      nb_temp_local_vars = 0;
      global_label_stack = NULL;
      local_label_stack = NULL;
      cur_text_section = NULL;
      sym_free_first = NULL;

}

ST_FUNC ElfSym *elfsym(Sym *s)  {
    if (!s || !s->c)      return NULL;
    return &((ElfSym *)symtab_section->data)[s->c];

}

ST_FUNC void update_storage(Sym *sym)  {
      ElfSym *esym;
      int sym_bind, old_sym_bind;
        esym = elfsym(sym);
      if (!esym)          return;
        if (sym->a.visibility)          esym->st_other = (esym->st_other & ~ELFW(ST_VISIBILITY)(-1))              | sym->a.visibility;
        if (sym->type.t & (VT_STATIC | VT_INLINE))          sym_bind = STB_LOCAL;
      else if (sym->a.weak)          sym_bind = STB_WEAK;
      else          sym_bind = STB_GLOBAL;
      old_sym_bind = ELFW(ST_BIND)(esym->st_info);
      if (sym_bind != old_sym_bind) {
          esym->st_info = ELFW(ST_INFO)(sym_bind, ELFW(ST_TYPE)(esym->st_info));

}    #ifdef TCC_TARGET_PE      if (sym->a.dllimport)          esym->st_other |= ST_PE_IMPORT;
      if (sym->a.dllexport)          esym->st_other |= ST_PE_EXPORT;
  #endif    #if 0      printf("storage %s: bind=%c vis=%d exp=%d imp=%d\n",          get_tok_str(sym->v, NULL),          sym_bind == STB_WEAK ? 'w' : sym_bind == STB_LOCAL ? 'l' : 'g',          sym->a.visibility,          sym->a.dllexport,          sym->a.dllimport          );
  #endif  
}

ST_FUNC void put_extern_sym2(Sym *sym, int sh_num,                              addr_t value, unsigned long size,                              int can_add_underscore)  {
      int sym_type, sym_bind, info, other, t;
      ElfSym *esym;
      const char *name;
      char buf1[256];
        if (!sym->c) {
          name = get_tok_str(sym->v, NULL);
          t = sym->type.t;
          if ((t & VT_BTYPE) == VT_FUNC) {
              sym_type = STT_FUNC;

} else if ((t & VT_BTYPE) == VT_VOID) {
              sym_type = STT_NOTYPE;
              if ((t & (VT_BTYPE|VT_ASM_FUNC)) == VT_ASM_FUNC)                  sym_type = STT_FUNC;

} else {
              sym_type = STT_OBJECT;

}          if (t & (VT_STATIC | VT_INLINE))              sym_bind = STB_LOCAL;
          else              sym_bind = STB_GLOBAL;
          other = 0;
    #ifdef TCC_TARGET_PE          if (sym_type == STT_FUNC && sym->type.ref) {
              Sym *ref = sym->type.ref;
              if (ref->a.nodecorate) {
                  can_add_underscore = 0;

}              if (ref->f.func_call == FUNC_STDCALL && can_add_underscore) {
                  sprintf(buf1, "_%s@%d", name, ref->f.func_args * PTR_SIZE);
                  name = buf1;
                  other |= ST_PE_STDCALL;
                  can_add_underscore = 0;

}          
}  #endif            if (sym->asm_label) {
              name = get_tok_str(sym->asm_label, NULL);
              can_add_underscore = 0;

}            if (tcc_state->leading_underscore && can_add_underscore) {
              buf1[0] = '_';
              pstrcpy(buf1 + 1, sizeof(buf1) - 1, name);
              name = buf1;

}            info = ELFW(ST_INFO)(sym_bind, sym_type);
          sym->c = put_elf_sym(symtab_section, value, size, info, other, sh_num, name);
            if (debug_modes)              tcc_debug_extern_sym(tcc_state, sym, sh_num, sym_bind, sym_type);

} else {
          esym = elfsym(sym);
          esym->st_value = value;
          esym->st_size = size;
          esym->st_shndx = sh_num;

}      update_storage(sym);

}

ST_FUNC void put_extern_sym(Sym *sym, Section *s, addr_t value, unsigned long size)  {
      if (nocode_wanted && (NODATA_WANTED || (s && s == cur_text_section)))          return;
      put_extern_sym2(sym, s ? s->sh_num : SHN_UNDEF, value, size, 1);

}

ST_FUNC void greloca(Section *s, Sym *sym, unsigned long offset, int type,                       addr_t addend)  {
      int c = 0;
        if (nocode_wanted && s == cur_text_section)          return;
        if (sym) {
          if (0 == sym->c)              put_extern_sym(sym, NULL, 0, 0);
          c = sym->c;

}        /* now we can add ELF relocation info */      put_elf_reloca(symtab_section, s, offset, type, c, addend);

}

static Sym *__sym_malloc(void)  {
      Sym *sym_pool, *sym, *last_sym;
      int i;
        sym_pool = tcc_malloc(SYM_POOL_NB * sizeof(Sym));
      dynarray_add(&sym_pools, &nb_sym_pools, sym_pool);
        last_sym = sym_free_first;
      sym = sym_pool;
      for(i = 0;
 i < SYM_POOL_NB;
 i++) {
          sym->next = last_sym;
          last_sym = sym;
          sym++;

}      sym_free_first = last_sym;
      return last_sym;

}

static inline Sym *sym_malloc(void)  {
      Sym *sym;
  #ifndef SYM_DEBUG      sym = sym_free_first;
      if (!sym)          sym = __sym_malloc();
      sym_free_first = sym->next;
      return sym;
  #else      sym = tcc_malloc(sizeof(Sym));
      return sym;
  #endif  
}

ST_INLN void sym_free(Sym *sym)  {
  #ifndef SYM_DEBUG      sym->next = sym_free_first;
      sym_free_first = sym;
  #else      tcc_free(sym);
  #endif  
}

ST_FUNC Sym *sym_push2(Sym **ps, int v, int t, int c)  {
      Sym *s;
        s = sym_malloc();
      memset(s, 0, sizeof *s);
      s->v = v;
      s->type.t = t;
      s->c = c;
      /* add in stack */      s->prev = *ps;
      *ps = s;
      return s;

}

ST_FUNC Sym *sym_find2(Sym *s, int v)  {
      while (s) {
          if (s->v == v)              return s;
          s = s->prev;

}      return NULL;

}

ST_INLN Sym *struct_find(int v)  {
      v -= TOK_IDENT;
      if ((unsigned)v >= (unsigned)(tok_ident - TOK_IDENT))          return NULL;
      return table_ident[v]->sym_struct;

}

ST_INLN Sym *sym_find(int v)  {
      v -= TOK_IDENT;
      if ((unsigned)v >= (unsigned)(tok_ident - TOK_IDENT))          return NULL;
      return table_ident[v]->sym_identifier;

}

static int sym_scope(Sym *s)  {
    if (IS_ENUM_VAL (s->type.t))      return s->type.ref->sym_scope;
    else      return s->sym_scope;

}

ST_FUNC Sym *sym_push(int v, CType *type, int r, int c)  {
      Sym *s, **ps;
      TokenSym *ts;
        if (local_stack)          ps = &local_stack;
      else          ps = &global_stack;
      s = sym_push2(ps, v, type->t, c);
      s->type.ref = type->ref;
      s->r = r;
      /* don't record fields or anonymous symbols */      /* XXX: simplify */      if (!(v & SYM_FIELD) && (v & ~SYM_STRUCT) < SYM_FIRST_ANOM) {
          /* record symbol in token array */          ts = table_ident[(v & ~SYM_STRUCT) - TOK_IDENT];
          if (v & SYM_STRUCT)              ps = &ts->sym_struct;
          else              ps = &ts->sym_identifier;
          s->prev_tok = *ps;
          *ps = s;
          s->sym_scope = local_scope;
          if (s->prev_tok && sym_scope(s->prev_tok) == s->sym_scope)              tcc_error("redeclaration of '%s'",                  get_tok_str(v & ~SYM_STRUCT, NULL));

}      return s;

}

ST_FUNC Sym *global_identifier_push(int v, int t, int c)  {
      Sym *s, **ps;
      s = sym_push2(&global_stack, v, t, c);
      s->r = VT_CONST | VT_SYM;
      /* don't record anonymous symbol */      if (v < SYM_FIRST_ANOM) {
          ps = &table_ident[v - TOK_IDENT]->sym_identifier;
          /* modify the top most local identifier, so that sym_identifier will             point to 's' when popped;
 happens when called from inline asm */          while (*ps != NULL && (*ps)->sym_scope)              ps = &(*ps)->prev_tok;
          s->prev_tok = *ps;
          *ps = s;

}      return s;

}

ST_FUNC void sym_pop(Sym **ptop, Sym *b, int keep)  {
      Sym *s, *ss, **ps;
      TokenSym *ts;
      int v;
        s = *ptop;
      while(s != b) {
          ss = s->prev;
          v = s->v;
          /* remove symbol in token array */          /* XXX: simplify */          if (!(v & SYM_FIELD) && (v & ~SYM_STRUCT) < SYM_FIRST_ANOM) {
              ts = table_ident[(v & ~SYM_STRUCT) - TOK_IDENT];
              if (v & SYM_STRUCT)                  ps = &ts->sym_struct;
              else                  ps = &ts->sym_identifier;
              *ps = s->prev_tok;

}   if (!keep)       sym_free(s);
          s = ss;

}      if (!keep)   *ptop = b;

}

ST_FUNC Sym *label_find(int v)  {
      v -= TOK_IDENT;
      if ((unsigned)v >= (unsigned)(tok_ident - TOK_IDENT))          return NULL;
      return table_ident[v]->sym_label;

}

ST_FUNC Sym *label_push(Sym **ptop, int v, int flags)  {
      Sym *s, **ps;
      s = sym_push2(ptop, v, VT_STATIC, 0);
      s->r = flags;
      ps = &table_ident[v - TOK_IDENT]->sym_label;
      if (ptop == &global_label_stack) {
          /* modify the top most local identifier, so that             sym_identifier will point to 's' when popped */          while (*ps != NULL)              ps = &(*ps)->prev_tok;

}      s->prev_tok = *ps;
      *ps = s;
      return s;

}

ST_FUNC void label_pop(Sym **ptop, Sym *slast, int keep)  {
      Sym *s, *s1;
      for(s = *ptop;
 s != slast;
 s = s1) {
          s1 = s->prev;
          if (s->r == LABEL_DECLARED) {
              tcc_warning_c(warn_all)("label '%s' declared but not used", get_tok_str(s->v, NULL));

} else if (s->r == LABEL_FORWARD) {
                  tcc_error("label '%s' used but not defined",                        get_tok_str(s->v, NULL));

} else {
              if (s->c) {
                  /* define corresponding symbol. A size of                     1 is put. */                  put_extern_sym(s, cur_text_section, s->jnext, 1);

}          
}          /* remove label */          if (s->r != LABEL_GONE)              table_ident[s->v - TOK_IDENT]->sym_label = s->prev_tok;
          if (!keep)              sym_free(s);
          else              s->r = LABEL_GONE;

}      if (!keep)          *ptop = slast;

}

static void vcheck_cmp(void)  {
      /* cannot let cpu flags if other instruction are generated. Also         avoid leaving VT_JMP anywhere except on the top of the stack         because it would complicate the code generator.           Don't do this when nocode_wanted.  vtop might come from         !nocode_wanted regions (see 88_codeopt.c) and transforming         it to a register without actually generating code is wrong         as their value might still be used for real.  All values         we push under nocode_wanted will eventually be popped         again, so that the VT_CMP/VT_JMP value will be in vtop         when code is unsuppressed again. */        /* However if it's just automatic suppression via CODE_OFF/ON()         then it seems that we better let things work undisturbed.         How can it work at all under nocode_wanted?  Well, gv() will         actually clear it at the gsym() in load()/VT_JMP in the         generator backends */        if (vtop->r == VT_CMP && 0 == (nocode_wanted & ~CODE_OFF_BIT))          gv(RC_INT);

}

static void vsetc(CType *type, int r, CValue *vc)  {
      if (vtop >= vstack + (VSTACK_SIZE - 1))          tcc_error("memory full (vstack)");
      vcheck_cmp();
      vtop++;
      vtop->type = *type;
      vtop->r = r;
      vtop->r2 = VT_CONST;
      vtop->c = *vc;
      vtop->sym = NULL;

}

ST_FUNC void vswap(void)  {
      SValue tmp;
        vcheck_cmp();
      tmp = vtop[0];
      vtop[0] = vtop[-1];
      vtop[-1] = tmp;

}

ST_FUNC void vpop(void)  {
      int v;
      v = vtop->r & VT_VALMASK;
  #if defined(TCC_TARGET_I386) || defined(TCC_TARGET_X86_64)      /* for x86, we need to pop the FP stack */      if (v == TREG_ST0) {
          o(0xd8dd);
 /* fstp %st(0) */      
} else  #endif      if (v == VT_CMP) {
          /* need to put correct jump if && or || without test */          gsym(vtop->jtrue);
          gsym(vtop->jfalse);

}      vtop--;

}

static void vpush(CType *type)  {
      vset(type, VT_CONST, 0);

}

static void vpush64(int ty, unsigned long long v)  {
      CValue cval;
      CType ctype;
      ctype.t = ty;
      ctype.ref = NULL;
      cval.i = v;
      vsetc(&ctype, VT_CONST, &cval);

}

ST_FUNC void vpushi(int v)  {
      vpush64(VT_INT, v);

}

static void vpushs(addr_t v)  {
      vpush64(VT_SIZE_T, v);

}

static inline void vpushll(long long v)  {
      vpush64(VT_LLONG, v);

}

ST_FUNC void vset(CType *type, int r, int v)  {
      CValue cval;
      cval.i = v;
      vsetc(type, r, &cval);

}

static void vseti(int r, int v)  {
      CType type;
      type.t = VT_INT;
      type.ref = NULL;
      vset(&type, r, v);

}

ST_FUNC void vpushv(SValue *v)  {
      if (vtop >= vstack + (VSTACK_SIZE - 1))          tcc_error("memory full (vstack)");
      vtop++;
      *vtop = *v;

}

static void vdup(void)  {
      vpushv(vtop);

}

ST_FUNC void vrotb(int n)  {
      SValue tmp;
      if (--n < 1)          return;
      vcheck_cmp();
      tmp = vtop[-n];
      memmove(vtop - n, vtop - n + 1, sizeof *vtop * n);
      vtop[0] = tmp;

}

ST_FUNC void vrott(int n)  {
      SValue tmp;
      if (--n < 1)          return;
      vcheck_cmp();
      tmp = vtop[0];
      memmove(vtop - n + 1, vtop - n, sizeof *vtop * n);
      vtop[-n] = tmp;

}

ST_FUNC void vrev(int n)  {
      int i;
      SValue tmp;
      vcheck_cmp();
      for (i = 0, n = -n;
 i > ++n;
 --i)          tmp = vtop[i], vtop[i] = vtop[n], vtop[n] = tmp;

}

ST_FUNC void vset_VT_CMP(int op)  {
      vtop->r = VT_CMP;
      vtop->cmp_op = op;
      vtop->jfalse = 0;
      vtop->jtrue = 0;

}

static void vset_VT_JMP(void)  {
      int op = vtop->cmp_op;
        if (vtop->jtrue || vtop->jfalse) {
          int origt = vtop->type.t;
          /* we need to jump to 'mov $0,%R' or 'mov $1,%R' */          int inv = op & (op < 2);
 /* small optimization */          vseti(VT_JMP+inv, gvtst(inv, 0));
          vtop->type.t |= origt & (VT_UNSIGNED | VT_DEFSIGN);

} else {
          /* otherwise convert flags (rsp. 0/1) to register */          vtop->c.i = op;
          if (op < 2) /* doesn't seem to happen */              vtop->r = VT_CONST;

}  
}

static void gvtst_set(int inv, int t)  {
      int *p;
        if (vtop->r != VT_CMP) {
          vpushi(0);
          gen_op(TOK_NE);
          if (vtop->r != VT_CMP) /* must be VT_CONST then */              vset_VT_CMP(vtop->c.i != 0);

}        p = inv ? &vtop->jfalse : &vtop->jtrue;
      *p = gjmp_append(*p, t);

}

static int gvtst(int inv, int t)  {
      int op, x, u;
        gvtst_set(inv, t);
      t = vtop->jtrue, u = vtop->jfalse;
      if (inv)          x = u, u = t, t = x;
      op = vtop->cmp_op;
        /* jump to the wanted target */      if (op > 1)          t = gjmp_cond(op ^ inv, t);
      else if (op != inv)          t = gjmp(t);
      /* resolve complementary jumps to here */      gsym(u);
        vtop--;
      return t;

}

static void gen_test_zero(int op)  {
      if (vtop->r == VT_CMP) {
          int j;
          if (op == TOK_EQ) {
              j = vtop->jfalse;
              vtop->jfalse = vtop->jtrue;
              vtop->jtrue = j;
              vtop->cmp_op ^= 1;

}      
} else {
          vpushi(0);
          gen_op(op);

}  
}

ST_FUNC void vpushsym(CType *type, Sym *sym)  {
      CValue cval;
      cval.i = 0;
      vsetc(type, VT_CONST | VT_SYM, &cval);
      vtop->sym = sym;

}

ST_FUNC Sym *get_sym_ref(CType *type, Section *sec, unsigned long offset, unsigned long size)  {
      int v;
      Sym *sym;
        v = anon_sym++;
      sym = sym_push(v, type, VT_CONST | VT_SYM, 0);
      sym->type.t |= VT_STATIC;
      put_extern_sym(sym, sec, offset, size);
      return sym;

}

static void vpush_ref(CType *type, Section *sec, unsigned long offset, unsigned long size)  {
      vpushsym(type, get_sym_ref(type, sec, offset, size));

}

ST_FUNC Sym *external_global_sym(int v, CType *type)  {
      Sym *s;
        s = sym_find(v);
      if (!s) {
          /* push forward reference */          s = global_identifier_push(v, type->t | VT_EXTERN, 0);
          s->type.ref = type->ref;

} else if (IS_ASM_SYM(s)) {
          s->type.t = type->t | (s->type.t & VT_EXTERN);
          s->type.ref = type->ref;
          update_storage(s);

}      return s;

}

ST_FUNC Sym *external_helper_sym(int v)  {
      CType ct = {
 VT_ASM_FUNC, NULL 
};
      return external_global_sym(v, &ct);

}

ST_FUNC void vpush_helper_func(int v)  {
      vpushsym(&func_old_type, external_helper_sym(v));

}

static void merge_symattr(struct SymAttr *sa, struct SymAttr *sa1)  {
      if (sa1->aligned && !sa->aligned)        sa->aligned = sa1->aligned;
      sa->packed |= sa1->packed;
      sa->weak |= sa1->weak;
      sa->nodebug |= sa1->nodebug;
      if (sa1->visibility != STV_DEFAULT) {
   int vis = sa->visibility;
   if (vis == STV_DEFAULT       || vis > sa1->visibility)     vis = sa1->visibility;
   sa->visibility = vis;

}      sa->dllexport |= sa1->dllexport;
      sa->nodecorate |= sa1->nodecorate;
      sa->dllimport |= sa1->dllimport;

}

static void merge_funcattr(struct FuncAttr *fa, struct FuncAttr *fa1)  {
      if (fa1->func_call && !fa->func_call)        fa->func_call = fa1->func_call;
      if (fa1->func_type && !fa->func_type)        fa->func_type = fa1->func_type;
      if (fa1->func_args && !fa->func_args)        fa->func_args = fa1->func_args;
      if (fa1->func_noreturn)        fa->func_noreturn = 1;
      if (fa1->func_ctor)        fa->func_ctor = 1;
      if (fa1->func_dtor)        fa->func_dtor = 1;

}

static void merge_attr(AttributeDef *ad, AttributeDef *ad1)  {
      merge_symattr(&ad->a, &ad1->a);
      merge_funcattr(&ad->f, &ad1->f);
        if (ad1->section)        ad->section = ad1->section;
      if (ad1->alias_target)        ad->alias_target = ad1->alias_target;
      if (ad1->asm_label)        ad->asm_label = ad1->asm_label;
      if (ad1->attr_mode)        ad->attr_mode = ad1->attr_mode;

}

static void patch_type(Sym *sym, CType *type)  {
      if (!(type->t & VT_EXTERN) || IS_ENUM_VAL(sym->type.t)) {
          if (!(sym->type.t & VT_EXTERN))              tcc_error("redefinition of '%s'", get_tok_str(sym->v, NULL));
          sym->type.t &= ~VT_EXTERN;

}        if (IS_ASM_SYM(sym)) {
          /* stay static if both are static */          sym->type.t = type->t & (sym->type.t | ~VT_STATIC);
          sym->type.ref = type->ref;
          if ((type->t & VT_BTYPE) != VT_FUNC && !(type->t & VT_ARRAY))              sym->r |= VT_LVAL;

}        if (!is_compatible_types(&sym->type, type)) {
          tcc_error("incompatible types for redefinition of '%s'",                    get_tok_str(sym->v, NULL));

} else if ((sym->type.t & VT_BTYPE) == VT_FUNC) {
          int static_proto = sym->type.t & VT_STATIC;
          /* warn if static follows non-static function declaration */          if ((type->t & VT_STATIC) && !static_proto              /* XXX this test for inline shouldn't be here.  Until we                 implement gnu-inline mode again it silences a warning for                 mingw caused by our workarounds.  */              && !((type->t | sym->type.t) & VT_INLINE))              tcc_warning("static storage ignored for redefinition of '%s'",                  get_tok_str(sym->v, NULL));
            /* set 'inline' if both agree or if one has static */          if ((type->t | sym->type.t) & VT_INLINE) {
              if (!((type->t ^ sym->type.t) & VT_INLINE)               || ((type->t | sym->type.t) & VT_STATIC))                  static_proto |= VT_INLINE;

}            if (0 == (type->t & VT_EXTERN)) {
              struct FuncAttr f = sym->type.ref->f;
              /* put complete type, use static from prototype */              sym->type.t = (type->t & ~(VT_STATIC|VT_INLINE)) | static_proto;
              sym->type.ref = type->ref;
              merge_funcattr(&sym->type.ref->f, &f);

} else {
              sym->type.t &= ~VT_INLINE | static_proto;

}            if (sym->type.ref->f.func_type == FUNC_OLD               && type->ref->f.func_type != FUNC_OLD) {
              sym->type.ref = type->ref;

}        
} else {
          if ((sym->type.t & VT_ARRAY) && type->ref->c >= 0) {
              /* set array size if it was omitted in extern declaration */              sym->type.ref->c = type->ref->c;

}          if ((type->t ^ sym->type.t) & VT_STATIC)              tcc_warning("storage mismatch for redefinition of '%s'",                  get_tok_str(sym->v, NULL));

}  
}

static void patch_storage(Sym *sym, AttributeDef *ad, CType *type)  {
      if (type)          patch_type(sym, type);
    #ifdef TCC_TARGET_PE      if (sym->a.dllimport != ad->a.dllimport)          tcc_error("incompatible dll linkage for redefinition of '%s'",              get_tok_str(sym->v, NULL));
  #endif      merge_symattr(&sym->a, &ad->a);
      if (ad->asm_label)          sym->asm_label = ad->asm_label;
      update_storage(sym);

}

static Sym *sym_copy(Sym *s0, Sym **ps)  {
      Sym *s;
      s = sym_malloc(), *s = *s0;
      s->prev = *ps, *ps = s;
      if (s->v < SYM_FIRST_ANOM) {
          ps = &table_ident[s->v - TOK_IDENT]->sym_identifier;
          s->prev_tok = *ps, *ps = s;

}      return s;

}

static void sym_copy_ref(Sym *s, Sym **ps)  {
      int bt = s->type.t & VT_BTYPE;
      if (bt == VT_FUNC || bt == VT_PTR || (bt == VT_STRUCT && s->sym_scope)) {
          Sym **sp = &s->type.ref;
          for (s = *sp, *sp = NULL;
 s;
 s = s->next) {
              Sym *s2 = sym_copy(s, ps);
              sp = &(*sp = s2)->next;
              sym_copy_ref(s2, ps);

}      
}  
}

static Sym *external_sym(int v, CType *type, int r, AttributeDef *ad)  {
      Sym *s;
        /* look for global symbol */      s = sym_find(v);
      while (s && s->sym_scope)          s = s->prev_tok;
        if (!s) {
          /* push forward reference */          s = global_identifier_push(v, type->t, 0);
          s->r |= r;
          s->a = ad->a;
          s->asm_label = ad->asm_label;
          s->type.ref = type->ref;
          /* copy type to the global stack */          if (local_stack)              sym_copy_ref(s, &global_stack);

} else {
          patch_storage(s, ad, type);

}      /* push variables on local_stack if any */      if (local_stack && (s->type.t & VT_BTYPE) != VT_FUNC)          s = sym_copy(s, &local_stack);
      return s;

}

ST_FUNC void save_regs(int n)  {
      SValue *p, *p1;
      for(p = vstack, p1 = vtop - n;
 p <= p1;
 p++)          save_reg(p->r);

}

ST_FUNC void save_reg(int r)  {
      save_reg_upstack(r, 0);

}

ST_FUNC void save_reg_upstack(int r, int n)  {
      int l, size, align, bt, r2;
      SValue *p, *p1, sv;
        if ((r &= VT_VALMASK) >= VT_CONST)          return;
      if (nocode_wanted)          return;
      l = r2 = 0;
      for(p = vstack, p1 = vtop - n;
 p <= p1;
 p++) {
          if ((p->r & VT_VALMASK) == r || p->r2 == r) {
              /* must save value on stack if not already done */              if (!l) {
                  bt = p->type.t & VT_BTYPE;
                  if (bt == VT_VOID)                      continue;
                  if ((p->r & VT_LVAL) || bt == VT_FUNC)                      bt = VT_PTR;
                  sv.type.t = bt;
                  size = type_size(&sv.type, &align);
                  l = get_temp_local_var(size, align, &r2);
                  sv.r = VT_LOCAL | VT_LVAL;
                  sv.c.i = l;
                  store(p->r & VT_VALMASK, &sv);
  #if defined(TCC_TARGET_I386) || defined(TCC_TARGET_X86_64)                  /* x86 specific: need to pop fp register ST0 if saved */                  if (r == TREG_ST0) {
                      o(0xd8dd);
 /* fstp %st(0) */                  
}  #endif                  /* special long long case */                  if (p->r2 < VT_CONST && USING_TWO_WORDS(bt)) {
                      sv.c.i += PTR_SIZE;
                      store(p->r2, &sv);

}              
}              /* mark that stack entry as being saved on the stack */              if (p->r & VT_LVAL) {
                  /* also clear the bounded flag because the                     relocation address of the function was stored in                     p->c.i */                  p->r = (p->r & ~(VT_VALMASK | VT_BOUNDED)) | VT_LLOCAL;

} else {
                  p->r = VT_LVAL | VT_LOCAL;
                  p->type.t &= ~VT_ARRAY;
 /* cannot combine VT_LVAL with VT_ARRAY */              
}              p->sym = NULL;
              p->r2 = r2;
              p->c.i = l;

}      
}  
}

ST_FUNC int get_reg(int rc)  {
      int r;
      SValue *p;
        /* find a free register */      for(r=0;
r<NB_REGS;
r++) {
          if (reg_classes[r] & rc) {
              if (nocode_wanted)                  return r;
              for(p=vstack;
p<=vtop;
p++) {
                  if ((p->r & VT_VALMASK) == r ||                      p->r2 == r)                      goto notfound;

}              return r;

}      notfound:;

}            /* no register left : free the first one on the stack (VERY         IMPORTANT to start from the bottom to ensure that we don't         spill registers used in gen_opi()) */      for(p=vstack;
p<=vtop;
p++) {
          /* look at second register (if long long) */          r = p->r2;
          if (r < VT_CONST && (reg_classes[r] & rc))              goto save_found;
          r = p->r & VT_VALMASK;
          if (r < VT_CONST && (reg_classes[r] & rc)) {
          save_found:              save_reg(r);
              return r;

}      
}      /* Should never comes here */      return -1;

}

static int get_temp_local_var(int size,int align, int *r2)  {
      int i;
      struct temp_local_variable *temp_var;
      SValue *p;
      int r;
      unsigned used = 0;
        /* mark locations that are still in use */      for (p = vstack;
 p <= vtop;
 p++) {
   r = p->r & VT_VALMASK;
   if (r == VT_LOCAL || r == VT_LLOCAL) {
       r = p->r2 - (VT_CONST + 1);
       if (r >= 0 && r < MAX_TEMP_LOCAL_VARIABLE_NUMBER)           used |= 1<<r;

}      
}      for (i=0;
i<nb_temp_local_vars;
i++) {
   temp_var=&arr_temp_local_vars[i];
   if(!(used & 1<<i)    && temp_var->size>=size    && temp_var->align>=align) {
  ret_tmp:       *r2 = (VT_CONST + 1) + i;
       return temp_var->location;

}      
}      loc = (loc - size) & -align;
      if (nb_temp_local_vars<MAX_TEMP_LOCAL_VARIABLE_NUMBER) {
   temp_var=&arr_temp_local_vars[i];
   temp_var->location=loc;
   temp_var->size=size;
   temp_var->align=align;
   nb_temp_local_vars++;
   goto ret_tmp;

}      *r2 = VT_CONST;
      return loc;

}

static void move_reg(int r, int s, int t)  {
      SValue sv;
        if (r != s) {
          save_reg(r);
          sv.type.t = t;
          sv.type.ref = NULL;
          sv.r = s;
          sv.c.i = 0;
          load(r, &sv);

}  
}

ST_FUNC void gaddrof(void)  {
      vtop->r &= ~VT_LVAL;
      /* tricky: if saved lvalue, then we can go back to lvalue */      if ((vtop->r & VT_VALMASK) == VT_LLOCAL)          vtop->r = (vtop->r & ~VT_VALMASK) | VT_LOCAL | VT_LVAL;

}

static void pop_local_syms(Sym *b, int keep)  {
  #ifdef CONFIG_TCC_BCHECK      if (tcc_state->do_bounds_check && !keep && (local_scope || !func_var))          add_local_bounds(local_stack, b);
  #endif      if (debug_modes)          tcc_add_debug_info (tcc_state, !local_scope, local_stack, b);
      sym_pop(&local_stack, b, keep);

}

static void incr_offset(int offset)  {
      int t = vtop->type.t;
      gaddrof();
 /* remove VT_LVAL */      vtop->type.t = VT_PTRDIFF_T;
 /* set scalar type */      vpushs(offset);
      gen_op('+');
      vtop->r |= VT_LVAL;
      vtop->type.t = t;

}

static void incr_bf_adr(int o)  {
      vtop->type.t = VT_BYTE | VT_UNSIGNED;
      incr_offset(o);

}

static void load_packed_bf(CType *type, int bit_pos, int bit_size)  {
      int n, o, bits;
      save_reg_upstack(vtop->r, 1);
      vpush64(type->t & VT_BTYPE, 0);
 // B X      bits = 0, o = bit_pos >> 3, bit_pos &= 7;
      do {
          vswap();
 // X B          incr_bf_adr(o);
          vdup();
 // X B B          n = 8 - bit_pos;
          if (n > bit_size)              n = bit_size;
          if (bit_pos)              vpushi(bit_pos), gen_op(TOK_SHR), bit_pos = 0;
 // X B Y          if (n < 8)              vpushi((1 << n) - 1), gen_op('&');
          gen_cast(type);
          if (bits)              vpushi(bits), gen_op(TOK_SHL);
          vrotb(3);
 // B Y X          gen_op('|');
 // B X          bits += n, bit_size -= n, o = 1;

} while (bit_size);
      vswap(), vpop();
      if (!(type->t & VT_UNSIGNED)) {
          n = ((type->t & VT_BTYPE) == VT_LLONG ? 64 : 32) - bits;
          vpushi(n), gen_op(TOK_SHL);
          vpushi(n), gen_op(TOK_SAR);

}  
}

static void store_packed_bf(int bit_pos, int bit_size)  {
      int bits, n, o, m, c;
      c = (vtop->r & (VT_VALMASK | VT_LVAL | VT_SYM)) == VT_CONST;
      vswap();
 // X B      save_reg_upstack(vtop->r, 1);
      bits = 0, o = bit_pos >> 3, bit_pos &= 7;
      do {
          incr_bf_adr(o);
 // X B          vswap();
 //B X          c ? vdup() : gv_dup();
 // B V X          vrott(3);
 // X B V          if (bits)              vpushi(bits), gen_op(TOK_SHR);
          if (bit_pos)              vpushi(bit_pos), gen_op(TOK_SHL);
          n = 8 - bit_pos;
          if (n > bit_size)              n = bit_size;
          if (n < 8) {
              m = ((1 << n) - 1) << bit_pos;
              vpushi(m), gen_op('&');
 // X B V1              vpushv(vtop-1);
 // X B V1 B              vpushi(m & 0x80 ? ~m & 0x7f : ~m);
              gen_op('&');
 // X B V1 B1              gen_op('|');
 // X B V2          
}          vdup(), vtop[-1] = vtop[-2];
 // X B B V2          vstore(), vpop();
 // X B          bits += n, bit_size -= n, bit_pos = 0, o = 1;

} while (bit_size);
      vpop(), vpop();

}

static int adjust_bf(SValue *sv, int bit_pos, int bit_size)  {
      int t;
      if (0 == sv->type.ref)          return 0;
      t = sv->type.ref->auxtype;
      if (t != -1 && t != VT_STRUCT) {
          sv->type.t = (sv->type.t & ~(VT_BTYPE | VT_LONG)) | t;
          sv->r |= VT_LVAL;

}      return t;

}

ST_FUNC int gv(int rc)  {
      int r, r2, r_ok, r2_ok, rc2, bt;
      int bit_pos, bit_size, size, align;
        /* NOTE: get_reg can modify vstack[] */      if (vtop->type.t & VT_BITFIELD) {
          CType type;
            bit_pos = BIT_POS(vtop->type.t);
          bit_size = BIT_SIZE(vtop->type.t);
          /* remove bit field info to avoid loops */          vtop->type.t &= ~VT_STRUCT_MASK;
            type.ref = NULL;
          type.t = vtop->type.t & VT_UNSIGNED;
          if ((vtop->type.t & VT_BTYPE) == VT_BOOL)              type.t |= VT_UNSIGNED;
            r = adjust_bf(vtop, bit_pos, bit_size);
            if ((vtop->type.t & VT_BTYPE) == VT_LLONG)              type.t |= VT_LLONG;
          else              type.t |= VT_INT;
            if (r == VT_STRUCT) {
              load_packed_bf(&type, bit_pos, bit_size);

} else {
              int bits = (type.t & VT_BTYPE) == VT_LLONG ? 64 : 32;
              /* cast to int to propagate signedness in following ops */              gen_cast(&type);
              /* generate shifts */              vpushi(bits - (bit_pos + bit_size));
              gen_op(TOK_SHL);
              vpushi(bits - bit_size);
              /* NOTE: transformed to SHR if unsigned */              gen_op(TOK_SAR);

}          r = gv(rc);

} else {
          if (is_float(vtop->type.t) &&               (vtop->r & (VT_VALMASK | VT_LVAL)) == VT_CONST) {
              /* CPUs usually cannot use float constants, so we store them                 generically in data segment */              init_params p = {
 rodata_section 
};
              unsigned long offset;
              size = type_size(&vtop->type, &align);
              if (NODATA_WANTED)                  size = 0, align = 1;
              offset = section_add(p.sec, size, align);
              vpush_ref(&vtop->type, p.sec, offset, size);
       vswap();
       init_putv(&p, &vtop->type, offset);
       vtop->r |= VT_LVAL;

}  #ifdef CONFIG_TCC_BCHECK          if (vtop->r & VT_MUSTBOUND)               gbound();
  #endif            bt = vtop->type.t & VT_BTYPE;
    #ifdef TCC_TARGET_RISCV64          /* XXX mega hack */          if (bt == VT_LDOUBLE && rc == RC_FLOAT)            rc = RC_INT;
  #endif          rc2 = RC2_TYPE(bt, rc);
            /* need to reload if:             - constant             - lvalue (need to dereference pointer)             - already a register, but not in the right class */          r = vtop->r & VT_VALMASK;
          r_ok = !(vtop->r & VT_LVAL) && (r < VT_CONST) && (reg_classes[r] & rc);
          r2_ok = !rc2 || ((vtop->r2 < VT_CONST) && (reg_classes[vtop->r2] & rc2));
            if (!r_ok || !r2_ok) {
                if (!r_ok) {
                  if (1 /* we can 'mov (r),r' in cases */                      && r < VT_CONST                      && (reg_classes[r] & rc)                      && !rc2                      )                      save_reg_upstack(r, 1);
                  else                      r = get_reg(rc);

}                if (rc2) {
                  int load_type = (bt == VT_QFLOAT) ? VT_DOUBLE : VT_PTRDIFF_T;
                  int original_type = vtop->type.t;
                    /* two register type load :                     expand to two words temporarily */                  if ((vtop->r & (VT_VALMASK | VT_LVAL)) == VT_CONST) {
                      /* load constant */                      unsigned long long ll = vtop->c.i;
                      vtop->c.i = ll;
 /* first word */                      load(r, vtop);
                      vtop->r = r;
 /* save register value */                      vpushi(ll >> 32);
 /* second word */                  
} else if (vtop->r & VT_LVAL) {
                      /* We do not want to modifier the long long pointer here.                         So we save any other instances down the stack */                      save_reg_upstack(vtop->r, 1);
                      /* load from memory */                      vtop->type.t = load_type;
                      load(r, vtop);
                      vdup();
                      vtop[-1].r = r;
 /* save register value */                      /* increment pointer to get second word */                      incr_offset(PTR_SIZE);

} else {
                      /* move registers */                      if (!r_ok)                          load(r, vtop);
                      if (r2_ok && vtop->r2 < VT_CONST)                          goto done;
                      vdup();
                      vtop[-1].r = r;
 /* save register value */                      vtop->r = vtop[-1].r2;

}                  /* Allocate second register. Here we rely on the fact that                     get_reg() tries first to free r2 of an SValue. */                  r2 = get_reg(rc2);
                  load(r2, vtop);
                  vpop();
                  /* write second register */                  vtop->r2 = r2;
              done:                  vtop->type.t = original_type;

} else {
                  if (vtop->r == VT_CMP)                      vset_VT_JMP();
                  /* one register type load */                  load(r, vtop);

}          
}          vtop->r = r;
  #ifdef TCC_TARGET_C67          /* uses register pairs for doubles */          if (bt == VT_DOUBLE)              vtop->r2 = r+1;
  #endif      
}      return r;

}

ST_FUNC void gv2(int rc1, int rc2)  {
      /* generate more generic register first. But VT_JMP or VT_CMP         values must be generated first in all cases to avoid possible         reload errors */      if (vtop->r != VT_CMP && rc1 <= rc2) {
          vswap();
          gv(rc1);
          vswap();
          gv(rc2);
          /* test if reload is needed for first register */          if ((vtop[-1].r & VT_VALMASK) >= VT_CONST) {
              vswap();
              gv(rc1);
              vswap();

}      
} else {
          gv(rc2);
          vswap();
          gv(rc1);
          vswap();
          /* test if reload is needed for first register */          if ((vtop[0].r & VT_VALMASK) >= VT_CONST) {
              gv(rc2);

}      
}  
}

static void gv_dup(void)  {
      int t, rc, r;
        t = vtop->type.t;
  #if PTR_SIZE == 4      if ((t & VT_BTYPE) == VT_LLONG) {
          if (t & VT_BITFIELD) {
              gv(RC_INT);
              t = vtop->type.t;

}          lexpand();
          gv_dup();
          vswap();
          vrotb(3);
          gv_dup();
          vrotb(4);
          /* stack: H L L1 H1 */          lbuild(t);
          vrotb(3);
          vrotb(3);
          vswap();
          lbuild(t);
          vswap();
          return;

}  #endif      /* duplicate value */      rc = RC_TYPE(t);
      gv(rc);
      r = get_reg(rc);
      vdup();
      load(r, vtop);
      vtop->r = r;

}

static uint64_t value64(uint64_t l1, int t)  {
      if ((t & VT_BTYPE) == VT_LLONG          || (PTR_SIZE == 8 && (t & VT_BTYPE) == VT_PTR))          return l1;
      else if (t & VT_UNSIGNED)          return (uint32_t)l1;
      else          return (uint32_t)l1 | -(l1 & 0x80000000);

}

static uint64_t gen_opic_sdiv(uint64_t a, uint64_t b)  {
      uint64_t x = (a >> 63 ? -a : a) / (b >> 63 ? -b : b);
      return (a ^ b) >> 63 ? -x : x;

}

static int gen_opic_lt(uint64_t a, uint64_t b)  {
      return (a ^ (uint64_t)1 << 63) < (b ^ (uint64_t)1 << 63);

}

static void gen_opic(int op)  {
      SValue *v1 = vtop - 1;
      SValue *v2 = vtop;
      int t1 = v1->type.t & VT_BTYPE;
      int t2 = v2->type.t & VT_BTYPE;
      int c1 = (v1->r & (VT_VALMASK | VT_LVAL | VT_SYM)) == VT_CONST;
      int c2 = (v2->r & (VT_VALMASK | VT_LVAL | VT_SYM)) == VT_CONST;
      uint64_t l1 = c1 ? value64(v1->c.i, v1->type.t) : 0;
      uint64_t l2 = c2 ? value64(v2->c.i, v2->type.t) : 0;
      int shm = (t1 == VT_LLONG) ? 63 : 31;
      int r;
        if (c1 && c2) {
          switch(op) {
          case '+': l1 += l2;
 break;
          case '-': l1 -= l2;
 break;
          case '&': l1 &= l2;
 break;
          case '^': l1 ^= l2;
 break;
          case '|': l1 |= l2;
 break;
          case '*': l1 *= l2;
 break;
            case TOK_PDIV:          case '/':          case '%':          case TOK_UDIV:          case TOK_UMOD:              /* if division by zero, generate explicit division */              if (l2 == 0) {
                  if (CONST_WANTED && !NOEVAL_WANTED)                      tcc_error("division by zero in constant");
                  goto general_case;

}              switch(op) {
              default: l1 = gen_opic_sdiv(l1, l2);
 break;
              case '%': l1 = l1 - l2 * gen_opic_sdiv(l1, l2);
 break;
              case TOK_UDIV: l1 = l1 / l2;
 break;
              case TOK_UMOD: l1 = l1 % l2;
 break;

}              break;
          case TOK_SHL: l1 <<= (l2 & shm);
 break;
          case TOK_SHR: l1 >>= (l2 & shm);
 break;
          case TOK_SAR:              l1 = (l1 >> 63) ? ~(~l1 >> (l2 & shm)) : l1 >> (l2 & shm);
              break;
              /* tests */          case TOK_ULT: l1 = l1 < l2;
 break;
          case TOK_UGE: l1 = l1 >= l2;
 break;
          case TOK_EQ: l1 = l1 == l2;
 break;
          case TOK_NE: l1 = l1 != l2;
 break;
          case TOK_ULE: l1 = l1 <= l2;
 break;
          case TOK_UGT: l1 = l1 > l2;
 break;
          case TOK_LT: l1 = gen_opic_lt(l1, l2);
 break;
          case TOK_GE: l1 = !gen_opic_lt(l1, l2);
 break;
          case TOK_LE: l1 = !gen_opic_lt(l2, l1);
 break;
          case TOK_GT: l1 = gen_opic_lt(l2, l1);
 break;
              /* logical */          case TOK_LAND: l1 = l1 && l2;
 break;
          case TOK_LOR: l1 = l1 || l2;
 break;
          default:              goto general_case;

}          v1->c.i = value64(l1, v1->type.t);
          v1->r |= v2->r & VT_NONCONST;
          vtop--;

} else {
          /* if commutative ops, put c2 as constant */          if (c1 && (op == '+' || op == '&' || op == '^' ||                      op == '|' || op == '*' || op == TOK_EQ || op == TOK_NE)) {
              vswap();
              c2 = c1;
 //c = c1, c1 = c2, c2 = c;
              l2 = l1;
 //l = l1, l1 = l2, l2 = l;

}          if (c1 && ((l1 == 0 &&                      (op == TOK_SHL || op == TOK_SHR || op == TOK_SAR)) ||                     (l1 == -1 && op == TOK_SAR))) {
              /* treat (0 << x), (0 >> x) and (-1 >> x) as constant */              vpop();

} else if (c2 && ((l2 == 0 && (op == '&' || op == '*')) ||                            (op == '|' &&                              (l2 == -1 || (l2 == 0xFFFFFFFF && t2 != VT_LLONG))) ||                            (l2 == 1 && (op == '%' || op == TOK_UMOD)))) {
              /* treat (x & 0), (x * 0), (x | -1) and (x % 1) as constant */              if (l2 == 1)                  vtop->c.i = 0;
              vswap();
              vtop--;

} else if (c2 && (((op == '*' || op == '/' || op == TOK_UDIV ||                            op == TOK_PDIV) &&                             l2 == 1) ||                            ((op == '+' || op == '-' || op == '|' || op == '^' ||                              op == TOK_SHL || op == TOK_SHR || op == TOK_SAR) &&                             l2 == 0) ||                            (op == '&' &&                              (l2 == -1 || (l2 == 0xFFFFFFFF && t2 != VT_LLONG))))) {
              /* filter out NOP operations like x*1, x-0, x&-1... */              vtop--;

} else if (c2 && (op == '*' || op == TOK_PDIV || op == TOK_UDIV)) {
              /* try to use shifts instead of muls or divs */              if (l2 > 0 && (l2 & (l2 - 1)) == 0) {
                  int n = -1;
                  while (l2) {
                      l2 >>= 1;
                      n++;

}                  vtop->c.i = n;
                  if (op == '*')                      op = TOK_SHL;
                  else if (op == TOK_PDIV)                      op = TOK_SAR;
                  else                      op = TOK_SHR;

}              goto general_case;

} else if (c2 && (op == '+' || op == '-') &&                     (r = vtop[-1].r & (VT_VALMASK | VT_LVAL | VT_SYM),                      r == (VT_CONST | VT_SYM) || r == VT_LOCAL)) {
              /* symbol + constant case */              if (op == '-')                  l2 = -l2;
       l2 += vtop[-1].c.i;
       /* The backends can't always deal with addends to symbols          larger than +-1<<31.  Don't construct such.  */       if ((int)l2 != l2)           goto general_case;
              vtop--;
              vtop->c.i = l2;

} else {
          general_case:                  /* call low level op generator */                  if (t1 == VT_LLONG || t2 == VT_LLONG ||                      (PTR_SIZE == 8 && (t1 == VT_PTR || t2 == VT_PTR)))                      gen_opl(op);
                  else                      gen_opi(op);

}          if (vtop->r == VT_CONST)              vtop->r |= VT_NONCONST;
 /* is const, but only by optimization */      
}  
}

static void gen_opif(int op)  {
      int c1, c2, i, bt;
      SValue *v1, *v2;
  #if defined _MSC_VER && defined __x86_64__      /* avoid bad optimization with f1 -= f2 for f1:-0.0, f2:0.0 */      volatile  #endif      long double f1, f2;
        v1 = vtop - 1;
      v2 = vtop;
      if (op == TOK_NEG)          v1 = v2;
      bt = v1->type.t & VT_BTYPE;
        /* currently, we cannot do computations with forward symbols */      c1 = (v1->r & (VT_VALMASK | VT_LVAL | VT_SYM)) == VT_CONST;
      c2 = (v2->r & (VT_VALMASK | VT_LVAL | VT_SYM)) == VT_CONST;
      if (c1 && c2) {
          if (bt == VT_FLOAT) {
              f1 = v1->c.f;
              f2 = v2->c.f;

} else if (bt == VT_DOUBLE) {
              f1 = v1->c.d;
              f2 = v2->c.d;

} else {
              f1 = v1->c.ld;
              f2 = v2->c.ld;

}          /* NOTE: we only do constant propagation if finite number (not             NaN or infinity) (ANSI spec) */          if (!(ieee_finite(f1) || !ieee_finite(f2)) && !CONST_WANTED)              goto general_case;
          switch(op) {
          case '+': f1 += f2;
 break;
          case '-': f1 -= f2;
 break;
          case '*': f1 *= f2;
 break;
          case '/':               if (f2 == 0.0) {
                  union {
 float f;
 unsigned u;

} x1, x2, y;
    /* If not in initializer we need to potentially generate       FP exceptions at runtime, otherwise we want to fold.  */                  if (!CONST_WANTED)                      goto general_case;
                  /* the run-time result of 0.0/0.0 on x87, also of other compilers                     when used to compile the f1 /= f2 below, would be -nan */                  x1.f = f1, x2.f = f2;
                  if (f1 == 0.0)                      y.u = 0x7fc00000;
 /* nan */                  else                      y.u = 0x7f800000;
 /* infinity */                  y.u |= (x1.u ^ x2.u) & 0x80000000;
 /* set sign */                  f1 = y.f;
                  break;

}              f1 /= f2;
              break;
          case TOK_NEG:              f1 = -f1;
              goto unary_result;
          case TOK_EQ:              i = f1 == f2;
   make_int:              vtop -= 2;
              vpushi(i);
              return;
          case TOK_NE:              i = f1 != f2;
       goto make_int;
          case TOK_LT:              i = f1 < f2;
       goto make_int;
          case TOK_GE:              i = f1 >= f2;
       goto make_int;
          case TOK_LE:              i = f1 <= f2;
       goto make_int;
          case TOK_GT:              i = f1 > f2;
       goto make_int;
          default:              goto general_case;

}          vtop--;
      unary_result:          /* XXX: overflow test ? */          if (bt == VT_FLOAT) {
              v1->c.f = f1;

} else if (bt == VT_DOUBLE) {
              v1->c.d = f1;

} else {
              v1->c.ld = f1;

}      
} else {
      general_case:          if (op == TOK_NEG) {
              gen_negf(op);

} else {
              gen_opf(op);

}      
}  
}

static void type_to_str(char *buf, int buf_size,                   CType *type, const char *varstr)  {
      int bt, v, t;
      Sym *s, *sa;
      char buf1[256];
      const char *tstr;
        t = type->t;
      bt = t & VT_BTYPE;
      buf[0] = '\0';
        if (t & VT_EXTERN)          pstrcat(buf, buf_size, "extern ");
      if (t & VT_STATIC)          pstrcat(buf, buf_size, "static ");
      if (t & VT_TYPEDEF)          pstrcat(buf, buf_size, "typedef ");
      if (t & VT_INLINE)          pstrcat(buf, buf_size, "inline ");
      if (bt != VT_PTR) {
          if (t & VT_VOLATILE)              pstrcat(buf, buf_size, "volatile ");
          if (t & VT_CONSTANT)              pstrcat(buf, buf_size, "const ");

}      if (((t & VT_DEFSIGN) && bt == VT_BYTE)          || ((t & VT_UNSIGNED)              && (bt == VT_SHORT || bt == VT_INT || bt == VT_LLONG)              && !IS_ENUM(t)              ))          pstrcat(buf, buf_size, (t & VT_UNSIGNED) ? "unsigned " : "signed ");
        buf_size -= strlen(buf);
      buf += strlen(buf);
        switch(bt) {
      case VT_VOID:          tstr = "void";
          goto add_tstr;
      case VT_BOOL:          tstr = "_Bool";
          goto add_tstr;
      case VT_BYTE:          tstr = "char";
          goto add_tstr;
      case VT_SHORT:          tstr = "short";
          goto add_tstr;
      case VT_INT:          tstr = "int";
          goto maybe_long;
      case VT_LLONG:          tstr = "long long";
      maybe_long:          if (t & VT_LONG)              tstr = "long";
          if (!IS_ENUM(t))              goto add_tstr;
          tstr = "enum ";
          goto tstruct;
      case VT_FLOAT:          tstr = "float";
          goto add_tstr;
      case VT_DOUBLE:          tstr = "double";
          if (!(t & VT_LONG))              goto add_tstr;
      case VT_LDOUBLE:          tstr = "long double";
      add_tstr:          pstrcat(buf, buf_size, tstr);
          break;
      case VT_STRUCT:          tstr = "struct ";
          if (IS_UNION(t))              tstr = "union ";
      tstruct:          pstrcat(buf, buf_size, tstr);
          v = type->ref->v & ~SYM_STRUCT;
          if (v >= SYM_FIRST_ANOM)              pstrcat(buf, buf_size, "<anonymous>");
          else              pstrcat(buf, buf_size, get_tok_str(v, NULL));
          break;
      case VT_FUNC:          s = type->ref;
          buf1[0]=0;
          if (varstr && '*' == *varstr) {
              pstrcat(buf1, sizeof(buf1), "(");
              pstrcat(buf1, sizeof(buf1), varstr);
              pstrcat(buf1, sizeof(buf1), ")");

}          pstrcat(buf1, buf_size, "(");
          sa = s->next;
          while (sa != NULL) {
              char buf2[256];
              type_to_str(buf2, sizeof(buf2), &sa->type, NULL);
              pstrcat(buf1, sizeof(buf1), buf2);
              sa = sa->next;
              if (sa)                  pstrcat(buf1, sizeof(buf1), ", ");

}          if (s->f.func_type == FUNC_ELLIPSIS)              pstrcat(buf1, sizeof(buf1), ", ...");
          pstrcat(buf1, sizeof(buf1), ")");
          type_to_str(buf, buf_size, &s->type, buf1);
          goto no_var;
      case VT_PTR:          s = type->ref;
          if (t & (VT_ARRAY|VT_VLA)) {
              if (varstr && '*' == *varstr)                  snprintf(buf1, sizeof(buf1), "(%s)[%d]", varstr, s->c);
              else                  snprintf(buf1, sizeof(buf1), "%s[%d]", varstr ? varstr : "", s->c);
              type_to_str(buf, buf_size, &s->type, buf1);
              goto no_var;

}          pstrcpy(buf1, sizeof(buf1), "*");
          if (t & VT_CONSTANT)              pstrcat(buf1, buf_size, "const ");
          if (t & VT_VOLATILE)              pstrcat(buf1, buf_size, "volatile ");
          if (varstr)              pstrcat(buf1, sizeof(buf1), varstr);
          type_to_str(buf, buf_size, &s->type, buf1);
          goto no_var;

}      if (varstr) {
          pstrcat(buf, buf_size, " ");
          pstrcat(buf, buf_size, varstr);

}   no_var:;

}

static void type_incompatibility_error(CType* st, CType* dt, const char* fmt)  {
      char buf1[256], buf2[256];
      type_to_str(buf1, sizeof(buf1), st, NULL);
      type_to_str(buf2, sizeof(buf2), dt, NULL);
      tcc_error(fmt, buf1, buf2);

}

static void type_incompatibility_warning(CType* st, CType* dt, const char* fmt)  {
      char buf1[256], buf2[256];
      type_to_str(buf1, sizeof(buf1), st, NULL);
      type_to_str(buf2, sizeof(buf2), dt, NULL);
      tcc_warning(fmt, buf1, buf2);

}

static int pointed_size(CType *type)  {
      int align;
      return type_size(pointed_type(type), &align);

}

static inline int is_null_pointer(SValue *p)  {
      if ((p->r & (VT_VALMASK | VT_LVAL | VT_SYM | VT_NONCONST)) != VT_CONST)          return 0;
      return ((p->type.t & VT_BTYPE) == VT_INT && (uint32_t)p->c.i == 0) ||          ((p->type.t & VT_BTYPE) == VT_LLONG && p->c.i == 0) ||          ((p->type.t & VT_BTYPE) == VT_PTR &&           (PTR_SIZE == 4 ? (uint32_t)p->c.i == 0 : p->c.i == 0) &&           ((pointed_type(&p->type)->t & VT_BTYPE) == VT_VOID) &&           0 == (pointed_type(&p->type)->t & (VT_CONSTANT | VT_VOLATILE))           );

}

static int is_compatible_func(CType *type1, CType *type2)  {
      Sym *s1, *s2;
        s1 = type1->ref;
      s2 = type2->ref;
      if (s1->f.func_call != s2->f.func_call)          return 0;
      if (s1->f.func_type != s2->f.func_type          && s1->f.func_type != FUNC_OLD          && s2->f.func_type != FUNC_OLD)          return 0;
      for (;
;
) {
          if (!is_compatible_unqualified_types(&s1->type, &s2->type))              return 0;
          if (s1->f.func_type == FUNC_OLD || s2->f.func_type == FUNC_OLD )              return 1;
          s1 = s1->next;
          s2 = s2->next;
          if (!s1)              return !s2;
          if (!s2)              return 0;

}  
}

static int compare_types(CType *type1, CType *type2, int unqualified)  {
      int bt1, t1, t2;
        t1 = type1->t & VT_TYPE;
      t2 = type2->t & VT_TYPE;
      if (unqualified) {
          /* strip qualifiers before comparing */          t1 &= ~(VT_CONSTANT | VT_VOLATILE);
          t2 &= ~(VT_CONSTANT | VT_VOLATILE);

}        /* Default Vs explicit signedness only matters for char */      if ((t1 & VT_BTYPE) != VT_BYTE) {
          t1 &= ~VT_DEFSIGN;
          t2 &= ~VT_DEFSIGN;

}      /* XXX: bitfields ? */      if (t1 != t2)          return 0;
        if ((t1 & VT_ARRAY)          && !(type1->ref->c < 0            || type2->ref->c < 0            || type1->ref->c == type2->ref->c))              return 0;
        /* test more complicated cases */      bt1 = t1 & VT_BTYPE;
      if (bt1 == VT_PTR) {
          type1 = pointed_type(type1);
          type2 = pointed_type(type2);
          return is_compatible_types(type1, type2);

} else if (bt1 == VT_STRUCT) {
          return (type1->ref == type2->ref);

} else if (bt1 == VT_FUNC) {
          return is_compatible_func(type1, type2);

} else if (IS_ENUM(type1->t) && IS_ENUM(type2->t)) {
          /* If both are enums then they must be the same, if only one is then             t1 and t2 must be equal, which was checked above already.  */          return type1->ref == type2->ref;

} else {
          return 1;

}  
}

static int combine_types(CType *dest, SValue *op1, SValue *op2, int op)  {
      CType *type1, *type2, type;
      int t1, t2, bt1, bt2;
      int ret = 1;
        /* for shifts, 'combine' only left operand */      if (op == SHIFT_OP)          op2 = op1;
        type1 = &op1->type, type2 = &op2->type;
      t1 = type1->t, t2 = type2->t;
      bt1 = t1 & VT_BTYPE, bt2 = t2 & VT_BTYPE;
        type.t = VT_VOID;
      type.ref = NULL;
        if (bt1 == VT_VOID || bt2 == VT_VOID) {
          ret = op == '?' ? 1 : 0;
          /* NOTE: as an extension, we accept void on only one side */          type.t = VT_VOID;

} else if (bt1 == VT_PTR || bt2 == VT_PTR) {
          if (op == '+') {
            if (!is_integer_btype(bt1 == VT_PTR ? bt2 : bt1))              ret = 0;

}          /* http://port70.net/~nsz/c/c99/n1256.html#6.5.15p6 */          /* If one is a null ptr constant the result type is the other.  */          else if (is_null_pointer (op2)) type = *type1;
          else if (is_null_pointer (op1)) type = *type2;
          else if (bt1 != bt2) {
              /* accept comparison or cond-expr between pointer and integer                 with a warning */              if ((op == '?' || op == CMP_OP)                  && (is_integer_btype(bt1) || is_integer_btype(bt2)))                tcc_warning("pointer/integer mismatch in %s",                            op == '?' ? "conditional expression" : "comparison");
              else if (op != '-' || !is_integer_btype(bt2))                ret = 0;
              type = *(bt1 == VT_PTR ? type1 : type2);

} else {
              CType *pt1 = pointed_type(type1);
              CType *pt2 = pointed_type(type2);
              int pbt1 = pt1->t & VT_BTYPE;
              int pbt2 = pt2->t & VT_BTYPE;
              int newquals, copied = 0;
              if (pbt1 != VT_VOID && pbt2 != VT_VOID                  && !compare_types(pt1, pt2, 1/*unqualif*/)) {
                  if (op != '?' && op != CMP_OP)                    ret = 0;
                  else                    type_incompatibility_warning(type1, type2,                      op == '?'                       ? "pointer type mismatch in conditional expression ('%s' and '%s')"                       : "pointer type mismatch in comparison('%s' and '%s')");

}              if (op == '?') {
                  /* pointers to void get preferred, otherwise the                     pointed to types minus qualifs should be compatible */                  type = *((pbt1 == VT_VOID) ? type1 : type2);
                  /* combine qualifs */                  newquals = ((pt1->t | pt2->t) & (VT_CONSTANT | VT_VOLATILE));
                  if ((~pointed_type(&type)->t & (VT_CONSTANT | VT_VOLATILE))                      & newquals)                    {
                      /* copy the pointer target symbol */                      type.ref = sym_push(SYM_FIELD, &type.ref->type,                                          0, type.ref->c);
                      copied = 1;
                      pointed_type(&type)->t |= newquals;

}                  /* pointers to incomplete arrays get converted to                     pointers to completed ones if possible */                  if (pt1->t & VT_ARRAY                      && pt2->t & VT_ARRAY                      && pointed_type(&type)->ref->c < 0                      && (pt1->ref->c > 0 || pt2->ref->c > 0))                    {
                      if (!copied)                        type.ref = sym_push(SYM_FIELD, &type.ref->type,                                            0, type.ref->c);
                      pointed_type(&type)->ref =                          sym_push(SYM_FIELD, &pointed_type(&type)->ref->type,                                   0, pointed_type(&type)->ref->c);
                      pointed_type(&type)->ref->c =                          0 < pt1->ref->c ? pt1->ref->c : pt2->ref->c;

}              
}          
}          if (op == CMP_OP)            type.t = VT_SIZE_T;

} else if (bt1 == VT_STRUCT || bt2 == VT_STRUCT) {
          if (op != '?' || !compare_types(type1, type2, 1))            ret = 0;
          type = *type1;

} else if (is_float(bt1) || is_float(bt2)) {
          if (bt1 == VT_LDOUBLE || bt2 == VT_LDOUBLE) {
              type.t = VT_LDOUBLE;

} else if (bt1 == VT_DOUBLE || bt2 == VT_DOUBLE) {
              type.t = VT_DOUBLE;

} else {
              type.t = VT_FLOAT;

}      
} else if (bt1 == VT_LLONG || bt2 == VT_LLONG) {
          /* cast to biggest op */          type.t = VT_LLONG | VT_LONG;
          if (bt1 == VT_LLONG)            type.t &= t1;
          if (bt2 == VT_LLONG)            type.t &= t2;
          /* convert to unsigned if it does not fit in a long long */          if ((t1 & (VT_BTYPE | VT_UNSIGNED | VT_BITFIELD)) == (VT_LLONG | VT_UNSIGNED) ||              (t2 & (VT_BTYPE | VT_UNSIGNED | VT_BITFIELD)) == (VT_LLONG | VT_UNSIGNED))            type.t |= VT_UNSIGNED;

} else {
          /* integer operations */          type.t = VT_INT | (VT_LONG & (t1 | t2));
          /* convert to unsigned if it does not fit in an integer */          if ((t1 & (VT_BTYPE | VT_UNSIGNED | VT_BITFIELD)) == (VT_INT | VT_UNSIGNED) ||              (t2 & (VT_BTYPE | VT_UNSIGNED | VT_BITFIELD)) == (VT_INT | VT_UNSIGNED))            type.t |= VT_UNSIGNED;

}      if (dest)        *dest = type;
      return ret;

}

ST_FUNC void gen_op(int op)  {
      int t1, t2, bt1, bt2, t;
      CType type1, combtype;
      int op_class = op;
        if (op == TOK_SHR || op == TOK_SAR || op == TOK_SHL)          op_class = SHIFT_OP;
      else if (TOK_ISCOND(op)) /* == != > ... */          op_class = CMP_OP;
    redo:      t1 = vtop[-1].type.t;
      t2 = vtop[0].type.t;
      bt1 = t1 & VT_BTYPE;
      bt2 = t2 & VT_BTYPE;
                if (bt1 == VT_FUNC || bt2 == VT_FUNC) {
   if (bt2 == VT_FUNC) {
       mk_pointer(&vtop->type);
       gaddrof();

}   if (bt1 == VT_FUNC) {
       vswap();
       mk_pointer(&vtop->type);
       gaddrof();
       vswap();

}   goto redo;

} else if (!combine_types(&combtype, vtop - 1, vtop, op_class)) {
  op_err:          tcc_error("invalid operand types for binary operation");

} else if (bt1 == VT_PTR || bt2 == VT_PTR) {
          /* at least one operand is a pointer */          /* relational op: must be both pointers */          int align;
          if (op_class == CMP_OP)              goto std_op;
          /* if both pointers, then it must be the '-' op */          if (bt1 == VT_PTR && bt2 == VT_PTR) {
              if (op != '-')                  goto op_err;
              vpush_type_size(pointed_type(&vtop[-1].type), &align);
              vtop->type.t &= ~VT_UNSIGNED;
              vrott(3);
              gen_opic(op);
              vtop->type.t = VT_PTRDIFF_T;
              vswap();
              gen_op(TOK_PDIV);

} else {
              /* exactly one pointer : must be '+' or '-'. */              if (op != '-' && op != '+')                  goto op_err;
              /* Put pointer as first operand */              if (bt2 == VT_PTR) {
                  vswap();
                  t = t1, t1 = t2, t2 = t;
                  bt2 = bt1;

}  #if PTR_SIZE == 4              if (bt2 == VT_LLONG)                  /* XXX: truncate here because gen_opl can't handle ptr + long long */                  gen_cast_s(VT_INT);
  #endif              type1 = vtop[-1].type;
              vpush_type_size(pointed_type(&vtop[-1].type), &align);
              gen_op('*');
  #ifdef CONFIG_TCC_BCHECK              if (tcc_state->do_bounds_check && !CONST_WANTED) {
                  /* if bounded pointers, we generate a special code to                     test bounds */                  if (op == '-') {
                      vpushi(0);
                      vswap();
                      gen_op('-');

}                  gen_bounded_ptr_add();

} else  #endif              {
                  gen_opic(op);

}              type1.t &= ~(VT_ARRAY|VT_VLA);
              /* put again type if gen_opic() swaped operands */              vtop->type = type1;

}      
} else {
          /* floats can only be used for a few operations */          if (is_float(combtype.t)              && op != '+' && op != '-' && op != '*' && op != '/'              && op_class != CMP_OP) {
              goto op_err;

}      std_op:          t = t2 = combtype.t;
          /* special case for shifts and long long: we keep the shift as             an integer */          if (op_class == SHIFT_OP)              t2 = VT_INT;
          /* XXX: currently, some unsigned operations are explicit, so             we modify them here */          if (t & VT_UNSIGNED) {
              if (op == TOK_SAR)                  op = TOK_SHR;
              else if (op == '/')                  op = TOK_UDIV;
              else if (op == '%')                  op = TOK_UMOD;
              else if (op == TOK_LT)                  op = TOK_ULT;
              else if (op == TOK_GT)                  op = TOK_UGT;
              else if (op == TOK_LE)                  op = TOK_ULE;
              else if (op == TOK_GE)                  op = TOK_UGE;

}          vswap();
          gen_cast_s(t);
          vswap();
          gen_cast_s(t2);
          if (is_float(t))              gen_opif(op);
          else              gen_opic(op);
          if (op_class == CMP_OP) {
              /* relational op: the result is an int */              vtop->type.t = VT_INT;

} else {
              vtop->type.t = t;

}      
}      // Make sure that we have converted to an rvalue:      if (vtop->r & VT_LVAL)          gv(is_float(vtop->type.t & VT_BTYPE) ? RC_FLOAT : RC_INT);

}

static void force_charshort_cast(void)  {
      int sbt = BFGET(vtop->r, VT_MUSTCAST) == 2 ? VT_LLONG : VT_INT;
      int dbt = vtop->type.t;
      vtop->r &= ~VT_MUSTCAST;
      vtop->type.t = sbt;
      gen_cast_s(dbt == VT_BOOL ? VT_BYTE|VT_UNSIGNED : dbt);
      vtop->type.t = dbt;

}

static void gen_cast_s(int t)  {
      CType type;
      type.t = t;
      type.ref = NULL;
      gen_cast(&type);

}

static void gen_cast(CType *type)  {
      int sbt, dbt, sf, df, c;
      int dbt_bt, sbt_bt, ds, ss, bits, trunc;
        /* special delayed cast for char/short */      if (vtop->r & VT_MUSTCAST)          force_charshort_cast();
        /* bitfields first get cast to ints */      if (vtop->type.t & VT_BITFIELD)          gv(RC_INT);
        dbt = type->t & (VT_BTYPE | VT_UNSIGNED);
      sbt = vtop->type.t & (VT_BTYPE | VT_UNSIGNED);
      if (sbt == VT_FUNC)          sbt = VT_PTR;
    again:      if (sbt != dbt) {
          sf = is_float(sbt);
          df = is_float(dbt);
          dbt_bt = dbt & VT_BTYPE;
          sbt_bt = sbt & VT_BTYPE;
          if (dbt_bt == VT_VOID)              goto done;
          if (sbt_bt == VT_VOID) {
  error:              cast_error(&vtop->type, type);

}            c = (vtop->r & (VT_VALMASK | VT_LVAL | VT_SYM)) == VT_CONST;
  #if !defined TCC_IS_NATIVE && !defined TCC_IS_NATIVE_387          /* don't try to convert to ldouble when cross-compiling             (except when it's '0' which is needed for arm:gen_negf()) */          if (dbt_bt == VT_LDOUBLE && !nocode_wanted && (sf || vtop->c.i != 0))              c = 0;
  #endif          if (c) {
              /* constant case: we can do it now */              /* XXX: in ISOC, cannot do it if error in convert */              if (sbt == VT_FLOAT)                  vtop->c.ld = vtop->c.f;
              else if (sbt == VT_DOUBLE)                  vtop->c.ld = vtop->c.d;
                if (df) {
                  if (sbt_bt == VT_LLONG) {
                      if ((sbt & VT_UNSIGNED) || !(vtop->c.i >> 63))                          vtop->c.ld = vtop->c.i;
                      else                          vtop->c.ld = -(long double)-vtop->c.i;

} else if(!sf) {
                      if ((sbt & VT_UNSIGNED) || !(vtop->c.i >> 31))                          vtop->c.ld = (uint32_t)vtop->c.i;
                      else                          vtop->c.ld = -(long double)-(uint32_t)vtop->c.i;

}                    if (dbt == VT_FLOAT)                      vtop->c.f = (float)vtop->c.ld;
                  else if (dbt == VT_DOUBLE)                      vtop->c.d = (double)vtop->c.ld;

} else if (sf && dbt == VT_BOOL) {
                  vtop->c.i = (vtop->c.ld != 0);

} else {
                  if(sf)                      /* the range of [int64_t] is enough to hold the integer part of any float value.                         Meanwhile, converting negative double to unsigned integer is UB.                         So first convert to [int64_t] here. */                      vtop->c.i = (int64_t)vtop->c.ld;
                  else if (sbt_bt == VT_LLONG || (PTR_SIZE == 8 && sbt == VT_PTR))                     ;
                  else if (sbt & VT_UNSIGNED)                      vtop->c.i = (uint32_t)vtop->c.i;
                  else                      vtop->c.i = ((uint32_t)vtop->c.i | -(vtop->c.i & 0x80000000));
                    if (dbt_bt == VT_LLONG || (PTR_SIZE == 8 && dbt == VT_PTR))                     ;
                  else if (dbt == VT_BOOL)                      vtop->c.i = (vtop->c.i != 0);
                  else {
                      uint32_t m = dbt_bt == VT_BYTE ? 0xff :                                   dbt_bt == VT_SHORT ? 0xffff :                                    0xffffffff;
                      vtop->c.i &= m;
                      if (!(dbt & VT_UNSIGNED))                          vtop->c.i |= -(vtop->c.i & ((m >> 1) + 1));

}              
}              goto done;

} else if (dbt == VT_BOOL              && (vtop->r & (VT_VALMASK | VT_LVAL | VT_SYM))                  == (VT_CONST | VT_SYM)) {
              /* addresses are considered non-zero (see tcctest.c:sinit23) */              vtop->r = VT_CONST;
              vtop->c.i = 1;
              goto done;

}            /* cannot generate code for global or static initializers */          if (nocode_wanted & DATA_ONLY_WANTED)              goto done;
            /* non constant case: generate code */          if (dbt == VT_BOOL) {
              gen_test_zero(TOK_NE);
              goto done;

}            if (sf || df) {
              if (sf && df) {
                  /* convert from fp to fp */                  gen_cvt_ftof(dbt);

} else if (df) {
                  /* convert int to fp */                  gen_cvt_itof1(dbt);

} else {
                  /* convert fp to int */                  sbt = dbt;
                  if (dbt_bt != VT_LLONG && dbt_bt != VT_INT)                      sbt = VT_INT;
                  gen_cvt_ftoi1(sbt);
                  goto again;
 /* may need char/short cast */              
}              goto done;

}            ds = btype_size(dbt_bt);
          ss = btype_size(sbt_bt);
          if (ds == 0 || ss == 0)              goto error;
            if (IS_ENUM(type->t) && type->ref->c < 0)              tcc_error("cast to incomplete type");
            /* same size and no sign conversion needed */          if (ds == ss && ds >= 4)              goto done;
          if (dbt_bt == VT_PTR || sbt_bt == VT_PTR) {
              tcc_warning("cast between pointer and integer of different size");
              if (sbt_bt == VT_PTR) {
                  /* put integer type to allow logical operations below */                  vtop->type.t = (PTR_SIZE == 8 ? VT_LLONG : VT_INT);

}          
}            /* processor allows {
 int a = 0, b = *(char*)&a;

}             That means that if we cast to less width, we can just             change the type and read it still later. */          #define ALLOW_SUBTYPE_ACCESS 1            if (ALLOW_SUBTYPE_ACCESS && (vtop->r & VT_LVAL)) {
              /* value still in memory */              if (ds <= ss)                  goto done;
              /* ss <= 4 here */              if (ds <= 4 && !(dbt == (VT_SHORT | VT_UNSIGNED) && sbt == VT_BYTE)) {
                  gv(RC_INT);
                  goto done;
 /* no 64bit envolved */              
}          
}          gv(RC_INT);
            trunc = 0;
  #if PTR_SIZE == 4          if (ds == 8) {
              /* generate high word */              if (sbt & VT_UNSIGNED) {
                  vpushi(0);
                  gv(RC_INT);

} else {
                  gv_dup();
                  vpushi(31);
                  gen_op(TOK_SAR);

}              lbuild(dbt);

} else if (ss == 8) {
              /* from long long: just take low order word */              lexpand();
              vpop();

}          ss = 4;
    #elif PTR_SIZE == 8          if (ds == 8) {
              /* need to convert from 32bit to 64bit */              if (sbt & VT_UNSIGNED) {
  #if defined(TCC_TARGET_RISCV64)                  /* RISC-V keeps 32bit vals in registers sign-extended.                     So here we need a zero-extension.  */                  trunc = 32;
  #else                  goto done;
  #endif              
} else {
                  gen_cvt_sxtw();
                  goto done;

}              ss = ds, ds = 4, dbt = sbt;

} else if (ss == 8) {
              /* RISC-V keeps 32bit vals in registers sign-extended.                 So here we need a sign-extension for signed types and                 zero-extension. for unsigned types. */  #if !defined(TCC_TARGET_RISCV64)              trunc = 32;
 /* zero upper 32 bits for non RISC-V targets */  #endif          
} else {
              ss = 4;

}  #endif            if (ds >= ss)              goto done;
  #if defined TCC_TARGET_I386 || defined TCC_TARGET_X86_64 || defined TCC_TARGET_ARM64          if (ss == 4) {
              gen_cvt_csti(dbt);
              goto done;

}  #endif          bits = (ss - ds) * 8;
          /* for unsigned, gen_op will convert SAR to SHR */          vtop->type.t = (ss == 8 ? VT_LLONG : VT_INT) | (dbt & VT_UNSIGNED);
          vpushi(bits);
          gen_op(TOK_SHL);
          vpushi(bits - trunc);
          gen_op(TOK_SAR);
          vpushi(trunc);
          gen_op(TOK_SHR);

}  done:      vtop->type = *type;
      vtop->type.t &= ~ ( VT_CONSTANT | VT_VOLATILE | VT_ARRAY );

}

ST_FUNC int type_size(CType *type, int *a)  {
      Sym *s;
      int bt;
        bt = type->t & VT_BTYPE;
      if (bt == VT_STRUCT) {
          /* struct/union */          s = type->ref;
          *a = s->r;
          return s->c;

} else if (bt == VT_PTR) {
          if (type->t & VT_ARRAY) {
              int ts;
              s = type->ref;
              ts = type_size(&s->type, a);
              if (ts < 0 && s->c < 0)                  ts = -ts;
              return ts * s->c;

} else {
              *a = PTR_SIZE;
              return PTR_SIZE;

}      
} else if (IS_ENUM(type->t) && type->ref->c < 0) {
          *a = 0;
          return -1;
 /* incomplete enum */      
} else if (bt == VT_LDOUBLE) {
          *a = LDOUBLE_ALIGN;
          return LDOUBLE_SIZE;

} else if (bt == VT_DOUBLE || bt == VT_LLONG) {
  #if (defined TCC_TARGET_I386 && !defined TCC_TARGET_PE) \   || (defined TCC_TARGET_ARM && !defined TCC_ARM_EABI)          *a = 4;
  #else          *a = 8;
  #endif          return 8;

} else if (bt == VT_INT || bt == VT_FLOAT) {
          *a = 4;
          return 4;

} else if (bt == VT_SHORT) {
          *a = 2;
          return 2;

} else if (bt == VT_QLONG || bt == VT_QFLOAT) {
          *a = 8;
          return 16;

} else {
          /* char, void, function, _Bool */          *a = 1;
          return 1;

}  
}

static void vpush_type_size(CType *type, int *a)  {
      if (type->t & VT_VLA) {
          type_size(&type->ref->type, a);
          vset(&int_type, VT_LOCAL|VT_LVAL, type->ref->c);

} else {
          int size = type_size(type, a);
          if (size < 0)              tcc_error("unknown type size");
          vpushs(size);

}  
}

static inline CType *pointed_type(CType *type)  {
      return &type->ref->type;

}

ST_FUNC void mk_pointer(CType *type)  {
      Sym *s;
      s = sym_push(SYM_FIELD, type, 0, -1);
      type->t = VT_PTR | (type->t & VT_STORAGE);
      type->ref = s;

}

static int is_compatible_types(CType *type1, CType *type2)  {
      return compare_types(type1,type2,0);

}

static int is_compatible_unqualified_types(CType *type1, CType *type2)  {
      return compare_types(type1,type2,1);

}

static void cast_error(CType *st, CType *dt)  {
      type_incompatibility_error(st, dt, "cannot convert '%s' to '%s'");

}

static void verify_assign_cast(CType *dt)  {
      CType *st, *type1, *type2;
      int dbt, sbt, qualwarn, lvl;
        st = &vtop->type;
 /* source type */      dbt = dt->t & VT_BTYPE;
      sbt = st->t & VT_BTYPE;
      if (dt->t & VT_CONSTANT)          tcc_warning("assignment of read-only location");
      switch(dbt) {
      case VT_VOID:          if (sbt != dbt)              tcc_error("assignment to void expression");
          break;
      case VT_PTR:          /* special cases for pointers */          /* '0' can also be a pointer */          if (is_null_pointer(vtop))              break;
          /* accept implicit pointer to integer cast with warning */          if (is_integer_btype(sbt)) {
              tcc_warning("assignment makes pointer from integer without a cast");
              break;

}          type1 = pointed_type(dt);
          if (sbt == VT_PTR)              type2 = pointed_type(st);
          else if (sbt == VT_FUNC)              type2 = st;
 /* a function is implicitly a function pointer */          else              goto error;
          if (is_compatible_types(type1, type2))              break;
          for (qualwarn = lvl = 0;
;
 ++lvl) {
              if (((type2->t & VT_CONSTANT) && !(type1->t & VT_CONSTANT)) ||                  ((type2->t & VT_VOLATILE) && !(type1->t & VT_VOLATILE)))                  qualwarn = 1;
              dbt = type1->t & (VT_BTYPE|VT_LONG);
              sbt = type2->t & (VT_BTYPE|VT_LONG);
              if (dbt != VT_PTR || sbt != VT_PTR)                  break;
              type1 = pointed_type(type1);
              type2 = pointed_type(type2);

}          if (!is_compatible_unqualified_types(type1, type2)) {
              if ((dbt == VT_VOID || sbt == VT_VOID) && lvl == 0) {
                  /* void * can match anything */              
} else if (dbt == sbt                  && is_integer_btype(sbt & VT_BTYPE)                  && IS_ENUM(type1->t) + IS_ENUM(type2->t)                      + !!((type1->t ^ type2->t) & VT_UNSIGNED) < 2) {
    /* Like GCC don't warn by default for merely changes       in pointer target signedness.  Do warn for different       base types, though, in particular for unsigned enums       and signed int targets.  */              
} else {
                  tcc_warning("assignment from incompatible pointer type");
                  break;

}          
}          if (qualwarn)              tcc_warning_c(warn_discarded_qualifiers)("assignment discards qualifiers from pointer target type");
          break;
      case VT_BYTE:      case VT_SHORT:      case VT_INT:      case VT_LLONG:          if (sbt == VT_PTR || sbt == VT_FUNC) {
              tcc_warning("assignment makes integer from pointer without a cast");

} else if (sbt == VT_STRUCT) {
              goto case_VT_STRUCT;

}          /* XXX: more tests */          break;
      case VT_STRUCT:      case_VT_STRUCT:          if (!is_compatible_unqualified_types(dt, st)) {
      error:              cast_error(st, dt);

}          break;

}  
}

static void gen_assign_cast(CType *dt)  {
      verify_assign_cast(dt);
      gen_cast(dt);

}

ST_FUNC void vstore(void)  {
      int sbt, dbt, ft, r, size, align, bit_size, bit_pos, delayed_cast;
        ft = vtop[-1].type.t;
      sbt = vtop->type.t & VT_BTYPE;
      dbt = ft & VT_BTYPE;
      verify_assign_cast(&vtop[-1].type);
        if (sbt == VT_STRUCT) {
          /* if structure, only generate pointer */          /* structure assignment : generate memcpy */          size = type_size(&vtop->type, &align);
          /* destination, keep on stack() as result */          vpushv(vtop - 1);
  #ifdef CONFIG_TCC_BCHECK          if (vtop->r & VT_MUSTBOUND)              gbound();
 /* check would be wrong after gaddrof() */  #endif          vtop->type.t = VT_PTR;
          gaddrof();
          /* source */          vswap();
  #ifdef CONFIG_TCC_BCHECK          if (vtop->r & VT_MUSTBOUND)              gbound();
  #endif          vtop->type.t = VT_PTR;
          gaddrof();
    #ifdef TCC_TARGET_NATIVE_STRUCT_COPY          if (1  #ifdef CONFIG_TCC_BCHECK              && !tcc_state->do_bounds_check  #endif              ) {
              gen_struct_copy(size);

} else  #endif          {
              /* type size */              vpushi(size);
              /* Use memmove, rather than memcpy, as dest and src may be same: */  #ifdef TCC_ARM_EABI              if(!(align & 7))                  vpush_helper_func(TOK_memmove8);
              else if(!(align & 3))                  vpush_helper_func(TOK_memmove4);
              else  #endif              vpush_helper_func(TOK_memmove);
              vrott(4);
              gfunc_call(3);

}        
} else if (ft & VT_BITFIELD) {
          /* bitfield store handling */            /* save lvalue as expression result (example: s.b = s.a = n;
) */          vdup(), vtop[-1] = vtop[-2];
            bit_pos = BIT_POS(ft);
          bit_size = BIT_SIZE(ft);
          /* remove bit field info to avoid loops */          vtop[-1].type.t = ft & ~VT_STRUCT_MASK;
            if (dbt == VT_BOOL) {
              gen_cast(&vtop[-1].type);
              vtop[-1].type.t = (vtop[-1].type.t & ~VT_BTYPE) | (VT_BYTE | VT_UNSIGNED);

}          r = adjust_bf(vtop - 1, bit_pos, bit_size);
          if (dbt != VT_BOOL) {
              gen_cast(&vtop[-1].type);
              dbt = vtop[-1].type.t & VT_BTYPE;

}          if (r == VT_STRUCT) {
              store_packed_bf(bit_pos, bit_size);

} else {
              unsigned long long mask = (1ULL << bit_size) - 1;
              if (dbt != VT_BOOL) {
                  /* mask source */                  if (dbt == VT_LLONG)                      vpushll(mask);
                  else                      vpushi((unsigned)mask);
                  gen_op('&');

}              /* shift source */              vpushi(bit_pos);
              gen_op(TOK_SHL);
              vswap();
              /* duplicate destination */              vdup();
              vrott(3);
              /* load destination, mask and or with source */              if (dbt == VT_LLONG)                  vpushll(~(mask << bit_pos));
              else                  vpushi(~((unsigned)mask << bit_pos));
              gen_op('&');
              gen_op('|');
              /* store result */              vstore();
              /* ... and discard */              vpop();

}      
} else if (dbt == VT_VOID) {
          --vtop;

} else {
              /* optimize char/short casts */              delayed_cast = 0;
              if ((dbt == VT_BYTE || dbt == VT_SHORT)                  && is_integer_btype(sbt)                  ) {
                  if ((vtop->r & VT_MUSTCAST)                      && btype_size(dbt) > btype_size(sbt)                      )                      force_charshort_cast();
                  delayed_cast = 1;

} else {
                  gen_cast(&vtop[-1].type);

}    #ifdef CONFIG_TCC_BCHECK              /* bound check case */              if (vtop[-1].r & VT_MUSTBOUND) {
                  vswap();
                  gbound();
                  vswap();

}  #endif              gv(RC_TYPE(dbt));
 /* generate value */                if (delayed_cast) {
                  vtop->r |= BFVAL(VT_MUSTCAST, (sbt == VT_LLONG) + 1);
                  //tcc_warning("deley cast %x -> %x", sbt, dbt);
                  vtop->type.t = ft & VT_TYPE;

}                /* if lvalue was saved on stack, must read it */              if ((vtop[-1].r & VT_VALMASK) == VT_LLOCAL) {
                  SValue sv;
                  r = get_reg(RC_INT);
                  sv.type.t = VT_PTRDIFF_T;
                  sv.r = VT_LOCAL | VT_LVAL;
                  sv.c.i = vtop[-1].c.i;
                  load(r, &sv);
                  vtop[-1].r = r | VT_LVAL;

}                r = vtop->r & VT_VALMASK;
              /* two word case handling :                 store second register at word + 4 (or +8 for x86-64)  */              if (USING_TWO_WORDS(dbt)) {
                  int load_type = (dbt == VT_QFLOAT) ? VT_DOUBLE : VT_PTRDIFF_T;
                  vtop[-1].type.t = load_type;
                  store(r, vtop - 1);
                  vswap();
                  incr_offset(PTR_SIZE);
                  vswap();
                  /* XXX: it works because r2 is spilled last ! */                  store(vtop->r2, vtop - 1);

} else {
                  /* single word */                  store(r, vtop - 1);

}          vswap();
          vtop--;
 /* NOT vpop() because on x86 it would flush the fp stack */      
}  
}

ST_FUNC void inc(int post, int c)  {
      test_lvalue();
      vdup();
 /* save lvalue */      if (post) {
          gv_dup();
 /* duplicate value */          vrotb(3);
          vrotb(3);

}      /* add constant */      vpushi(c - TOK_MID);
       gen_op('+');
      vstore();
 /* store value */      if (post)          vpop();
 /* if post op, return saved value */  
}

ST_FUNC CString* parse_mult_str (const char *msg)  {
      /* read the string */      if (tok != TOK_STR)          expect(msg);
      cstr_reset(&initstr);
      while (tok == TOK_STR) {
          /* XXX: add \0 handling too ? */          cstr_cat(&initstr, tokc.str.data, -1);
          next();

}      cstr_ccat(&initstr, '\0');
      return &initstr;

}

ST_FUNC int exact_log2p1(int i)  {
    int ret;
    if (!i)      return 0;
    for (ret = 1;
 i >= 1 << 8;
 ret += 8)      i >>= 8;
    if (i >= 1 << 4)      ret += 4, i >>= 4;
    if (i >= 1 << 2)      ret += 2, i >>= 2;
    if (i >= 1 << 1)      ret++;
    return ret;

}

static void parse_attribute(AttributeDef *ad)  {
      int t, n;
      char *astr;
        redo:      if (tok != TOK_ATTRIBUTE1 && tok != TOK_ATTRIBUTE2)          return;
      next();
      skip('(');
      skip('(');
      while (tok != ')') {
          if (tok < TOK_IDENT)              expect("attribute name");
          t = tok;
          next();
          switch(t) {
   case TOK_CLEANUP1:   case TOK_CLEANUP2:   {
       Sym *s;
         skip('(');
       s = sym_find(tok);
       if (!s) {
           tcc_warning_c(warn_implicit_function_declaration)(                      "implicit declaration of function '%s'", get_tok_str(tok, &tokc));
           s = external_global_sym(tok, &func_old_type);

} else if ((s->type.t & VT_BTYPE) != VT_FUNC)                  tcc_error("'%s' is not declared as function", get_tok_str(tok, &tokc));
       ad->cleanup_func = s;
       next();
              skip(')');
       break;

}          case TOK_CONSTRUCTOR1:          case TOK_CONSTRUCTOR2:              ad->f.func_ctor = 1;
              break;
          case TOK_DESTRUCTOR1:          case TOK_DESTRUCTOR2:              ad->f.func_dtor = 1;
              break;
          case TOK_ALWAYS_INLINE1:          case TOK_ALWAYS_INLINE2:              ad->f.func_alwinl = 1;
              break;
          case TOK_SECTION1:          case TOK_SECTION2:              skip('(');
       astr = parse_mult_str("section name")->data;
              ad->section = find_section(tcc_state, astr);
              skip(')');
              break;
          case TOK_ALIAS1:          case TOK_ALIAS2:              skip('(');
       astr = parse_mult_str("alias(\"target\")")->data;
              /* save string as token, for later */              ad->alias_target = tok_alloc_const(astr);
              skip(')');
              break;
   case TOK_VISIBILITY1:   case TOK_VISIBILITY2:              skip('(');
       astr = parse_mult_str("visibility(\"default|hidden|internal|protected\")")->data;
       if (!strcmp (astr, "default"))           ad->a.visibility = STV_DEFAULT;
       else if (!strcmp (astr, "hidden"))           ad->a.visibility = STV_HIDDEN;
       else if (!strcmp (astr, "internal"))           ad->a.visibility = STV_INTERNAL;
       else if (!strcmp (astr, "protected"))           ad->a.visibility = STV_PROTECTED;
       else                  expect("visibility(\"default|hidden|internal|protected\")");
              skip(')');
              break;
          case TOK_ALIGNED1:          case TOK_ALIGNED2:              if (tok == '(') {
                  next();
                  n = expr_const();
                  if (n <= 0 || (n & (n - 1)) != 0)                       tcc_error("alignment must be a positive power of two");
                  skip(')');

} else {
                  n = MAX_ALIGN;

}              ad->a.aligned = exact_log2p1(n);
       if (n != 1 << (ad->a.aligned - 1))         tcc_error("alignment of %d is larger than implemented", n);
              break;
          case TOK_PACKED1:          case TOK_PACKED2:              ad->a.packed = 1;
              break;
          case TOK_WEAK1:          case TOK_WEAK2:              ad->a.weak = 1;
              break;
          case TOK_NODEBUG1:          case TOK_NODEBUG2:              ad->a.nodebug = 1;
              break;
          case TOK_UNUSED1:          case TOK_UNUSED2:              /* currently, no need to handle it because tcc does not                 track unused objects */              break;
          case TOK_NORETURN1:          case TOK_NORETURN2:              ad->f.func_noreturn = 1;
              break;
          case TOK_CDECL1:          case TOK_CDECL2:          case TOK_CDECL3:              ad->f.func_call = FUNC_CDECL;
              break;
          case TOK_STDCALL1:          case TOK_STDCALL2:          case TOK_STDCALL3:              ad->f.func_call = FUNC_STDCALL;
              break;
  #ifdef TCC_TARGET_I386          case TOK_REGPARM1:          case TOK_REGPARM2:              skip('(');
              n = expr_const();
              if (n > 3)                   n = 3;
              else if (n < 0)                  n = 0;
              if (n > 0)                  ad->f.func_call = FUNC_FASTCALL1 + n - 1;
              skip(')');
              break;
          case TOK_FASTCALL1:          case TOK_FASTCALL2:          case TOK_FASTCALL3:              ad->f.func_call = FUNC_FASTCALLW;
              break;
          case TOK_THISCALL1:          case TOK_THISCALL2:          case TOK_THISCALL3:              ad->f.func_call = FUNC_THISCALL;
              break;
  #endif          case TOK_MODE:              skip('(');
              switch(tok) {
                  case TOK_MODE_DI:                      ad->attr_mode = VT_LLONG + 1;
                      break;
                  case TOK_MODE_QI:                      ad->attr_mode = VT_BYTE + 1;
                      break;
                  case TOK_MODE_HI:                      ad->attr_mode = VT_SHORT + 1;
                      break;
                  case TOK_MODE_SI:                  case TOK_MODE_word:                      ad->attr_mode = VT_INT + 1;
                      break;
                  default:                      tcc_warning("__mode__(%s) not supported\n", get_tok_str(tok, NULL));
                      break;

}              next();
              skip(')');
              break;
          case TOK_DLLEXPORT:              ad->a.dllexport = 1;
              break;
          case TOK_NODECORATE:              ad->a.nodecorate = 1;
              break;
          case TOK_DLLIMPORT:              ad->a.dllimport = 1;
              break;
          default:              tcc_warning_c(warn_unsupported)("'%s' attribute ignored", get_tok_str(t, NULL));
              /* skip parameters */              if (tok == '(') {
                  int parenthesis = 0;
                  do {
                      if (tok == '(')                           parenthesis++;
                      else if (tok == ')')                           parenthesis--;
                      next();

} while (parenthesis && tok != -1);

}              break;

}          if (tok != ',')              break;
          next();

}      skip(')');
      skip(')');
      goto redo;

}

static Sym * find_field (CType *type, int v, int *cumofs)  {
      Sym *s = type->ref;
      int v1 = v | SYM_FIELD;
      if (!(v & SYM_FIELD)) {
 /* top-level call */          if ((type->t & VT_BTYPE) != VT_STRUCT)              expect("struct or union");
          if (v < TOK_UIDENT)              expect("field name");
          if (s->c < 0)              tcc_error("dereferencing incomplete type '%s'",                  get_tok_str(s->v & ~SYM_STRUCT, 0));

}      while ((s = s->next) != NULL) {
          if (s->v == v1) {
              *cumofs = s->c;
              return s;

}          if ((s->type.t & VT_BTYPE) == VT_STRUCT            && s->v >= (SYM_FIRST_ANOM | SYM_FIELD)) {
              /* try to find field in anonymous sub-struct/union */              Sym *ret = find_field (&s->type, v1, cumofs);
              if (ret) {
                  *cumofs += s->c;
                  return ret;

}          
}      
}      if (!(v & SYM_FIELD))          tcc_error("field not found: %s", get_tok_str(v, NULL));
      return s;

}

static void check_fields (CType *type, int check)  {
      Sym *s = type->ref;
        while ((s = s->next) != NULL) {
          int v = s->v & ~SYM_FIELD;
          if (v < SYM_FIRST_ANOM) {
              TokenSym *ts = table_ident[v - TOK_IDENT];
              if (check && (ts->tok & SYM_FIELD))                  tcc_error("duplicate member '%s'", get_tok_str(v, NULL));
              ts->tok ^= SYM_FIELD;

} else if ((s->type.t & VT_BTYPE) == VT_STRUCT)              check_fields (&s->type, check);

}  
}

static void struct_layout(CType *type, AttributeDef *ad)  {
      int size, align, maxalign, offset, c, bit_pos, bit_size;
      int packed, a, bt, prevbt, prev_bit_size;
      int pcc = !tcc_state->ms_bitfields;
      int pragma_pack = *tcc_state->pack_stack_ptr;
