       if (pcc && bit_size >= 0)           size = (bit_size + 7) >> 3;
       offset = 0;
       if (size > c)           c = size;

} else if (bit_size < 0) {
              if (pcc)                  c += (bit_pos + 7) >> 3;
       c = (c + align - 1) & -align;
       offset = c;
       if (size > 0)           c += size;
       bit_pos = 0;
       prevbt = VT_STRUCT;
       prev_bit_size = 0;

} else {
       /* A bit-field.  Layout is more complicated.  There are two          options: PCC (GCC) compatible and MS compatible */              if (pcc) {
    /* In PCC layout a bit-field is placed adjacent to the                     preceding bit-fields, except if:                     - it has zero-width                     - an individual alignment was given                     - it would overflow its base type container and                       there is no packing */                  if (bit_size == 0) {
              new_field:        c = (c + ((bit_pos + 7) >> 3) + align - 1) & -align;
        bit_pos = 0;

} else if (f->a.aligned) {
                      goto new_field;

} else if (!packed) {
                      int a8 = align * 8;
               int ofs = ((c * 8 + bit_pos) % a8 + bit_size + a8 - 1) / a8;
