        c = (c + align - 1) & -align;
        offset = c;
        bit_pos = 0;
        /* In MS bitfield mode a bit-field run always uses           at least as many bits as the underlying type.           To start a new run it's also required that this           or the last bit-field had non-zero width.  */        if (bit_size || prev_bit_size)            c += size;

}    /* In MS layout the records alignment is normally       influenced by the field, except for a zero-width       field at the start of a run (but by further zero-width       fields it is again).  */    if (bit_size == 0 && prevbt != bt)        align = 1;
