} else if (s > 2) {
                  t.t = VT_INT;

} else if (s > 1) {
                  t.t = VT_SHORT;

} else {
                  t.t = VT_BYTE;

}              s = type_size(&t, &align);
              c0 = cx;

}            if (px + bit_size <= s * 8 && cx + s <= c  #ifdef TCC_TARGET_ARM              && !(cx & (align - 1))  #endif              ) {
              /* update offset and bit position */              f->c = cx;
              bit_pos = px;
       f->type.t = (f->type.t & ~(0x3f << VT_STRUCT_SHIFT))            | (bit_pos << VT_STRUCT_SHIFT);
              if (s != size)                  f->auxtype = t.t;
