              /* fall back to load/store single-byte wise */              f->auxtype = VT_STRUCT;
  #ifdef BF_DEBUG              printf("FIX field %s : load byte-wise\n",                   get_tok_str(f->v & ~SYM_FIELD, NULL));
  #endif          
}      
}  
}

