          case TOK_FLOAT:              u = VT_FLOAT;
              goto basic_type;
          case TOK_DOUBLE:              if ((t & (VT_BTYPE|VT_LONG)) == VT_LONG) {
                  t = (t & ~(VT_BTYPE|VT_LONG)) | VT_LDOUBLE;

} else {
                  u = VT_DOUBLE;
                  goto basic_type;

}              next();
              break;
          case TOK_ENUM:              struct_decl(&type1, VT_ENUM);
          basic_type2:              u = type1.t;
              type->ref = type1.ref;
              goto basic_type1;
          case TOK_STRUCT:              struct_decl(&type1, VT_STRUCT);
              goto basic_type2;
          case TOK_UNION:              struct_decl(&type1, VT_UNION);
              goto basic_type2;
