              type->t = t;
              parse_btype_qualify(type, VT_ATOMIC);
              t = type->t;
              if (tok == '(') {
                  parse_expr_type(&type1);
                  /* remove all storage modifiers except typedef */                  type1.t &= ~(VT_STORAGE&~VT_TYPEDEF);
                  if (type1.ref)                      sym_to_attr(ad, type1.ref);
                  goto basic_type2;

}              break;
          case TOK_CONST1:          case TOK_CONST2:          case TOK_CONST3:              type->t = t;
              parse_btype_qualify(type, VT_CONSTANT);
              t = type->t;
              next();
              break;
          case TOK_VOLATILE1:          case TOK_VOLATILE2:          case TOK_VOLATILE3:              type->t = t;
