              /* remove all storage modifiers except typedef */              type1.t &= ~(VT_STORAGE&~VT_TYPEDEF);
       if (type1.ref)                  sym_to_attr(ad, type1.ref);
              goto basic_type2;
          case TOK_THREAD_LOCAL:              tcc_error("_Thread_local is not implemented");
          default:              if (typespec_found)                  goto the_end;
              s = sym_find(tok);
              if (!s || !(s->type.t & VT_TYPEDEF))                  goto the_end;
                n = tok, next();
              if (tok == ':' && ignore_label) {
                  /* ignore if it's a label */                  unget_tok(n);
                  goto the_end;

}                t &= ~(VT_BTYPE|VT_LONG);
              u = t & ~(VT_CONSTANT | VT_VOLATILE), t ^= u;
              type->t = (s->type.t & ~VT_TYPEDEF) | u;
              type->ref = s->type.ref;
              if (t)                  parse_btype_qualify(type, t);
              t = type->t;
              /* get attributes from typedef */              sym_to_attr(ad, s);
              typespec_found = 1;
              st = bt = -2;
              break;

}          type_found = 1;

}  the_end:      if (tcc_state->char_is_unsigned) {
          if ((t & (VT_DEFSIGN|VT_BTYPE)) == VT_BYTE)              t |= VT_UNSIGNED;

}      /* VT_LONG is used just as a modifier for VT_INT / VT_LLONG */      bt = t & (VT_BTYPE|VT_LONG);
      if (bt == VT_LONG)          t |= LONG_SIZE == 8 ? VT_LLONG : VT_INT;
  #ifdef TCC_USING_DOUBLE_FOR_LDOUBLE      if (bt == VT_LDOUBLE)          t = (t & ~(VT_BTYPE|VT_LONG)) | (VT_DOUBLE|VT_LONG);
  #endif      type->t = t;
      return type_found;

}

static inline void convert_parameter_type(CType *pt)  {
      /* remove const and volatile qualifiers (XXX: const could be used         to indicate a const function parameter */      pt->t &= ~(VT_CONSTANT | VT_VOLATILE);
      /* array must be transformed to pointer according to ANSI C */      pt->t &= ~(VT_ARRAY | VT_VLA);
      if ((pt->t & VT_BTYPE) == VT_FUNC) {
          mk_pointer(pt);

}  
}

ST_FUNC CString* parse_asm_str(void)  {
      skip('(');
      return parse_mult_str("string constant");

}

static int asm_label_instr(void)  {
      int v;
      char *astr;
        next();
      astr = parse_asm_str()->data;
      skip(')');
  #ifdef ASM_DEBUG      printf("asm_alias: \"%s\"\n", astr);
  #endif      v = tok_alloc_const(astr);
      return v;

}

static int post_type(CType *type, AttributeDef *ad, int storage, int td)  {
      int n, l, t1, arg_size, align;
      Sym **plast, *s, *first;
      AttributeDef ad1;
      CType pt;
      TokenString *vla_array_tok = NULL;
      int *vla_array_str = NULL;
        if (tok == '(') {
          /* function type, or recursive declarator (return if so) */          next();
   if (TYPE_DIRECT == (td & (TYPE_DIRECT|TYPE_ABSTRACT)))     return 0;
   if (tok == ')')     l = 0;
   else if (parse_btype(&pt, &ad1, 0))     l = FUNC_NEW;
   else if (td & (TYPE_DIRECT|TYPE_ABSTRACT)) {
       merge_attr (ad, &ad1);
       return 0;

} else     l = FUNC_OLD;
            first = NULL;
          plast = &first;
          arg_size = 0;
          ++local_scope;
          if (l) {
              for(;
;
) {
                  /* read param name and compute offset */                  if (l != FUNC_OLD) {
                      if ((pt.t & VT_BTYPE) == VT_VOID && tok == ')')                          break;
                      type_decl(&pt, &ad1, &n, TYPE_DIRECT | TYPE_ABSTRACT | TYPE_PARAM);
                      if ((pt.t & VT_BTYPE) == VT_VOID)                          tcc_error("parameter declared as void");
                      if (n == 0)                          n = SYM_FIELD;

} else {
                      n = tok;
                      pt.t = VT_VOID;
 /* invalid type */                      pt.ref = NULL;
                      next();

}                  if (n < TOK_UIDENT)                      expect("identifier");
                  convert_parameter_type(&pt);
                  arg_size += (type_size(&pt, &align) + PTR_SIZE - 1) / PTR_SIZE;
                  /* these symbols may be evaluated for VLArrays (see below, under                     nocode_wanted) which is why we push them here as normal symbols                     temporarily.  Example: int func(int a, int b[++a]);
 */                  s = sym_push(n, &pt, VT_LOCAL|VT_LVAL, 0);
                  *plast = s;
                  plast = &s->next;
                  if (tok == ')')                      break;
                  skip(',');
                  if (l == FUNC_NEW && tok == TOK_DOTS) {
                      l = FUNC_ELLIPSIS;
                      next();
                      break;

}    if (l == FUNC_NEW && !parse_btype(&pt, &ad1, 0))        tcc_error("invalid type");

}          
} else              /* if no parameters, then old type prototype */              l = FUNC_OLD;
          skip(')');
          /* remove parameter symbols from token table, keep on stack */          if (first) {
              sym_pop(local_stack ? &local_stack : &global_stack, first->prev, 1);
              for (s = first;
 s;
 s = s->next)                  s->v |= SYM_FIELD;

}          --local_scope;
          /* NOTE: const is ignored in returned type as it has a special             meaning in gcc / C++ */          type->t &= ~VT_CONSTANT;
           /* some ancient pre-K&R C allows a function to return an array             and the array brackets to be put after the arguments, such              that "int c()[]" means something like "int[] c()" */          if (tok == '[') {
              next();
              skip(']');
 /* only handle simple "[]" */              mk_pointer(type);

}          /* we push a anonymous symbol which will contain the function prototype */          ad->f.func_args = arg_size;
          ad->f.func_type = l;
          s = sym_push(SYM_FIELD, type, 0, 0);
          s->a = ad->a;
          s->f = ad->f;
          s->next = first;
          type->t = VT_FUNC;
          type->ref = s;

} else if (tok == '[') {
   int saved_nocode_wanted = nocode_wanted;
          /* array definition */          next();
          n = -1;
          t1 = 0;
          if (td & TYPE_PARAM) while (1) {
       /* XXX The optional type-quals and static should only be accepted          in parameter decls.  The '*' as well, and then even only          in prototypes (not function defs).  */       switch (tok) {
       case TOK_RESTRICT1: case TOK_RESTRICT2: case TOK_RESTRICT3:       case TOK_CONST1:       case TOK_VOLATILE1:       case TOK_STATIC:       case '*':    next();
    continue;
       default:    break;

}              if (tok != ']') {
    /* Code generation is not done now but has to be done       at start of function. Save code here for later use. */           nocode_wanted = 1;
    skip_or_save_block(&vla_array_tok);
    unget_tok(0);
    vla_array_str = vla_array_tok->str;
    begin_macro(vla_array_tok, 2);
    next();
           gexpr();
    end_macro();
    next();
    goto check;

}              break;

} else if (tok != ']') {
              if (!local_stack || (storage & VT_STATIC))                  vpushi(expr_const());
              else {
    /* VLAs (which can only happen with local_stack && !VT_STATIC)       length must always be evaluated, even under nocode_wanted,       so that its size slot is initialized (e.g. under sizeof       or typeof).  */    nocode_wanted = 0;
    gexpr();

}  check:              if ((vtop->r & (VT_VALMASK | VT_LVAL | VT_SYM)) == VT_CONST) {
                  n = vtop->c.i;
                  if (n < 0)                      tcc_error("invalid array size");

} else {
                  if (!is_integer_btype(vtop->type.t & VT_BTYPE))                      tcc_error("size of variable length array should be an integer");
                  n = 0;
                  t1 = VT_VLA;

}          
}          skip(']');
          /* parse next post type */          post_type(type, ad, storage, (td & ~(TYPE_DIRECT|TYPE_ABSTRACT)) | TYPE_NEST);
            if ((type->t & VT_BTYPE) == VT_FUNC)              tcc_error("declaration of an array of functions");
          if ((type->t & VT_BTYPE) == VT_VOID              || type_size(type, &align) < 0)              tcc_error("declaration of an array of incomplete type elements");
            t1 |= type->t & VT_VLA;
            if (t1 & VT_VLA) {
              if (n < 0) {
    if  (td & TYPE_NEST)                      tcc_error("need explicit inner array size in VLAs");

}       else {
                  loc -= type_size(&int_type, &align);
                  loc &= -align;
                  n = loc;
                    vpush_type_size(type, &align);
                  gen_op('*');
                  vset(&int_type, VT_LOCAL|VT_LVAL, n);
                  vswap();
                  vstore();

}          
}          if (n != -1)              vpop();
   nocode_wanted = saved_nocode_wanted;
                            /* we push an anonymous symbol which will contain the array             element type */          s = sym_push(SYM_FIELD, type, 0, n);
          type->t = (t1 ? VT_VLA : VT_ARRAY) | VT_PTR;
          type->ref = s;
            if (vla_array_str) {
              /* for function args, the top dimension is converted to pointer */       if ((t1 & VT_VLA) && (td & TYPE_NEST))           s->vla_array_str = vla_array_str;
       else           tok_str_free_str(vla_array_str);

}      
}      return 1;

}

static CType *type_decl(CType *type, AttributeDef *ad, int *v, int td)  {
      CType *post, *ret;
      int qualifiers, storage;
        /* recursive type, remove storage bits first, apply them later again */      storage = type->t & VT_STORAGE;
      type->t &= ~VT_STORAGE;
      post = ret = type;
        while (tok == '*') {
          qualifiers = 0;
      redo:          next();
          switch(tok) {
          case TOK__Atomic:              qualifiers |= VT_ATOMIC;
              goto redo;
          case TOK_CONST1:          case TOK_CONST2:          case TOK_CONST3:              qualifiers |= VT_CONSTANT;
              goto redo;
          case TOK_VOLATILE1:          case TOK_VOLATILE2:          case TOK_VOLATILE3:              qualifiers |= VT_VOLATILE;
              goto redo;
          case TOK_RESTRICT1:          case TOK_RESTRICT2:          case TOK_RESTRICT3:              goto redo;
   /* XXX: clarify attribute handling */   case TOK_ATTRIBUTE1:   case TOK_ATTRIBUTE2:       parse_attribute(ad);
       break;

}          mk_pointer(type);
          type->t |= qualifiers;
   if (ret == type)       /* innermost pointed to type is the one for the first derivation */       ret = pointed_type(type);

}        if (tok == '(') {
   /* This is possibly a parameter type list for abstract declarators      ('int ()'), use post_type for testing this.  */   if (!post_type(type, ad, 0, td)) {
       /* It's not, so it's a nested declarator, and the post operations          apply to the innermost pointed to type (if any).  */       /* XXX: this is not correct to modify 'ad' at this point, but          the syntax is not clear */       parse_attribute(ad);
       post = type_decl(type, ad, v, td);
       skip(')');

} else     goto abstract;

} else if (tok >= TOK_IDENT && (td & TYPE_DIRECT)) {
   /* type identifier */   *v = tok;
   next();

} else {
    abstract:   if (!(td & TYPE_ABSTRACT))     expect("identifier");
   *v = 0;

}      post_type(post, ad, post != ret ? 0 : storage,                td & ~(TYPE_DIRECT|TYPE_ABSTRACT));
      parse_attribute(ad);
      type->t |= storage;
      return ret;

}

ST_FUNC void indir(void)  {
      if ((vtop->type.t & VT_BTYPE) != VT_PTR) {
          if ((vtop->type.t & VT_BTYPE) == VT_FUNC)              return;
          expect("pointer");

}      if (vtop->r & VT_LVAL)          gv(RC_INT);
      vtop->type = *pointed_type(&vtop->type);
      /* Arrays and functions are never lvalues */      if (!(vtop->type.t & (VT_ARRAY | VT_VLA))          && (vtop->type.t & VT_BTYPE) != VT_FUNC) {
          vtop->r |= VT_LVAL;
          /* if bound checking, the referenced pointer must be checked */  #ifdef CONFIG_TCC_BCHECK          if (tcc_state->do_bounds_check)              vtop->r |= VT_MUSTBOUND;
  #endif      
}  
}

static void gfunc_param_typed(Sym *func, Sym *arg)  {
      int func_type;
      CType type;
        func_type = func->f.func_type;
      if (func_type == FUNC_OLD ||          (func_type == FUNC_ELLIPSIS && arg == NULL)) {
          /* default casting : only need to convert float to double */          if ((vtop->type.t & VT_BTYPE) == VT_FLOAT) {
              gen_cast_s(VT_DOUBLE);

} else if (vtop->type.t & VT_BITFIELD) {
              type.t = vtop->type.t & (VT_BTYPE | VT_UNSIGNED);
       type.ref = vtop->type.ref;
              gen_cast(&type);

} else if (vtop->r & VT_MUSTCAST) {
              force_charshort_cast();

}      
} else if (arg == NULL) {
          tcc_error("too many arguments to function");

} else {
          type = arg->type;
          type.t &= ~VT_CONSTANT;
 /* need to do that to avoid false warning */          gen_assign_cast(&type);

}  
}

static void expr_type(CType *type, void (*expr_fn)(void))  {
      nocode_wanted++;
      expr_fn();
      *type = vtop->type;
      vpop();
      nocode_wanted--;

}

static void parse_expr_type(CType *type)  {
      int n;
      AttributeDef ad;
        skip('(');
      if (parse_btype(type, &ad, 0)) {
          type_decl(type, &ad, &n, TYPE_ABSTRACT);

} else {
          expr_type(type, gexpr);

}      skip(')');

}

static void parse_type(CType *type)  {
      AttributeDef ad;
      int n;
        if (!parse_btype(type, &ad, 0)) {
          expect("type");

}      type_decl(type, &ad, &n, TYPE_ABSTRACT);

}

static void parse_builtin_params(int nc, const char *args)  {
      char c, sep = '(';
      CType type;
      if (nc)          nocode_wanted++;
      next();
      if (*args == 0)   skip(sep);
      while ((c = *args++)) {
   skip(sep);
   sep = ',';
          if (c == 't') {
              parse_type(&type);
       vpush(&type);
       continue;

}          expr_eq();
          type.ref = NULL;
          type.t = 0;
   switch (c) {
       case 'e':    continue;
       case 'V':                  type.t = VT_CONSTANT;
       case 'v':                  type.t |= VT_VOID;
                  mk_pointer (&type);
                  break;
       case 'S':                  type.t = VT_CONSTANT;
       case 's':                  type.t |= char_type.t;
                  mk_pointer (&type);
                  break;
       case 'i':                  type.t = VT_INT;
                  break;
       case 'l':                  type.t = VT_SIZE_T;
                  break;
       default:                  break;

}          gen_assign_cast(&type);

}      skip(')');
      if (nc)          nocode_wanted--;

}

static void parse_atomic(int atok)  {
      int size, align, arg, t, save = 0;
      CType *atom, *atom_ptr, ct = {
0
};
      SValue store;
      char buf[40];
      static const char *const templates[] = {
          /*           * Each entry consists of callback and function template.           * The template represents argument types and return type.           *           * ? void (return-only)           * b bool           * a atomic           * A read-only atomic           * p pointer to memory           * v value           * l load pointer           * s save pointer           * m memory model           */            /* keep in order of appearance in tcctok.h: */          /* __atomic_store */            "alm.?",          /* __atomic_load */             "Asm.v",          /* __atomic_exchange */         "alsm.v",          /* __atomic_compare_exchange */ "aplbmm.b",          /* __atomic_fetch_add */        "avm.v",          /* __atomic_fetch_sub */        "avm.v",          /* __atomic_fetch_or */         "avm.v",          /* __atomic_fetch_xor */        "avm.v",          /* __atomic_fetch_and */        "avm.v",          /* __atomic_fetch_nand */       "avm.v",          /* __atomic_and_fetch */        "avm.v",          /* __atomic_sub_fetch */        "avm.v",          /* __atomic_or_fetch */         "avm.v",          /* __atomic_xor_fetch */        "avm.v",          /* __atomic_and_fetch */        "avm.v",          /* __atomic_nand_fetch */       "avm.v"      
};
      const char *template = templates[(atok - TOK___atomic_store)];
        atom = atom_ptr = NULL;
      size = 0;
 /* pacify compiler */      next();
      skip('(');
      for (arg = 0;
;
) {
          expr_eq();
          switch (template[arg]) {
          case 'a':          case 'A':              atom_ptr = &vtop->type;
              if ((atom_ptr->t & VT_BTYPE) != VT_PTR)                  expect("pointer");
              atom = pointed_type(atom_ptr);
              size = type_size(atom, &align);
              if (size > 8                  || (size & (size - 1))                  || (atok > TOK___atomic_compare_exchange                      && (0 == btype_size(atom->t & VT_BTYPE)                          || (atom->t & VT_BTYPE) == VT_PTR)))                  expect("integral or integer-sized pointer target type");
              /* GCC does not care either: */              /* if (!(atom->t & VT_ATOMIC))                  tcc_warning("pointer target declaration is missing '_Atomic'");
 */              break;
            case 'p':              if ((vtop->type.t & VT_BTYPE) != VT_PTR               || type_size(pointed_type(&vtop->type), &align) != size)                  tcc_error("pointer target type mismatch in argument %d", arg + 1);
              gen_assign_cast(atom_ptr);
              break;
          case 'v':              gen_assign_cast(atom);
              break;
          case 'l':              indir();
              gen_assign_cast(atom);
              break;
          case 's':              save = 1;
              indir();
              store = *vtop;
              vpop();
              break;
          case 'm':              gen_assign_cast(&int_type);
              break;
          case 'b':              ct.t = VT_BOOL;
              gen_assign_cast(&ct);
              break;

}          if ('.' == template[++arg])              break;
          skip(',');

}      skip(')');
        ct.t = VT_VOID;
      switch (template[arg + 1]) {
      case 'b':          ct.t = VT_BOOL;
          break;
      case 'v':          ct = *atom;
          break;

}        sprintf(buf, "%s_%d", get_tok_str(atok, 0), size);
      vpush_helper_func(tok_alloc_const(buf));
      vrott(arg - save + 1);
      gfunc_call(arg - save);
        vpush(&ct);
      PUT_R_RET(vtop, ct.t);
      t = ct.t & VT_BTYPE;
      if (t == VT_BYTE || t == VT_SHORT || t == VT_BOOL) {
  #ifdef PROMOTE_RET          vtop->r |= BFVAL(VT_MUSTCAST, 1);
  #else          vtop->type.t = VT_INT;
  #endif      
}      gen_cast(&ct);
      if (save) {
          vpush(&ct);
          *vtop = store;
          vswap();
          vstore();

}  
}

ST_FUNC void unary(void)  {
      int n, t, align, size, r;
      CType type;
      Sym *s;
      AttributeDef ad;
        /* generate line number info */      if (debug_modes)          tcc_debug_line(tcc_state), tcc_tcov_check_line (tcc_state, 1);
        type.ref = NULL;
      /* XXX: GCC 2.95.3 does not generate a table although it should be         better here */   tok_next:      switch(tok) {
      case TOK_EXTENSION:          next();
          goto tok_next;
      case TOK_LCHAR:  #ifdef TCC_TARGET_PE          t = VT_SHORT|VT_UNSIGNED;
          goto push_tokc;
  #endif      case TOK_CINT:      case TOK_CCHAR:    t = VT_INT;
   push_tokc:   type.t = t;
   vsetc(&type, VT_CONST, &tokc);
          next();
          break;
      case TOK_CUINT:          t = VT_INT | VT_UNSIGNED;
          goto push_tokc;
      case TOK_CLLONG:          t = VT_LLONG;
   goto push_tokc;
      case TOK_CULLONG:          t = VT_LLONG | VT_UNSIGNED;
   goto push_tokc;
      case TOK_CFLOAT:          t = VT_FLOAT;
   goto push_tokc;
      case TOK_CDOUBLE:          t = VT_DOUBLE;
   goto push_tokc;
      case TOK_CLDOUBLE:  #ifdef TCC_USING_DOUBLE_FOR_LDOUBLE          t = VT_DOUBLE | VT_LONG;
  #else          t = VT_LDOUBLE;
  #endif   goto push_tokc;
      case TOK_CLONG:          t = (LONG_SIZE == 8 ? VT_LLONG : VT_INT) | VT_LONG;
   goto push_tokc;
      case TOK_CULONG:          t = (LONG_SIZE == 8 ? VT_LLONG : VT_INT) | VT_LONG | VT_UNSIGNED;
   goto push_tokc;
      case TOK___FUNCTION__:          if (!gnu_ext)              goto tok_identifier;
          /* fall thru */      case TOK___FUNC__:          tok = TOK_STR;
          cstr_reset(&tokcstr);
          cstr_cat(&tokcstr, funcname, 0);
          tokc.str.size = tokcstr.size;
          tokc.str.data = tokcstr.data;
          goto case_TOK_STR;
      case TOK_LSTR:  #ifdef TCC_TARGET_PE          t = VT_SHORT | VT_UNSIGNED;
  #else          t = VT_INT;
  #endif          goto str_init;
      case TOK_STR:      case_TOK_STR:          /* string parsing */          t = char_type.t;
      str_init:          if (tcc_state->warn_write_strings & WARN_ON)              t |= VT_CONSTANT;
          type.t = t;
          mk_pointer(&type);
          type.t |= VT_ARRAY;
          memset(&ad, 0, sizeof(AttributeDef));
          ad.section = rodata_section;
          decl_initializer_alloc(&type, &ad, VT_CONST, 2, 0, 0);
          break;
      case TOK_SOTYPE:      case '(':          t = tok;
          next();
          /* cast ? */          if (parse_btype(&type, &ad, 0)) {
              type_decl(&type, &ad, &n, TYPE_ABSTRACT);
              skip(')');
              /* check ISOC99 compound literal */              if (tok == '{
') {
                      /* data is allocated locally by default */                  if (global_expr)                      r = VT_CONST;
                  else                      r = VT_LOCAL;
                  /* all except arrays are lvalues */                  if (!(type.t & VT_ARRAY))                      r |= VT_LVAL;
                  memset(&ad, 0, sizeof(AttributeDef));
                  decl_initializer_alloc(&type, &ad, r, 1, 0, 0);

} else if (t == TOK_SOTYPE) {
 /* from sizeof/alignof (...) */                  vpush(&type);
                  return;

} else {
                  unary();
                  gen_cast(&type);

}          
} else if (tok == '{
') {
       int saved_nocode_wanted = nocode_wanted;
              if (CONST_WANTED && !NOEVAL_WANTED)                  expect("constant");
              if (0 == local_scope)                  tcc_error("statement expression outside of function");
              /* save all registers */              save_regs(0);
              /* statement expression : we do not accept break/continue                 inside as GCC does.  We do retain the nocode_wanted state,          as statement expressions can't ever be entered from the          outside, so any reactivation of code emission (from labels          or loop heads) can be disabled again after the end of it. */              block(STMT_EXPR);
              /* If the statement expr can be entered, then we retain the current                 nocode_wanted state (from e.g. a 'return 0;
' in the stmt-expr).                 If it can't be entered then the state is that from before the                 statement expression.  */              if (saved_nocode_wanted)                nocode_wanted = saved_nocode_wanted;
              skip(')');

} else {
              gexpr();
              skip(')');

}          break;
      case '*':          next();
          unary();
          indir();
          break;
      case '&':          next();
          unary();
          /* functions names must be treated as function pointers,             except for unary '&' and sizeof. Since we consider that             functions are not lvalues, we only have to handle it             there and in function calls. */          /* arrays can also be used although they are not lvalues */          if ((vtop->type.t & VT_BTYPE) != VT_FUNC &&              !(vtop->type.t & (VT_ARRAY | VT_VLA)))              test_lvalue();
          if (vtop->sym)            vtop->sym->a.addrtaken = 1;
          mk_pointer(&vtop->type);
          gaddrof();
          break;
      case '!':          next();
          unary();
          gen_test_zero(TOK_EQ);
          break;
      case '~':          next();
          unary();
          vpushi(-1);
          gen_op('^');
          break;
      case '+':          next();
          unary();
          if ((vtop->type.t & VT_BTYPE) == VT_PTR)              tcc_error("pointer not accepted for unary plus");
          /* In order to force cast, we add zero, except for floating point      where we really need an noop (otherwise -0.0 will be transformed      into +0.0).  */   if (!is_float(vtop->type.t)) {
