       gen_op('+');

}          break;
      case TOK_SIZEOF:      case TOK_ALIGNOF1:      case TOK_ALIGNOF2:      case TOK_ALIGNOF3:          t = tok;
          next();
          if (tok == '(')              tok = TOK_SOTYPE;
          expr_type(&type, unary);
          if (t == TOK_SIZEOF) {
              vpush_type_size(&type, &align);
              gen_cast_s(VT_SIZE_T);

} else {
