          if (c < 0)              save_regs(1), cc = 0;
          else if (c != i)              nocode_wanted++, f = 1;
          if (tok != op)              break;
          if (c < 0)              t = gvtst(i, t);
          else              vpop();
          next();
          expr_landor_next(op);

}      if (cc || f) {
          vpop();
          vpushi(i ^ f);
          gsym(t);
          nocode_wanted -= f;

