}

static int is_cond_bool(SValue *sv)  {
      if ((sv->r & (VT_VALMASK | VT_LVAL | VT_SYM)) == VT_CONST          && (sv->type.t & VT_BTYPE) == VT_INT)          return (unsigned)sv->c.i < 2;
      if (sv->r == VT_CMP)          return 1;
      return 0;

}

