static inline int64_t expr_const64(void)  {
      int64_t c;
      expr_const1();
      if ((vtop->r & (VT_VALMASK | VT_LVAL | VT_SYM | VT_NONCONST)) != VT_CONST)          expect("constant expression");
      c = vtop->c.i;
      vpop();
      return c;

}

ST_FUNC int expr_const(void)  {
      int c;
      int64_t wc = expr_const64();
      c = wc;
      if (c != wc && (unsigned)c != wc)          tcc_error("constant exceeds 32 bit");
