}  
}

static int gcase(struct case_t **base, int len, int dsym)  {
      struct case_t *p;
      int t, l2, e;
        t = vtop->type.t & VT_BTYPE;
      if (t != VT_LLONG)          t = VT_INT;
      while (len) {
          /* binary search while len > 8, else linear */          l2 = len > 8 ? len/2 : 0;
          p = base[l2];
          vdup(), vpush64(t, p->v2);
          if (l2 == 0 && p->v1 == p->v2) {
              gen_op(TOK_EQ);
 /* jmp to case when equal */              gsym_addr(gvtst(0, 0), p->ind);

} else {
              /* case v1 ... v2 */              gen_op(TOK_GT);
 /* jmp over when > V2 */              if (len == 1) /* last case test jumps to default when false */                  dsym = gvtst(0, dsym), e = 0;
              else                  e = gvtst(0, 0);
              vdup(), vpush64(t, p->v1);
              gen_op(TOK_GE);
 /* jmp to case when >= V1 */              gsym_addr(gvtst(0, 0), p->ind);
              dsym = gcase(base, l2, dsym);
              gsym(e);

}          ++l2, base += l2, len -= l2;

}      /* jump automagically will suppress more jumps */      return gjmp(dsym);

}

static void end_switch(void)  {
      struct switch_t *sw = cur_switch;
      dynarray_reset(&sw->p, &sw->n);
      cur_switch = sw->prev;
      tcc_free(sw);

}

static void try_call_scope_cleanup(Sym *stop)  {
      Sym *cls = cur_scope->cl.s;
        for (;
 cls != stop;
 cls = cls->next) {
   Sym *fs = cls->cleanup_func;
   Sym *vs = cls->prev_tok;
     vpushsym(&fs->type, fs);
   vset(&vs->type, vs->r, vs->c);
   vtop->sym = vs;
          mk_pointer(&vtop->type);
   gaddrof();
   gfunc_call(1);

}  
}

static void try_call_cleanup_goto(Sym *cleanupstate)  {
      Sym *oc, *cc;
      int ocd, ccd;
        if (!cur_scope->cl.s)   return;
        /* search NCA of both cleanup chains given parents and initial depth */      ocd = cleanupstate ? cleanupstate->v & ~SYM_FIELD : 0;
      for (ccd = cur_scope->cl.n, oc = cleanupstate;
 ocd > ccd;
 --ocd, oc = oc->next)       ;
      for (cc = cur_scope->cl.s;
 ccd > ocd;
 --ccd, cc = cc->next)       ;
      for (;
 cc != oc;
 cc = cc->next, oc = oc->next, --ccd)       ;
        try_call_scope_cleanup(cc);

}

static void block_cleanup(struct scope *o)  {
      int jmp = 0;
      Sym *g, **pg;
      for (pg = &pending_gotos;
 (g = *pg) && g->c > o->cl.n;
) {
          if (g->prev_tok->r & LABEL_FORWARD) {
              Sym *pcl = g->next;
              if (!jmp)                  jmp = gjmp(0);
              gsym(pcl->jnext);
              try_call_scope_cleanup(o->cl.s);
              pcl->jnext = gjmp(0);
              if (!o->cl.n)                  goto remove_pending;
              g->c = o->cl.n;
              pg = &g->prev;

} else {
      remove_pending:              *pg = g->prev;
              sym_free(g);

}      
}      gsym(jmp);
      try_call_scope_cleanup(o->cl.s);

}

static void vla_restore(int loc)  {
      if (loc)          gen_vla_sp_restore(loc);

}

static void vla_leave(struct scope *o)  {
      struct scope *c = cur_scope, *v = NULL;
      for (;
 c != o && c;
 c = c->prev)        if (c->vla.num)          v = c;
      if (v)        vla_restore(v->vla.locorig);

}

static void new_scope(struct scope *o)  {
      /* copy and link previous scope */      *o = *cur_scope;
      o->prev = cur_scope;
      cur_scope = o;
      cur_scope->vla.num = 0;
        /* record local declaration stack position */      o->lstk = local_stack;
      o->llstk = local_label_stack;
      ++local_scope;

}

static void prev_scope(struct scope *o, int is_expr)  {
      vla_leave(o->prev);
        if (o->cl.s != o->prev->cl.s)          block_cleanup(o->prev);
        /* pop locally defined labels */      label_pop(&local_label_stack, o->llstk, is_expr);
        /* In the is_expr case (a statement expression is finished here),         vtop might refer to symbols on the local_stack.  Either via the         type or via vtop->sym.  We can't pop those nor any that in turn         might be referred to.  To make it easier we don't roll back         any symbols in that case;
