static void parse_init_elem(int expr_type)  {
      int saved_global_expr;
      switch(expr_type) {
      case EXPR_CONST:          /* compound literals must be allocated globally in this case */          saved_global_expr = global_expr;
          global_expr = 1;
          expr_const1();
          global_expr = saved_global_expr;
          /* NOTE: symbols are accepted, as well as lvalue for anon symbols      (compound literals).  */          if (((vtop->r & (VT_VALMASK | VT_LVAL)) != VT_CONST               && ((vtop->r & (VT_SYM|VT_LVAL)) != (VT_SYM|VT_LVAL)                   || vtop->sym->v < SYM_FIRST_ANOM))  #ifdef TCC_TARGET_PE                   || ((vtop->r & VT_SYM) && vtop->sym->a.dllimport)  #endif             )              tcc_error("initializer element is not constant");
          break;
      case EXPR_ANY:          expr_eq();
          break;

}  
}

static void init_putz(init_params *p, unsigned long c, int size)  {
      init_assert(p, c + size);
