}

static void decl_design_delrels(Section *sec, int c, int size)  {
      ElfW_Rel *rel, *rel2, *rel_end;
      if (!sec || !sec->reloc)          return;
      rel = rel2 = (ElfW_Rel*)sec->reloc->data;
      rel_end = (ElfW_Rel*)(sec->reloc->data + sec->reloc->data_offset);
      while (rel < rel_end) {
          if (rel->r_offset >= c && rel->r_offset < c + size) {
              sec->reloc->data_offset -= sizeof *rel;

} else {
              if (rel2 != rel)                  memcpy(rel2, rel, sizeof *rel);
              ++rel2;

}          ++rel;

}  
}

static void decl_design_flex(init_params *p, Sym *ref, int index)  {
      if (ref == p->flex_array_ref) {
          if (index >= ref->c)              ref->c = index + 1;

} else if (ref->c < 0)          tcc_error("flexible array has zero size in this context");

}

static int decl_designator(init_params *p, CType *type, unsigned long c,                             Sym **cur_field, int flags, int al)  {
      Sym *s, *f;
      int index, index_last, align, l, nb_elems, elem_size;
      unsigned long corig = c;
        elem_size = 0;
      nb_elems = 1;
        if (flags & DIF_HAVE_ELEM)          goto no_designator;
        if (gnu_ext && tok >= TOK_UIDENT) {
          l = tok, next();
          if (tok == ':')              goto struct_field;
          unget_tok(l);

}        /* NOTE: we only support ranges for last designator */      while (nb_elems == 1 && (tok == '[' || tok == '.')) {
          if (tok == '[') {
              if (!(type->t & VT_ARRAY))                  expect("array type");
              next();
              index = index_last = expr_const();
              if (tok == TOK_DOTS && gnu_ext) {
                  next();
                  index_last = expr_const();

}              skip(']');
              s = type->ref;
              decl_design_flex(p, s, index_last);
              if (index < 0 || index_last >= s->c || index_last < index)           tcc_error("index exceeds array bounds or range is empty");
              if (cur_field)    (*cur_field)->c = index_last;
              type = pointed_type(type);
              elem_size = type_size(type, &align);
              c += index * elem_size;
              nb_elems = index_last - index + 1;

} else {
              int cumofs;
              next();
              l = tok;
          struct_field:              next();
       f = find_field(type, l, &cumofs);
              if (cur_field)                  *cur_field = f;
       type = &f->type;
              c += cumofs;

}          cur_field = NULL;

}      if (!cur_field) {
