       expect("=");

}      
} else {
      no_designator:          if (type->t & VT_ARRAY) {
       index = (*cur_field)->c;
              s = type->ref;
              decl_design_flex(p, s, index);
              if (index >= s->c)                  tcc_error("too many initializers");
              type = pointed_type(type);
              elem_size = type_size(type, &align);
              c += index * elem_size;

