}        decl_initializer(p, type, c, flags & ~DIF_FIRST);
        if (!(flags & DIF_SIZE_ONLY) && nb_elems > 1) {
          Sym aref = {
0
};
          CType t1;
          int i;
          if (p->sec || (type->t & VT_ARRAY)) {
              /* make init_putv/vstore believe it were a struct */              aref.c = elem_size;
              t1.t = VT_STRUCT, t1.ref = &aref;
              type = &t1;

}          if (p->sec)              vpush_ref(type, p->sec, c, elem_size);
          else       vset(type, VT_LOCAL|VT_LVAL, c);
          for (i = 1;
 i < nb_elems;
 i++) {
              vdup();
              init_putv(p, type, c + elem_size * i);

}          vpop();

}        c += nb_elems * elem_size;
      if (c - corig > al)        al = c - corig;
      return al;

}

