static void func_vla_arg_code(Sym *arg)  {
      int align;
      TokenString *vla_array_tok = NULL;
        if (arg->type.ref)          func_vla_arg_code(arg->type.ref);
        if ((arg->type.t & VT_VLA) && arg->type.ref->vla_array_str) {
   loc -= type_size(&int_type, &align);
   loc &= -align;
   arg->type.ref->c = loc;
     unget_tok(0);
   vla_array_tok = tok_str_alloc();
   vla_array_tok->str = arg->type.ref->vla_array_str;
   begin_macro(vla_array_tok, 1);
   next();
   gexpr();
   end_macro();
   next();
   vpush_type_size(&arg->type.ref->type, &align);
   gen_op('*');
   vset(&int_type, VT_LOCAL|VT_LVAL, arg->type.ref->c);
   vswap();
   vstore();
   vpop();

}  
}

static void func_vla_arg(Sym *sym)  {
      Sym *arg;
        for (arg = sym->type.ref->next;
 arg;
 arg = arg->next)          if ((arg->type.t & VT_BTYPE) == VT_PTR && (arg->type.ref->type.t & VT_VLA))              func_vla_arg_code(arg->type.ref);

}

static void gen_function(Sym *sym)  {
      struct scope f = {
 0 
};
      cur_scope = root_scope = &f;
      nocode_wanted = 0;
        ind = cur_text_section->data_offset;
      if (sym->a.aligned) {
   size_t newoff = section_add(cur_text_section, 0,          1 << (sym->a.aligned - 1));
   gen_fill_nops(newoff - ind);

}        funcname = get_tok_str(sym->v, NULL);
      func_ind = ind;
      func_vt = sym->type.ref->type;
      func_var = sym->type.ref->f.func_type == FUNC_ELLIPSIS;
        /* NOTE: we patch the symbol size later */      put_extern_sym(sym, cur_text_section, ind, 0);
        if (sym->type.ref->f.func_ctor)          add_array (tcc_state, ".init_array", sym->c);
      if (sym->type.ref->f.func_dtor)          add_array (tcc_state, ".fini_array", sym->c);
        /* put debug symbol */      tcc_debug_funcstart(tcc_state, sym);
        /* push a dummy symbol to enable local sym storage */      sym_push2(&local_stack, SYM_FIELD, 0, 0);
      local_scope = 1;
 /* for function parameters */      nb_temp_local_vars = 0;
      gfunc_prolog(sym);
      tcc_debug_prolog_epilog(tcc_state, 0);
        local_scope = 0;
      rsym = 0;
      func_vla_arg(sym);
      block(0);
      gsym(rsym);
        nocode_wanted = 0;
      /* reset local stack */      pop_local_syms(NULL, 0);
      tcc_debug_prolog_epilog(tcc_state, 1);
      gfunc_epilog();
        /* end of function */      tcc_debug_funcend(tcc_state, ind - func_ind);
        /* patch symbol size */      elfsym(sym)->st_size = ind - func_ind;
        cur_text_section->data_offset = ind;
      local_scope = 0;
      label_pop(&global_label_stack, NULL, 0);
      sym_pop(&all_cleanups, NULL, 0);
        /* It's better to crash than to generate wrong code */      cur_text_section = NULL;
      funcname = "";
 /* for safety */      func_vt.t = VT_VOID;
 /* for safety */      func_var = 0;
 /* for safety */      ind = 0;
 /* for safety */      func_ind = -1;
      nocode_wanted = DATA_ONLY_WANTED;
      check_vstack();
        /* do this after funcend debug info */      next();

}

static void gen_inline_functions(TCCState *s)  {
      Sym *sym;
