static int check_symbols(TCCState *s1, struct macho *mo)  {
      int sym_index, sym_end;
      int ret = 0;
        mo->ilocal = mo->iextdef = mo->iundef = -1;
      sym_end = symtab_section->data_offset / sizeof(ElfW(Sym));
      for (sym_index = 1;
 sym_index < sym_end;
 ++sym_index) {
          int elf_index = ((struct nlist_64 *)mo->symtab->data + sym_index - 1)->n_value;
          ElfW(Sym) *sym = (ElfW(Sym) *)symtab_section->data + elf_index;
          const char *name = (char*)symtab_section->link->data + sym->st_name;
          unsigned type = ELFW(ST_TYPE)(sym->st_info);
          unsigned bind = ELFW(ST_BIND)(sym->st_info);
          unsigned vis  = ELFW(ST_VISIBILITY)(sym->st_other);
            dprintf("%4d (%4d): %09lx %4d %4d %4d %3d %s\n",                  sym_index, elf_index, (long)sym->st_value,                  type, bind, vis, sym->st_shndx, name);
          if (bind == STB_LOCAL) {
              if (mo->ilocal == -1)                mo->ilocal = sym_index - 1;
              if (mo->iextdef != -1 || mo->iundef != -1)                tcc_error("local syms after global ones");

} else if (sym->st_shndx != SHN_UNDEF) {
              if (mo->iextdef == -1)                mo->iextdef = sym_index - 1;
              if (mo->iundef != -1)                tcc_error("external defined symbol after undefined");

} else if (sym->st_shndx == SHN_UNDEF) {
              if (mo->iundef == -1)                mo->iundef = sym_index - 1;
              if (ELFW(ST_BIND)(sym->st_info) == STB_WEAK    || s1->output_type != TCC_OUTPUT_EXE                  || find_elf_sym(s1->dynsymtab_section, name)) {
                  /* Mark the symbol as coming from a dylib so that                     relocate_syms doesn't complain.  Normally bind_exe_dynsyms                     would do this check, and place the symbol into dynsym                     which is checked by relocate_syms.  But Mach-O doesn't use                     bind_exe_dynsyms.  */                  sym->st_shndx = SHN_FROMDLL;
                  continue;

}              tcc_error_noabort("undefined symbol '%s'", name);
              ret = -1;

}      
}      return ret;

}

static void convert_symbol(TCCState *s1, struct macho *mo, struct nlist_64 *pn)  {
      struct nlist_64 n = *pn;
      ElfSym *sym = (ElfW(Sym) *)symtab_section->data + pn->n_value;
      const char *name = (char*)symtab_section->link->data + sym->st_name;
      switch(ELFW(ST_TYPE)(sym->st_info)) {
      case STT_NOTYPE:      case STT_OBJECT:      case STT_FUNC:      case STT_SECTION:          n.n_type = N_SECT;
          break;
      case STT_FILE:          n.n_type = N_ABS;
          break;
      default:          tcc_error("unhandled ELF symbol type %d %s",                    ELFW(ST_TYPE)(sym->st_info), name);

}      if (sym->st_shndx == SHN_UNDEF)        tcc_error("should have been rewritten to SHN_FROMDLL: %s", name);
      else if (sym->st_shndx == SHN_FROMDLL)        n.n_type = N_UNDF, n.n_sect = 0;
      else if (sym->st_shndx == SHN_ABS)        n.n_type = N_ABS, n.n_sect = 0;
      else if (sym->st_shndx >= SHN_LORESERVE)        tcc_error("unhandled ELF symbol section %d %s", sym->st_shndx, name);
      else if (!mo->elfsectomacho[sym->st_shndx]) {
        if (strncmp(s1->sections[sym->st_shndx]->name, ".debug_", 7))          tcc_error("ELF section %d(%s) not mapped into Mach-O for symbol %s",                    sym->st_shndx, s1->sections[sym->st_shndx]->name, name);

}      else        n.n_sect = mo->elfsectomacho[sym->st_shndx];
      if (ELFW(ST_BIND)(sym->st_info) == STB_GLOBAL)        n.n_type |=  N_EXT;
      else if (ELFW(ST_BIND)(sym->st_info) == STB_WEAK)        n.n_desc |= N_WEAK_REF | (n.n_type != N_UNDF ? N_WEAK_DEF : 0);
      n.n_strx = pn->n_strx;
      n.n_value = sym->st_value;
      *pn = n;

}

static void convert_symbols(TCCState *s1, struct macho *mo)  {
      struct nlist_64 *pn;
      for_each_elem(mo->symtab, 0, pn, struct nlist_64)          convert_symbol(s1, mo, pn);

}

static int machosymcmp(const void *_a, const void *_b, void *arg)  {
      TCCState *s1 = arg;
      int ea = ((struct nlist_64 *)_a)->n_value;
      int eb = ((struct nlist_64 *)_b)->n_value;
      ElfSym *sa = (ElfSym *)symtab_section->data + ea;
      ElfSym *sb = (ElfSym *)symtab_section->data + eb;
      int r;
      /* locals, then defined externals, then undefined externals, the         last two sections also by name, otherwise stable sort */      r = (ELFW(ST_BIND)(sb->st_info) == STB_LOCAL)          - (ELFW(ST_BIND)(sa->st_info) == STB_LOCAL);
      if (r)        return r;
      r = (sa->st_shndx == SHN_UNDEF) - (sb->st_shndx == SHN_UNDEF);
      if (r)        return r;
      if (ELFW(ST_BIND)(sa->st_info) != STB_LOCAL) {
          const char * na = (char*)symtab_section->link->data + sa->st_name;
          const char * nb = (char*)symtab_section->link->data + sb->st_name;
          r = strcmp(na, nb);
          if (r)            return r;

}      return ea - eb;

}

static void tcc_qsort (void  *base, size_t nel, size_t width,                         int (*comp)(const void *, const void *, void *), void *arg)  {
      size_t wnel, gap, wgap, i, j, k;
      char *a, *b, tmp;
        wnel = width * nel;
      for (gap = 0;
 ++gap < nel;
)          gap *= 3;
      while ( gap /= 3 ) {
          wgap = width * gap;
          for (i = wgap;
 i < wnel;
 i += width) {
              for (j = i - wgap;
;
j -= wgap) {
                  a = j + (char *)base;
                  b = a + wgap;
                  if ( (*comp)(a, b, arg) <= 0 )                      break;
                  k = width;
                  do {
                      tmp = *a;
                      *a++ = *b;
                      *b++ = tmp;

} while ( --k );
                  if (j < wgap)                      break;

}          
}      
}  
}

static void create_symtab(TCCState *s1, struct macho *mo)  {
      int sym_index, sym_end;
      struct nlist_64 *pn;
