              pe_set_datadir(&pe_header, IMAGE_DIRECTORY_ENTRY_IAT,                  pe->iat_offs, pe->iat_size);

}          if (pe->exp_size) {
              pe_set_datadir(&pe_header, IMAGE_DIRECTORY_ENTRY_EXPORT,                  pe->exp_offs, pe->exp_size);

}            memcpy(psh->Name, sh_name, umin(strlen(sh_name), sizeof psh->Name));
          if (si->cls == sec_debug)              need_strtab += pe_put_long_secname((char*)psh->Name, sh_name);
            psh->Characteristics = si->pe_flags;
          psh->VirtualAddress = addr;
          psh->Misc.VirtualSize = size;
          pe_header.opthdr.SizeOfImage =              umax(pe_virtual_align(pe, size + addr), pe_header.opthdr.SizeOfImage);
            if (si->data_size) {
              psh->PointerToRawData = file_offset;
              file_offset = pe_file_align(pe, file_offset + si->data_size);
              psh->SizeOfRawData = file_offset - psh->PointerToRawData;
              if (si->cls == sec_text)                  pe_header.opthdr.SizeOfCode += psh->SizeOfRawData;
              else                  pe_header.opthdr.SizeOfInitializedData += psh->SizeOfRawData;

}      
}        //pe_header.filehdr.TimeDateStamp = time(NULL);
      pe_header.filehdr.NumberOfSections = pe->sec_count;
      pe_header.opthdr.AddressOfEntryPoint = pe->start_addr;
      pe_header.opthdr.SizeOfHeaders = pe->sizeofheaders;
      pe_header.opthdr.ImageBase = pe->imagebase;
      pe_header.opthdr.Subsystem = pe->subsystem;
      if (pe->s1->pe_stack_size)          pe_header.opthdr.SizeOfStackReserve = pe->s1->pe_stack_size;
      if (PE_DLL == pe->type)          pe_header.filehdr.Characteristics = CHARACTERISTICS_DLL;
      pe_header.filehdr.Characteristics |= pe->s1->pe_characteristics;
      if (need_strtab) {
          pe_header.filehdr.PointerToSymbolTable = file_offset;
          pe_header.filehdr.NumberOfSymbols = N_COFF_SYMS;

}      pe_fwrite(&pe_header, sizeof pe_header, &pf);
      for (i = 0;
 i < pe->sec_count;
 ++i)          pe_fwrite(&pe->sec_info[i]->ish, sizeof(IMAGE_SECTION_HEADER), &pf);
        file_offset = pe->sizeofheaders;
      for (i = 0;
 i < pe->sec_count;
 ++i) {
          Section *s;
          si = pe->sec_info[i];
          if (!si->data_size)              continue;
          for (s = si->sec;
 s;
 s = s->prev) {
              pe_fpad(&pf, file_offset);
              pe_fwrite(s->data, s->data_offset, &pf);
              if (s->prev)                  file_offset += s->prev->sh_addr - s->sh_addr;

}          file_offset = si->ish.PointerToRawData + si->ish.SizeOfRawData;
          pe_fpad(&pf, file_offset);

}        if (need_strtab) {
          /* create a tiny COFF string table with the long section names */          pe_fwrite(&coff_strtab_size, sizeof coff_strtab_size, &pf);
          pe_fwrite(dwarf_secs, sizeof dwarf_secs - 1, &pf);
          file_offset = pf.pos;

}        pf.sum += file_offset;
      fseek(pf.op, offsetof(struct pe_header, opthdr.CheckSum), SEEK_SET);
      pe_fwrite(&pf.sum, sizeof (DWORD), &pf);
        fclose (pf.op);
  #ifndef _WIN32      chmod(pe->filename, 0777);
  #endif        if (2 == pe->s1->verbose)          printf("-------------------------------\n");
      if (pe->s1->verbose)          printf("<- %s (%u bytes)\n", pe->filename, (unsigned)file_offset);
        if (s1->do_debug & 16)          pe_create_pdb(s1, pe->filename);
      return 0;

}

static struct import_symbol *pe_add_import(struct pe_info *pe, int sym_index)  {
      int i;
      int dll_index;
      struct pe_import_info *p;
      struct import_symbol *s;
      ElfW(Sym) *isym;
        isym = (ElfW(Sym) *)pe->s1->dynsymtab_section->data + sym_index;
      dll_index = isym->st_size;
        i = dynarray_assoc ((void**)pe->imp_info, pe->imp_count, dll_index);
      if (-1 != i) {
          p = pe->imp_info[i];
          goto found_dll;

}      p = tcc_mallocz(sizeof *p);
      p->dll_index = dll_index;
      dynarray_add(&pe->imp_info, &pe->imp_count, p);
    found_dll:      i = dynarray_assoc ((void**)p->symbols, p->sym_count, sym_index);
      if (-1 != i)          return p->symbols[i];
        s = tcc_mallocz(sizeof *s);
      dynarray_add(&p->symbols, &p->sym_count, s);
      s->sym_index = sym_index;
      return s;

}

static void pe_free_imports(struct pe_info *pe)  {
      int i;
      for (i = 0;
 i < pe->imp_count;
 ++i) {
          struct pe_import_info *p = pe->imp_info[i];
          dynarray_reset(&p->symbols, &p->sym_count);

}      dynarray_reset(&pe->imp_info, &pe->imp_count);

}

static void pe_build_imports(struct pe_info *pe)  {
      int thk_ptr, ent_ptr, dll_ptr, sym_cnt, i;
      DWORD rva_base = pe->thunk->sh_addr - pe->imagebase;
      int ndlls = pe->imp_count;
      TCCState *s1 = pe->s1;
        for (sym_cnt = i = 0;
 i < ndlls;
 ++i)          sym_cnt += pe->imp_info[i]->sym_count;
        if (0 == sym_cnt)          return;
        pe_align_section(pe->thunk, 16);
      pe->imp_size = (ndlls + 1) * sizeof(IMAGE_IMPORT_DESCRIPTOR);
      pe->iat_size = (sym_cnt + ndlls) * sizeof(ADDR3264);
      dll_ptr = pe->thunk->data_offset;
      thk_ptr = dll_ptr + pe->imp_size;
      ent_ptr = thk_ptr + pe->iat_size;
      pe->imp_offs = dll_ptr + rva_base;
      pe->iat_offs = thk_ptr + rva_base;
      section_ptr_add(pe->thunk, pe->imp_size + 2*pe->iat_size);
        for (i = 0;
 i < pe->imp_count;
 ++i) {
          IMAGE_IMPORT_DESCRIPTOR *hdr;
          int k, n, dllindex;
          ADDR3264 v;
          struct pe_import_info *p = pe->imp_info[i];
          const char *name;
          DLLReference *dllref;
            dllindex = p->dll_index;
          if (dllindex)              name = (dllref = pe->s1->loaded_dlls[dllindex-1])->name;
          else              name = "", dllref = NULL;
            /* put the dll name into the import header */          v = put_elf_str(pe->thunk, name);
          hdr = (IMAGE_IMPORT_DESCRIPTOR*)(pe->thunk->data + dll_ptr);
          hdr->FirstThunk = thk_ptr + rva_base;
          hdr->OriginalFirstThunk = ent_ptr + rva_base;
          hdr->Name = v + rva_base;
            for (k = 0, n = p->sym_count;
 k <= n;
 ++k) {
              if (k < n) {
                  int iat_index = p->symbols[k]->iat_index;
                  int sym_index = p->symbols[k]->sym_index;
                  ElfW(Sym) *imp_sym = (ElfW(Sym) *)pe->s1->dynsymtab_section->data + sym_index;
                  ElfW(Sym) *org_sym = (ElfW(Sym) *)symtab_section->data + iat_index;
                  const char *name = (char*)pe->s1->dynsymtab_section->link->data + imp_sym->st_name;
                  int ordinal;
                    org_sym->st_value = thk_ptr;
                  org_sym->st_shndx = pe->thunk->sh_num;
                    if (dllref)                      v = 0, ordinal = imp_sym->st_value;
 /* ordinal from pe_load_def */                  else                      ordinal = 0, v = imp_sym->st_value;
 /* address from tcc_add_symbol() */    #ifdef TCC_IS_NATIVE                  if (pe->type == PE_RUN) {
                      if (dllref) {
                          if ( !dllref->handle )                              dllref->handle = LoadLibraryA(dllref->name);
                          v = (ADDR3264)GetProcAddress(dllref->handle, ordinal?(char*)0+ordinal:name);

}                      if (!v)                          tcc_error_noabort("could not resolve symbol '%s'", name);

} else  #endif                  if (ordinal) {
                      v = ordinal | (ADDR3264)1 << (sizeof(ADDR3264)*8 - 1);

} else {
                      v = pe->thunk->data_offset + rva_base;
                      section_ptr_add(pe->thunk, sizeof(WORD));
 /* hint, not used */                      put_elf_str(pe->thunk, name);

}                
} else {
                  v = 0;
 /* last entry is zero */              
}                *(ADDR3264*)(pe->thunk->data+thk_ptr) =              *(ADDR3264*)(pe->thunk->data+ent_ptr) = v;
              thk_ptr += sizeof (ADDR3264);
              ent_ptr += sizeof (ADDR3264);

}          dll_ptr += sizeof(IMAGE_IMPORT_DESCRIPTOR);

}  
}

static int sym_cmp(const void *va, const void *vb)  {
      const char *ca = (*(struct pe_sort_sym**)va)->name;
      const char *cb = (*(struct pe_sort_sym**)vb)->name;
      return strcmp(ca, cb);

}

static void pe_build_exports(struct pe_info *pe)  {
      ElfW(Sym) *sym;
      int sym_index, sym_end;
      DWORD rva_base, base_o, func_o, name_o, ord_o, str_o;
      IMAGE_EXPORT_DIRECTORY *hdr;
      int sym_count, ord;
      struct pe_sort_sym **sorted, *p;
      TCCState *s1 = pe->s1;
        FILE *op;
      char buf[260];
      const char *dllname;
      const char *name;
        rva_base = pe->thunk->sh_addr - pe->imagebase;
      sym_count = 0, sorted = NULL, op = NULL;
        sym_end = symtab_section->data_offset / sizeof(ElfW(Sym));
      for (sym_index = 1;
 sym_index < sym_end;
 ++sym_index) {
          sym = (ElfW(Sym)*)symtab_section->data + sym_index;
          name = pe_export_name(pe->s1, sym);
          if (sym->st_other & ST_PE_EXPORT) {
              p = tcc_malloc(sizeof *p);
              p->index = sym_index;
              p->name = name;
              dynarray_add(&sorted, &sym_count, p);

}  #if 0          if (sym->st_other & ST_PE_EXPORT)              printf("export: %s\n", name);
          if (sym->st_other & ST_PE_STDCALL)              printf("stdcall: %s\n", name);
  #endif      
}        if (0 == sym_count)          return;
        qsort (sorted, sym_count, sizeof *sorted, sym_cmp);
        pe_align_section(pe->thunk, 16);
      dllname = tcc_basename(pe->filename);
        base_o = pe->thunk->data_offset;
      func_o = base_o + sizeof(IMAGE_EXPORT_DIRECTORY);
      name_o = func_o + sym_count * sizeof (DWORD);
      ord_o = name_o + sym_count * sizeof (DWORD);
      str_o = ord_o + sym_count * sizeof(WORD);
        hdr = section_ptr_add(pe->thunk, str_o - base_o);
      hdr->Characteristics        = 0;
      hdr->Base                   = 1;
      hdr->NumberOfFunctions      = sym_count;
      hdr->NumberOfNames          = sym_count;
      hdr->AddressOfFunctions     = func_o + rva_base;
      hdr->AddressOfNames         = name_o + rva_base;
      hdr->AddressOfNameOrdinals  = ord_o + rva_base;
      hdr->Name                   = str_o + rva_base;
      put_elf_str(pe->thunk, dllname);
    #if 1      /* automatically write exports to <output-filename>.def */      pstrcpy(buf, sizeof buf, pe->filename);
      strcpy(tcc_fileextension(buf), ".def");
      op = fopen(buf, "wb");
      if (NULL == op) {
          tcc_error_noabort("could not create '%s': %s", buf, strerror(errno));

} else {
          fprintf(op, "LIBRARY %s\n\nEXPORTS\n", dllname);
          if (pe->s1->verbose)              printf("<- %s (%d symbol%s)\n", buf, sym_count, &"s"[sym_count < 2]);

}  #endif        for (ord = 0;
 ord < sym_count;
 ++ord)      {
          p = sorted[ord], sym_index = p->index, name = p->name;
          /* insert actual address later in relocate_sections() */          put_elf_reloc(symtab_section, pe->thunk,              func_o, R_XXX_RELATIVE, sym_index);
          *(DWORD*)(pe->thunk->data + name_o)              = pe->thunk->data_offset + rva_base;
          *(WORD*)(pe->thunk->data + ord_o)              = ord;
          put_elf_str(pe->thunk, name);
          func_o += sizeof (DWORD);
          name_o += sizeof (DWORD);
          ord_o += sizeof (WORD);
          if (op)              fprintf(op, "%s\n", name);

}        pe->exp_offs = base_o + rva_base;
      pe->exp_size = pe->thunk->data_offset - base_o;
      dynarray_reset(&sorted, &sym_count);
      if (op)          fclose(op);

}

static void pe_build_reloc (struct pe_info *pe)  {
      DWORD offset, block_ptr, sh_addr, addr;
      int count, i;
      ElfW_Rel *rel, *rel_end;
      Section *s = NULL, *sr;
      struct pe_reloc_header *hdr;
        sh_addr = offset = block_ptr = count = i = 0;
      rel = rel_end = NULL;
        for(;
;
) {
          if (rel < rel_end) {
              int type = ELFW(R_TYPE)(rel->r_info);
              addr = rel->r_offset + sh_addr;
              ++ rel;
              if (type != REL_TYPE_DIRECT)                  continue;
              if (count == 0) {
 /* new block */                  block_ptr = pe->reloc->data_offset;
                  section_ptr_add(pe->reloc, sizeof(struct pe_reloc_header));
                  offset = addr & 0xFFFFFFFF<<12;

}              if ((addr -= offset)  < (1<<12)) {
 /* one block spans 4k addresses */                  WORD *wp = section_ptr_add(pe->reloc, sizeof (WORD));
                  *wp = addr | PE_IMAGE_REL<<12;
                  ++count;
                  continue;

}              -- rel;

} else if (s) {
              sr = s->reloc;
              if (sr) {
                  rel = (ElfW_Rel *)sr->data;
                  rel_end = (ElfW_Rel *)(sr->data + sr->data_offset);
                  sh_addr = s->sh_addr;

}              s = s->prev;
              continue;

} else if (i < pe->sec_count) {
              s = pe->sec_info[i]->sec, ++i;
              continue;

} else if (!count)              break;
            /* fill the last block and ready for a new one */          if (count & 1) /* align for DWORDS */              section_ptr_add(pe->reloc, sizeof(WORD)), ++count;
          hdr = (struct pe_reloc_header *)(pe->reloc->data + block_ptr);
          hdr -> offset = offset - pe->imagebase;
          hdr -> size = count * sizeof(WORD) + sizeof(struct pe_reloc_header);
          count = 0;

}  
}

static int pe_section_class(Section *s)  {
      int type, flags;
      const char *name;
      type = s->sh_type;
      flags = s->sh_flags;
      name = s->name;
        if (0 == memcmp(name, ".stab", 5) || 0 == memcmp(name, ".debug_", 7)) {
          return sec_debug;

} else if (flags & SHF_ALLOC) {
          if (type == SHT_PROGBITS           || type == SHT_INIT_ARRAY           || type == SHT_FINI_ARRAY) {
              if (flags & SHF_EXECINSTR)                  return sec_text;
              if (flags & SHF_WRITE)                  return sec_data;
              if (0 == strcmp(name, ".rsrc"))                  return sec_rsrc;
              if (0 == strcmp(name, ".iedat"))                  return sec_idata;
              if (0 == strcmp(name, ".pdata"))                  return sec_pdata;
              return sec_rdata;

} else if (type == SHT_NOBITS) {
              return sec_bss;

}          return sec_other;

} else {
          if (0 == strcmp(name, ".reloc"))              return sec_reloc;

}      return sec_last;

}

static int pe_assign_addresses (struct pe_info *pe)  {
      int i, k, n, c, nbs;
      ADDR3264 addr;
      int *sec_order, *sec_cls;
      struct section_info *si;
      Section *s;
      TCCState *s1 = pe->s1;
        if (PE_DLL == pe->type)          pe->reloc = new_section(pe->s1, ".reloc", SHT_PROGBITS, 0);
      //pe->thunk = new_section(pe->s1, ".iedat", SHT_PROGBITS, SHF_ALLOC);
        nbs = s1->nb_sections;
      sec_order = tcc_mallocz(2 * sizeof (int) * nbs);
      sec_cls = sec_order + nbs;
      for (i = 1;
 i < nbs;
 ++i) {
          s = s1->sections[i];
          k = pe_section_class(s);
          for (n = i;
 n > 1 && k < (c = sec_cls[n - 1]);
 --n)              sec_cls[n] = c, sec_order[n] = sec_order[n - 1];
          sec_cls[n] = k, sec_order[n] = i;

}      si = NULL;
      addr = pe->imagebase + 1;
        for (i = 1;
 (c = sec_cls[i]) < sec_last;
 ++i) {
          s = s1->sections[sec_order[i]];
            if (PE_MERGE_DATA && c == sec_bss)              c = sec_data;
            if (si && c == si->cls && c != sec_debug) {
              /* merge with previous section */              s->sh_addr = addr = ((addr - 1) | (16 - 1)) + 1;

} else {
              si = NULL;
              s->sh_addr = addr = pe_virtual_align(pe, addr);

}            if (NULL == pe->thunk              && c == (data_section == rodata_section ? sec_data : sec_rdata))              pe->thunk = s;
            if (s == pe->thunk) {
              pe_build_imports(pe);
              pe_build_exports(pe);

}          if (s == pe->reloc)              pe_build_reloc (pe);
            if (0 == s->data_offset)              continue;
            if (si)              goto add_section;
            si = tcc_mallocz(sizeof *si);
          dynarray_add(&pe->sec_info, &pe->sec_count, si);
            strcpy(si->name, s->name);
          si->cls = c;
          si->sh_addr = addr;
            si->pe_flags = IMAGE_SCN_MEM_READ;
          if (s->sh_flags & SHF_EXECINSTR)              si->pe_flags |= IMAGE_SCN_MEM_EXECUTE | IMAGE_SCN_CNT_CODE;
          else if (s->sh_type == SHT_NOBITS)              si->pe_flags |= IMAGE_SCN_CNT_UNINITIALIZED_DATA;
          else              si->pe_flags |= IMAGE_SCN_CNT_INITIALIZED_DATA;
          if (s->sh_flags & SHF_WRITE)              si->pe_flags |= IMAGE_SCN_MEM_WRITE;
          if (0 == (s->sh_flags & SHF_ALLOC))              si->pe_flags |= IMAGE_SCN_MEM_DISCARDABLE;
    add_section:          addr += s->data_offset;
          si->sh_size = addr - si->sh_addr;
          if (s->sh_type != SHT_NOBITS) {
              Section **ps = &si->sec;
              while (*ps)                  ps = &(*ps)->prev;
              *ps = s, s->prev = NULL;
              si->data_size = si->sh_size;

}          //printf("%08x %05x %08x %s\n", si->sh_addr, si->sh_size, si->pe_flags, s->name);

}  #if 0      for (i = 1;
 i < nbs;
 ++i) {
          Section *s = s1->sections[sec_order[i]];
          int type = s->sh_type;
          int flags = s->sh_flags;
          printf("section %-16s %-10s %p %04x %s,%s,%s\n",              s->name,              type == SHT_PROGBITS ? "progbits" :              type == SHT_INIT_ARRAY ? "initarr" :              type == SHT_FINI_ARRAY ? "finiarr" :              type == SHT_NOBITS ? "nobits" :              type == SHT_SYMTAB ? "symtab" :              type == SHT_STRTAB ? "strtab" :              type == SHT_RELX ? "rel" : "???",              s->sh_addr,              (unsigned)s->data_offset,              flags & SHF_ALLOC ? "alloc" : "",              flags & SHF_WRITE ? "write" : "",              flags & SHF_EXECINSTR ? "exec" : ""              );
          fflush(stdout);

}      s1->verbose = 2;
  #endif      tcc_free(sec_order);
      return 0;

}

static int pe_isafunc(TCCState *s1, int sym_index)  {
      Section *sr = text_section->reloc;
      ElfW_Rel *rel, *rel_end;
      ElfW(Addr)info = ELFW(R_INFO)(sym_index, R_XXX_FUNCCALL);
  #ifdef R_XXX_FUNCCALL2      ElfW(Addr)info2 = ELFW(R_INFO)(sym_index, R_XXX_FUNCCALL2);
  #endif      if (!sr)          return 0;
      rel_end = (ElfW_Rel *)(sr->data + sr->data_offset);
      for (rel = (ElfW_Rel *)sr->data;
 rel < rel_end;
 rel++) {
          if (rel->r_info == info)              return 1;
  #ifdef R_XXX_FUNCCALL2          if (rel->r_info == info2)              return 1;
  #endif      
}      return 0;

}

static int pe_check_symbols(struct pe_info *pe)  {
      ElfW(Sym) *sym;
      int sym_index, sym_end;
      int ret = 0;
      TCCState *s1 = pe->s1;
        pe_align_section(text_section, 8);
        sym_end = symtab_section->data_offset / sizeof(ElfW(Sym));
      for (sym_index = 1;
 sym_index < sym_end;
 ++sym_index) {
            sym = (ElfW(Sym) *)symtab_section->data + sym_index;
          if (sym->st_shndx == SHN_UNDEF) {
                const char *name = (char*)symtab_section->link->data + sym->st_name;
              unsigned type = ELFW(ST_TYPE)(sym->st_info);
              int imp_sym = pe_find_import(pe->s1, sym);
              struct import_symbol *is;
                if (imp_sym <= 0)                  goto not_found;
                if (type == STT_NOTYPE) {
                  /* symbols from assembler have no type, find out which */                  if (pe_isafunc(s1, sym_index))                      type = STT_FUNC;
                  else                      type = STT_OBJECT;

}                is = pe_add_import(pe, imp_sym);
                if (type == STT_FUNC) {
                  unsigned offset = is->thk_offset;
                  if (offset) {
                      /* got aliased symbol, like stricmp and _stricmp */                  
} else {
                      char buffer[100];
                      unsigned char *p;
                        /* add a helper symbol, will be patched later in                         pe_build_imports */                      sprintf(buffer, "IAT.%s", name);
                      is->iat_index = put_elf_sym(                          symtab_section, 0, sizeof(DWORD),                          ELFW(ST_INFO)(STB_LOCAL, STT_OBJECT),                          0, SHN_UNDEF, buffer);
                        offset = text_section->data_offset;
                      is->thk_offset = offset;
                        /* add the 'jmp IAT[x]' instruction */  #ifdef TCC_TARGET_ARM                      p = section_ptr_add(text_section, 8+4);
 // room for code and address                      write32le(p + 0, 0xE59FC000);
 // arm code ldr ip, [pc];
 PC+8+0 = 0001xxxx                      write32le(p + 4, 0xE59CF000);
 // arm code ldr pc, [ip]                      put_elf_reloc(symtab_section, text_section,                          offset + 8, R_XXX_THUNKFIX, is->iat_index);
 // offset to IAT position  #else                      p = section_ptr_add(text_section, 8);
                      write16le(p, 0x25FF);
  #ifdef TCC_TARGET_X86_64                      write32le(p + 2, (DWORD)-4);
  #endif                      put_elf_reloc(symtab_section, text_section,                           offset + 2, R_XXX_THUNKFIX, is->iat_index);
  #endif                  
}                  /* tcc_realloc might have altered sym's address */                  sym = (ElfW(Sym) *)symtab_section->data + sym_index;
                    /* patch the original symbol */                  sym->st_value = offset;
                  sym->st_shndx = text_section->sh_num;
                  sym->st_other &= ~ST_PE_EXPORT;
 /* do not export */                  continue;

}                if (type == STT_OBJECT) {
 /* data, ptr to that should be */                  if (0 == is->iat_index) {
                      /* original symbol will be patched later in pe_build_imports */                      is->iat_index = sym_index;
                      continue;

}              
}            not_found:              if (ELFW(ST_BIND)(sym->st_info) == STB_WEAK)                  /* STB_WEAK undefined symbols are accepted */                  continue;
              ret = tcc_error_noabort("undefined symbol '%s'%s", name,                  imp_sym < 0 ? ", missing __declspec(dllimport)?":"");

} else if (pe->s1->rdynamic                     && ELFW(ST_BIND)(sym->st_info) != STB_LOCAL) {
              /* if -rdynamic option, then export all non local symbols */              sym->st_other |= ST_PE_EXPORT;

}      
}      return ret;

}

ST_FUNC int pe_putimport(TCCState *s1, int dllindex, const char *name, addr_t value)  {
      return set_elf_sym(          s1->dynsymtab_section,          value,          dllindex, /* st_size */          ELFW(ST_INFO)(STB_GLOBAL, STT_NOTYPE),          0,          value ? SHN_ABS : SHN_UNDEF,          name          );

}

static int read_mem(int fd, unsigned offset, void *buffer, unsigned len)  {
      lseek(fd, offset, SEEK_SET);
      return len == read(fd, buffer, len);

}

static int get_dllexports(int fd, char **pp)  {
      int i, k, l, n, n0, ret;
      char *p;
        IMAGE_SECTION_HEADER ish;
      IMAGE_EXPORT_DIRECTORY ied;
      IMAGE_DOS_HEADER dh;
      IMAGE_FILE_HEADER ih;
      DWORD sig, ref, addr;
      DWORD *namep = NULL, p0 = 0, p1;
        int pef_hdroffset, opt_hdroffset, sec_hdroffset;
        n = n0 = 0;
      p = NULL;
      ret = 1;
      if (!read_mem(fd, 0, &dh, sizeof dh))          goto the_end;
      if (!read_mem(fd, dh.e_lfanew, &sig, sizeof sig))          goto the_end;
      if (sig != 0x00004550)          goto the_end;
      pef_hdroffset = dh.e_lfanew + sizeof sig;
      if (!read_mem(fd, pef_hdroffset, &ih, sizeof ih))          goto the_end;
      opt_hdroffset = pef_hdroffset + sizeof ih;
      if (ih.Machine == 0x014C) {
          IMAGE_OPTIONAL_HEADER32 oh;
          sec_hdroffset = opt_hdroffset + sizeof oh;
          if (!read_mem(fd, opt_hdroffset, &oh, sizeof oh))              goto the_end;
          if (IMAGE_DIRECTORY_ENTRY_EXPORT >= oh.NumberOfRvaAndSizes)              goto the_end_0;
          addr = oh.DataDirectory[IMAGE_DIRECTORY_ENTRY_EXPORT].VirtualAddress;

} else if (ih.Machine == 0x8664) {
          IMAGE_OPTIONAL_HEADER64 oh;
          sec_hdroffset = opt_hdroffset + sizeof oh;
          if (!read_mem(fd, opt_hdroffset, &oh, sizeof oh))              goto the_end;
          if (IMAGE_DIRECTORY_ENTRY_EXPORT >= oh.NumberOfRvaAndSizes)              goto the_end_0;
          addr = oh.DataDirectory[IMAGE_DIRECTORY_ENTRY_EXPORT].VirtualAddress;

} else          goto the_end;
        //printf("addr: %08x\n", addr);
      for (i = 0;
 i < ih.NumberOfSections;
 ++i) {
          if (!read_mem(fd, sec_hdroffset + i * sizeof ish, &ish, sizeof ish))              goto the_end;
          //printf("vaddr: %08x\n", ish.VirtualAddress);
          if (addr >= ish.VirtualAddress && addr < ish.VirtualAddress + ish.SizeOfRawData)              goto found;

}      goto the_end_0;
  found:      ref = ish.VirtualAddress - ish.PointerToRawData;
      if (!read_mem(fd, addr - ref, &ied, sizeof ied))          goto the_end;
      k = ied.NumberOfNames;
      if (k) {
          namep = tcc_malloc(l = k * sizeof *namep);
          if (!read_mem(fd, ied.AddressOfNames - ref, namep, l))              goto the_end;
          for (i = l = 0;
 i < k;
 ++i) {
              p1 = namep[i] - ref;
              if (p1 != p0)                  lseek(fd, p0 = p1, SEEK_SET), l = 0;
              do {
                  if (0 == l) {
                      if (n + 1000 >= n0)                          p = tcc_realloc(p, n0 += 1000);
                      if ((l = read(fd, p + n, 1000 - 1)) <= 0)                          goto the_end;

}                  --l, ++p0;

} while (p[n++]);

}          p[n] = 0;

}  the_end_0:      ret = 0;
  the_end:      tcc_free(namep);
      if (ret && p)          tcc_free(p), p = NULL;
      *pp = p;
      return ret;

}

static int pe_load_res(TCCState *s1, int fd)  {
      struct pe_rsrc_header hdr;
      Section *rsrc_section;
      int i, ret = -1, sym_index;
      BYTE *ptr;
      unsigned offs;
        if (!read_mem(fd, 0, &hdr, sizeof hdr))          goto quit;
        if (hdr.filehdr.Machine != IMAGE_FILE_MACHINE          || hdr.filehdr.NumberOfSections != 1          || strcmp((char*)hdr.sectionhdr.Name, ".rsrc") != 0)          goto quit;
        rsrc_section = new_section(s1, ".rsrc", SHT_PROGBITS, SHF_ALLOC);
      ptr = section_ptr_add(rsrc_section, hdr.sectionhdr.SizeOfRawData);
      offs = hdr.sectionhdr.PointerToRawData;
      if (!read_mem(fd, offs, ptr, hdr.sectionhdr.SizeOfRawData))          goto quit;
      offs = hdr.sectionhdr.PointerToRelocations;
      sym_index = put_elf_sym(symtab_section, 0, 0, 0, 0, rsrc_section->sh_num, ".rsrc");
      for (i = 0;
 i < hdr.sectionhdr.NumberOfRelocations;
 ++i) {
          struct pe_rsrc_reloc rel;
          if (!read_mem(fd, offs, &rel, sizeof rel))              goto quit;
          // printf("rsrc_reloc: %x %x %x\n", rel.offset, rel.size, rel.type);
          if (rel.type != RSRC_RELTYPE)              goto quit;
          put_elf_reloc(symtab_section, rsrc_section,              rel.offset, R_XXX_RELATIVE, sym_index);
          offs += sizeof rel;

}      ret = 0;
  quit:      return ret;

}

static char *trimfront(char *p)  {
      while ((unsigned char)*p <= ' ' && *p && *p != '\n')   ++p;
      return p;

}

static char *get_token(char **s, char *f)  {
      char *p = *s, *e;
      p = e = trimfront(p);
      while ((unsigned char)*e > ' ')          ++e;
      *s = trimfront(e);
      *f = **s;
 *e = 0;
      return p;

}

static int pe_load_def(TCCState *s1, int fd)  {
      int state = 0, ret = -1, dllindex = 0, ord;
      char dllname[80], *buf, *line, *p, *x, next;
        buf = tcc_load_text(fd);
      if (!buf)          return ret;
        for (line = buf;
;
 ++line)  {
          p = get_token(&line, &next);
          if (!(*p && *p != ';
'))              goto skip;
          switch (state) {
          case 0:              if (0 != stricmp(p, "LIBRARY") || next == '\n')                  goto quit;
              pstrcpy(dllname, sizeof dllname, get_token(&line, &next));
              ++state;
              break;
          case 1:              if (0 != stricmp(p, "EXPORTS"))                  goto quit;
              ++state;
              break;
          case 2:              dllindex = tcc_add_dllref(s1, dllname, 0)->index;
              ++state;
              /* fall through */          default:              /* get ordinal and will store in sym->st_value */              ord = 0;
              if (next == '@') {
                  x = get_token(&line, &next);
                  ord = (int)strtol(x + 1, &x, 10);

}              //printf("token %s;
 %s : %d\n", dllname, p, ord);
              pe_putimport(s1, dllindex, p, ord);
              break;

}  skip:          while ((unsigned char)next > ' ')              get_token(&line, &next);
          if (next != '\n')              break;

}      ret = 0;
  quit:      tcc_free(buf);
      return ret;

}

static int pe_load_dll(TCCState *s1, int fd, const char *filename)  {
      char *p, *q;
      DLLReference *ref = tcc_add_dllref(s1, tcc_basename(filename), 0);
      if (ref->found)          return 0;
      if (get_dllexports(fd, &p))          return -1;
      if (p) {
          for (q = p;
 *q;
 q += 1 + strlen(q))              pe_putimport(s1, ref->index, q, 0);
          tcc_free(p);

}      return 0;

}

ST_FUNC int pe_load_file(struct TCCState *s1, int fd, const char *filename)  {
      int ret = -1;
      char buf[10];
      if (0 == strcmp(tcc_fileextension(filename), ".def"))          ret = pe_load_def(s1, fd);
      else if (pe_load_res(s1, fd) == 0)          ret = 0;
      else if (read_mem(fd, 0, buf, 4) && 0 == memcmp(buf, "MZ", 2))          ret = pe_load_dll(s1, fd, filename);
      return ret;

}

PUB_FUNC int tcc_get_dllexports(const char *filename, char **pp)  {
      int ret, fd = open(filename, O_RDONLY | O_BINARY);
      if (fd < 0)          return -1;
      ret = get_dllexports(fd, pp);
      close(fd);
      return ret;

}

static void pe_add_runtime(TCCState *s1, struct pe_info *pe)  {
      const char *start_symbol;
      int pe_type;
        if (TCC_OUTPUT_DLL == s1->output_type) {
          pe_type = PE_DLL;
          start_symbol = PE_STDSYM("__dllstart","@12");

} else {
          const char *run_symbol;
          if (find_elf_sym(symtab_section, PE_STDSYM("WinMain","@16"))) {
              start_symbol = "__winstart";
              run_symbol = "__runwinmain";
              pe_type = PE_GUI;

} else if (find_elf_sym(symtab_section, PE_STDSYM("wWinMain","@16"))) {
              start_symbol = "__wwinstart";
              run_symbol = "__runwwinmain";
              pe_type = PE_GUI;

} else if (find_elf_sym(symtab_section, "wmain")) {
              start_symbol = "__wstart";
              run_symbol = "__runwmain";
              pe_type = PE_EXE;

} else {
              start_symbol =  "__start";
              run_symbol = "__runmain";
              pe_type = PE_EXE;
              if (s1->pe_subsystem == 2)                  pe_type = PE_GUI;

}            if (TCC_OUTPUT_MEMORY == s1->output_type && !s1->nostdlib)              start_symbol = run_symbol;

}      if (s1->elf_entryname) {
          pe->start_symbol = start_symbol = s1->elf_entryname;

} else {
          pe->start_symbol = start_symbol + 1;
          if (!s1->leading_underscore || strchr(start_symbol, '@'))              ++start_symbol;

}    #ifdef CONFIG_TCC_BACKTRACE      if (s1->do_backtrace) {
  #ifdef CONFIG_TCC_BCHECK          if (s1->do_bounds_check && s1->output_type != TCC_OUTPUT_DLL)              tcc_add_support(s1, "bcheck.o");
  #endif          if (s1->output_type == TCC_OUTPUT_EXE)              tcc_add_support(s1, "bt-exe.o");
          if (s1->output_type == TCC_OUTPUT_DLL)              tcc_add_support(s1, "bt-dll.o");
          if (s1->output_type != TCC_OUTPUT_DLL)              tcc_add_support(s1, "bt-log.o");
          tcc_add_btstub(s1);

}  #endif        /* grab the startup code from libtcc1.a */  #ifdef TCC_IS_NATIVE      if (TCC_OUTPUT_MEMORY != s1->output_type || s1->run_main)  #endif      set_global_sym(s1, start_symbol, NULL, 0);
        if (0 == s1->nostdlib) {
          static const char * const libs[] = {
              "msvcrt", "kernel32", "", "user32", "gdi32", NULL          
};
          const char * const *pp, *p;
          if (TCC_LIBTCC1[0])              tcc_add_support(s1, TCC_LIBTCC1);
          for (pp = libs;
 0 != (p = *pp);
 ++pp) {
              if (*p)                  tcc_add_library(s1, p);
              else if (PE_DLL != pe_type && PE_GUI != pe_type)                  break;

}      
}        /* need this for 'tccelf.c:relocate_sections()' */      if (TCC_OUTPUT_DLL == s1->output_type)          s1->output_type = TCC_OUTPUT_EXE;
      if (TCC_OUTPUT_MEMORY == s1->output_type)          pe_type = PE_RUN;
      pe->type = pe_type;

}

static void pe_set_options(TCCState * s1, struct pe_info *pe)  {
      if (PE_DLL == pe->type) {
          /* XXX: check if is correct for arm-pe target */          pe->imagebase = 0x10000000;

} else {
  #if defined(TCC_TARGET_ARM)          pe->imagebase = 0x00010000;
  #else          pe->imagebase = 0x00400000;
  #endif      
}    #if defined(TCC_TARGET_ARM)      /* we use "console" subsystem by default */      pe->subsystem = 9;
  #else      if (PE_DLL == pe->type || PE_GUI == pe->type)          pe->subsystem = 2;
      else          pe->subsystem = 3;
  #endif      /* Allow override via -Wl,-subsystem=... option */      if (s1->pe_subsystem != 0)          pe->subsystem = s1->pe_subsystem;
        /* set default file/section alignment */      if (pe->subsystem == 1) {
          pe->section_align = 0x20;
          pe->file_align = 0x20;

} else {
          pe->section_align = 0x1000;
          pe->file_align = 0x200;

}        if (s1->section_align != 0)          pe->section_align = s1->section_align;
      if (s1->pe_file_align != 0)          pe->file_align = s1->pe_file_align;
        if ((pe->subsystem >= 10) && (pe->subsystem <= 12))          pe->imagebase = 0;
        if (s1->has_text_addr)          pe->imagebase = s1->text_addr;

}

ST_FUNC int pe_output_file(TCCState *s1, const char *filename)  {
      struct pe_info pe;
        memset(&pe, 0, sizeof pe);
      pe.filename = filename;
      pe.s1 = s1;
      s1->filetype = 0;
    #ifdef CONFIG_TCC_BCHECK      tcc_add_bcheck(s1);
  #endif      tcc_add_pragma_libs(s1);
      pe_add_runtime(s1, &pe);
      resolve_common_syms(s1);
      pe_set_options(s1, &pe);
      pe_check_symbols(&pe);
        if (s1->nb_errors)         ;
      else if (filename) {
          pe_assign_addresses(&pe);
          relocate_syms(s1, s1->symtab, 0);
          s1->pe_imagebase = pe.imagebase;
          relocate_sections(s1);
          pe.start_addr = (DWORD)              (get_sym_addr(s1, pe.start_symbol, 1, 1) - pe.imagebase);
          if (0 == s1->nb_errors)              pe_write(&pe);
          dynarray_reset(&pe.sec_info, &pe.sec_count);

} else {
  #ifdef TCC_IS_NATIVE          pe.thunk = data_section;
          pe_build_imports(&pe);
          s1->run_main = pe.start_symbol;
  #ifdef TCC_TARGET_X86_64          s1->uw_pdata = find_section(s1, ".pdata");
  #endif  #endif      
}      pe_free_imports(&pe);
  #if PE_PRINT_SECTIONS      if (s1->g_debug & 8)          pe_print_sections(s1, "tcc.log");
  #endif      return s1->nb_errors ? -1 : 0;

}

ST_FUNC void skip(int c)  {
      if (tok != c) {
          char tmp[40];
          pstrcpy(tmp, sizeof tmp, get_tok_str(c, &tokc));
          tcc_error("'%s' expected (got \"%s\")", tmp, get_tok_str(tok, &tokc));

}      next();

}

ST_FUNC void expect(const char *msg)  {
      tcc_error("%s expected", msg);

}

static void cstr_realloc(CString *cstr, int new_size)  {
      int size;
        size = cstr->size_allocated;
      if (size < 8)          size = 8;
 /* no need to allocate a too small first string */      while (size < new_size)          size = size * 2;
      cstr->data = tcc_realloc(cstr->data, size);
      cstr->size_allocated = size;

}

ST_INLN void cstr_ccat(CString *cstr, int ch)  {
      int size;
      size = cstr->size + 1;
      if (size > cstr->size_allocated)          cstr_realloc(cstr, size);
      cstr->data[size - 1] = ch;
      cstr->size = size;

}

ST_INLN char *unicode_to_utf8 (char *b, uint32_t Uc)  {
      if (Uc<0x80) *b++=Uc;
      else if (Uc<0x800) *b++=192+Uc/64, *b++=128+Uc%64;
      else if (Uc-0xd800u<0x800) goto error;
      else if (Uc<0x10000) *b++=224+Uc/4096, *b++=128+Uc/64%64, *b++=128+Uc%64;
      else if (Uc<0x110000) *b++=240+Uc/262144, *b++=128+Uc/4096%64, *b++=128+Uc/64%64, *b++=128+Uc%64;
      else error: tcc_error("0x%x is not a valid universal character", Uc);
      return b;

}

ST_INLN void cstr_u8cat(CString *cstr, int ch)  {
      char buf[4], *e;
      e = unicode_to_utf8(buf, (uint32_t)ch);
      cstr_cat(cstr, buf, e - buf);

}

ST_FUNC void cstr_cat(CString *cstr, const char *str, int len)  {
      int size;
      if (len <= 0)          len = strlen(str) + 1 + len;
      size = cstr->size + len;
      if (size > cstr->size_allocated)          cstr_realloc(cstr, size);
      memmove(cstr->data + cstr->size, str, len);
      cstr->size = size;

}

ST_FUNC void cstr_wccat(CString *cstr, int ch)  {
      int size;
      size = cstr->size + sizeof(nwchar_t);
      if (size > cstr->size_allocated)          cstr_realloc(cstr, size);
      *(nwchar_t *)(cstr->data + size - sizeof(nwchar_t)) = ch;
      cstr->size = size;

}

ST_FUNC void cstr_new(CString *cstr)  {
      memset(cstr, 0, sizeof(CString));

}

ST_FUNC void cstr_free(CString *cstr)  {
      tcc_free(cstr->data);

}

ST_FUNC void cstr_reset(CString *cstr)  {
      cstr->size = 0;

}

ST_FUNC int cstr_vprintf(CString *cstr, const char *fmt, va_list ap)  {
      va_list v;
      int len, size = 80;
      for (;
;
) {
          size += cstr->size;
          if (size > cstr->size_allocated)              cstr_realloc(cstr, size);
          size = cstr->size_allocated - cstr->size;
          va_copy(v, ap);
          len = vsnprintf(cstr->data + cstr->size, size, fmt, v);
          va_end(v);
          if (len >= 0 && len < size)              break;
          size *= 2;

}      cstr->size += len;
      return len;

}

ST_FUNC int cstr_printf(CString *cstr, const char *fmt, ...)  {
      va_list ap;
 int len;
      va_start(ap, fmt);
      len = cstr_vprintf(cstr, fmt, ap);
      va_end(ap);
      return len;

}

static void add_char(CString *cstr, int c)  {
      if (c == '\'' || c == '\"' || c == '\\') {
          /* XXX: could be more precise if char or string */          cstr_ccat(cstr, '\\');

}      if (c >= 32 && c <= 126) {
          cstr_ccat(cstr, c);

} else {
          cstr_ccat(cstr, '\\');
          if (c == '\n') {
              cstr_ccat(cstr, 'n');

} else {
              cstr_ccat(cstr, '0' + ((c >> 6) & 7));
              cstr_ccat(cstr, '0' + ((c >> 3) & 7));
              cstr_ccat(cstr, '0' + (c & 7));

}      
}  
}

static TokenSym *tok_alloc_new(TokenSym **pts, const char *str, int len)  {
      TokenSym *ts, **ptable;
      int i;
        if (tok_ident >= SYM_FIRST_ANOM)           tcc_error("memory full (symbols)");
        /* expand token table if needed */      i = tok_ident - TOK_IDENT;
      if ((i % TOK_ALLOC_INCR) == 0) {
          ptable = tcc_realloc(table_ident, (i + TOK_ALLOC_INCR) * sizeof(TokenSym *));
          table_ident = ptable;

}        ts = tal_realloc(toksym_alloc, 0, sizeof(TokenSym) + len);
      table_ident[i] = ts;
      ts->tok = tok_ident++;
      ts->sym_define = NULL;
      ts->sym_label = NULL;
      ts->sym_struct = NULL;
      ts->sym_identifier = NULL;
      ts->len = len;
      ts->hash_next = NULL;
      memcpy(ts->str, str, len);
      ts->str[len] = '\0';
      *pts = ts;
      return ts;

}

ST_FUNC TokenSym *tok_alloc(const char *str, int len)  {
      TokenSym *ts, **pts;
      int i;
      unsigned int h;
            h = TOK_HASH_INIT;
      for(i=0;
i<len;
i++)          h = TOK_HASH_FUNC(h, ((unsigned char *)str)[i]);
      h &= (TOK_HASH_SIZE - 1);
        pts = &hash_ident[h];
      for(;
;
) {
          ts = *pts;
          if (!ts)              break;
          if (ts->len == len && !memcmp(ts->str, str, len))              return ts;
          pts = &(ts->hash_next);

}      return tok_alloc_new(pts, str, len);

}

ST_FUNC int tok_alloc_const(const char *str)  {
      return tok_alloc(str, strlen(str))->tok;

}

ST_FUNC const char *get_tok_str(int v, CValue *cv)  {
      char *p;
      int i, len;
        cstr_reset(&cstr_buf);
      p = cstr_buf.data;
        switch(v) {
      case TOK_CINT:      case TOK_CUINT:      case TOK_CLONG:      case TOK_CULONG:      case TOK_CLLONG:      case TOK_CULLONG:          /* XXX: not quite exact, but only useful for testing  */  #ifdef _WIN32          sprintf(p, "%u", (unsigned)cv->i);
  #else          sprintf(p, "%llu", (unsigned long long)cv->i);
  #endif          break;
      case TOK_LCHAR:          cstr_ccat(&cstr_buf, 'L');
      case TOK_CCHAR:          cstr_ccat(&cstr_buf, '\'');
          add_char(&cstr_buf, cv->i);
          cstr_ccat(&cstr_buf, '\'');
          cstr_ccat(&cstr_buf, '\0');
          break;
      case TOK_PPNUM:      case TOK_PPSTR:          return (char*)cv->str.data;
      case TOK_LSTR:          cstr_ccat(&cstr_buf, 'L');
      case TOK_STR:          cstr_ccat(&cstr_buf, '\"');
          if (v == TOK_STR) {
              len = cv->str.size - 1;
              for(i=0;
i<len;
i++)                  add_char(&cstr_buf, ((unsigned char *)cv->str.data)[i]);

} else {
              len = (cv->str.size / sizeof(nwchar_t)) - 1;
              for(i=0;
i<len;
i++)                  add_char(&cstr_buf, ((nwchar_t *)cv->str.data)[i]);

}          cstr_ccat(&cstr_buf, '\"');
          cstr_ccat(&cstr_buf, '\0');
          break;
        case TOK_CFLOAT:          return strcpy(p, "<float>");
      case TOK_CDOUBLE:          return strcpy(p, "<double>");
      case TOK_CLDOUBLE:          return strcpy(p, "<long double>");
      case TOK_LINENUM:          return strcpy(p, "<linenumber>");
        /* above tokens have value, the ones below don't */      case TOK_LT:          v = '<';
          goto addv;
      case TOK_GT:          v = '>';
          goto addv;
      case TOK_DOTS:          return strcpy(p, "...");
      case TOK_A_SHL:          return strcpy(p, "<<=");
      case TOK_A_SAR:          return strcpy(p, ">>=");
      case TOK_EOF:          return strcpy(p, "<eof>");
      case 0: /* anonymous nameless symbols */          return strcpy(p, "<no name>");
      default:          v &= ~(SYM_FIELD | SYM_STRUCT);
          if (v < TOK_IDENT) {
              /* search in two bytes table */              const unsigned char *q = tok_two_chars;
              while (*q) {
                  if (q[2] == v) {
                      *p++ = q[0];
                      *p++ = q[1];
                      *p = '\0';
                      return cstr_buf.data;

}                  q += 3;

}              if (v >= 127 || (v < 32 && !is_space(v) && v != '\n')) {
                  sprintf(p, "<\\x%02x>", v);
                  break;

}      addv:              *p++ = v;
              *p = '\0';

} else if (v < tok_ident) {
              return table_ident[v - TOK_IDENT]->str;

} else if (v >= SYM_FIRST_ANOM) {
              /* special name for anonymous symbol */              sprintf(p, "L.%u", v - SYM_FIRST_ANOM);

} else {
              /* should never happen */              return NULL;

}          break;

}      return cstr_buf.data;

}

static int handle_eob(void)  {
      BufferedFile *bf = file;
      int len;
        /* only tries to read if really end of buffer */      if (bf->buf_ptr >= bf->buf_end) {
          if (bf->fd >= 0) {
  #if defined(PARSE_DEBUG)              len = 1;
  #else              len = IO_BUF_SIZE;
  #endif              len = read(bf->fd, bf->buffer, len);
              if (len < 0)                  len = 0;

} else {
              len = 0;

