          break;

}      case TOK_PRAGMA:          if (!pragma_parse(s1))              goto ignore;
          break;
      case TOK_LINEFEED:          goto the_end;
      default:          /* ignore gas line comment in an 'S' file. */          if (saved_parse_flags & PARSE_FLAG_ASM_FILE)              goto ignore;
          if (tok == '!' && is_bof)              /* '#!' is ignored at beginning to allow C scripts. */              goto ignore;
