}      skip_to_eol(1);
   the_end:      parse_flags = saved_parse_flags;

}

static void parse_escape_string(CString *outstr, const uint8_t *buf, int is_long)  {
      int c, n, i;
      const uint8_t *p;
        p = buf;
      for(;
;
) {
          c = *p;
          if (c == '\0')              break;
          if (c == '\\') {
              p++;
              /* escape */              c = *p;
              switch(c) {
              case '0': case '1': case '2': case '3':              case '4': case '5': case '6': case '7':                  /* at most three octal digits */                  n = c - '0';
                  p++;
                  c = *p;
                  if (isoct(c)) {
                      n = n * 8 + c - '0';
                      p++;
                      c = *p;
                      if (isoct(c)) {
                          n = n * 8 + c - '0';
                          p++;

}                  
}                  c = n;
                  goto add_char_nonext;
              case 'x': i = 0;
 goto parse_hex_or_ucn;
              case 'u': i = 4;
 goto parse_hex_or_ucn;
              case 'U': i = 8;
 goto parse_hex_or_ucn;
      parse_hex_or_ucn:                  p++;
                  n = 0;
                  do {
                      c = *p;
                      if (c >= 'a' && c <= 'f')                          c = c - 'a' + 10;
                      else if (c >= 'A' && c <= 'F')                          c = c - 'A' + 10;
                      else if (isnum(c))                          c = c - '0';
                      else if (i >= 0)                          expect("more hex digits in universal-character-name");
                      else                          goto add_hex_or_ucn;
                      n = n * 16 + c;
                      p++;

} while (--i);
    if (is_long) {
      add_hex_or_ucn:                      c = n;
        goto add_char_nonext;

}                  cstr_u8cat(outstr, n);
                  continue;
              case 'a':                  c = '\a';
                  break;
              case 'b':                  c = '\b';
                  break;
              case 'f':                  c = '\f';
                  break;
              case 'n':                  c = '\n';
                  break;
              case 'r':                  c = '\r';
                  break;
              case 't':                  c = '\t';
                  break;
              case 'v':                  c = '\v';
                  break;
              case 'e':                  if (!gnu_ext)                      goto invalid_escape;
                  c = 27;
                  break;
              case '\'':              case '\"':              case '\\':               case '?':                  break;
              default:              invalid_escape:                  if (c >= '!' && c <= '~')                      tcc_warning("unknown escape sequence: \'\\%c\'", c);
                  else                      tcc_warning("unknown escape sequence: \'\\x%x\'", c);
                  break;

}          
} else if (is_long && c >= 0x80) {
              /* assume we are processing UTF-8 sequence */              /* reference: The Unicode Standard, Version 10.0, ch3.9 */                int cont;
 /* count of continuation bytes */              int skip;
 /* how many bytes should skip when error occurred */              int i;
                /* decode leading byte */              if (c < 0xC2) {
               skip = 1;
 goto invalid_utf8_sequence;

} else if (c <= 0xDF) {
               cont = 1;
 n = c & 0x1f;

} else if (c <= 0xEF) {
               cont = 2;
 n = c & 0xf;

} else if (c <= 0xF4) {
               cont = 3;
 n = c & 0x7;

} else {
               skip = 1;
 goto invalid_utf8_sequence;

}                /* decode continuation bytes */              for (i = 1;
 i <= cont;
 i++) {
                  int l = 0x80, h = 0xBF;
                    /* adjust limit for second byte */                  if (i == 1) {
                      switch (c) {
                      case 0xE0: l = 0xA0;
 break;
                      case 0xED: h = 0x9F;
 break;
                      case 0xF0: l = 0x90;
 break;
                      case 0xF4: h = 0x8F;
 break;

}                  
}                    if (p[i] < l || p[i] > h) {
                      skip = i;
 goto invalid_utf8_sequence;

}                    n = (n << 6) | (p[i] & 0x3f);

}                /* advance pointer */              p += 1 + cont;
              c = n;
              goto add_char_nonext;
                /* error handling */          invalid_utf8_sequence:              tcc_warning("ill-formed UTF-8 subsequence starting with: \'\\x%x\'", c);
              c = 0xFFFD;
              p += skip;
              goto add_char_nonext;

}          p++;
      add_char_nonext:          if (!is_long)              cstr_ccat(outstr, c);
          else {
  #ifdef TCC_TARGET_PE              /* store as UTF-16 */              if (c < 0x10000) {
                  cstr_wccat(outstr, c);

} else {
                  c -= 0x10000;
                  cstr_wccat(outstr, (c >> 10) + 0xD800);
                  cstr_wccat(outstr, (c & 0x3FF) + 0xDC00);

}  #else              cstr_wccat(outstr, c);
  #endif          
}      
}      /* add a trailing '\0' */      if (!is_long)          cstr_ccat(outstr, '\0');
      else          cstr_wccat(outstr, '\0');

}

static void parse_string(const char *s, int len)  {
      uint8_t buf[1000], *p = buf;
      int is_long, sep;
        if ((is_long = *s == 'L'))          ++s, --len;
      sep = *s++;
      len -= 2;
      if (len >= sizeof buf)          p = tcc_malloc(len + 1);
      memcpy(p, s, len);
      p[len] = 0;
        cstr_reset(&tokcstr);
      parse_escape_string(&tokcstr, p, is_long);
      if (p != buf)          tcc_free(p);
        if (sep == '\'') {
          int char_size, i, n, c;
          /* XXX: make it portable */          if (!is_long)              tok = TOK_CCHAR, char_size = 1;
          else              tok = TOK_LCHAR, char_size = sizeof(nwchar_t);
          n = tokcstr.size / char_size - 1;
          if (n < 1)              tcc_error("empty character constant");
          if (n > 1)              tcc_warning_c(warn_all)("multi-character character constant");
          for (c = i = 0;
 i < n;
 ++i) {
              if (is_long)                  c = ((nwchar_t *)tokcstr.data)[i];
              else                  c = (c << 8) | ((char *)tokcstr.data)[i];

}          tokc.i = c;

} else {
          tokc.str.size = tokcstr.size;
          tokc.str.data = tokcstr.data;
          if (!is_long)              tok = TOK_STR;
          else              tok = TOK_LSTR;

}  
}

static void bn_lshift(unsigned int *bn, int shift, int or_val)  {
      int i;
      unsigned int v;
      for(i=0;
i<BN_SIZE;
i++) {
          v = bn[i];
          bn[i] = (v << shift) | or_val;
          or_val = v >> (32 - shift);

}  
}

static void bn_zero(unsigned int *bn)  {
      int i;
      for(i=0;
i<BN_SIZE;
i++) {
          bn[i] = 0;

}  
}

static void parse_number(const char *p)  {
