}          tok_alloc(p, r - p - 1);
          p = r;

}        /* we add dummy defines for some special macros to speed up tests         and to have working defined() */      define_push(TOK___LINE__, MACRO_OBJ, NULL, NULL);
      define_push(TOK___FILE__, MACRO_OBJ, NULL, NULL);
      define_push(TOK___DATE__, MACRO_OBJ, NULL, NULL);
      define_push(TOK___TIME__, MACRO_OBJ, NULL, NULL);
      define_push(TOK___COUNTER__, MACRO_OBJ, NULL, NULL);

}

ST_FUNC void tccpp_delete(TCCState *s)  {
      int i, n;
        dynarray_reset(&s->cached_includes, &s->nb_cached_includes);
        /* free tokens */      n = tok_ident - TOK_IDENT;
      if (n > total_idents)          total_idents = n;
      for(i = 0;
 i < n;
 i++)          tal_free(toksym_alloc, table_ident[i]);
      tcc_free(table_ident);
      table_ident = NULL;
        /* free static buffers */      cstr_free(&tokcstr);
      cstr_free(&cstr_buf);
      tok_str_free_str(tokstr_buf.str);
      tok_str_free_str(unget_buf.str);
        /* free allocators */      tal_delete(toksym_alloc);
      toksym_alloc = NULL;
      tal_delete(tokstr_alloc);
      tokstr_alloc = NULL;

}

static void tok_print(const int *str, const char *msg, ...)  {
      FILE *fp = tcc_state->ppfp;
      va_list ap;
      int t, t0, s;
      CValue cval;
        va_start(ap, msg);
      vfprintf(fp, msg, ap);
      va_end(ap);
        s = t0 = 0;
      while (str) {
   TOK_GET(&t, &str, &cval);
   if (t == 0 || t == TOK_EOF)       break;
          if (pp_need_space(t0, t))              s = 0;
   fprintf(fp, &" %s"[s], t == TOK_PLCHLDR ? "<>" : get_tok_str(t, &cval));
          s = 1, t0 = t;

}      fprintf(fp, "\n");

}

static void pp_line(TCCState *s1, BufferedFile *f, int level)  {
      int d = f->line_num - f->line_ref;
        if (s1->dflag & 4)   return;
        if (s1->Pflag == LINE_MACRO_OUTPUT_FORMAT_NONE) {
         ;

} else if (level == 0 && f->line_ref && d < 8) {
   while (d > 0)       fputs("\n", s1->ppfp), --d;

} else if (s1->Pflag == LINE_MACRO_OUTPUT_FORMAT_STD) {
   fprintf(s1->ppfp, "#line %d \"%s\"\n", f->line_num, f->filename);

} else {
   fprintf(s1->ppfp, "# %d \"%s\"%s\n", f->line_num, f->filename,       level > 0 ? " 1" : level < 0 ? " 2" : "");

}      f->line_ref = f->line_num;

}

static void define_print(TCCState *s1, int v)  {
      FILE *fp;
      Sym *s;
        s = define_find(v);
      if (NULL == s || NULL == s->d)          return;
        fp = s1->ppfp;
      fprintf(fp, "#define %s", get_tok_str(v, NULL));
      if (s->type.t & MACRO_FUNC) {
          Sym *a = s->next;
          fprintf(fp,"(");
          if (a)              for (;
;
) {
                  fprintf(fp,"%s", get_tok_str(a->v, NULL));
                  if (!(a = a->next))                      break;
                  fprintf(fp,",");

}          fprintf(fp,")");

}      tok_print(s->d, "");

}

static void pp_debug_defines(TCCState *s1)  {
      int v, t;
      const char *vs;
      FILE *fp;
        t = pp_debug_tok;
      if (t == 0)          return;
        file->line_num--;
      pp_line(s1, file, 0);
      file->line_ref = ++file->line_num;
        fp = s1->ppfp;
      v = pp_debug_symv;
      vs = get_tok_str(v, NULL);
      if (t == TOK_DEFINE) {
          define_print(s1, v);

} else if (t == TOK_UNDEF) {
          fprintf(fp, "#undef %s\n", vs);

} else if (t == TOK_push_macro) {
          fprintf(fp, "#pragma push_macro(\"%s\")\n", vs);

} else if (t == TOK_pop_macro) {
          fprintf(fp, "#pragma pop_macro(\"%s\")\n", vs);

}      pp_debug_tok = 0;

}

static int pp_need_space(int a, int b)  {
      return 'E' == a ? '+' == b || '-' == b          : '+' == a ? TOK_INC == b || '+' == b          : '-' == a ? TOK_DEC == b || '-' == b          : a >= TOK_IDENT || a == TOK_PPNUM ? b >= TOK_IDENT || b == TOK_PPNUM          : 0;

}

static int pp_check_he0xE(int t, const char *p)  {
      if (t == TOK_PPNUM && toup(strchr(p, 0)[-1]) == 'E')          return 'E';
      return t;

}

ST_FUNC int tcc_preprocess(TCCState *s1)  {
      BufferedFile **iptr;
      int token_seen, spcs, level;
      const char *p;
      char white[400];
        parse_flags = PARSE_FLAG_PREPROCESS                  | (parse_flags & PARSE_FLAG_ASM_FILE)                  | PARSE_FLAG_LINEFEED                  | PARSE_FLAG_SPACES                  | PARSE_FLAG_ACCEPT_STRAYS                 ;
