int find(int n, int i1, int a, int b, int op)  {
      int i, j;
      int c;
        if (stack_ptr >= 0) {
          stack_res[3*stack_ptr] = a;
          stack_op[stack_ptr] = op;
          stack_res[3*stack_ptr+1] = b;
          stack_res[3*stack_ptr+2] = n;
          if (n == result)              return 1;
          tab[i1] = n;

}        for(i=0;
i<nb_num;
i++) {
          for(j=i+1;
j<nb_num;
j++) {
              a = tab[i];
              b = tab[j];
              if (a != 0 && b != 0) {
                    tab[j] = 0;
                  stack_ptr++;
                    if (find(a + b, i, a, b, '+'))                      return 1;
                  if (find(a - b, i, a, b, '-'))                      return 1;
                  if (find(b - a, i, b, a, '-'))                      return 1;
                  if (find(a * b, i, a, b, '*'))                      return 1;
                  if (b != 0) {
                      c = a / b;
                      if (find(c, i, a, b, '/'))                          return 1;

}                    if (a != 0) {
                      c = b / a;
                      if (find(c, i, b, a, '/'))                          return 1;

}                    stack_ptr--;
                  tab[i] = a;
                  tab[j] = b;

}          
}      
}        return 0;

}

