int __aeabi_idiv(int numerator, int denominator)  {
      unsigned num, den;
      uidiv_t ret;
        if (numerator >= 0)          num = numerator;
      else          num = 0 - numerator;
      if (denominator >= 0)          den = denominator;
      else          den = 0 - denominator;
      ret = aeabi_uidivmod(num, den);
      if ((numerator & INT_MIN) != (denominator & INT_MIN)) /* signs differ */          ret.quot *= -1;
      return ret.quot;

}

