void __bt_init_dll(int bcheck)  {
      const char *s = all_names;
      void **p = (void**)&all_ptrs;
      do {
          *p = (void*)GetProcAddress(GetModuleHandle(NULL), (char*)s);
          if (NULL == *p) {
              char buf[100];
              sprintf(buf,                  "Error: function '%s()' not found in executable. "                  "(Need -bt or -b for linking the exe.)", s);
              if (GetStdHandle(STD_ERROR_HANDLE))                  fprintf(stderr, "TCC/BCHECK: %s\n", buf), fflush(stderr);
              else                  MessageBox(NULL, buf, "TCC/BCHECK", MB_ICONERROR);
              ExitProcess(1);

}          s = strchr(s,'\0') + 1, ++p;

} while (*s && (bcheck || p < &all_ptrs.__bound_ptr_add));

}

__declspec(dllexport)  void __bt_init(rt_context *p, int is_exe)  {
      __attribute__((weak)) int main();
      __attribute__((weak)) void __bound_init(void*, int);
        //fprintf(stderr, "__bt_init %d %p %p %p\n", is_exe, p, p->stab_sym, p->bounds_start), fflush(stderr);
        /* call __bound_init here due to redirection of sigaction */      /* needed to add global symbols */      if (p->bounds_start)   __bound_init(p->bounds_start, -1);
        /* add to chain */      rt_wait_sem();
      p->next = g_rc, g_rc = p;
      rt_post_sem();
      if (is_exe) {
          /* we are the executable (not a dll) */          p->top_func = main;
          set_exception_handler();

}  
}

__declspec(dllexport)  void __bt_exit(rt_context *p)  {
      struct rt_context *rc, **pp;
      __attribute__((weak)) void __bound_exit_dll(void*);
        //fprintf(stderr, "__bt_exit %d %p\n", !!p->top_func, p);
        if (p->bounds_start)   __bound_exit_dll(p->bounds_start);
        /* remove from chain */      rt_wait_sem();
      for (pp = &g_rc;
 rc = *pp, rc;
 pp = &rc->next)          if (rc == p) {
              *pp = rc->next;
              break;

}      rt_post_sem();

}

