static long double f3_zero(int sgn)  {
      long double f;
      u128_t x = {
 0, (uint64_t)sgn << 63 
};
      memcpy(&f, &x, 16);
      return f;

}

static long double f3_infinity(int sgn)  {
      long double f;
      u128_t x = {
 0, (uint64_t)sgn << 63 | 0x7fff000000000000 
};
      memcpy(&f, &x, 16);
      return f;

}

static long double f3_NaN(void)  {
      long double f;
  #if 0      // ARM's default NaN usually has just the top fraction bit set:      u128_t x = {
  0, 0x7fff800000000000 
};
  #else      // GCC's library sets all fraction bits:      u128_t x = {
 -1, 0x7fffffffffffffff 
};
  #endif      memcpy(&f, &x, 16);
      return f;

}

static int fp3_convert_NaN(long double *f, int sgn, u128_t mnt)  {
      u128_t x = {
 mnt.x0,                   mnt.x1 | 0x7fff800000000000 | (uint64_t)sgn << 63 
};
      memcpy(f, &x, 16);
      return 1;

}

static int fp3_detect_NaNs(long double *f,                             int a_sgn, int a_exp, u128_t a,                             int b_sgn, int b_exp, u128_t b)  {
      // Detect signalling NaNs:      if (a_exp == 32767 && (a.x0 | a.x1 << 16) && !(a.x1 >> 47 & 1))          return fp3_convert_NaN(f, a_sgn, a);
      if (b_exp == 32767 && (b.x0 | b.x1 << 16) && !(b.x1 >> 47 & 1))          return fp3_convert_NaN(f, b_sgn, b);
        // Detect quiet NaNs:      if (a_exp == 32767 && (a.x0 | a.x1 << 16))          return fp3_convert_NaN(f, a_sgn, a);
      if (b_exp == 32767 && (b.x0 | b.x1 << 16))          return fp3_convert_NaN(f, b_sgn, b);
        return 0;

}

static void f3_unpack(int *sgn, int32_t *exp, u128_t *mnt, long double f)  {
      u128_t x;
      memcpy(&x, &f, 16);
      *sgn = x.x1 >> 63;
      *exp = x.x1 >> 48 & 32767;
      x.x1 = x.x1 << 16 >> 16;
      if (*exp)          x.x1 |= (uint64_t)1 << 48;
      else          *exp = 1;
      *mnt = x;

}

static u128_t f3_normalise(int32_t *exp, u128_t mnt)  {
      int sh;
      if (!(mnt.x0 | mnt.x1))          return mnt;
      if (!mnt.x1) {
          mnt.x1 = mnt.x0;
          mnt.x0 = 0;
          *exp -= 64;

}      for (sh = 32;
 sh;
 sh >>= 1) {
          if (!(mnt.x1 >> (64 - sh))) {
              mnt.x1 = mnt.x1 << sh | mnt.x0 >> (64 - sh);
              mnt.x0 = mnt.x0 << sh;
              *exp -= sh;

}      
}      return mnt;

}

static u128_t f3_sticky_shift(int32_t sh, u128_t x)  {
    if (sh >= 128) {
        x.x0 = !!(x.x0 | x.x1);
        x.x1 = 0;
        return x;

}    if (sh >= 64) {
        x.x0 = x.x1 | !!x.x0;
        x.x1 = 0;
        sh -= 64;

}    if (sh > 0) {
        x.x0 = x.x0 >> sh | x.x1 << (64 - sh) | !!(x.x0 << (64 - sh));
        x.x1 = x.x1 >> sh;

}    return x;

}

static long double f3_round(int sgn, int32_t exp, u128_t x)  {
      long double f;
      int error;
        if (exp > 0) {
          x = f3_sticky_shift(13, x);

}      else {
          x = f3_sticky_shift(14 - exp, x);
          exp = 0;

}        error = x.x0 & 3;
      x.x0 = x.x0 >> 2 | x.x1 << 62;
      x.x1 = x.x1 >> 2;
        if (error == 3 || ((error == 2) & (x.x0 & 1))) {
          if (!++x.x0) {
              ++x.x1;
              if (x.x1 == (uint64_t)1 << 48)                  exp = 1;
              else if (x.x1 == (uint64_t)1 << 49) {
                  ++exp;
                  x.x0 = x.x0 >> 1 | x.x1 << 63;
                  x.x1 = x.x1 >> 1;

}          
}      
}        if (exp >= 32767)          return f3_infinity(sgn);
        x.x1 = x.x1 << 16 >> 16 | (uint64_t)exp << 48 | (uint64_t)sgn << 63;
      memcpy(&f, &x, 16);
      return f;

}

static long double f3_add(long double fa, long double fb, int neg)  {
      u128_t a, b, x;
      int32_t a_exp, b_exp, x_exp;
      int a_sgn, b_sgn, x_sgn;
      long double fx;
        f3_unpack(&a_sgn, &a_exp, &a, fa);
      f3_unpack(&b_sgn, &b_exp, &b, fb);
        if (fp3_detect_NaNs(&fx, a_sgn, a_exp, a, b_sgn, b_exp, b))          return fx;
        b_sgn ^= neg;
        // Handle infinities and zeroes:      if (a_exp == 32767 && b_exp == 32767 && a_sgn != b_sgn)          return f3_NaN();
      if (a_exp == 32767)          return f3_infinity(a_sgn);
      if (b_exp == 32767)          return f3_infinity(b_sgn);
      if (!(a.x0 | a.x1 | b.x0 | b.x1))          return f3_zero(a_sgn & b_sgn);
        a.x1 = a.x1 << 3 | a.x0 >> 61;
      a.x0 = a.x0 << 3;
      b.x1 = b.x1 << 3 | b.x0 >> 61;
      b.x0 = b.x0 << 3;
        if (a_exp <= b_exp) {
          a = f3_sticky_shift(b_exp - a_exp, a);
          a_exp = b_exp;

}      else {
          b = f3_sticky_shift(a_exp - b_exp, b);
          b_exp = a_exp;

}        x_sgn = a_sgn;
      x_exp = a_exp;
      if (a_sgn == b_sgn) {
          x.x0 = a.x0 + b.x0;
          x.x1 = a.x1 + b.x1 + (x.x0 < a.x0);

}      else {
          x.x0 = a.x0 - b.x0;
          x.x1 = a.x1 - b.x1 - (x.x0 > a.x0);
          if (x.x1 >> 63) {
              x_sgn ^= 1;
              x.x0 = -x.x0;
              x.x1 = -x.x1 - !!x.x0;

}      
}        if (!(x.x0 | x.x1))          return f3_zero(0);
        x = f3_normalise(&x_exp, x);
        return f3_round(x_sgn, x_exp + 12, x);

}

long double __addtf3(long double a, long double b)  {
      return f3_add(a, b, 0);

}

long double __subtf3(long double a, long double b)  {
      return f3_add(a, b, 1);

}

long double __multf3(long double fa, long double fb)  {
      u128_t a, b, x;
      int32_t a_exp, b_exp, x_exp;
