            p = fmt;
      for(;
;
) {
          c = *p;
          if (c == '\0')              break;
          p++;
          if (c == '%') {
              c = *p;
              switch(c) {
              case '\0':                  goto the_end;
              case 'd':                  i = va_arg(ap, int);
                  printf("%d", i);
                  break;
              case 'f':                  d = va_arg(ap, double);
                  printf("%f", d);
                  break;
              case 'l':                  ll = va_arg(ap, long long);
                  printf(LONG_LONG_FORMAT, ll);
                  break;
              case 'F':                  ld = va_arg(ap, LONG_DOUBLE);
                  printf("%Lf", ld);
                  break;

}              p++;

} else {
              putchar(c);

}      
}   the_end:      va_end(aq);
      va_end(ap);

}

