void cmp(long double a, long double b)  {
      u128_t ax = copy_ild(a);
      u128_t bx = copy_ild(b);
      int eq = (a == b);
      int ne = (a != b);
      int lt = (a < b);
      int le = (a <= b);
      int gt = (a > b);
      int ge = (a >= b);
        check(eq == 0 || eq == 1);
      check(lt == 0 || lt == 1);
      check(gt == 0 || gt == 1);
      check(ne == !eq && le == (lt | eq) && ge == (gt | eq));
      check(eq + lt + gt < 2);
        printf("cmp %016llx%016llx %016llx%016llx %d %d %d\n",             ax.x1, ax.x0, bx.x1, bx.x0, lt, eq, gt);

}

