          int i;
          for (i = -130;
 i <= 130;
 i++) {
              int s1 = (uint32_t)i % 3 < 1;
              int s2 = (uint32_t)i % 5 < 2;
              fadd(make(s1, 16384    , 0x502c065e4f71a65d, 0xd2f9bdb031f4f031),                   make(s2, 16384 + i, 0xae267395a9bc1033, 0xb56b5800da1ba448));

}      
}        // Check normalisation:      {
          uint64_t a0 = 0xc6bab0a6afbef5ed;
          uint64_t a1 = 0x4f84136c4a2e9b52;
          int ee[] = {
 0, 1, 10000 
};
          int e, i;
          for (e = 0;
 e < sizeof(ee) / sizeof(*ee);
 e++) {
              int exp = ee[e];
              fsub(make(0, exp, a1, a0), make(0, 0, 0, 0));
              for (i = 63;
 i >= 0;
 i--)                  fsub(make(0, exp, a1 | (uint64_t)1 << i >> 1, a0),                       make(0, exp, a1 >> i << i, 0));
              for (i = 63;
 i >=0;
 i--)                  fsub(make(0, exp, a1, a0 | (uint64_t)1 << i >> 1),                       make(0, exp, a1, a0 >> i << i));

}      
}        // Carry/overflow from rounding:      {
          fadd(make(0, 114, -1, -1), make(0, 1, 0, 0));
          fadd(make(0, 32766, -1, -1), make(0, 32653, 0, 0));
