        for (i = 0;
 i < 2;
 i++)          for (j = 0;
 j < 112;
 j++)              fmul(make(0, 16383, (uint64_t)1 << i, 0),                   make(0, 16383,                        j < 64 ? 0 : (uint64_t)1 << (j - 64),                        j < 64 ? (uint64_t)1 << j : 0));

