void smash(char *p, int n) {
    memset(p, 0, n);

}

int test1(int n) {
    int i;
    char *array_ptrs[LOOP_COUNT];
        for (i = 0;
 i < LOOP_COUNT;
 ++i) {
      char test[n];
      smash(test, n);
      array_ptrs[i] = test;

}        return (array_ptrs[0]-array_ptrs[LOOP_COUNT-1] < n) ? 0 : 1;

}

int test2(int n) {
    char *array_ptrs[LOOP_COUNT];
      int i = 0;
  loop:;
    char test[n];
    smash(test, n);
    if (i >= LOOP_COUNT)      goto end;
    array_ptrs[i] = test;
    ++i;
    goto loop;
    end:    smash(test, n);
    char test2[n];
    smash(test2, n);
    return (array_ptrs[0] - array_ptrs[LOOP_COUNT-1] < n) ? 0 : 1;

}

int test3(int n) {
    char test[n];
    smash(test, n);
    goto label;
  label:    smash(test, n);
    char test2[n];
    smash(test2, n);
    return (test-test2 >= n) ? 0 : 1;

}

